import { selectSnippet } from '../../requests/index';
import {
  pasteContentEditableSelectionWithHTML,
  replaceTextAreaSelection,
} from '../highlight/textarea';
import { getLocationFromOffset } from '../../utils/html-utils';
import { sendMessage, sendMessageAsync } from '../../utils/chrome-adapter';
import { applyCachedFocus, cacheFocus } from '../../utils/caret-utils';
import { getTopFrameHostname } from '../../utils/location';
import { SAPLING_ENV } from '../../globals';

let cachedFocus = null; // output of cacheFocus OR { isClipboard: true }
let cachedUpdatedFocusLength = null;

const styleKeys = [
  'font-family',
  'font-size',
  'font-style',
  'font-weight',
  'color',
  'line-height',
  'letter-spacing',
  'word-spacing',
];

const styleKeysCamel = [
  'fontFamily',
  'fontSize',
  'fontStyle',
  'fontWeight',
  'color',
  'lineHeight',
  'letterSpacing',
  'wordSpacing',
];

function getSnippetStyle(rootNode) {
  // return first set of hard coded font styles we find
  let fontStyle = {};
  for (let childNode of rootNode.childNodes) {
    if (childNode.style) {
      let { style } = childNode;
      for (let styleKey of styleKeysCamel) {
        if (style[styleKey] && style[styleKey] !== 'default') {
          fontStyle[styleKey] = style[styleKey];
        }
      }
    }
    if (Object.keys(fontStyle).length > 0) {
      return fontStyle;
    }
    const childFontStyle = getSnippetStyle(childNode);
    if (Object.keys(childFontStyle).length > 0) {
      return childFontStyle;
    }
  }
  return {};
}

export async function getStyleAndCopySnippetToClipboard(insertHTML, styleTransferFocusNode) {
  // figure out if snippet has hard coded font styles
  const parser = new DOMParser();
  const doc = parser.parseFromString(insertHTML, 'text/html');
  const snippetStyle = getSnippetStyle(doc.body);

  let fontStyle = {};
  // if snippet has no hard coded font style, use font style from local elements
  if (Object.keys(snippetStyle).length === 0) {
    let styleTransferNode;
    if (styleTransferFocusNode) {
      const selectionNode = styleTransferFocusNode.getRootNode().getSelection();
      if (selectionNode) {
        styleTransferNode = selectionNode.anchorNode || selectionNode.focusNode;
        while (styleTransferNode
               && styleTransferNode.nodeType !== Node.ELEMENT_NODE
               && styleTransferNode.parentElement) {
          styleTransferNode = styleTransferNode.parentElement;
        }
      }
    }
    styleTransferNode = styleTransferNode || styleTransferFocusNode;
    if (styleTransferNode) {
      let nodeStyle = window.getComputedStyle(styleTransferNode);
      for (let styleKey of styleKeys) {
        if (styleKey in nodeStyle) {
          fontStyle[styleKey] = nodeStyle[styleKey];
        }
      }
      if ('font-size' in nodeStyle) {
        if (!nodeStyle['font-size'].startsWith('0')) {
          fontStyle['font-size'] = nodeStyle['font-size'];
        }
      }
    }
  }
  await sendMessageAsync({ action: 'copy-snippet', html: insertHTML, fontStyle });
  return { ...snippetStyle, ...fontStyle };
}

/*
 * focusedElemeent: DOM node
 * mode: clipboard, insert, inline or undefined
 */
export function cacheSnippetFocus(focusedElement, data) {
  let mode = null;
  if (data) {
    mode = data.mode;
  }
  if (focusedElement.id === 'sapling-snippet-form') {
    return;
  }

  let focusDetails = cacheFocus(focusedElement);
  if (!focusDetails) {
    // either nothing is focused OR
    // an x-origin IFRAME with no contentDocument
    // we will rely on the content script in the IFRAME to do the injection
    cachedFocus = { isClipboard: true };
    return;
  }
  focusDetails.mode = mode;

  if (focusDetails.isContentEditable) {
    if (mode === 'inline' && focusDetails.range.startOffset > 0) {
      // 1 character adjustment for inline search key
      focusDetails.range = focusDetails.range.cloneRange();
      focusDetails.range.setStart(
        focusDetails.range.startContainer,
        focusDetails.range.startOffset - 1,
      );
    }
    cachedFocus = focusDetails;
    sendMessage({
      mode,
      action: 'snippet-focus-found',
    });
  } else if (focusDetails.isTextarea) {
    if (mode === 'inline' && focusDetails.start > 0) {
      // 1 character adjustment for inline search key
      focusDetails.start--;
    }
    cachedFocus = focusDetails;
    sendMessage({
      mode,
      action: 'snippet-focus-found',
    });
  } else {
    cachedFocus = focusDetails;
    cachedFocus.isClipboard = true;
    sendMessage({
      mode: 'clipboard',
      action: 'snippet-focus-found',
    });
  }
}

function computeUpdatedCachedFocus() {
  if (!cachedUpdatedFocusLength || !cachedFocus) {
    return;
  }
  if (cachedFocus.isContentEditable) {
    let cachedRange = cachedFocus.range;
    const rangeEnd = getLocationFromOffset(cachedRange.startContainer, 0, cachedUpdatedFocusLength + cachedRange.startOffset, null);
    cachedRange.setEnd(rangeEnd.domElement, rangeEnd.domOffset);
  } else if (cachedFocus.isTextarea) {
    const { start } = cachedFocus;
    cachedFocus.end = start + cachedUpdatedFocusLength;
  }
}

export function addSnippet() {
  if (!cachedFocus) {
    return;
  }
  let { element } = cachedFocus.element;
  let snippetString = $(element).html();
  // base364 encode html to pass into the snippet page
  snippetString = btoa(unescape(encodeURIComponent(snippetString)));
  let params = $.param({ preload: snippetString });
  let newSnippetUrl = `${SAPLING_ENV.WEBSITE_URL}/snippets/new?${params}`;
  window.open(newSnippetUrl);
}

function clearSnippetCallbackData() {
  cachedFocus = null;
  cachedUpdatedFocusLength = null;
}

export function resetSnippetFocus() {
  computeUpdatedCachedFocus();
  applyCachedFocus(cachedFocus);
  clearSnippetCallbackData();
}

export async function injectSnippet(snippet, currentQueryTerms, queryCount) {
  if (!cachedFocus) {
    return;
  }
  computeUpdatedCachedFocus();
  applyCachedFocus(cachedFocus);
  const { deepestIframe, element, mode, isClipboard } = cachedFocus;
  if (!deepestIframe) {
    const { range } = cachedFocus;
    // only insert from content script closest to the focused element
    if (cachedFocus.isContentEditable) {
      await sendMessageAsync({ action: 'cache-clipboard' });
      const style = await getStyleAndCopySnippetToClipboard(snippet.rich_text, element);
      pasteContentEditableSelectionWithHTML(range, snippet.plain_text, snippet.rich_text, element, style);
      sendMessage({ action: 'pop-cached-clipboard' });
      const eventType = mode === 'inline' ? 'inline' : 'insert';
      selectSnippet(snippet.id, eventType, currentQueryTerms, queryCount);
    } else if (cachedFocus.isTextarea) {
      const { start, end } = cachedFocus;
      const hostname = getTopFrameHostname();
      if (hostname.endsWith('figma.com')) {
        window.dispatchEvent(new CustomEvent(
          'sapling-figma-selection',
          {
            detail: { bufferLength: end - start },
          },
        ));
      }
      replaceTextAreaSelection(element, start, end, snippet.plain_text);
      let newEnd = start + snippet.plain_text.length;
      // set cursor to end of expansion
      element.setSelectionRange(newEnd, newEnd);
      const eventType = cachedFocus.mode === 'inline' ? 'inline' : 'insert';
      selectSnippet(snippet.id, eventType, currentQueryTerms, queryCount);
    }
  }

  if (isClipboard) {
    getStyleAndCopySnippetToClipboard(snippet.rich_text);
    selectSnippet(snippet.id, 'clipboard', currentQueryTerms, queryCount);
  }
  clearSnippetCallbackData();
}

export function updateSnippetCachedFocusLength(focusLength) {
  // this is called before every additional key stroke is registered.
  // the actual new range is computed before use
  cachedUpdatedFocusLength = focusLength;
}
