export function updateSaplingEmbedded(throttled=false) {
  $('#slidecheck').prop('disabled', isToggleDisabled());
  $('#slidecheck').prop('checked', isEnabledOnSite());

  $('#advanced-edits-slidecheck').prop('disabled', isToggleDisabled());
  $('#advanced-edits-slidecheck').prop('checked', isAdvancedEditsEnabledOnSite());

  $('#complete-slidecheck').prop('disabled', isCompleteToggleDisabled());
  $('#complete-slidecheck').prop('checked', isCompleteEnabledOnSite());

  $('#badge-slidecheck').prop('checked', isBadgeEnabledOnSite());
  $('#tone-slidecheck').prop('checked', isToneEnabledOnSite());
  $('#ai-detect-slidecheck').prop('checked', isAIDetectEnabledOnSite());
  $('#rephrase-slidecheck').prop('checked', isRephraseEnabledOnSite());

  $('#lang-select').val(getLang());

  if (throttled) {
    if (isUserAnonymous()) {
      $('#subscription-banner').html('Daily limit exceeded for <a href="https://sapling.ai/integrations" target="_blank">premium domain</a>.<br/> Do you need to <a href="https://sapling.ai/user/sign-in">sign in</a>?');
    } else {
      $('#subscription-banner').html('Daily limit exceeded for <a href="https://sapling.ai/integrations" target="_blank">premium domain</a>.<br/> Contact <a href="https://sapling.ai/contact" target="_blank">Sapling Sales</a> to subscribe.');
    }
    $('#subscription-banner').css({
      'font-weight': '500',
      border: '2px solid #555',
    });
    $('#subscription-banner').show();
    return;
  }

  if (isEnabledOnSite() || isCompleteEnabledOnSite()) {
    makeToolbarIconActive();
  } else {
    makeToolbarIconInactive();
  }
}

function onChangeSlideCheck() {
  const grammarIsChecked = $('#slidecheck').prop('checked');
  const completeIsChecked = $('#complete-slidecheck').prop('checked');
  const badgeIsChecked = $('#badge-slidecheck').prop('checked');
  const toneIsChecked = $('#tone-slidecheck').prop('checked');
  const aiDetectIsChecked = $('#ai-detect-slidecheck').prop('checked');
  const rephraseIsChecked = $('#rephrase-slidecheck').prop('checked');
  const advancedEditsIsChecked = $('#advanced-edits-slidecheck').prop('checked');

  setGrammarAndCompleteEnabledSettings(grammarIsChecked, completeIsChecked, badgeIsChecked, toneIsChecked, aiDetectIsChecked, rephraseIsChecked, advancedEditsIsChecked);

  if (grammarIsChecked || completeIsChecked) {
    makeToolbarIconActive();
  } else {
    makeToolbarIconInactive();
  }

  $('#refresh-warning').show(400);
}

function onChangeLang() {
  const lang = $('#lang-select').val();
  setLang(lang);
}

