function fetchSavedHtml() {
  sendMessageHandler('popup/GET_HTML', {}, (response) => {
    const { popupHtml } = response;
    if (popupHtml) {
      const text = $(`<span>${popupHtml}</span>`).text();
      if (text) {
        const block = document.getElementById('sapling-embedded-editable');
        block.innerHTML = popupHtml;
        $(block).focus();
      }
    }
  });
}

export function showSubscriptionBanner(jqueryEl) {
  if (!isSubscription()) {
    if (isUserEmailConfirmed()) {
      jqueryEl.html('<a target="_blank" href="https://sapling.ai/plans"><strong>Upgrade</strong></a> or sign in to see premium edits.');
      jqueryEl.css({
        'background-color': '#fff3cd',
        border: '0',
        color: '#856404',
      });
    } else if (!isUserAnonymous() && !isUserEmailConfirmed()) {
      jqueryEl.html('<strong>Please confirm your email using the link in email we sent you.</strong>');
      jqueryEl.css({
        'background-color': '#fff3cd',
        border: '0',
        color: '#856404',
      });
    } else {
      jqueryEl.html(`<strong><a target="_blank" href="${SAPLING_ENV.WEBSITE_URL}/user/register">Sign up</a></strong>`);
      jqueryEl.css({
        'background-color': '#fff3cd',
        border: '0',
        color: '#856404',
      });
    }
    jqueryEl.show();
  } else {
    const trialDaysLeft = getSubscriptionTrialDaysLeft();
    if (trialDaysLeft === null || trialDaysLeft > 30) {
      jqueryEl.html(`<strong>${getSubscriptionTier().toUpperCase()}</strong>`);
      jqueryEl.css({
        'background-color': '#deefde',
        border: '0',
      });
      $('#team-premium-banner').hide();
    } else {
      if (trialDaysLeft <= 1) {
        jqueryEl.html(`<a target="_blank" href="https://sapling.ai/plans"><strong${getSubscriptionTier().toUpperCase()}</strong></a> (<strong>1 day</strong> left)`);
      } else {
        jqueryEl.html(`<a target="_blank" href="https://sapling.ai/plans"><strong>${getSubscriptionTier().toUpperCase()}</strong></a> (<strong>${trialDaysLeft} days</strong> left)`);
      }
      jqueryEl.css({
        'background-color': '#fff3cd',
        color: '#856404',
        border: '1px solid #ffeeba',
      });
    }

    jqueryEl.show();
  }
}

function updateUserProperties() {
  if (isUserAnonymous()) {
    $('#login-signup-block').show();
    $('#sapling-embedded-editable').hide();
    $('#user-manager-form').show();
    $('#login-settings-row').show();
    $('#logout-settings-row').hide();
    $('#confirm-message').hide();
  } else if (!isUserEmailConfirmed()) {
    $('#confirm-message').show();
    $('#login-signup-block').hide();
    $('#sapling-embedded-editable').hide();
    $('#user-manager-form').show();
    $('#login-settings-row').show();
    $('#logout-settings-row').hide();
  } else {
    $('#confirm-message').hide();
    $('#login-signup-block').hide();
    if (isUserPopupEditorEnabled()) {
      $('#sapling-embedded-editable').show();
    } else {
      $('#sapling-embedded-editable').hide();
      $('#sapling-embedded-container').css('background-color', '#eee');
    }
    $('#user-manager-form').hide();
    $('#login-settings-row').hide();
    const userEmail = getUserEmail();
    if (userEmail.endsWith('@ba.com') || userEmail.endsWith('avios.com') || userEmail.endsWith('@iaggbs.com')) {
      $('#logout-settings-row').hide();
    } else {
      $('#logout-settings-row').show();
    }
  }

  showSubscriptionBanner($('#subscription-banner'));

  updateSaplingEmbedded();
}

function setUserUsage(usage) {
  if (usage.is_anonymous) {
    $('#user-usage').hide();
    return;
  }

  $('#user-usage-since').html(usage.since.substring(0, usage.since.length - 13));


  if (usage.accepts) {
    $('#user-usage-accepts').html(usage.accepts);
    $('#user-usage-ignores').html(usage.rejects || '0');
    $('#user-usage').show();
  } else {
    $('#user-usage').hide();
  }
}

export function getUserProperties(ignoreCache) {
  getUserPromise(ignoreCache).then(() => {
    updateUserProperties();
  });
  $('#user-usage').hide();
  getUserUsage((usage) => {
    setUserUsage(usage);
  }, (usage) => { $('#user-usage').hide(); });
}

function initUserLogin() {
  $('#logout-button').click(() => {
    logoutUser(() => {
      getUserProperties(true);
    }, () => {
      getUserProperties(true);
    });
  });

  getUserProperties(false);
}

