function setupEndpointInputListeners() {
  if (!isUserAnonymous() || !SAPLING_CONFIGURABLE_ENDPOINT) {
    return;
  }

  $('#endpoint-settings-row').css('display', 'flex');
  localStorageGet(['apiURL', 'websiteURL'], (obj) => {
    const { apiURL, websiteURL } = obj;
    if (apiURL) {
      if (SAPLING_CONFIGURABLE_ENDPOINT) {
        $('#apiurl').val(apiURL);
      } else {
        localStorageRemove('apiURL');
      }
    }
    if (websiteURL) {
      if (SAPLING_CONFIGURABLE_ENDPOINT) {
        $('#weburl').val(websiteURL);
      } else {
        localStorageRemove('websiteURL');
      }
    }
  });

  $('#apiurl').change((e) => {
    const apiURL = $(e.target).val();
    if (SAPLING_CONFIGURABLE_ENDPOINT) {
      localStorageSet({ apiURL });
    }
  });
  $('#weburl').change((e) => {
    const websiteURL = $(e.target).val();
    if (SAPLING_CONFIGURABLE_ENDPOINT) {
      localStorageSet({ websiteURL });
    }
  });
}

function onScratchPadContentMutation() {
  port.postMessage(scratchPad.innerHTML);
}
const MUTATION_WAIT_IN_MILLISECONDS = 200;
const onScratchPadContentMutationDebounced = _.debounce(
  onScratchPadContentMutation,
  MUTATION_WAIT_IN_MILLISECONDS,
  {
    leading: false,
    trailing: true,
  },
);

function initScratchPad() {
  scratchPad = document.getElementById('sapling-embedded-editable');
  port = chrome.runtime.connect();
  scratchPadObserver = new MutationObserver(onScratchPadContentMutationDebounced);
  const contentMutationCfg = {
    attributes: true,
    childList: true,
    characterData: true,
    subtree: true,
    characterDataOldValue: false,
  };
  scratchPadObserver.observe(scratchPad, contentMutationCfg);
}

let aiDetectProcessedText = '';
function initAIDetectPopup() {
  if (!SAPLING_ENV.AI_DETECT_ANYWHERE_EXTENSION) {
    return;
  }

  $('#sapling-embedded-editable').attr(
    'placeholder',
    'Type/paste some text here to check if it may have been generated by AI.'
  );
  $('#sapling-embedded-editable').attr('sapling-ignore', true);

  if (!isAccountPremium()) {
    $('#ai-detect-message').html(`<a href="https://sapling.ai/plans" target="_blank">[Pro Feature] Subscribe to enable</a>`);
    $('#ai-detect-message a').css('color', 'maroon');
    $('#ai-detect-message a').css('text-decoration', 'underline');
  }

  const getText = () => $('#sapling-embedded-editable')[0].innerText.trim();
  const updatePopupState = () => {
    if (!isAccountPremium()) {
      return;
    }

    const currentText = getText();

    if (currentText.split(' ').length >= 50) {
      $('#run-ai-detect').removeClass('disabled');
      $('#ai-detect-min-length').html('');
    } else {
      $('#ai-detect-min-length').html(`
        Minimum ${50 - currentText.split(' ').length} more word${50 - currentText.split(' ').length === 1 ? '' : 's'} needed.
      `);
      $('#run-ai-detect').addClass('disabled');
    }

    if (currentText != aiDetectProcessedText) {
      $('#ai-detect-message').html(``);
      $('#sapling-embedded-editable span').css('background-color', 'white');
    }
  }

  $('#sapling-embedded-editable').on('input', () => {
    updatePopupState();
  });
  setTimeout(() => updatePopupState(), 500);

  $('#run-ai-detect').on('click', () => {
    $('#ai-detect-message').css('color', 'black');
    $('#ai-detect-message').html(`Processing...`);
    $('#run-ai-detect').addClass('disabled');

    getAIDetectionScores(
      getText(),
      'ai-detect-popup',
      {language: 'en'}, // context
      ({data, success}) => {
        $('#run-ai-detect').removeClass('disabled');

        if (!success) {
          $('#ai-detect-message').css('color', 'red');
          $('#ai-detect-message').html(`An unknown error occurred.`);
          return;
        }

        let { score_string, score, text, hash } = data.aidetect;

        aiDetectProcessedText = text;

        score = score * 100;
        $('#ai-detect-message').css('color', percentToRGB(score));
        $('#ai-detect-message').html(`
          ${score.toFixed(2)}% AI generated
          <div style="display: inline-block;">
              <a href="https://sapling.ai/ai-content-detector/${hash}" target="__blank" style="color: #535f99;" title="Use to share a detailed link to this AI Detection analysis. Link will expire in 3 days.">
                [ certificate ]
              </a>
          </div>
        `);

        $('#sapling-embedded-editable').html(`${score_string}`);
      },
    );
  });
}

export default function initializeSaplingEmbedded() {
  if (SAPLING_ENV.AI_DETECT_ANYWHERE_EXTENSION) {
    $('#sapling-embedded-popup').addClass('is-ai-detect');
  }
  appendSaplingEmbedded();
  fetchSavedHtml();
  initPremiumBanners();
  initUserLogin();
  initPopupMessage();
  initNavigation();
  setupEndpointInputListeners();
  initScratchPad();
  initAIDetectPopup();
}
