export function isInIframe() {
  try {
    return window.self !== window.top;
  } catch (e) {
    // errors are thrown in cross-origin iframes
    return true;
  }
}

export function onIframeReady(iframe, successFn) {
  const DELAY = 500; // Hackety hack hack
  iframe.on('load', () => {
    setTimeout(successFn, DELAY);
  });

  // https://stackoverflow.com/questions/17158932/how-to-detect-when-an-iframe-has-already-been-loaded
  // Did not work well
  const firstFrame = iframe.get(0);
  try {
    if (firstFrame && firstFrame.contentWindow && firstFrame.contentWindow.document.readyState === 'complete') {
      setTimeout(successFn, DELAY);
    }
  } catch (e) {
    // errors are thrown in cross-origin iframes
    setTimeout(successFn, DELAY);
  }
}

/**
 * This is a leniant iframe positioning helper for SDK positining inside iframes
 */
export function getIframeBoundingRect(elem) {
  let elementWindow;
  let doc = elem.ownerDocument;
  elementWindow = doc.defaultView || doc.parentWindow;
  if (elementWindow.self === elementWindow.top) {
    return { x: 0, y: 0 };
  }
  let iframes = document.getElementsByTagName('iframe');
  for (let i = 0; i < iframes.length; i++) {
    if (iframes[i].contentWindow !== elementWindow) {
      continue;
    }
    let iframeRect = iframes[i].getBoundingClientRect();
    return { x: iframeRect.x, y: iframeRect.y };
  }
  return { x: 0, y: 0 };
}
