import { getLocationFromOffset } from '../utils/html-utils';
import getCursorTextOffset from '../utils/cursor-placement';

const maxSectionLength = 4000;
const sectioningThresholdLength = 2000;
const maxNumSections = 8;
const sectionRegexes = [
  new RegExp(`[\\s\\S]{0,${maxSectionLength}}</div>`, 'imy'),
  new RegExp(`[\\s\\S]{0,${maxSectionLength}}</p>`, 'imy'),
  new RegExp(`[\\s\\S]{0,${maxSectionLength}}<br ?/?>`, 'imy'),
  new RegExp(`[\\s\\S]{0,${maxSectionLength}}(\\.|\\?|!)(?=[^>]*(<|$))`, 'imy'),
];

function findEndOfSection(html, htmlOffset) {
  if ((html.length - htmlOffset) <= sectioningThresholdLength) {
    let sectionTextLength = $(`<span>${html}</span>`).text().length;
    return { sectionHtml: html, sectionTextLength, endIndex: html.length, skippedText: 0 };
  }

  let endIndex = htmlOffset + maxSectionLength;
  // Try to split at paragraphs, then sentences, then spaces, then anywhere.
  for (let i = 0; i < sectionRegexes.length; i += 1) {
    const regex = sectionRegexes[i];
    regex.lastIndex = htmlOffset;
    const match = html.match(sectionRegexes[i]);
    if (match) {
      endIndex = htmlOffset + match[0].length;
    }
  }

  // inline code is treated as text
  // multi-line code defines section boundaries
  // otherwise, server will not have correct state for if a section is code or not
  let codeStartIndex = html.indexOf('<code>', htmlOffset);
  while (codeStartIndex !== -1 && codeStartIndex < endIndex) {
    const codeEndIndex = html.indexOf('</code>', codeStartIndex);
    if (codeEndIndex >= 0) {
      const codeBlock = html.slice(codeStartIndex, codeEndIndex + 7);
      const containsNewline = /<br\s?\/?>/i.test(codeBlock);
      if (containsNewline) {
        // we drop multi-line code blocks. only include text up to the start of code block
        const sectionHtml = html.slice(htmlOffset, codeStartIndex);
        let sectionTextLength = $(`<span>${sectionHtml}</span>`).text().length;
        const skippedText = $(`<span>${codeBlock}</span>`).text().length;
        return { sectionHtml, sectionTextLength, endIndex: codeEndIndex + 7, skippedText };
      }
    }
    codeStartIndex = html.indexOf('<code>', codeStartIndex + 6);
  }

  const sectionHtml = html.slice(htmlOffset, endIndex);
  let sectionTextLength = $(`<span>${sectionHtml}</span>`).text().length;
  return { sectionHtml, sectionTextLength, endIndex, skippedText: 0 };
}

function hashString(str) {
  let hash = 0;
  let i = null;
  let chr = null;
  if (str.length === 0) return hash;
  for (i = 0; i < str.length; i += 1) {
    chr = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + chr; // eslint-disable-line no-bitwise
    hash |= 0; // eslint-disable-line no-bitwise
  }
  return hash;
}

async function createSections(fullHtml) {
  const sections = [];
  let htmlOffset = 0;
  let textOffset = 0; // excludes html tags

  let chunkCounter = 0;
  while (htmlOffset < fullHtml.length) {
    const { sectionHtml, sectionTextLength, endIndex, skippedText } = findEndOfSection(fullHtml, htmlOffset);
    sections.push({
      html: sectionHtml,
      htmlLength: sectionHtml.length,
      htmlOffset,
      htmlHash: hashString(sectionHtml),
      textOffset,
      textLength: sectionTextLength,
    });
    htmlOffset = endIndex;
    textOffset += sectionTextLength + skippedText;
    chunkCounter++;
    if (chunkCounter % 25 === 0) {
      // return to event loop to prevent taking too much time
      await new Promise(resolve => setTimeout(resolve, 50));
    }
  }

  return sections;
}

function getSectionTopOffset(parentContainer, section) {
  const start = getLocationFromOffset(
    parentContainer, 0, section.textOffset,
    parentContainer, false, false,
  );
  const range = document.createRange();
  range.selectNodeContents(start.domElement);
  return range.getBoundingClientRect().top;
}

function sortAndPrioritizeVisibleSections(sections, parentContainer) {
  // Use middle of browser window as heuristic for what is visible
  const visibleMiddle = window.innerHeight / 2;

  // Sort regions by proximity to visible heuristic
  sections.sort((a, b) => {
    const aTop = getSectionTopOffset(parentContainer, a);
    const bTop = getSectionTopOffset(parentContainer, b);
    return Math.abs(aTop - visibleMiddle) - Math.abs(bTop - visibleMiddle);
  });

  // Find edits for portion of document near cursor
  for (let k = 0; k < sections.length; k += 1) {
    const section = sections[k];
    if (k < maxNumSections) {
      section.priority = k;
    } else {
      section.priority = 100;
    }
  }
  return sections;
}

function sortAndPrioritizeSectionsAroundCursor(sections, cursorPos) {
  // Sort sections by proximity to cursor
  sections.sort((a, b) => Math.abs(a.textOffset - cursorPos) - Math.abs(b.textOffset - cursorPos));
  // Only find edits for portion of document near cursor
  for (let k = 0; k < sections.length; k += 1) {
    const section = sections[k];
    if (k < maxNumSections) {
      section.priority = k;
    } else {
      section.priority = 100;
    }
  }
  return sections;
}

export async function getSectionsAroundCursor(strippedInnerHtml, parentContainer) {
  const cursorPos = getCursorTextOffset(parentContainer) || 0;
  const sections = await createSections(strippedInnerHtml);
  if (sections.length === 0) {
    return [];
  }
  return sortAndPrioritizeSectionsAroundCursor(sections, cursorPos);
}

export async function getVisibleSections(strippedInnerHtml, parentContainer) {
  const sections = await createSections(strippedInnerHtml);
  if (sections.length === 0) {
    return [];
  }
  return sortAndPrioritizeVisibleSections(sections, parentContainer);
}

