import { postSettings, postLang, getUser } from '../requests/index';
import { syncStorageGet, syncStorageSet, sendMessage } from '../utils/chrome-adapter';
import { isTextInput } from '../utils/html-utils';
import { getTopFrameHostname } from '../utils/location';
import { SAPLING_ENV } from '../globals';

// global variable indicating if should be turned on for site
let isEnabledOnSiteLocally = null; // null means not set
let isCompleteEnabledOnSiteLocally = null; // null means not set
let isBadgeEnabledOnSiteLocally = null; // null means not set
let isToneEnabledOnSiteLocally = null; // null means not set
let isAIDetectEnabledOnSiteLocally = null; // null means not set
let isRephraseEnabledOnSiteLocally = null; // null means not set
let isAdvancedEditsEnabledOnSiteLocally = null; // null means not set
let lang = 'en'; // eslint-disable-line no-unused-vars
let isAnonymous = true;
let isEmailConfirmed = true;
let isSuggestFeatureEnabled = false;
let isPopupEditorEnabled = true;
let isSnippetsFeatureEnabled = true;
let isAdvancedEditsFeatureEnabled = false;
let isPowerButtonEnabled = true;
let subscriptionTier = 'free';
let subscriptionEndDatetime = null;
let fetchedUserProperties = false;
let userEmail = '';
let disableToggleOnSiteRemotely = null;
let isEnabledOnSiteRemotely = null;
let isSupportedOnSiteRemotely = null;
let disableBadgeOnSiteRemotely = null;
let completeShortcut = null;
let snippetShortcut = '\\';
let checkInputs = false;
let rephraseEnabled = false;
let toneEnabled = false;
let aiDetectEnabled = false;
let multiFillinEnabled = false;
let validLangs = ['en', 'zh', 'de', 'es', 'fr', 'he', 'it', 'jp', 'ja', 'ko',
  'pt', 'ar', 'nl', 'pl', 'ru', 'sv', 'tl', 'no', 'hi',
  'cs', 'da', 'el', 'et', 'fa', 'fi', 'hr', 'hu', 'id', 'lt',
  'lv', 'ro', 'sk', 'sl', 'sr', 'th', 'tr', 'uk', 'vi'];

export function fetchGrammarAndCompleteEnableSettings(resolve) {
  const hostname = getTopFrameHostname();
  const syncKey = `crioenabled${hostname}`;
  const completeSyncKey = `completeEnabled-${hostname}`;
  const badgeSyncKey = `badgeEnabled-${hostname}`;
  const toneSyncKey = `toneEnabled-${hostname}`;
  const aiDetectSyncKey = `aiDetectEnabled-${hostname}`;
  const rephraseSyncKey = `rephraseEnabled-${hostname}`;
  const advancedEditsSyncKey = `advancedEditsEnabled-${hostname}`;
  syncStorageGet([syncKey, completeSyncKey, badgeSyncKey, toneSyncKey, aiDetectSyncKey, rephraseSyncKey, advancedEditsSyncKey], (obj) => {
    isEnabledOnSiteLocally = obj[syncKey];
    isCompleteEnabledOnSiteLocally = obj[completeSyncKey];
    isBadgeEnabledOnSiteLocally = obj[badgeSyncKey];
    isToneEnabledOnSiteLocally = obj[toneSyncKey];
    isAIDetectEnabledOnSiteLocally = obj[aiDetectSyncKey];
    isRephraseEnabledOnSiteLocally = obj[rephraseSyncKey];
    isAdvancedEditsEnabledOnSiteLocally = obj[advancedEditsSyncKey];
    resolve();
  });
}

export function setGrammarAndCompleteEnabledSettings(
      isGrammarEnabled,
      isCompleteEnabled,
      isBadgeEnabled,
      isToneEnabled,
      isAIDetectEnabled,
      isRephraseEnabled,
      isAdvancedEditsEnabled,
  ) {
  const hostname = getTopFrameHostname();
  const syncKey = `crioenabled${hostname}`;
  const completeSyncKey = `completeEnabled-${hostname}`;
  const badgeSyncKey = `badgeEnabled-${hostname}`;
  const toneSyncKey = `toneEnabled-${hostname}`;
  const aiDetectSyncKey = `aiDetectEnabled-${hostname}`;
  const rephraseSyncKey = `rephraseEnabled-${hostname}`;
  const advancedEditsSyncKey = `advancedEditsEnabled-${hostname}`;
  const setting = {};

  setting[syncKey] = isGrammarEnabled;
  setting[completeSyncKey] = isCompleteEnabled;
  setting[badgeSyncKey] = isBadgeEnabled;
  setting[toneSyncKey] = isToneEnabled;
  setting[aiDetectSyncKey] = isAIDetectEnabled;
  setting[rephraseSyncKey] = isRephraseEnabled;
  setting[advancedEditsSyncKey] = isAdvancedEditsEnabled;

  let isEnabled = isGrammarEnabled || isCompleteEnabled;
  let observersOn = false;
  let observersOff = false;
  if (isEnabled) {
    if (!isEnabledOnSiteLocally && !isCompleteEnabledOnSiteLocally) {
      observersOn = true;
    }
  } else if (isEnabledOnSiteLocally || isCompleteEnabledOnSiteLocally) {
    observersOff = true;
  }
  syncStorageSet(setting, () => {
    sendMessage({
      hostname,
      observersOn,
      observersOff,
      action: 'background/GRAMMAR_OR_COMPLETE_TOGGLED',
    });
  });
  postSettings(isGrammarEnabled, isCompleteEnabled);
}

export function getUserPromise(ignoreCache) {
  return new Promise((resolve) => {
    getUser(ignoreCache, (user) => {
      setUserProperties(user);
      resolve();
    }, () => {
      resolve();
    });
  });
}

export function setUserProperties(user) {
  isAnonymous = user.is_anonymous;
  isEmailConfirmed = user.email_confirmed;
  if (Object.hasOwn(user, 'email')) {
    userEmail = user.email;
  } else {
    userEmail = '';
  }
  isSuggestFeatureEnabled = user.suggest;
  completeShortcut = user.shortcuts.complete;
  snippetShortcut = user.shortcuts.snippet;
  isSnippetsFeatureEnabled = user.snippets;
  isAdvancedEditsFeatureEnabled = user.annotations;
  isPowerButtonEnabled = user.power_button;
  lang = user.lang;
  if (Object.hasOwn(user, 'popup_editor')) {
    isPopupEditorEnabled = user.popup_editor;
  }
  if (Object.hasOwn(user, 'check_inputs')) {
    checkInputs = user.check_inputs;
  }
  if (Object.hasOwn(user, 'rephrase')) {
    rephraseEnabled = user.rephrase;
  }
  if (Object.hasOwn(user, 'tone')) {
    toneEnabled = user.tone;
  }
  if (Object.hasOwn(user, 'ai_detect')) {
    aiDetectEnabled = user.ai_detect;
  }
  if (Object.hasOwn(user, 'multiFillin')) {
    multiFillinEnabled = user.multiFillin;
  }

  const { subscription } = user;
  if (subscription) {
    subscriptionTier = subscription.tier;
    subscriptionEndDatetime = subscription.end_datetime;
  }
  fetchedUserProperties = true;
}

export function setSiteSettings(settings) {
  for (let idx = 0; idx < settings.length; idx += 1) {
    const setting = settings[idx];
    const {
      disable_toggle: disableToggle,
      disable_badge: disableBadge,
      enabled,
      supported,
    } = setting;
    disableToggleOnSiteRemotely = disableToggleOnSiteRemotely || disableToggle;
    disableBadgeOnSiteRemotely = disableBadgeOnSiteRemotely || disableBadge;
    isSupportedOnSiteRemotely = isSupportedOnSiteRemotely || supported;
    isEnabledOnSiteRemotely = isEnabledOnSiteRemotely || enabled;
  }
}

export function didFetchUserProperties() {
  return fetchedUserProperties;
}

export function isUserAnonymous() {
  return isAnonymous;
}

export function isUserPopupEditorEnabled() {
  return isPopupEditorEnabled;
}

export function isUserEmailConfirmed() {
  return isEmailConfirmed;
}

export function isSubscription() {
  return subscriptionTier !== 'free';
}

export function getSubscriptionTier() {
  return subscriptionTier;
}

export function areSuggestionsEnabled() {
  return isSuggestFeatureEnabled;
}

export function isBadgePowerButtonEnabled() {
  return isPowerButtonEnabled;
}

export function areSnippetsEnabled() {
  return isSnippetsFeatureEnabled;
}

export function areAdvancedEditsEnabled() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return Sapling.advancedEdits.advanced_edits;
  }
  return isAdvancedEditsFeatureEnabled;
}

export function getCompleteShortcut() {
  return completeShortcut;
}

export function getSnippetShortcut() {
  return snippetShortcut;
}

export function getSubscriptionTrialDaysLeft() {
  if (!subscriptionEndDatetime) {
    return subscriptionEndDatetime;
  }

  const day = 24 * 60 * 60 * 1000;
  const currentDate = new Date();
  const endDate = new Date(subscriptionEndDatetime);
  if (endDate.getTime() - currentDate.getTime() < 0) {
    return null;
  }

  const numDays = Math.round(Math.abs((endDate.getTime() - currentDate.getTime()) / day));
  return Math.max(numDays, 1);
}

export function isCheckableTextElement(el) {
  const tagName = el.tagName.toLowerCase();
  if (tagName === 'textarea' ||
      tagName === 'lightning-textarea' ||
      (checkInputs && isTextInput(el))) {
    return true;
  }
  return false;
}

export function isSupportedHost() {
  return isSupportedOnSiteRemotely !== false;
}

export function isEnabledOnSite() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return true;
  } else if (isEnabledOnSiteRemotely !== null) {
    return isEnabledOnSiteRemotely;
  }
  if (isSubscription() && isEnabledOnSiteLocally === true) {
    return true;
  }
  return isEnabledOnSiteLocally !== false && isSupportedHost();
}

// This controls if advanced edits show by default.
export function isAdvancedEditsEnabledOnSite() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return true;
  } else if (isEnabledOnSiteRemotely !== null) {
    return isEnabledOnSiteRemotely;
  }
  if (isSubscription() && isAdvancedEditsEnabledOnSiteLocally === true) {
    return true;
  }
  return isAdvancedEditsEnabledOnSiteLocally !== false && isSupportedHost();
}

export function isEnabledOnElement(element) {
  if (SAPLING_ENV.MODE === 'SDK') {
    return true;
  } else if (!isEnabledOnSite()) {
    return false;
  } else if ($(element).attr('sapling-ignore') === 'true') {
    return false;
  } else if ($(element).attr('aria-label') === 'To' ||
      $(element).attr('aria-label') === 'Cc' ||
      $(element).attr('aria-label') === 'Bcc') {
    return false;
  }
  const hostname = getTopFrameHostname();
  if (hostname.includes('github.com') && $(element).attr('spellcheck') === 'false') {
    return false;
  }
  return true;
}

export function isCompleteEnabledOnSite() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return Sapling.autocomplete;
  }

  const hostname = getTopFrameHostname();
  if (hostname.includes('sapling.ai')) {
    return true;
  }
  if (isEnabledOnSiteRemotely !== null) {
    return isEnabledOnSiteRemotely;
  }
  if (isSubscription() && isCompleteEnabledOnSiteLocally !== false) {
    return true;
  }
  return false;
}

export function isCompleteEnabledOnElement(element) {
  if (!isCompleteEnabledOnSite()) {
    return false;
  } else if (SAPLING_ENV.MODE !== 'SDK' && $(element).attr('sapling-ignore') === 'true') {
    return false;
  } else if ($(element).is('input') &&
        ($(element).attr('autocomplete') === 'off' ||
         $(element).attr('autocomplete') === 'false')) {
    return false;
  }
  return true;
}

export function isToggleDisabled() {
  if (disableToggleOnSiteRemotely !== null) {
    return disableToggleOnSiteRemotely;
  }
  return !(isSupportedHost() || isEnabledOnSite() || isCompleteEnabledOnSite() || isSubscription());
}

export function isCompleteToggleDisabled() {
  return !isSubscription();
}

export function isRephraseEnabled() {
  //return isSubscription();
  return isRephraseEnabledOnSite() && rephraseEnabled;
}

export function isRephraseBackendEnabled() {
  return rephraseEnabled;
}

export function isRephraseEnabledOnSite() {
  if (isRephraseEnabledOnSiteLocally === false) {
    return false;
  }
  return true;
}

export function isAIDetectEnabled() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return true;
  }

  return isAccountPremium() && aiDetectEnabled && isAIDetectEnabledOnSite();
}

export function isAIDetectEnabledOnSite() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return false;
  }

  if (isAIDetectEnabledOnSiteLocally === false) {
    return false;
  }

  return true;
}

export function isAIDetectBackendEnabled() {
  return isAccountPremium() && aiDetectEnabled;
}

export function isToneEnabled() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return Sapling.toneEnabled;
  }

  return isToneEnabledOnSite() && isAccountPremium() && toneEnabled;
}

export function isMultiFillinEnabled() {
  return multiFillinEnabled;
}

export function isToneBackendEnabled() {
  return isAccountPremium() && toneEnabled;
}

export function isToneEnabledOnSite() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return false;
  }

  if (isToneEnabledOnSiteLocally === false) {
    return false;
  }

  return true;
}

export function isBadgeEnabledOnSite() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return Sapling.statusBadge;
  }

  if (isBadgeEnabledOnSiteLocally === false || disableBadgeOnSiteRemotely === true) {
    return false;
  }
  return true;
}

export function isCheckInputsEnabled() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return true;
  }
  return checkInputs;
}

export function showToggleDisabledTag() {
  return disableToggleOnSiteRemotely === true;
}

export function showPremiumOnlyTag() {
  return !isSubscription();
}

export function setLang(newLang) {
  if (validLangs.includes(newLang)) {
    lang = newLang;
  }
  postLang(lang);
}

export function getLang() {
  return lang;
}

export function getUserEmail() {
  return userEmail;
}

export function isAccountPremium() {
  if (isUserAnonymous()) {
    return false;
  } else if (!isUserEmailConfirmed()) {
    return false;
  } else if (!isSubscription()) {
    return false;
  }
  return true;
}
