// Utilities for working with shadow DOM

import { isTextInput } from './html-utils';

export function getDeepActiveElementThroughIframes(focusedElement) {
  // recurse through iframe(s) to get to the actual focus element
  let deepestIframe = null;
  let deepFocusedElement = focusedElement;
  while (deepFocusedElement && deepFocusedElement.nodeName === 'IFRAME') {
    deepestIframe = deepFocusedElement;
    let { contentDocument } = deepFocusedElement;
    if (!contentDocument) {
      contentDocument = $(deepFocusedElement).contents()[0];
    }
    if (!contentDocument) {
      return {
        deepestIframe: null,
        deepFocusedElement: null,
      };
    }
    deepFocusedElement = getDeepActiveElement(contentDocument);
  }

  return {
    deepestIframe,
    deepFocusedElement,
  };
}

export function isDescendant(parent, child) {
  let node = child.parentNode || child.host;
  while (node != null) {
    if (node === parent) {
      return true;
    }
    node = node.parentNode || node.host;
  }
  return false;
}

function isShadow(el) {
  if (el.shadowRoot) return true;
  return false;
}

export function getShadowRoot(el) {
  // returns the deepest shadow root of element, if exists
  let parent = (el && el.parentNode);
  while (parent) {
    if (parent.toString() === '[object ShadowRoot]') {
      return parent;
    }
    parent = parent.parentNode;
  }
  return false;
}

export function elIsTextArea(el, includeInputs = false) {
  return el.tagName === 'TEXTAREA' || (includeInputs && isTextInput(el));
}

export function elIsContentEditable(el) {
  return el.isContentEditable && el.tagName !== 'TEXTAREA';
}

function shadowQueryHelper(nodes, queryFunc, resultList, inShadow) {
  for (let i = 0, el; el = nodes[i]; ++i) {
    if (queryFunc(el) && inShadow) {
      resultList.push(el);
    }
    if (isShadow(el)) {
      shadowQueryHelper(el.shadowRoot.querySelectorAll('*'), queryFunc, resultList, true);
    }
  }
}

export function shadowQuery(queryFunc) {
  let resultList = [];
  let nodes = document.querySelectorAll('*');
  shadowQueryHelper(nodes, queryFunc, resultList, false);
  return resultList;
}

export function shadowElementsThatContain(qel) {
  return shadowQuery(el => el.contains(qel));
}

export function documentContains(qel) {
  let doc = qel.ownerDocument || document;
  if (doc.contains(qel)) return true;
  let els = shadowElementsThatContain(qel);
  return els.length > 0;
}

export function deepFind(query) {
  let initList = $.find(query);
  let shadowList = shadowQuery(el => $(el).is(query));
  return initList.concat(shadowList);
}

export function getDeepTarget(event) {
  let target = event.path || (event.composedPath && event.composedPath());
  if (target.length < 1) {
    return event.target;
  }
  return target[0];
}

export function getDeepActiveElement(activeDocument) {
  let activeEl = null;
  if (activeDocument.hasFocus && activeDocument.hasFocus()) {
    activeEl = activeDocument.activeElement;
    while (isShadow(activeEl)) activeEl = activeEl.shadowRoot.activeElement;
  }
  return activeEl;
}
