// We cache results that should be shown and propagate the changes
// to the frontend overlay.
// {
//   containerId: {
//     shadowHost: (domElement),
//     shadowHostObserver: (MutationObserver),
//     badge: Badge instance, holding badge domElement,
//     overlayDomElement: (domElement),
//     annotationsOverlay: AnnotationsOverlay instance, holding domElement,
//     containerDomElement: (domElement),
//     textAreaId: uuid,
//     edits: {
//       editId: {  # TODO: we may need to self-generate this
//         edit: {},
//         editRange: {},
//         domElements: [(domElement)],
//         isHover: true/false,
//       }
//     }
//   }
// }
const saplingIdToInfo = {};

// {
//   containerId: (id),
//   editId: (id),
// }
let hoveredElement = null;

// containerId -> observer
let abolutePositionParentObservers = {};

// Get edit count to display total in toolbar
export function getEditCountForOverlay(parentContainer) {
  const containerId = getContainerId(parentContainer);
  if (containerId) {
    const parentContainerInfo = saplingIdToInfo[containerId];
    if (parentContainerInfo) {
      return Object.keys(parentContainerInfo.edits).length;
    }
  }

  return 0;
}

export function removeOverlay(containerId) {
  let containerInfo = saplingIdToInfo[containerId];
  if (!containerInfo) return;
  let {
    shadowHost,
    badge,
    annotationsOverlay,
    toneOverlay,
    aiDetectOverlay,
  } = containerInfo;
  if (shadowHost) {
    shadowHost.remove();
  }
  if (badge) {
    badge.removeUIElements();
  }
  if (annotationsOverlay) {
    annotationsOverlay.removeUIElements();
  }
  if (toneOverlay) {
    toneOverlay.removeUIElements();
  }
  if (aiDetectOverlay) {
    aiDetectOverlay.removeUIElements();
  }
}

