function onAttributeMutation(parentContainer, mutationsList) {
  for (let mutation of mutationsList) {
    if ($(mutation.target).hasClass('notion-text-block')) {
      initOrUpdateContainerOverlay(parentContainer);
      return;
    }
  }
}

function initParentAttributeMutationObserver(containerId, parentContainer, nonstaticParent) {
  // notion.so toggles content-editables erratically between position:relative and position:static
  // as the user moves the mouse. This causes first non-static parent of the overlay to change and
  // the edit overlay to jump around
  // We listen to style changes and reposition the overlay accordingly
  // If confident with performance, it is reasonable to turn this on for all websites
  if (!nonstaticParent) {
    return;
  } else if (abolutePositionParentObservers[containerId]) {
    return;
  }

  const mutationCfg = {
    attributes: true,
    attributeFilter: ['style'],
    childList: true,
    subtree: true,
  };
  const observer = new MutationObserver((mutationsList) => {
    onAttributeMutation(parentContainer, mutationsList);
  });
  observer.observe(nonstaticParent, mutationCfg);
  abolutePositionParentObservers[containerId] = observer;
  saveObservers(containerId, parentContainer, false, 'mutationObservers', observer);
}

export function initAIDetectContainerOverlay(parentContainer) {
  const containerId = getContainerId(parentContainer);
  if (!containerId) {
    return;
  }
  let containerInfo = saplingIdToInfo[containerId] || { edits: {} };
  let { shadowHost, badge } = containerInfo;

  if (!containerInfo.aiDetectOverlay) {
    containerInfo.aiDetectOverlay = new AIDetectOverlay(shadowHost, containerId, badge);
    containerInfo.aiDetectOverlay.createUIElements();
  }

  return {containerId, aiDetectOverlay: containerInfo.aiDetectOverlay};
}

// TODO Refactor and comment this
export function initOrUpdateContainerOverlay(parentContainer) {
  if (SAPLING_ENV.MODE !== 'SDK' && parentContainer.hasAttribute('sapling-ignore')) {
    return;
  }
  // Avoid Editor.js
  if ($(parentContainer).parents('.codex-editor').length) {
    return;
  }

  const containerId = getContainerId(parentContainer);
  if (!containerId) {
    return;
  }
  let containerInfo = saplingIdToInfo[containerId] || { edits: {} };
  let { shadowHost, badge } = containerInfo;

  if (shadowHost && !documentContains(shadowHost)) {
    shadowHost.remove();
    shadowHost = null;
  }
  if (!shadowHost) {
    let siblingElement = parentContainer;
    if ($(parentContainer).is('td') && parentContainer.parentNode) {
      // special case: putting elements as siblings to td
      // causes table format issues so we put them on the parent level
      // Because multiple content-editables can share a single parent, we
      // don't run the sibling deletion loop.
      siblingElement = parentContainer.parentNode.parentNode;
    } else {
      // remove existing overlays
      let { nextSibling } = siblingElement;
      while (nextSibling &&
          nextSibling.nodeType === Node.ELEMENT_NODE &&
          nextSibling.getAttribute('is-sapling-overlay')) {
        let nodeToRemove = nextSibling;
        nextSibling = nextSibling.nextSibling;
        nodeToRemove.remove();
      }
    }

    // create new overlay
    shadowHost = document.createElement('div');
    shadowHost.setAttribute('is-sapling-overlay', true);
    $(shadowHost).css({ 'pointer-events': 'none' });
    $(siblingElement).after(shadowHost);
    shadowHost.attachShadow({ mode: 'open' });
    let overlayDomElement = document.createElement('div');
    $(overlayDomElement).addClass('tag-container');
    $(overlayDomElement).css({ position: 'absolute' });
    $(shadowHost.shadowRoot).prepend(editCSS);
    shadowHost.shadowRoot.appendChild(overlayDomElement);

    if (!badge) {
      badge = new Badge();
      badge.createUIElements(parentContainer, shadowHost, containerId, containerInfo);
    }
    containerInfo.badge = badge;

    if (!containerInfo.annotationsOverlay && areAdvancedEditsEnabled()) {
      containerInfo.annotationsOverlay = new AnnotationsOverlay(containerId, shadowHost);
      containerInfo.annotationsOverlay.createUIElements();
    }

    if (!containerInfo.toneOverlay && isToneEnabled()) {
      containerInfo.toneOverlay = new ToneOverlay(shadowHost, containerId, badge);
      containerInfo.toneOverlay.createUIElements();
    }

    containerInfo.shadowHost = shadowHost;
    containerInfo.overlayDomElement = overlayDomElement;
    containerInfo.containerDomElement = parentContainer;
    containerInfo.textAreaId = getTextAreaId(parentContainer);

    observeOverlayDomRemoval(containerId, containerInfo);
    if (getTopFrameHostname() === 'notion.so') {
      let { nonstaticParent } = getCSSOverlayForElement(parentContainer);
      initParentAttributeMutationObserver(containerId, parentContainer, nonstaticParent);
    }
  } // end init shadowhost

  let { frameDimensions } = getCSSOverlayForElement(parentContainer);
  const effectiveZIndex = getEffectiveZIndex(parentContainer);
  // Use effective z-index + 1 to appear on top, with a reasonable minimum of 100
  const badgeZIndex = Math.max(effectiveZIndex + 1, 100);
  $(shadowHost).css({
    overflow: 'hidden',
    'padding-bottom': '2px', // space for edit span
    'z-index': badgeZIndex,
    position: frameDimensions.position,
    left: frameDimensions.left,
    top: frameDimensions.top,
    height: frameDimensions.height, // facebook requires this 2px buffer
    width: frameDimensions.width,
  });
  if (containerInfo.annotationsOverlay) {
    containerInfo.annotationsOverlay.queryAndUpdate();
  }
  if (containerInfo.toneOverlay) {
    containerInfo.toneOverlay.queryAndUpdate();
  }
  if (containerInfo.aiDetectOverlay) {
    containerInfo.aiDetectOverlay.queryAndUpdate();
  }
  copyTextFormat(parentContainer, shadowHost);
  saplingIdToInfo[containerId] = containerInfo;
  addOverlay(containerId, containerInfo);
}

function zoomClientRect(clientRect, parentContainerInfo) {
  return clientRect;

  // currently unneeded
  const isFigma =
    $(parentContainerInfo.containerDomElement).attr('sapling-figma-text-id') != null;
  if (!isFigma) {
    return clientRect;
  }

  const zoom = $(parentContainerInfo.containerDomElement).data('figma-zoom');
  return {
    ...clientRect,
    left: clientRect.left * zoom,
    right: clientRect.right * zoom,
    top: clientRect.top * zoom,
    bottom: clientRect.bottom * zoom,
    width: clientRect.width * zoom,
    height: clientRect.height * zoom,
  };
}

// TODO Refactor and comment this
function getRangeClientRects(editRange, parentContainerInfo) {
  const overlayDomElement = parentContainerInfo.shadowHost;
  const overlayClientRect = overlayDomElement.getBoundingClientRect();

  const finalRects = [];
  const clientRects = editRange.getClientRects();
  for (let i = 0; i < clientRects.length; i += 1) {
    const clientRect = zoomClientRect(clientRects[i], parentContainerInfo);
    finalRects.push({
      left: clientRect.left - overlayClientRect.left,
      top: clientRect.top - overlayClientRect.top,
      height: clientRect.height,
      width: clientRect.width,
    });
  }

  return finalRects;
}

// Get background image for edits
function getBackgroundImage(edit, isHover) {
  let isPremium = edit.premium;
  if (edit.category in ANNOTATION_STYLES) {
    let key = 'background-image';
    if (edit.category === 'hard_to_read' && edit.difficulty === 'hard') {
      key = 'background-image2';
    }
    return ANNOTATION_STYLES[edit.category][key];
  }
  if (isPremium) {
    if (isHover) {
      return 'linear-gradient(to right, rgba(255, 214, 51, 0.15), rgba(255, 214, 51, 0.15))';
    }
    return 'linear-gradient(to right, #eeb122, #ffd633)';
  }

  if (isHover) {
    return 'linear-gradient(to right, rgba(255, 0, 0, 0.15), rgba(255, 0, 0, 0.15))';
  }

  return 'linear-gradient(to right, #ff0000, #ff0000)';
}

// Get background color for edits
function getBackgroundColor(edit, isHover) {
  let isPremium = edit.premium;
  if (isHover) {
    if (edit.category in ANNOTATION_STYLES) {
      let key = 'background-color';
      if (edit.category === 'hard_to_read' && edit.difficulty === 'hard') {
        key = 'background-color2';
      }
      return ANNOTATION_STYLES[edit.category][key];
    } else if (isPremium) {
      return '#eeb122';
    }
    return '#ff0000';
  }

  return '';
}

export function applyTagCSS(editInfo, isHover) {
  if (editInfo.edit.fillin) return;
  const editInfoTemp = editInfo;
  editInfoTemp.isHover = isHover;
  let tagCSS = {
    opacity: 0.85,
    transition: '',
    'background-color': getBackgroundColor(editInfo.edit, isHover),
    'background-image': getBackgroundImage(editInfo.edit, isHover),
    '-webkit-transition': '',
    '-ms-transition': '',
  };

  if (isHover) {
    tagCSS = {
      'background-color': getBackgroundColor(editInfo.edit, isHover),
      'background-image': getBackgroundImage(editInfo.edit, isHover),
    };
    if (!editInfo.edit.category) {
      tagCSS['opacity'] = 0.15;
      tagCSS['transition'] = 'background-color 200ms linear';
      tagCSS['-webkit-transition'] = 'background-color 200ms linear';
      tagCSS['-ms-transition'] = 'background-color 200ms linear';
    }
  }
  editInfo.domElements.forEach((domElement) => {
    $(domElement).css(tagCSS);
  });
}

function tagFocused(saplingSpan, containerId, editId) {
  $(saplingSpan).on('keyup', (e) => {
    if (e.key === 'Enter') {
      const containerInfo = saplingIdToInfo[containerId];
      const { edits, overlayDomElement, annotationsOverlay } = containerInfo;
      if (!edits) {
        return;
      }
      const editInfo = edits[editId];
      e.preventDefault();
      e.stopPropagation();
      setHoveredElement(editId, containerId, editInfo, annotationsOverlay, overlayDomElement, true);
    }
  });
}

function tagBlurred(saplingSpan, containerId, editId) {
  $(saplingSpan).off('keyup');
}

function updateTagOverlay(containerId, editId) {
  const parentContainerInfo = saplingIdToInfo[containerId];
  if (!parentContainerInfo) return;
  const editInfo = parentContainerInfo.edits[editId];
  const { editRange } = parentContainerInfo.edits[editId];

  if (editInfo.edit.category && !parentContainerInfo.annotationsOverlay) {
    return;
  }

  // get new client rects
  // use shadow host as parentContainerInfo.overlayDomElement has position 0,0 in firefox
  const clientRects = getRangeClientRects(
    editRange,
    parentContainerInfo,
  );

  // relatively rare case when client rect count changes
  const spansToAdd = clientRects.length - editInfo.domElements.length;
  if (spansToAdd > 0) {
    for (let i = 0; i < spansToAdd; i++) {
      const saplingSpan = document.createElement('span');
      saplingSpan.classList.add('sapling-edit');
      saplingSpan.setAttribute('tabindex', '0');
      saplingSpan.setAttribute('aria-label', `Sapling Edit for: ${editInfo.edit.originalText}. Replacement: ${editInfo.edit.replacementText}.`);
      saplingSpan.setAttribute('aria-keyshortcuts', 'Enter');
      saplingSpan.setAttribute('role', 'button');
      saplingSpan.setAttribute('sapling-edit-id', editId);
      saplingSpan.setAttribute('sapling-container-id', containerId);
      saplingSpan.onfocus = () => tagFocused(saplingSpan, containerId, editId);
      saplingSpan.onblur = () => tagBlurred(saplingSpan, containerId, editId);
      parentContainerInfo.overlayDomElement.appendChild(saplingSpan);
      editInfo.domElements.push(saplingSpan);
    }
  } else if (spansToAdd < 0) {
    for (let i = 0; i > spansToAdd; i--) {
      const spanToRemove = editInfo.domElements.pop();
      spanToRemove.remove();
    }
  }

  // update existing rectangles
  for (let i = 0; i < clientRects.length; i += 1) {
    const clientRect = clientRects[i];
    const saplingSpan = editInfo.domElements[i];
    $(saplingSpan).css({
      left: clientRect.left,
      top: clientRect.top,
      height: clientRect.height,
      width: clientRect.width,
    });
    if (editInfo.edit.fillin) {
      $(saplingSpan).css({
        border: '1px solid #6f68f7',
        'border-radius': '0.4em',
      });
    } else if (editInfo.edit.annotation) {
      if (editInfo.edit.annotationStyle) {
        $(saplingSpan).css(editInfo.edit.annotationStyle);
      }
    } else {
      $(saplingSpan).css({
        'background-image': getBackgroundImage(editInfo.edit, false),
      });
    }
  }
  if (editInfo.edit.category && parentContainerInfo.annotationsOverlay) {
    parentContainerInfo.annotationsOverlay.updateAnnotationForOverlay(editId, editInfo);
  }

  if (editInfo.isHover) {
    applyTagCSS(editInfo, true);
  }
}

export function clearTagForOverlayFormat(containerId, editId) {
  let containerInfo = saplingIdToInfo[containerId];
  if (!containerInfo) return;
  const { edits, annotationsOverlay } = containerInfo;
  if (!edits[editId]) return;
  edits[editId].domElements.forEach((elem) => elem.remove());
  if (edits[editId].isHover) {
    hideEditControlForOverlayFormat();
  }
  delete edits[editId];
  if (annotationsOverlay) {
    annotationsOverlay.clearAnnotationForOverlay(editId);
  }
}

export function clearTagsForOverlayFormat(parentContainer, editIds) {
  const containerId = getContainerId(parentContainer);
  for (let idx = 0; idx < editIds.length; idx += 1) {
    clearTagForOverlayFormat(containerId, editIds[idx]);
  }
}

function applyTagWithOverlayFormat(
  parentContainer,
  editRange,
  edit,
  overlappingEditsForOverlay,
) {
  const overlappingEditsForOverlayObj = overlappingEditsForOverlay;
  const containerId = getContainerId(parentContainer);
  let containerInfo = saplingIdToInfo[containerId];
  if (!containerInfo) return;
  const { edits } = containerInfo;
  if (edit.editId in containerInfo.edits) {
    // if already exists and valid. don't reapply.
    const {
      editRange: origEditRange,
    } = edits[edit.editId];
    if (isValidRange(origEditRange, edit, false)) {
      if (overlappingEditsForOverlayObj) {
        delete overlappingEditsForOverlayObj[edit.editId];
      }
      return;
    }
  }
  if (overlappingEditsForOverlayObj) {
    for ( // eslint-disable-line no-restricted-syntax
      const editId of Object.keys(overlappingEditsForOverlayObj)
    ) {
      const {
        edit: overlappingEdit,
        editRange: overlappingEditRange,
      } = overlappingEditsForOverlayObj[editId];

      if (rangesIntersect(overlappingEditRange, editRange)) {
        if (overlappingEditRange.toString() === editRange.toString()) {
          if (overlappingEdit.editId in edits && !edits[editId].isHover) {
            clearTagForOverlayFormat(containerId, overlappingEdit.editId);
          }

          delete overlappingEditsForOverlayObj[editId];
          break;
        }

        clearTagForOverlayFormat(containerId, editId);
        delete overlappingEditsForOverlayObj[editId];
        // TODO: keep hover if approximately in right place.
      }
    }
  }

  if (edit.editId in edits) {
    edits[edit.editId].edit = edit;
    edits[edit.editId].editRange = editRange;
  } else {
    edits[edit.editId] = {
      editRange,
      edit,
      domElements: [],
      isHover: false,
    };
  }

  updateTagOverlay(containerId, edit.editId);
}

export function applyTag(
  parentContainer,
  startDomElement,
  startIndex,
  endDomElement,
  endIndex,
  edit,
  overlappingEditsForOverlay = null,
) {
  // Apply tag edit to selected word.  Make sure cursor position is maintained.
  const editRange = document.createRange();
  editRange.setStart(startDomElement, startIndex);
  editRange.setEnd(endDomElement, endIndex);

  if (!isValidRange(editRange, edit)) {
    return null;
  }

  return applyTagWithOverlayFormat(
    parentContainer,
    editRange,
    edit,
    overlappingEditsForOverlay,
  );
}

function getOffset(offset, container, removedNodes) {
  let runningOffset = 0;
  for (let idx = 0; idx < removedNodes.length; idx += 1) {
    const removedNode = removedNodes[idx];
    const textLength = removedNode.textContent.length;
    if (removedNode.contains(container)) {
      return runningOffset + offset;
    }

    runningOffset += textLength;
  }

  return null;
}

function getOldLength(mutation) {
  let length = 0;
  let prev = mutation.previousSibling;
  while (prev) {
    length += prev.textContent.length;
    prev = prev.previousSibling;
  }
  let next = mutation.nextSibling;
  while (next) {
    length += next.textContent.length;
    next = next.nextSibling;
  }

  for (let idx = 0; idx < mutation.removedNodes.length; idx += 1) {
    const removedNode = mutation.removedNodes[idx];
    length += removedNode.textContent.length;
  }

  return length;
}

function getNewRangeFromOffset(oldEditRange, startNode, newStartOffset, endNode, newEndOffset) {
  let {
    startContainer, startOffset,
    endContainer, endOffset,
  } = oldEditRange;
  if (!documentContains(startNode) || !documentContains(endNode)) {
    return null;
  }

  if (newStartOffset !== null) {
    const start =
      getLocationFromOffset(startNode, 0, newStartOffset, endNode, false, false);
    if (start) {
      startContainer = start.domElement;
      startOffset = start.domOffset;
    }
  }
  if (newEndOffset !== null) {
    const end =
      getLocationFromOffset(startNode, 0, newEndOffset, endNode, false, true);
    if (end) {
      endContainer = end.domElement;
      endOffset = end.domOffset;
    }
  }

  const newEditRange = document.createRange();
  if (!documentContains(startContainer) || !documentContains(endContainer) ||
    startContainer.length <= startOffset || endContainer.length <= endOffset ||
    startOffset < 0 || endOffset < 0) {
    return null;
  }
  newEditRange.setStart(startContainer, startOffset);
  newEditRange.setEnd(endContainer, endOffset);

  return newEditRange;
}

export function updateRangeForOverlayFormatForChildList(containerId, mutation) {
  if (!(containerId in saplingIdToInfo)) {
    return;
  }

  const { removedNodes } = mutation;
  if (removedNodes.length === 0) {
    return;
  }

  const { edits } = saplingIdToInfo[containerId];
  Object.keys(edits).forEach((editId) => {
    const { edit, editRange } = edits[editId];
    const newStartOffset =
      getOffset(editRange.startOffset, editRange.startContainer, removedNodes);
    const newEndOffset =
      getOffset(editRange.endOffset, editRange.endContainer, removedNodes);

    if (newStartOffset !== null || newEndOffset !== null) {
      const startNode = mutation.previousSibling || mutation.target;
      const newEditRange = getNewRangeFromOffset(
        editRange,
        startNode,
        newStartOffset,
        mutation.target,
        newEndOffset,
      );
      if (newEditRange && isValidRange(newEditRange, edit, false)) {
        edits[editId].editRange = newEditRange;
        updateTagOverlay(
          containerId,
          editId,
        );
      } else {
        const possibleDiff = mutation.target.textContent.length - getOldLength(mutation);
        const diffEditRange = getNewRangeFromOffset(
          editRange,
          startNode,
          newStartOffset + possibleDiff,
          mutation.target,
          newEndOffset + possibleDiff,
        );
        if (diffEditRange && isValidRange(diffEditRange, edit, false)) {
          edits[editId].editRange = diffEditRange;
          updateTagOverlay(
            containerId,
            editId,
          );
        }
      }
    }
  });
}

export function updateRangeForOverlayFormatForCharacterData(containerId, mutation) {
  if (!(containerId in saplingIdToInfo)) {
    return;
  }

  const { edits } = saplingIdToInfo[containerId];
  Object.keys(edits).forEach((editId) => {
    const { edit, editRange } = edits[editId];

    // only relevant if startContainer or before modified.
    if (editRange.startContainer !== mutation.target) {
      return;
    }
    // if below true, then just update the range.
    if (rangeIsValid(editRange)) {
      const recreatedEditRange = editRange.cloneRange();
      if (isValidRange(recreatedEditRange, edit, false)) {
        edits[editId].editRange = recreatedEditRange;
        return;
      }
    }

    // try to shift range and see if it still works.
    const indexDiff = mutation.target.length - mutation.oldValue.length;
    const newStartOffset = editRange.startOffset + indexDiff;
    let newEndOffset = editRange.endOffset;
    if (editRange.endContainer === mutation.target) {
      newEndOffset += indexDiff;
    }
    if (newStartOffset >= 0 && newStartOffset <= editRange.startContainer.length &&
        newEndOffset >= 0 && newEndOffset <= editRange.endContainer.length) {
      const newEditRange = document.createRange();
      newEditRange.setStart(editRange.startContainer, newStartOffset);
      newEditRange.setEnd(editRange.endContainer, newEndOffset);
      if (isValidRange(newEditRange, edit, false)) {
        edits[editId].editRange = newEditRange;
        updateTagOverlay(
          containerId,
          editId,
        );
      }
    }

    // ultimately if something is invalid, then clear it.
    if (!rangeIsValid(edits[editId].editRange)) {
      clearTagForOverlayFormat(containerId, editId);
    }
  });
}

export async function getOverlappingEditsForOverlayFormat(
  parentContainer,
  startNode,
  startIndex,
  endNode,
  endIndex,
) {
  const selectRange = document.createRange();
  selectRange.setStart(startNode, startIndex);
  selectRange.setEnd(endNode, endIndex);

  const containerId = getContainerId(parentContainer);
  let containerInfo = saplingIdToInfo[containerId];
  if (!containerInfo) return;
  const { edits } = saplingIdToInfo[containerId];
  const overlappingEditsForOverlay = {};
  const editEntries = Object.entries(edits);

  let chunkCounter = 0;
  for (let i = 0; i < editEntries.length; i++) {
    const editId = editEntries[i][0];
    const { editRange } = editEntries[i][1];
    if (documentContains(editRange.startContainer) &&
        documentContains(editRange.endContainer) &&
        rangesIntersect(editRange, selectRange)) {
      overlappingEditsForOverlay[editId] = edits[editId];
    }
    chunkCounter++;
    if (chunkCounter % 100 === 0) {
      // return to event loop to prevent taking too much time
      await new Promise(resolve => setTimeout(resolve, 50));
    }
  }
  return overlappingEditsForOverlay;
}

export function validateTagWithOverlayFormat(containerId) {
  let containerInfo = saplingIdToInfo[containerId];
  if (!containerInfo) return;
  const { edits } = saplingIdToInfo[containerId];
  Object.keys(edits).forEach((editId) => {
    const { editRange, edit } = edits[editId];
    if (!isValidRange(editRange, edit, false)) {
      clearTagForOverlayFormat(containerId, editId);
    }
  });
}

function isCursorOnBadge(containerId, event) {
  const parentContainerInfo = saplingIdToInfo[containerId];
  if (!parentContainerInfo ||
    !parentContainerInfo.badge ||
    !parentContainerInfo.badge.badge) {
    return false;
  }
  let badgeElement = parentContainerInfo.badge.badge;
  let { top, bottom, left, right } = badgeElement[0].getBoundingClientRect();
  if (left <= event.clientX && event.clientX <= right &&
      top <= event.clientY && event.clientY <= bottom) {
    return true;
  }
  return false;
}

function isCursorInRange(editRange, containerId, event) {
  let hoveredContainerId = null;
  const target = getDeepTarget(event);
  if (target) {
    const targetContainerId = getContainerId(target);
    if (targetContainerId) {
      hoveredContainerId = targetContainerId;
    } else {
      let parents = $(target).parents();
      for (let i = 0; i < parents.length; i++) {
        let elem = parents[i];
        const parentContainerId = getContainerId(elem);
        if (parentContainerId) {
          hoveredContainerId = parentContainerId;
          break;
        }
      }
    }
  }
  if (hoveredContainerId && !saplingIdToInfo[hoveredContainerId]) {
    // hoveredContainerId may refer to an overlay that has been removed
    hoveredContainerId = null;
  }

  if (!hoveredContainerId || hoveredContainerId === containerId) {
    const clientRects = editRange.getClientRects();
    const parentContainerInfo = saplingIdToInfo[containerId];

    for (let i = 0; i < clientRects.length; i += 1) {
      const clientRect = zoomClientRect(clientRects[i], parentContainerInfo);
      if (clientRect.top <= event.clientY &&
          clientRect.bottom >= event.clientY &&
          clientRect.left <= event.clientX &&
          clientRect.right >= event.clientX) {
        return true;
      }
    }
  }
  return false;
}

export function clearHoveredElement() {
  if (hoveredElement) {
    if (hoveredElement.containerId in saplingIdToInfo) {
      const { edits } = saplingIdToInfo[hoveredElement.containerId];
      if (hoveredElement.editId in edits) {
        const editInfo = edits[hoveredElement.editId];
        applyTagCSS(editInfo, false);
      }
    }
    hoveredElement = null;
  }
}

function setHoveredElement(editId, containerId, editInfo, annotationsOverlay, overlayDomElement, focus = false) {
  const { edit, domElements } = editInfo;
  // advanced edits are sometimes hidden
  if (editInfo.edit.category) {
    if (!annotationsOverlay) {
      return false;
    } else if (!(annotationsOverlay.annotationsAlwaysVisible || annotationsOverlay.editsVisible)) {
      return false;
    }
  } else if (editInfo.edit.fillin) {
    return false;
  }
  if (hoveredElement && (editId === hoveredElement.editId)) {
    return true;
  }
  // clear current hovered element;
  clearHoveredElement();
  applyTagCSS(editInfo, true);
  hoveredElement = { editId, containerId };

  showEditControlForOverlayFormat(containerId, edit, domElements, overlayDomElement, focus);
  return true;
}

export function isHoveredElementInContainer(containerId) {
  return hoveredElement && hoveredElement.containerId === containerId;
}

export function hasMishoveredElement() {
  if (hoveredElement) {
    if (hoveredElement.containerId in saplingIdToInfo) {
      const { edits } = saplingIdToInfo[hoveredElement.containerId];
      if (hoveredElement.editId in edits) {
        const edit = edits[hoveredElement.editId];
        const { editRange } = edit;
        if (!documentContains(editRange.startContainer) ||
          !documentContains(editRange.endContainer)) {
          return true;
        }
      } else {
        return true;
      }
    }
  }

  return false;
}

function isCursorInEditControl(event) {
  const editControl = $(SAPLING_ENV.CONTROL_ELEMENT).get(0);
  if (!editControl) {
    return false;
  }
  const clientRects = editControl.getClientRects();
  for (let i = 0; i < clientRects.length; i += 1) {
    const clientRect = clientRects[i];
    if (clientRect.top <= event.clientY &&
        clientRect.top + clientRect.height >= event.clientY &&
        clientRect.left <= event.clientX &&
        clientRect.left + clientRect.width >= event.clientX) {
      return true;
    }
  }
  return false;
}

export function onClickWithOverlayFormat(block) {
  const FILLIN_PADDING = 2;
  const [rephraseControls, rephraseButton] = getRephraseControls();
  let containerId = getContainerId(block);
  let containerInfo = saplingIdToInfo[containerId];
  if (!containerInfo) return;
  const { edits } = containerInfo;
  if (isCheckableTextElement(block)) {
    if (rephraseControls) {
      rephraseControls.hideControls();
    }
    // figure out if text caret is within an edit
    if (containerId in saplingIdToInfo) {
      Object.keys(edits).forEach((editId) => {
        const editInfo = edits[editId];
        const { editRange } = editInfo;
        let isCaretInFillinRange = false;
        const cursorOffset = getCursorTextOffset(block, true);
        if ((editRange.startOffset + FILLIN_PADDING <= cursorOffset) &&
            (cursorOffset + FILLIN_PADDING <= editRange.endOffset)) {
          isCaretInFillinRange = true;
        }

        if (isCaretInFillinRange) {
          if (editInfo.edit.fillin) {
            block.setSelectionRange(editRange.startOffset, editRange.endOffset);
            maybeStartMultiFillinEditMode(block, editInfo, edits);
          }
        }
      });
    }
  } else {
    if (rephraseControls) {
      rephraseControls.hideControls();
    }
    const selection = block.getRootNode().getSelection();
    const range = selection.rangeCount && selection.getRangeAt(0);
    if (!range) {
      return;
    }
    // figure out if text caret is within an edit
    Object.keys(edits).forEach((editId) => {
      const editInfo = edits[editId];
      const { editRange } = editInfo;

      let isCaretAfterRangeStart = false;
      let isCaretBeforeRangeEnd = false;
      if (editRange.compareBoundaryPoints(Range.START_TO_START, range) !== 1) {
        isCaretAfterRangeStart = true;
      }
      if (editRange.compareBoundaryPoints(Range.END_TO_END, range) !== -1) {
        isCaretBeforeRangeEnd = true;
      }
      const isCaretInRange = isCaretAfterRangeStart && isCaretBeforeRangeEnd;

      if (isCaretInRange) {
        if (editInfo.edit.fillin) {
          let sel = window.getSelection();
          sel.removeAllRanges();
          sel.addRange(editRange);
          maybeStartMultiFillinEditMode(block, editInfo, edits);
        }
      }
    });
  }
}

export function onCursorMoveWithOverlayFormat(block) {
  let matchedEdit = false;

  let containerId = getContainerId(block);
  let containerInfo = saplingIdToInfo[containerId];
  if (!containerInfo) return;
  const { edits, overlayDomElement, annotationsOverlay } = containerInfo;
  if (!edits) {
    return;
  }
  let hoveredEdits = [];
  if (isCheckableTextElement(block)) {
    // figure out if text caret is hovering over an edit
    for (const editInfo of Object.values(edits)) {
      const { editRange } = editInfo;
      let isCaretInRange = false;
      const cursorOffset = getCursorTextOffset(block, true);
      if (editRange.startOffset <= cursorOffset && cursorOffset <= editRange.endOffset) {
        isCaretInRange = true;
      }

      if (isCaretInRange) {
        hoveredEdits.push(editInfo);
      }
    }
  } else {
    let selection;
    try {
      selection = block.getRootNode().getSelection();
    } catch (e) {
      //  TypeError: block.getRootNode().getSelection is not a function
      return;
    }
    const range = selection.rangeCount && selection.getRangeAt(0);
    if (!range) {
      return;
    }
    // figure out if text caret is hovering over an edit

    for (const editInfo of Object.values(edits)) {
      const { editRange } = editInfo;

      let isCaretAfterRangeStart = false;
      let isCaretBeforeRangeEnd = false;
      if (editRange.compareBoundaryPoints(Range.START_TO_START, range) !== 1) {
        isCaretAfterRangeStart = true;
      }
      if (editRange.compareBoundaryPoints(Range.END_TO_END, range) !== -1) {
        isCaretBeforeRangeEnd = true;
      }
      const isCaretInRange = isCaretAfterRangeStart && isCaretBeforeRangeEnd;

      if (isCaretInRange) {
        hoveredEdits.push(editInfo);
      }
    }
  }
  if (hoveredEdits.length) {
    matchedEdit = true;
    let editInfo = resolveActiveEdits(hoveredEdits);
    let { editId } = editInfo.edit;
    let set = setHoveredElement(editId, containerId, editInfo, annotationsOverlay, overlayDomElement);
    matchedEdit = matchedEdit || set;
  }

  if (!matchedEdit) {
    hideEditControlForOverlayFormat();
  }
}

export function onMouseMoveWithOverlayFormat(event) {
  // figure out hovered edit or badges
  let hoveredInfo = null;
  for (const [containerId, parentContainerInfo] of Object.entries(saplingIdToInfo)) {
    const { edits, overlayDomElement, annotationsOverlay } = parentContainerInfo;
    if (!edits) {
      continue;
    }
    let hoveredEdits = [];
    for (const editInfo of Object.values(edits)) {
      const { edit, editRange, isHover } = editInfo;
      if (edit.category && !annotationsOverlay.editsVisible) {
        continue;
      } else if (edit.fillin) {
        continue;
      }
      if (isHover && isCursorInEditControl(event)) {
        // prioritize edit control over edit markup
        hoveredEdits = [editInfo];
        break;
      } else if (isCursorInRange(editRange, containerId, event, edit)) {
        hoveredEdits.push(editInfo);
      }
    }
    if (hoveredEdits.length) {
      let editInfo = resolveActiveEdits(hoveredEdits);
      hoveredInfo = {
        editInfo,
        containerId,
        overlayDomElement,
        annotationsOverlay,
      };
    }
    if (isCursorOnBadge(containerId, event)) {
      parentContainerInfo.badge.showBadgeDashboard();
    }
  }

  // handle showing or timing out edit controls
  let hover = false;
  if (hoveredInfo) {
    let { editInfo, containerId, overlayDomElement, annotationsOverlay } = hoveredInfo;
    let { editId } = editInfo.edit;
    hover = setHoveredElement(editId, containerId, editInfo, annotationsOverlay, overlayDomElement);
  }
  if (hover) {
    clearHoverTimer();
  } else {
    hideEditControlForOverlayFormat();
  }
}

// readjust positions on resize
export function onUpdateTagForOverlayFormatPerContainer(containerId) {
  let containerInfo = saplingIdToInfo[containerId];
  if (!containerInfo) return;
  const { edits } = containerInfo;
  Object.keys(edits).forEach((editId) => {
    updateTagOverlay(
      containerId,
      editId,
    );
  });
}

export function onResizeOverlayFormatPerContainer(parentContainer) {
  initOrUpdateContainerOverlay(parentContainer);

  const containerId = getContainerId(parentContainer);
  onUpdateTagForOverlayFormatPerContainer(containerId);
}

export function removeContainerIdForOverlayFormat(containerId) {
  if (containerId in saplingIdToInfo) {
    saplingIdToInfo[containerId].overlayDomElement.remove();
    if (saplingIdToInfo[containerId].summaryAnnotationsContainer) {
      saplingIdToInfo[containerId].summaryAnnotationsContainer.removeUIElements();
    }
    delete saplingIdToInfo[containerId];
  }
}

export function getContainer(containerId) {
  if (containerId in saplingIdToInfo) {
    return saplingIdToInfo[containerId].containerDomElement;
  }
  return null;
}

export function getContainerInfo(containerId) {
  return saplingIdToInfo[containerId];
}

export function clearEdits() {
  for (const [containerId, info] of Object.entries(saplingIdToInfo)) {
    for (const [editId, editInfo] of Object.entries(info.edits)) {
      for (const domElem of editInfo.domElements) {
        domElem.remove();
      }
    }
    info.edits = {};
  }
}

function handleOverlayDomRemoval(containerId, observer) {
  let containerInfo = saplingIdToInfo[containerId];
  if (!containerInfo) {
    observer.disconnect();
    return;
  }
  if (!document.contains(containerInfo.shadowHost)) {
    observer.disconnect();
    removeContainerIdForOverlayFormat(containerId);
  }
}

function observeOverlayDomRemoval(containerId, containerInfo) {
  const observer = new MutationObserver((mutations, obs) => {
    handleOverlayDomRemoval(containerId, obs);
  });
  const config = { childList: true, subtree: false };
  observer.observe(containerInfo.shadowHost.parentNode, config);
  containerInfo.shadowHostObserver = containerInfo;
}
