import { selectSnippet, getShortcutSnippets } from '../../requests/index';
import {
  replaceTextAreaSelection,
  pasteContentEditableSelectionWithHTML,
} from '../highlight/textarea';
import { getSnippetShortcut } from '../settings';
import {
  getStyleAndCopySnippetToClipboard,
  updateSnippetCachedFocusLength,
} from './snippet-injector';
import { getCaretCoord, getRangeFromFocusElement } from '../../utils/caret-utils';
import { sendMessage, sendMessageAsync } from '../../utils/chrome-adapter';
import { isInIframe } from '../../utils/iframe';
import { getTopFrameHostname } from '../../utils/location';

const RESET_KEYS = new Set([
  'ArrowUp',
  'ArrowDown',
  'ArrowLeft',
  'ArrowRight',
  'Enter',
  'Tab',
  'Delete',
  'Escape',
  'Home',
  'End',
  'PageUp',
  'PageDown',
]);
const CONTROL_KEYS = new Set([
  'ArrowUp',
  'ArrowDown',
  'Enter',
  'Escape',
]);

class TrieNode {
  constructor() {
    this.children = {};
    this.end = false;
  }

  insert(word) {
    let node = this;
    for (let i = 0; i < word.length; i++) {
      if (!node.children[word[i]]) {
        node.children[word[i]] = new TrieNode();
      }
      node = node.children[word[i]];
      if (i === word.length - 1) {
        node.end = true;
      }
    }
  }

  contains(word) {
    // returns 0 if not, 1 if prefix, 2 if complete match
    let node = this;
    for (let i = 0; i < word.length; i++) {
      if (node.children[word[i]]) {
        node = node.children[word[i]];
      } else {
        return 0;
      }
    }
    return (node.end ? 2 : 1);
  }
}

let SEARCH_PREFIX = '\\';
let INLINE_SEARCH_TRIGGERED = false;
let SNIPPET_TRIE = new TrieNode();
let SNIPPET_LOOKUP = {};
let CHAR_BUFFER = [];

function hasSelectedText(target) {
  if (target && target.nodeName) {
    const nodeName = target.nodeName.toLowerCase();
    if (nodeName === 'textarea' || nodeName === 'input') {
      return target.selectionStart != null &&
        target.selectionStart !== target.selectionEnd;
    }
  }

  const selection = window.getSelection();
  if (!selection || selection.rangeCount === 0 || selection.isCollapsed) {
    return false;
  }

  const range = selection.getRangeAt(0);
  const commonAncestor = range.commonAncestorContainer;
  return target && (target.contains(commonAncestor) || target === commonAncestor);
}

function processSnippetsIntoTrie(snippets) {
  if (!snippets) {
    return;
  }
  let newSnippetTrie = new TrieNode();
  let newSnippetLookup = {};

  for (let i = 0; i < snippets.length; i++) {
    const snippet = snippets[i];
    const key = snippet.shortcut;
    if (key) {
      let lowercaseKey = key.toLowerCase();
      newSnippetTrie.insert(lowercaseKey);
      newSnippetLookup[lowercaseKey] = snippet;
    }
  }
  SNIPPET_TRIE = newSnippetTrie;
  SNIPPET_LOOKUP = newSnippetLookup;
}

export function syncSnippetAutoExpander() {
  getShortcutSnippets(
    (snippets) => {
      processSnippetsIntoTrie(snippets);
    },
    (e) => {
      // TODO: alert to end user that snippets are not sync-ed
    },
  );

  let snippetShortcut = getSnippetShortcut();
  if (snippetShortcut != null) {
    SEARCH_PREFIX = snippetShortcut;
  }
}

export function clearKeyPressBuffer(snippetInteraction) {
  if (INLINE_SEARCH_TRIGGERED && snippetInteraction) {
    INLINE_SEARCH_TRIGGERED = false;
    // hide snippet UI
    sendMessage({ action: 'snippet-control' });
  } else {
    CHAR_BUFFER = [];
  }
}

export function launchSnippetControl(x, y, windowHeight, caretY) {
  let coordinates = { top: '', bottom: '', left: x };
  if (windowHeight - y < 300) {
    // if there isn't a lot of space, place finder above the cursor
    coordinates.bottom = windowHeight - caretY + 10;
  } else {
    coordinates.top = y;
  }

  sendMessage(
    {
      action: 'snippet-control',
      data: { coordinates, mode: 'inline', show: true },
    },
  );
  INLINE_SEARCH_TRIGGERED = true;
  maybeHandleInlineSearch();
}

/*
 * cross-origin workaround to get global iframe position from the iframe's content script
 *
 * return-iframe-bounding-rect is the spiritual "callback" of get-iframe-bounding-rect
 * jumping through more than 2 nested iframes causes the chrome api callbacks to stop working
 * instead, we keep track of context through the result, and fire back at the original
 * content script when done with recursion
*/
export function recursiveGetIframeBoundingRect(request) {
  let iframes = document.getElementsByTagName('iframe');
  const requestURL = new URL(request.href);
  for (let i = 0; i < iframes.length; i++) {
    if (request.href !== 'about:blank' || iframes[i].src) {
      let urlMatch = false;
      let nameMatch = false;
      let frameURL; // try reading url directly, in case url has changed
      let frameSRC; // try reading src attribute for cross domain iframes
      try {
        frameSRC = new URL(iframes[i].src);
      // eslint-disable-next-line no-empty
      } catch (e) {
      }

      if (frameSRC && (
        requestURL.protocol === frameSRC.protocol &&
        requestURL.host === frameSRC.host &&
        requestURL.pathname === frameSRC.pathname
      )) {
        urlMatch = true;
      }

      try {
        frameURL = new URL(iframes[i].contentWindow.location.href);
      } catch (e) {
        // cross domain iframe, cannot get iframe location from parent. relax matching to just name
        urlMatch = true;
      }

      if (frameURL && (
        requestURL.protocol === frameURL.protocol &&
        requestURL.host === frameURL.host &&
        requestURL.pathname === frameURL.pathname
      )) {
        urlMatch = true;
      }

      if (request.name === iframes[i].name) {
        nameMatch = true;
      }

      if (!urlMatch || !nameMatch) {
        continue;
      }
    }

    let windowHeight = $(window).height();
    // found the right iframe, add offset
    let iframeRect = iframes[i].getBoundingClientRect();
    request.windowHeight = windowHeight;

    request.x += iframeRect.x;
    request.y += iframeRect.y;
    request.caretY += iframeRect.y;

    if (isInIframe()) {
      // if in iframe, recurse!
      sendMessage({
        action: 'get-iframe-bounding-rect',
        tabId: request.tabId,
        frameId: request.frameId,
        href: window.location.href,
        name: window.name,
        x: request.x,
        y: request.y,
        caretY: request.caretY,
        frameIds: request.frameIds,
      });
    } else {
      sendMessage({
        action: 'return-iframe-bounding-rect',
        tabId: request.tabId,
        frameId: request.frameId,
        windowHeight: request.windowHeight,
        x: request.x,
        y: request.y,
        caretY: request.caretY,
      });
    }
    break;
  }
}

export async function autoExpandSnippet(target) {
  let bufferWord = CHAR_BUFFER.join('');

  CHAR_BUFFER = [];
  let snippet = SNIPPET_LOOKUP[bufferWord];
  if (target.getAttribute('contenteditable') === 'true' ||
      target.getAttribute('contenteditable') === '' ||
      target.getAttribute('contenteditable') === 'plaintext-only') {
    let range = getRangeFromFocusElement(target, null);
    let newStart = Math.max(0, range.startOffset - bufferWord.length + 1);
    range.setStart(range.startContainer, newStart);
    // document.execCommand('delete', false, null);
    if (snippet.rich_text !== '') {
      await sendMessageAsync({ action: 'cache-clipboard' });
      const style = await getStyleAndCopySnippetToClipboard(snippet.rich_text, target);
      pasteContentEditableSelectionWithHTML(range, snippet.plain_text, snippet.rich_text, target, style);
      sendMessage({ action: 'pop-cached-clipboard' });
    }
    selectSnippet(snippet.id, 'shortcut', bufferWord, 0);
  } else if (target.nodeName.toLowerCase() === 'textarea') {
    let newStart = Math.max(0, target.selectionStart - bufferWord.length + 1);
    let newEnd = newStart + snippet.plain_text.length;
    const hostname = getTopFrameHostname();
    if (hostname.endsWith('figma.com')) {
      window.dispatchEvent(new CustomEvent(
        'sapling-figma-selection',
        {
          detail: { bufferLength: bufferWord.length - 1 },
        },
      ));
    }
    replaceTextAreaSelection(
      target,
      newStart,
      target.selectionEnd,
      snippet.plain_text,
    );
    // set cursor to end of expansion
    target.setSelectionRange(newEnd, newEnd);
    selectSnippet(snippet.id, 'shortcut', bufferWord, 0);
  }
}

export function handleKeyDown(target, key) {
  // return if the keypress should be propagated
  if (INLINE_SEARCH_TRIGGERED) {
    if (CONTROL_KEYS.has(key)) {
      // command needs to be passed to content script with snippet UI
      sendMessage({ action: 'snippet-control', data: { key } });
      return false;
    }
  }

  if (hasSelectedText(target)) {
    // any keystroke that lands while text is selected will replace or delete
    // that selection, so the previously buffered prefix is no longer adjacent
    // to the caret and must be discarded
    CHAR_BUFFER = [];
    maybeHandleInlineSearch();
    return true;
  }

  if (key === 'Backspace') {
    CHAR_BUFFER.pop();
    maybeHandleInlineSearch();
  } else if (RESET_KEYS.has(key)) {
    CHAR_BUFFER = [];
  }
  return true;
}

export function clearInlineSearchState() {
  INLINE_SEARCH_TRIGGERED = false;
  CHAR_BUFFER = [];
}

function maybeHandleInlineSearch() {
  if (!INLINE_SEARCH_TRIGGERED) {
    return;
  }
  const bufferStr = CHAR_BUFFER.join('');
  updateSnippetCachedFocusLength(bufferStr.length);
  if (bufferStr.startsWith(SEARCH_PREFIX)) {
    let queryString = bufferStr.substring(SEARCH_PREFIX.length);
    sendMessage({ action: 'snippet-control', data: { query: queryString } });
  } else {
    INLINE_SEARCH_TRIGGERED = false;
    // hide snippet UI
    sendMessage({ action: 'snippet-control', data: { show: false } });
  }
}

export function handleKeyPress(target, key) {
  if (key.length > 1) {
    return false;
  }

  CHAR_BUFFER.push(key.toLowerCase());
  let containsExpansion = SNIPPET_TRIE.contains(CHAR_BUFFER);
  if (containsExpansion === 2) {
    // prioritize auto text expansion
    autoExpandSnippet(target);
    return true;
  }

  const bufferStr = CHAR_BUFFER.join('');
  if (bufferStr === SEARCH_PREFIX) {
    // next, prioritize showing snippet search
    let coord = getCaretCoord(target);
    let caretY = coord.top;
    let finderY = coord.top + coord.height + 10;
    let finderX = coord.left;
    let windowHeight = $(window).height();
    if (isInIframe()) {
      // current content script is in iframe
      sendMessage({
        action: 'get-iframe-bounding-rect',
        href: window.location.href,
        name: window.name,
        x: finderX,
        y: finderY,
        caretY,
        frameIds: [],
      });
    } else {
      launchSnippetControl(finderX, finderY, windowHeight, caretY);
    }
  } else {
    maybeHandleInlineSearch();
  }

  if (containsExpansion === 1) {
    // wait and see
  } else if (containsExpansion === 0 && !INLINE_SEARCH_TRIGGERED) {
    // trim char buffer if we aren't doing an inline search
    while (true) {
      let spaceIndex = CHAR_BUFFER.indexOf(' ');
      if (spaceIndex >= 0) {
        CHAR_BUFFER = CHAR_BUFFER.slice(spaceIndex + 1, CHAR_BUFFER.length);
      } else {
        return false;
      }
      if (CHAR_BUFFER.length === 0) {
        return false;
      }
      if (SNIPPET_TRIE.contains(CHAR_BUFFER) !== 0) {
        return false;
      }
    }
  }
}
