import {
  elIsTextArea,
  isDescendant,
  getDeepActiveElementThroughIframes,
  getShadowRoot,
} from './sdom';

export function getRangeFromFocusElement(deepFocusedElement, deepestIframe) {
  let rangeDocument; // rangeDocument is a shadowRoot, iframe, or window
  let shadowRoot = getShadowRoot(deepFocusedElement);
  if (shadowRoot) {
    if (deepestIframe && !isDescendant(deepestIframe.contentDocument, shadowRoot)) {
      rangeDocument = deepestIframe.contentDocument;
    } else {
      rangeDocument = shadowRoot;
    }
  } else {
    rangeDocument = deepestIframe ? deepestIframe.contentDocument : window;
  }

  let range = rangeDocument.getSelection().getRangeAt(0);

  return range;
}

export function focusEquals(f1, f2) {
  if (!f1 || !f2) {
    return false;
  } else if (f1.isContentEditable) {
    let r1 = f1.range;
    let r2 = f2.range;
    return (r1.startContainer === r2.startContainer)
      && (r1.startOffset === r2.startOffset)
      && (r1.endContainer === r2.endContainer)
      && (r1.endOffset === r2.endOffset);
  } else if (f1.isTextarea) {
    return (f1.start === f2.start)
      && (f1.end === f2.end);
  }
  return false;
}

export function cacheFocus(focusedElement) {
  // returns object that represents the currenet focus/selection/caret location
  let { deepestIframe, deepFocusedElement } = getDeepActiveElementThroughIframes(focusedElement);
  if (!deepFocusedElement) {
    // most likely a x-origin IFRAME with no contentDocument
    // we will rely on the content script in the IFRAME to do the injection
    return null;
  }
  let focusDetails;
  if (deepFocusedElement.getAttribute('contenteditable') === 'true' ||
      deepFocusedElement.getAttribute('contenteditable') === '' ||
      deepFocusedElement.getAttribute('contenteditable') === 'plaintext-only') {
    let cachedFocusRange = getRangeFromFocusElement(deepFocusedElement, deepestIframe);
    focusDetails = {
      deepestIframe,
      isContentEditable: true,
      isTextarea: false,
      element: deepFocusedElement,
      range: cachedFocusRange,
    };
  } else if (elIsTextArea(deepFocusedElement)) {
    focusDetails = {
      deepestIframe,
      isContentEditable: false,
      isTextarea: true,
      element: deepFocusedElement,
      start: deepFocusedElement.selectionStart,
      end: deepFocusedElement.selectionEnd,
    };
  } else {
    focusDetails = {
      deepestIframe,
      isContentEditable: false,
      isTextarea: false,
      element: deepFocusedElement,
    };
  }
  return focusDetails;
}

function applyEditableFocus(element, range) {
  element.focus();
  let sel = window.getSelection();
  sel.removeAllRanges();
  sel.addRange(range);
}

function applyTextAreaFocus(element, start, end) {
  element.focus();
  element.setSelectionRange(start, end);
}

export function applyCachedFocus(focusDetails) {
  // takes output of cacheFocus, applis the focus at that point in time
  if (!focusDetails) {
    return;
  }
  if (focusDetails.isContentEditable) {
    applyEditableFocus(focusDetails.element, focusDetails.range);
  } else if (focusDetails.isTextarea) {
    applyTextAreaFocus(focusDetails.element, focusDetails.start, focusDetails.end);
  }
}

export function insertTextAtCaret(text) {
  // FIXME execCommand seems to be obsoleted, but every browser still supports
  document.execCommand('insertText', false, text);
}

function insertContentEditableText(range, text) {
  const {
    startContainer, startOffset,
    endContainer, endOffset,
  } = range;

  // Clamp offsets to node length to prevent IndexSizeError if the DOM changed
  // since the range was captured (e.g. concurrent mutations on the same node).
  const startLen = startContainer.nodeType === Node.TEXT_NODE
    ? startContainer.length : startContainer.childNodes.length;
  const endLen = endContainer.nodeType === Node.TEXT_NODE
    ? endContainer.length : endContainer.childNodes.length;
  const safeStartOffset = Math.min(startOffset, startLen);
  const safeEndOffset = Math.min(endOffset, endLen);

  let staticRange;
  try {
    staticRange = new StaticRange({
      startContainer,
      startOffset: safeStartOffset,
      endContainer,
      endOffset: safeEndOffset,
    });
  } catch (e) {
    // If StaticRange is not supported or construction fails, we skip the InputEvent
  }
  
  // Only dispatch InputEvent if we successfully created a StaticRange
  if (staticRange) {
    const inputEventInit = {
      inputType: 'insertText',
      data: text,
      bubbles: true,
      cancelable: false,
      targetRanges: [staticRange],
    };
    // Needed by CK Editor (and Coda?)
    try {
      range.startContainer.dispatchEvent(new InputEvent('beforeinput', inputEventInit));
    } catch (e) {
      // Ignore InputEvent construction errors (e.g. offset out of range)
    }
  }

  if (startContainer === endContainer) {
    startContainer.replaceData(safeStartOffset, safeEndOffset - safeStartOffset, text);
  } else {
    startContainer.insertData(safeStartOffset, text);
  }

  // Move cursor to end
  range.selectNodeContents(endContainer);
  range.collapse(false);
}

// For CK Editor, may work elsewhere too
export function insertTextAtCaret2(text) {
  let sel = window.getSelection();
  if (sel.getRangeAt && sel.rangeCount) {
    let range = sel.getRangeAt(0);
    insertContentEditableText(range, text);
  }
}

export function getCaretCoord(editable) {
  if (editable.nodeName === 'TEXTAREA' || editable.nodeName === 'INPUT') {
    let coord = getCaretCoordinates(editable, editable.selectionEnd);
    let offsetCoord = editable.getBoundingClientRect();
    return {
      left: offsetCoord.left + coord.left - $(editable).scrollLeft(),
      top: offsetCoord.top + coord.top - $(editable).scrollTop(),
      height: coord.height,
    };
  }

  let selection = editable.getRootNode().getSelection();
  let range = selection.getRangeAt(0);
  if (range.startOffset === 0) {
    // workaround for getBoundingClientRect returning 0 on empty ranges
    range = range.cloneRange();
    try {
      range.setEnd(range.startContainer, 1);
    } catch (e) {
      // empty range, use start container instead
      let parentRect = range.startContainer.getBoundingClientRect();
      let countainer = $(range.startContainer);
      let height = parseInt(countainer.css('padding-top')) +
                   parseInt(countainer.css('border-top-width')) +
                   parseInt(countainer.css('font-size'));
      let leftPadding = parseInt(countainer.css('padding-left')) +
                        parseInt(countainer.css('border-left-width'));
      return {
        left: parentRect.left + leftPadding,
        top: parentRect.top,
        height,
      };
    }
  }
  let rect = range.getBoundingClientRect();
  if (rect.x === 0 && rect.y === 0) {
    // sometimes the try catch is not triggered for empty editables
    // try another workaround as well
    // getBoundingClientRect returns 0 values for collapsed ranges.
    // temporarily add and remove a zero space width as a workaround
    let padNode = document.createTextNode('\ufeff');
    range.insertNode(padNode);
    rect = range.getBoundingClientRect();
    padNode.remove();
  }
  return rect;
}

