import { SAPLING_ENV } from '../../globals';
import {
  getBounds,
  getTextAreaId,
  getVisibleEditElem,
} from '../../utils/html-utils';
import { getTopFrameHostname } from '../../utils/location';
import {
  getContainer,
  hasMishoveredElement,
  clearHoveredElement,
  hideAnnotationEdits,
} from '../highlight/overlay';
import {
  acceptCallbackForContainerAndEdit,
  addToDictionaryForContainerAndEdit,
  hoverEventCallbackForOverlayFormat,
  rejectCallbackForOverlayFormat,
} from '../highlight/edit-action';
import { getTextArea } from '../highlight/textarea';
import {
  isSubscription,
  getSubscriptionTrialDaysLeft,
  isUserEmailConfirmed,
  isUserAnonymous,
} from '../settings';
import {
  getIframeBoundingRect,
} from '../../utils/iframe';
import { editCSS, compactEditCSS, extendedEditCSS } from './style-elements';

// We have to wait to see if user moves mouse over edit controls before hiding
let hoverTimer = null;
const HOVER_WAIT = 300;
let shadowDom = null;

export function hideEditControls() {
  $('#active-edit', shadowDom).removeAttr('id');
  $('#active-edit', shadowDom).removeAttr('sapling-edit-id');
  $('#active-edit', shadowDom).removeAttr('sapling-container-id');
  $(SAPLING_ENV.CONTROL_ELEMENT).remove();

  clearHoveredElement();
}
export function maybeInitEditControls() {
  if ($(SAPLING_ENV.CONTROL_ELEMENT).length) {
    return;
  }
  let shadowHost = document.createElement(SAPLING_ENV.CONTROL_ELEMENT);
  $(shadowHost).css({
    zIndex: '2147483647',
    font: '12pt "Helvetica Neue", Helvetica, Arial, sans-serif',
    position: 'absolute',
    textAlign: 'center',
  });
  $('html').append(shadowHost);
  shadowHost.attachShadow({ mode: 'open' });
  shadowDom = shadowHost.shadowRoot;
  $(SAPLING_ENV.CONTROL_ELEMENT).hide();

  let ignoreText = 'Ignore';
  let acceptText = 'Accept';
  let additionalEditCSS = compactEditCSS();
  let customCSS = '';
  if (SAPLING_ENV.MODE === 'SDK') {
    ignoreText = Sapling.appearance.variables.ignoreText;
    acceptText = Sapling.appearance.variables.acceptText;
    if (!Sapling.appearance.compact) {
      additionalEditCSS = extendedEditCSS();
    }
    if (Sapling.appearance.customCSS) {
      customCSS = Sapling.appearance.customCSS;
    }
  }
  $(shadowDom).html(`
    ${editCSS()}
    ${additionalEditCSS}
    <style type="text/css">
    ${customCSS}
    </style>
    <div id="sapling-edit-controls" role="menu">

      <div id="type-row">
        <div class="icon-sapling-type"></div>
        <div id="type-text"></div>
      </div>

      <div id="text-row">
        <div id="original-text-row">
          <div class="icon-sapling-original-text"></div>
          <div id="original-text"></div>
        </div>

        <div class="icon-sapling-right-arrow"></div>

        <div id="replacement-text-row">
          <div class="icon-sapling-replacement-text"></div>
          <div id="replacement-text"></div>
        </div>
      </div>

      <div id="accept-row" class="edit-controls-row">
        <div id="accept-button" tabindex="-1" role="menuitem" aria-keyshortcuts="Enter ArrowDown">
          <div class="icon-sapling-accept"></div>
          <div id="accept-text" aria-label="Accept">${acceptText}</div>
        </div>
      </div>

      <div id="ignore-row" class="edit-controls-row">
        <div id="ignore-button" tabindex="-1" role="menuitem" aria-keyshortcuts="Enter ArrowUp">
          <div class="icon-sapling-reject"></div>
          <div id="ignore-text" aria-label="Reject">${ignoreText}</div>
        </div>
      </div>

      <div id="description-row" class="edit-controls-row">
        <div class="icon-sapling-description"></div>
        <div id="description-text"></div>
      </div>

      <div id="snooze-row" class="edit-controls-row">
        <div id="snooze-button" tabindex="-1">
          <div class="icon-sapling-reject"></div>
          <div id="snooze-text">Hide Advanced Edits</div>
        </div>
      </div>

      <div id="dictionary-row" class="edit-controls-row">
        <div id="dictionary-button" tabindex="-1">
          <div class="icon-sapling-reject"></div>
          <div id="dictionary-text">Add to Dictionary</div>
        </div>
      </div>

      <div id="premium-banner-row" class="edit-controls-row">
        <div id="premium-button" tabindex="-1">
          <div id="premium-text">
            Your trial ends in 1 day
          </div>
        </div>
      </div>

      <span id="hide-control" tabindex="-1"></span>
    </div>`);

  $('#accept-button', shadowDom).on('blur', () => {
    console.log('accept blur');
  });

  $('#ignore-button', shadowDom).on('blur', () => {
    console.log('ignore blur');
  });

  $('#sapling-edit-controls', shadowDom).on('keydown', (e) => {
    if (e.key === 'Escape') {
      const containerId = $(SAPLING_ENV.CONTROL_ELEMENT).attr('sapling-container-id');
      let newFocus = getContainer(containerId);
      let textAreaId = getTextAreaId(newFocus);

      // if a container is mirroring a textArea, we want to focus that instead
      if (textAreaId) {
        newFocus = getTextArea(textAreaId);
      }
      hideEditControls();
      newFocus.focus();
    }
  });
  // on completing the tab cycle, hide the edit controls
  $('#hide-control', shadowDom).focus((e) => {
    e.preventDefault();
    e.stopPropagation();

    const containerId = $(SAPLING_ENV.CONTROL_ELEMENT).attr('sapling-container-id');
    let newFocus = getContainer(containerId);
    let textAreaId = getTextAreaId(newFocus);

    // if a container is mirroring a textArea, we want to focus that instead
    if (textAreaId) {
      newFocus = getTextArea(textAreaId);
    }
    hideEditControls();
    newFocus.focus();
  });
}

function acceptCallback(containerId, edit, properties) {
  acceptCallbackForContainerAndEdit(containerId, edit, properties);
}

function rejectCallback(containerId, edit, properties) {
  rejectCallbackForOverlayFormat(containerId, edit, properties);
}

function snoozeCallback(containerId) {
  hideAnnotationEdits(containerId);
  hideEditControls();
}

function addToDictionaryCallback(containerId, edit) {
  addToDictionaryForContainerAndEdit(containerId, edit.editId);
}

function premiumCallback() {
  window.open(`${SAPLING_ENV.WEBSITE_URL}/plans#trial_pro_edit_click`);
}

function signInCallback() {
  window.open(`${SAPLING_WEB_URL}/user/sign-in#edit_click`);
}

function resetEditControls() {
  $('#accept-button', shadowDom).off('click mousedown keyup');
  $('#ignore-button', shadowDom).off('click mousedown keyup');
  $('#snooze-button', shadowDom).off('click mousedown keyup');
  $('#dictionary-button', shadowDom).off('click mousedown keyup');
  $('#premium-button', shadowDom).off('click mousedown keyup');

  $('#type-text', shadowDom).html('');
  $('#description-text', shadowDom).html('');
  $('#snooze-row', shadowDom).hide();
  $('#dictionary-row', shadowDom).hide();
  $('#accept-row', shadowDom).show();
  $('#ignore-row', shadowDom).show();

  $('#text-row', shadowDom).hide();
  $('#description-row', shadowDom).hide();
  // drop other classes from type icon
  $('.icon-sapling-type', shadowDom).attr('class', 'icon-sapling-type');

  if (SAPLING_ENV.MODE === 'SDK' && !Sapling.appearance.compact) {
    $('#text-row', shadowDom).css('display', 'flex');
    $('#description-row', shadowDom).show();
  }
}

function showDescription(containerId, edit) {
  if (edit.description) {
    $('#description-text', shadowDom).html(edit.description);
    let minWidth = (Math.min(edit.description.length, 35) / 35 * 220);
    $('#description-text', shadowDom).css('min-width', minWidth);
    $('#description-row', shadowDom).css('display', 'flex'); // show wraps wrong
  }
}

function setAdvancedEditControlState(containerId, edit) {
  if (!edit.category) {
    return;
  }
  if (SAPLING_ENV.MODE !== 'SDK' || !Sapling.autoShowAdvancedEdits) {
    $('#snooze-row', shadowDom).show();
  }

  $('#type-text', shadowDom).html(edit.category.replace(/_/g, ' '));
  $('.icon-sapling-type', shadowDom).addClass(edit.category);

  // some advanced edits have no suggestion
  if (edit.category === 'voice' ||
      edit.category === 'hard_to_read' ||
      edit.category === 'profanity') {
    $('#text-row', shadowDom).hide();
    $('#accept-row', shadowDom).hide();
  }
}

function setEditControlActions(containerId, edit, properties) {
  // websites like airtable dismiss content editables on mousedown
  $('#accept-button', shadowDom).mousedown((e) => {
    e.stopPropagation();
    e.preventDefault();
  });
  $('#ignore-button', shadowDom).mousedown((e) => {
    e.stopPropagation();
    e.preventDefault();
  });
  $('#snooze-button', shadowDom).mousedown((e) => {
    e.stopPropagation();
    e.preventDefault();
  });
  $('#dictionary-button', shadowDom).mousedown((e) => {
    e.stopPropagation();
    e.preventDefault();
  });
  $('#premium-button', shadowDom).mousedown((e) => {
    e.stopPropagation();
    e.preventDefault();
  });

  $('#ignore-button', shadowDom).click(() => rejectCallback(containerId, edit, properties));
  $('#premium-button', shadowDom).click(premiumCallback);
  $('#snooze-button', shadowDom).click(() => snoozeCallback(containerId));
  $('#dictionary-button', shadowDom).click(() => addToDictionaryCallback(containerId, edit));
  $('#ignore-button', shadowDom).keyup((e) => {
    if (e.key === 'Enter') {
      rejectCallback(containerId, edit, properties);
      getContainer(containerId).focus();
    } else if (e.key === 'ArrowUp') {
      $('#accept-button', shadowDom).focus();
    }
  });
  hoverEventCallbackForOverlayFormat(containerId, edit, properties);
}

function setSDKControlState(containerId, edit) {
  let acceptText = edit.replacementText;
  let { originalText } = edit;
  if (edit.replacementText === '') {
    acceptText = `<del> ${edit.originalText} </del>`;
  } else {
    originalText = `<del> ${edit.originalText} </del>`;
  }
  const acceptButtonJq = $('#accept-button', shadowDom);
  let properties = {
    is_premium: edit.premium,
    is_enabled: true,
  };
  acceptButtonJq.click(() => acceptCallback(containerId, edit, properties));
  // keyboard focus navigation of menu options
  acceptButtonJq.keyup((e) => {
    if (e.key === 'Enter') {
      acceptCallback(containerId, edit, properties);
    } else if (e.key === 'ArrowDown') {
      $('#ignore-button', shadowDom).focus();
    }
  });

  $('#type-text', shadowDom).html(edit.generalErrorType);
  $('#original-text', shadowDom).html(originalText);
  $('#replacement-text', shadowDom).html(acceptText);
  $('#description-text', shadowDom).html(edit.description);

  let errorClass = edit.generalErrorType;
  if (errorClass) {
    errorClass = errorClass.split(' ')[0].split('/')[0].toLowerCase();
  }
  $('.icon-sapling-type', shadowDom).addClass(errorClass);

  let specialAcceptCallback = null;
  if (edit.premium && edit.replacementText == null) {
    // replacementText is not sent back for public API KEY and users with no subscription
    if (isUserAnonymous()) {
      acceptText = '[Sign in to see premium edit]';
      acceptButtonJq.off('click').click(signInCallback);
      specialAcceptCallback = signInCallback;
      acceptButtonJq.off('keyup');
      properties.is_enabled = false;
    } else if (!isUserEmailConfirmed()) {
      acceptText = '[Confirm email to see premium edit]';
      acceptButtonJq.off('click').click(signInCallback);
      specialAcceptCallback = signInCallback;
      acceptButtonJq.off('keyup');
      properties.is_enabled = false;
    } else if (!isSubscription()) {
      acceptText = '[Pro Edit: Only in Sapling Pro]';
      acceptButtonJq.off('click').click(premiumCallback);
      specialAcceptCallback = premiumCallback;
      acceptButtonJq.off('keyup');
      properties.is_enabled = false;
    }
  }
  if (Sapling.appearance.compact) {
    $('#accept-text', shadowDom).html(acceptText);
  } else {
    if (specialAcceptCallback) {
      $('#text-row', shadowDom).addClass('gated-text-row').html(acceptText);
      $('#text-row', shadowDom).click(specialAcceptCallback);
      $('#description-text', shadowDom).hide();
    }
    $('#accept-text', shadowDom).html(Sapling.appearance.variables.acceptText);
  }
  setAdvancedEditControlState(containerId, edit);
  showDescription(containerId, edit);
  if (Sapling.addToDictionary) {
    if (edit.generalErrorType !== 'Grammar') {
      if (edit.dictionary) {
        // don' show dictionary option on spelling or custom errors
        $('#dictionary-row', shadowDom).show();
      }
    }
  }
  setEditControlActions(containerId, edit, properties);
}

function setChromeControlState(containerId, edit) {
  let acceptText = edit.replacementText;
  if (edit.replacementText === '') {
    acceptText = `<del> ${edit.originalText} </del>`;
  }
  const acceptButtonJq = $('#accept-button', shadowDom);
  let properties = {
    is_premium: edit.premium,
    is_enabled: true,
  };
  // keyboard focus navigation of menu options
  acceptButtonJq.keyup((e) => {
    if (e.key === 'Enter') {
      acceptCallback(containerId, edit, properties);
    } else if (e.key === 'ArrowDown') {
      $('#ignore-button', shadowDom).focus();
    }
  });
  acceptButtonJq.click(() => acceptCallback(containerId, edit, properties));
  const isWelcomePage = getTopFrameHostname() === SAPLING_ENV.WEBSITE_HOSTNAME;
  if (!isWelcomePage) {
    if (isUserAnonymous() && (edit.requireLogin || edit.premium)) {
      acceptText = '[Sign in to see premium edit]';
      acceptButtonJq.off('click').click(signInCallback);
      acceptButtonJq.off('keyup');
      properties.is_enabled = false;
    } else if (edit.premium) {
      if (!isUserEmailConfirmed()) {
        acceptText = '[Confirm email to see premium edit]';
        acceptButtonJq.off('click').click(signInCallback);
        acceptButtonJq.off('keyup');
        properties.is_enabled = false;
      } else if (!isSubscription()) {
        acceptText = '[Pro Edit: Only in Sapling Pro]';
        acceptButtonJq.off('click').click(premiumCallback);
        acceptButtonJq.off('keyup');
        properties.is_enabled = false;
      }
    }
  }
  $('#accept-text', shadowDom).html(acceptText);
  setAdvancedEditControlState(containerId, edit);
  showDescription(containerId, edit);
  setEditControlActions(containerId, edit, properties);
}

export function maybeTabIntoEditControls() {
  const editId = $(SAPLING_ENV.CONTROL_ELEMENT).attr('sapling-edit-id');
  if (editId) {
    $('#accept-button', shadowDom).focus();
    return true;
  }
  return false;
}

export function hideEditControlsImmediatelyIfNoActiveEdit() {
  if (hasMishoveredElement()) {
    hideEditControls();
  }
}

export function clearHoverTimer() {
  clearTimeout(hoverTimer);
  hoverTimer = null;
}

function displayOrHidePremiumBanner(premium) {
  const trialDaysLeft = getSubscriptionTrialDaysLeft();
  if (trialDaysLeft !== null && premium && trialDaysLeft < 4) {
    if (trialDaysLeft === 1) {
      $('#premium-text', shadowDom).html('Your trial ends in 1 day');
    } else if (trialDaysLeft < 4) {
      $('#premium-text', shadowDom).html(`Your trial ends in ${trialDaysLeft} days`);
    }
    $('#premium-banner-row', shadowDom).show();
  } else {
    $('#premium-banner-row', shadowDom).hide();
  }
}

export function showEditControlForOverlayFormat(containerId, edit, domElements, parentOverlay, focus = false) {
  clearHoverTimer();
  $('#active-edit', shadowDom).removeAttr('id');

  maybeInitEditControls();
  resetEditControls();

  if (SAPLING_ENV.MODE === 'SDK') {
    setSDKControlState(containerId, edit);
  } else {
    setChromeControlState(containerId, edit);
  }
  displayOrHidePremiumBanner(edit.premium);

  $(SAPLING_ENV.CONTROL_ELEMENT).attr('sapling-edit-id', edit.editId);
  $(SAPLING_ENV.CONTROL_ELEMENT).attr('sapling-container-id', containerId);

  const target = domElements[0];
  $(target).attr('id', 'active-edit');

  if (!target) {
    return;
  }
  const clientRect = target.getBoundingClientRect();
  // Center edit controls around phrase origin
  let leftPos = clientRect.left - 18;
  leftPos = Math.min(leftPos, (window.innerWidth + window.scrollX) - $(SAPLING_ENV.CONTROL_ELEMENT).width() - 16);
  leftPos = Math.max(leftPos, 8);

  // put edit under all bounding rect boxes so that text is not obscured
  let originTop = clientRect.top + $(target).height();
  for (let i = 1; i < domElements.length; i++) {
    const newTarget = domElements[i];
    const newClientRect = newTarget.getBoundingClientRect();

    const newOriginTop = newClientRect.top + $(newTarget).height();
    if (newOriginTop > originTop) {
      originTop = newOriginTop;
    }
  }

  let topPos = originTop + window.scrollY;
  if (topPos + $(SAPLING_ENV.CONTROL_ELEMENT).height() > window.innerHeight + window.scrollY) {
    const newOriginTop = (clientRect.top - $(SAPLING_ENV.CONTROL_ELEMENT).height()) + window.scrollY;
    if (newOriginTop >= 0) {
      topPos = newOriginTop;
    }
  }

  if (SAPLING_ENV.MODE === 'SDK') {
    let iframeAdjustment = getIframeBoundingRect(target);
    leftPos += iframeAdjustment.x;
    topPos += iframeAdjustment.y;
  }

  // Shift within bounds of text input
  const visibleEditElem = getVisibleEditElem(parentOverlay);
  const textInputBounds = getBounds(visibleEditElem);

  $(SAPLING_ENV.CONTROL_ELEMENT).data('bounds', textInputBounds);
  $(SAPLING_ENV.CONTROL_ELEMENT).data('defaultHeight', $(SAPLING_ENV.CONTROL_ELEMENT).outerHeight());
  $(SAPLING_ENV.CONTROL_ELEMENT).data('defaultOrigin', { left: leftPos, top: topPos });

  $(SAPLING_ENV.CONTROL_ELEMENT).css({
    left: leftPos,
    top: topPos,
  });
  $(SAPLING_ENV.CONTROL_ELEMENT).fadeIn(200);

  if (focus) {
    $('#accept-button', shadowDom).focus();
  }
}

export function hideEditControlForOverlayFormat() {
  if (!hoverTimer) {
    hoverTimer = setTimeout(hideEditControls, HOVER_WAIT);
  }
}
