import { documentContains } from '../../utils/sdom';

// {
//   containerId: {
//     domElement:,
//     mutationObservers: [],
//     resizeObservers: [],
//     jqueryObservers: [],
//     eventListeners: [],
//   },
// }
let containerIdToObservers = {};
// {
//   textAreaId: {
//     domElement:,
//     resizeObservers: [],  # unobserve
//     jqueryObservers: [],  # off
//     eventListeners: [],  # removeEventListener
//     intervals: [],  # clearInterval
//   },
// }
let textAreaIdToObservers = {};

// {
//   shadowHost: (domElement),
//   badge: Badge instance, holding badge domElement,
//   annotationsOverlay: AnnotationsOverlay instance, holding domElement,
// }
let SAPLING_OVERLAYS = {};

let DOCUMENT_OBSERVERS = [];
let SAPLING_EVENT_LISTENERS = [];

export function saveEventListener(info) {
  // for removal, define: { element, event, handler, options }
  SAPLING_EVENT_LISTENERS.push(info);
}

export function saveDocumentObserver(observer) {
  DOCUMENT_OBSERVERS.push(observer);
}

export function saveObservers(containerId, domElement, isTextArea, observerType, object) {
  let globalObj = isTextArea ? textAreaIdToObservers : containerIdToObservers;
  let containerObj = {};
  if (containerId in globalObj) {
    containerObj = globalObj[containerId];
  }
  if (!('domElement' in containerObj)) {
    containerObj.domElement = domElement;
  }
  let observers = [];
  if (observerType in containerObj) {
    observers = containerObj[observerType];
  }

  observers.push(object);
  containerObj[observerType] = observers;
  globalObj[containerId] = containerObj;
}

export function disableObserver(containerId, isTextArea) {
  let globalObj = isTextArea ? textAreaIdToObservers : containerIdToObservers;
  if (containerId in globalObj) {
    let containerObj = globalObj[containerId];
    if ('intervals' in containerObj) {
      containerObj.intervals.forEach((interval) => {
        clearInterval(interval);
      });
    }
    if ('eventListeners' in containerObj) {
      containerObj.eventListeners.forEach((info) => {
        info.element.removeEventListener(info.event, info.handler, info.options);
      });
    }
    if ('jqueryObservers' in containerObj) {
      containerObj.jqueryObservers.forEach((element) => {
        $(element).off();
      });
    }
    if ('resizeObservers' in containerObj) {
      containerObj.resizeObservers.forEach((info) => {
        info.observer.unobserve(info.container);
      });
    }
    if ('mutationObservers' in containerObj) {
      containerObj.mutationObservers.forEach((observer) => {
        observer.disconnect();
      });
    }

    delete globalObj[containerId];
  }
}

function disableObservers() {
  Object.keys(containerIdToObservers).forEach((containerId) => {
    disableObserver(containerId, false);
  });
  Object.keys(textAreaIdToObservers).forEach((containerId) => {
    disableObserver(containerId, true);
  });
}

export function addOverlay(id, overlayInfo) {
  SAPLING_OVERLAYS[id] = overlayInfo;
}

function teardownOverlay(overlayInfo) {
  if (!overlayInfo) {
    return;
  }
  if (overlayInfo.shadowHost) {
    overlayInfo.shadowHost.remove();
  }
  if (overlayInfo.badge) {
    overlayInfo.badge.removeUIElements();
  }
  if (overlayInfo.annotationsOverlay) {
    overlayInfo.annotationsOverlay.removeUIElements();
  }
}

function teardownOverlays() {
  for (const [id, overlyInfo] of Object.entries(SAPLING_OVERLAYS)) {
    teardownOverlay(overlyInfo);
  }
}

export function checkAndDisableInactiveObservers() {
  Object.keys(containerIdToObservers).forEach((containerId) => {
    if (!documentContains(containerIdToObservers[containerId].domElement)) {
      disableObserver(containerId, false);
    }
  });
  Object.keys(textAreaIdToObservers).forEach((containerId) => {
    if (!documentContains(textAreaIdToObservers[containerId].domElement)) {
      disableObserver(containerId, true);
    }
  });
}

export function disconnectAllObservers() {
  DOCUMENT_OBSERVERS.forEach((observer) => {
    observer.disconnect();
  });
  DOCUMENT_OBSERVERS = [];
  SAPLING_EVENT_LISTENERS.forEach((info) => {
    info.element.removeEventListener(info.event, info.handler, info.options);
  });
  SAPLING_EVENT_LISTENERS = [];
  disableObservers();
  teardownOverlays();
}
