export function getSnippets(queryTerms, context, sendResponse) {
  const timeZoneOffset = new Date().getTimezoneOffset();
  const params = {
    context,
    queryTerms,
    timeZoneOffset,
    template: true,
    usageStats: false,
    includeSuggest: true,
  };
  let getURL = '/get_snippets';

  if (queryTerms === '') {
    getURL = '/most_used_snippets';
  }

  sendAuthenticatedBackendRequest(
    getURL,
    'post',
    params,
    (snippets) => {
      // drop empty snippets (folder indicators)
      const filteredSnippets = snippets.snippets.filter(
        (snippet) => snippet.title || snippet.rich_text);
      snippets.snippets = filteredSnippets;
      sendResponse({ data: snippets, status: true, success: true });
    },
    (e) => {
      sendResponse({ data: { message: e.responseJSON.msg }, status: true, success: false });
    },
  );
}

