export function firstRangeSubset(rangeOne, rangeTwo) {
  const {
    startContainer,
    startOffset,
    endContainer,
    endOffset,
  } = rangeTwo;
  return rangeOne.isPointInRange(startContainer, startOffset) &&
    rangeOne.isPointInRange(endContainer, endOffset);
}

export function firstRangeFrontIntersect(rangeOne, rangeTwo) {
  const {
    endContainer,
    endOffset,
  } = rangeTwo;
  return rangeOne.isPointInRange(endContainer, endOffset);
}

export function firstRangeIntersect(rangeOne, rangeTwo) {
  // touching does not signifiy intersects
  const {
    startContainer,
    startOffset,
    endContainer,
    endOffset,
  } = rangeTwo;
  return rangeOne.isPointInRange(startContainer, startOffset) ||
    rangeOne.isPointInRange(endContainer, endOffset);
}

export function rangesIntersect(rangeOne, rangeTwo) {
  // touching does not signifiy intersects
  return firstRangeIntersect(rangeOne, rangeTwo) ||
    firstRangeIntersect(rangeTwo, rangeOne);
}

function isValidOffset(node, offset) {
  return offset <= (node.nodeType === Node.TEXT_NODE ? node.length : node.childNodes.length);
}

export function rangeIsValid(range) {
  const {
    startContainer,
    startOffset,
    endContainer,
    endOffset,
  } = range;
  return !!startContainer && !!endContainer &&
    startContainer.ownerDocument === endContainer.ownerDocument &&
    isValidOffset(startContainer, startOffset) &&
    isValidOffset(endContainer, endOffset);
}

function isEditable(el) {
  if (['TEXTAREA', 'INPUT'].includes(el.nodeName)) {
    return true;
  }
  if (el.isContentEditable) return true;
  return false;
}

export function findTopmostContenteditable() {
  let currentElement = document.activeElement;
  if (!isEditable(currentElement)) {
    return null;
  }
  while (currentElement.parentElement) {
    let parent = currentElement.parentElement;
    if (isEditable(parent)) {
      currentElement = parent;
    } else {
      // If parent is not contenteditable, currentElement is the topmost contenteditable
      break;
    }
  }
  return currentElement;
}

export function inEditable() {
  if (['TEXTAREA', 'INPUT'].includes(document.activeElement.nodeName)) {
    return true;
  } else if (document.activeElement.isContentEditable) {
    return true;
  }
  return false;
}
