import _ from 'lodash';
import { getSnippets, sendEvent } from '../../requests/index';
import { areSnippetsEnabled } from '../settings';
import { MakeViewPortDraggable } from '../../utils/draggable';
import { getSnippetStyling } from './style-elements';
import { sendMessage } from '../../utils/chrome-adapter';

export class SnippetControl {
  constructor() {
    this.MAX_ROWS = 10;
    this.snippetLaunched = false;
    this.previousQueryTerms = null;
    this.currentQueryTerms = '';
    this.queryCount = 0; // for stats, resets every time a snippet is selected
    this.activeRow = 0;
    this.displayedSnippets = [];
    this.defaultSnippets = []; // If specified, move finder on launch
    this.launchCoordinates = {}; // If specified, move finder on launch
    this.snippetDragger = null;

    this.shadowRoot = null;
    this.snippetControl = null;
    this.snippetTable = null;
    this.snippetTableBody = null;
    this.snippetInput = null;
    this.snippetStatus = null;
    this.debouncedGetSnippetsAndUpdate = _.debounce(this.getSnippetsAndUpdate, 200);
    this.snippetControlsKeydownHandler = this.snippetControlsKeydownHandler.bind(this);
  }

  createUIElements() {
    if (this.snippetControl) {
      return;
    }
    let oldShadowhost = $('html > sapling-snippet-controls');
    if (oldShadowhost[0]) {
      // this can happen if the extension is reloaded
      oldShadowhost.remove();
    }

    let shadowHost = document.createElement('sapling-snippet-controls');
    this.snippetControl = $(shadowHost);
    $('html').append(this.snippetControl);
    shadowHost.attachShadow({ mode: 'open' });
    this.shadowRoot = $(shadowHost.shadowRoot);
    // inject snippet css
    this.shadowRoot.append(getSnippetStyling());

    this.snippetTable = $(`
<div id="sapling-snippet-table">
  <div id="sapling-table-header">
    <div id="sapling-snippet-form-container">
      <span id="input-spacer"></span>
      <input
        id="sapling-snippet-form"
        type="text"
        placeholder="Type to search..."
        aria-label="Use Snippet"
        autocomplete="off">

    </div>
    <span id="snippet-dismiss">&times;</span>
  </div>
  <div id="sapling-table-body">
  </div>
  <div id="sapling-table-footer">
    <div id="sapling-table-footer-left">
      <div class="sapling-button-logo"></div>
      <div id="sapling-snippet-status"></div>
    </div>
    <div id="sapling-table-footer-right">
      <div id="nav-instructions">
        <span class="snippet-key">&#8593;&#8595;</span> navigate &nbsp;
        <span class="snippet-key" style="position:relative; top:1px;">&crarr;</span> select &nbsp;
        <span class="snippet-key">esc</span> close &nbsp;
      </div>
      <div id="add-snippet">
        <div class="sapling-button-snippets"></div>
        <div>&nbsp;add snippet</div>
      </div>
    </div>
  </div>
</div>
`);

    let tableHTML = $('<div id="sapling-snippet-table-container"></div>');
    tableHTML.append(this.snippetTable);
    this.shadowRoot.append(tableHTML);

    this.snippetInput = $('#sapling-snippet-form', this.shadowRoot);
    this.snippetStatus = $('#sapling-snippet-status', this.shadowRoot);
    this.snippetTableBody = $('#sapling-table-body', this.shadowRoot);
    this.setupCallbacks();
  }

  setupCallbacks() {
    $('#snippet-dismiss', this.shadowRoot).on('mousedown', (event) => {
      if (event.which === 1) {
        this.hideSnippetFinder();
      }
    });

    $('#add-snippet', this.shadowRoot).on('mousedown', (event) => {
      if (event.which === 1) {
        event.preventDefault();
        event.stopPropagation();
        sendMessage({
          action: 'snippet-add',
        });
      }
    });

    let inputSpacer = $('#input-spacer', this.shadowRoot);
    this.snippetInput.on('input', () => {
      inputSpacer.text(this.snippetInput.val());
      // resize input to text
      // min of 130 (to fit placeholder)
      // max of 500 (to fit status)
      this.snippetInput.width(Math.min(500, Math.max(inputSpacer.width() + 10, 150)));
    });
    inputSpacer.text(this.snippetInput.val());
    this.snippetInput.width(150);

    // focus the input on clicking the bar
    $('#sapling-snippet-form-container', this.shadowRoot).on('mouseup', () => { this.snippetInput.focus(); });

    let draggJq = $('#sapling-table-footer', this.shadowRoot).add(this.snippetTable);

    this.snippetDragger = new MakeViewPortDraggable(
      this.snippetTable,
      draggJq,
      '#sapling-snippet-form,#snippet-dismiss,.sapling-clickable-row,.sapling-snippet-body',
      true,
    );

    // add debouncer to input
    this.snippetInput.on('input', () => this.debouncedGetSnippetsAndUpdate(this.snippetInput.val()));
    // prevent navigation hooks on website from stealing focus back
    this.snippetInput.on(
      'keydown keypress',
      (event) => {
        let evt = event || window.event;
        if (typeof evt.stopPropagation !== 'undefined') {
          evt.stopPropagation();
        } else {
          evt.cancelBubble = true;
        }
      },
    );
    // esc key to dismiss
    this.snippetInput.on('keydown', this.inputKeydownHandler);
    this.snippetStatus.hide();

    // click outside to dismiss
    this.snippetTable.focusout(() => {
      if ($('#sapling-snippet-table :hover', this.shadowRoot).length) {
        // hack: prevent focusout on overriding click events
        return;
      }
      if (this.snippetLaunched) {
        this.hideSnippetFinder();
      }
    });

    // document360 has weird snippet insertion behavior without this
    this.snippetTableBody.on('mousedown', '.sapling-clickable-row', (event) => {
      event.stopPropagation();
      event.preventDefault();
    });

    // allow click to select
    this.snippetTableBody.on('click', '.sapling-clickable-row', (event) => {
      let rowNumber = $(event.currentTarget).index();
      this.updateActiveRow(rowNumber);
      this.rowSelected(rowNumber);
      event.stopPropagation();
      event.preventDefault();
    });

    // reset any state from a previous content script
    this.previousQueryTerms = null;
    this.debouncedGetSnippetsAndUpdate('');
  }

  getSnippetsAndUpdate(newQueryTerms) {
    // called on debounced user input
    // query on empty string fetches most used snippets
    if (!this.snippetControl) {
      // snippet controls are not instantiated in this content script
      return;
    }
    this.snippetStatus.hide();
    if (newQueryTerms === '' || newQueryTerms !== this.previousQueryTerms) {
      getSnippets(
        newQueryTerms,
        (data) => { this.onQuerySuccess(newQueryTerms, data); },
        this.onQueryFailure,
      );
      this.previousQueryTerms = newQueryTerms;
    }
  }

  onQuerySuccess(queryTerms, data) {
    this.currentQueryTerms = queryTerms;
    this.queryCount += 1;
    this.displayedSnippets = data.snippets.slice(0, this.MAX_ROWS);
    if (queryTerms === '') {
      this.defaultSnippets = this.displayedSnippets;
    }
    this.drawRows();
    if (data.snippets.length === 0) {
      this.snippetStatus.text('No Results');
      this.snippetStatus.fadeIn(400);
    } else if (this.snippetTable.hasClass('clipboard-mode')) {
      this.snippetStatus.text('copy to clipboard');
      this.snippetStatus.fadeIn(400);
    }
  }

  onQueryFailure() {
    this.snippetStatus.text('Connectivity Error');
    this.snippetStatus.show();
  }

  updateActiveRow(rowNumber) {
    $($('#sapling-table-body > div', this.shadowRoot)[rowNumber]).addClass('active').siblings().removeClass('active');
    this.activeRow = rowNumber;
  }

  showSnippetFinder() {
    if (!areSnippetsEnabled()) {
      return;
    }

    // while we mark the snippet finder as "shown" nothing is shown
    // until we receive the callback specifying the clipboard mode
    if (this.snippetLaunched) {
      return;
    }
    this.snippetLaunched = true;
    this.createUIElements();
  }

  hideSnippetFinder() {
    this.snippetLaunched = false;
    window.removeEventListener('keydown', this.snippetControlsKeydownHandler, true);
    window.removeEventListener('keyup', this.snippetControlsKeydownHandler, true);
    if (!this.snippetControl) {
      return;
    }
    this.snippetControl.hide();
    if (!this.snippetInput) {
      return;
    }
    // remove focus from snippet form, so that it can launch again in clipboard mode
    this.snippetInput.blur();
    sendMessage({ action: 'hide-snippet-controls' });
  }

  /* If show is specified, toggle action is idempotent */
  toggleSnippetFinder(coordinates, show) {
    if (coordinates) {
      this.launchCoordinates = coordinates;
    }
    if (show) {
      this.showSnippetFinder();
    } else if (show === false) {
      this.hideSnippetFinder();
    } else if (this.snippetLaunched) {
      this.hideSnippetFinder();
    } else {
      this.showSnippetFinder();
    }
  }

  handleSnippetControlCommand(data) {
    if (data.query != null) {
      this.debouncedGetSnippetsAndUpdate(data.query);
    } else if (data.key != null) {
      this.snippetControlsKeydownHandler({
        key: data.key,
        stopPropagation: () => {},
        preventDefault: () => {},
      });
    } else if (data.show != null) {
      if (data.show) {
        this.showSnippetFinder();
      } else {
        this.hideSnippetFinder();
      }
    }
  }

  snippetControlsKeydownHandler(evt) {
    if (evt.key === 'Enter') {
      this.rowSelected(this.activeRow);
      evt.preventDefault();
      evt.stopPropagation();
      return false;
    } else if (evt.key === 'Escape') {
      this.hideSnippetFinder();
      evt.preventDefault();
      evt.stopPropagation();
      return false;
    } else if (evt.key === 'ArrowUp') {
      if (this.activeRow > 0) {
        this.updateActiveRow(this.activeRow - 1);
        this.maybeScrollActiveElementIntoView(this.activeRow);
      }
      evt.preventDefault();
      evt.stopPropagation();
      return false;
    } else if (evt.key === 'ArrowDown') {
      if (this.activeRow < this.displayedSnippets.length - 1) {
        this.updateActiveRow(this.activeRow + 1);
        this.maybeScrollActiveElementIntoView(this.activeRow);
      }
      evt.preventDefault();
      evt.stopPropagation();
      return false;
    }
    // propagate event
    return true;
  }

  rowSelected(rowNum) {
    if (rowNum + 1 > this.displayedSnippets.length) {
      this.hideSnippetFinder();
      return;
    }
    let snippet = this.displayedSnippets[rowNum];
    sendMessage({
      snippet,
      currentQueryTerms: this.currentQueryTerms,
      queryCount: this.queryCount,
      action: 'snippet-selected',
    });
    this.queryCount = 0;
    this.hideSnippetFinder();
  }

  inputKeydownHandler(evt) {
    if (evt.key === 'ArrowUp') {
      // up arrow pressed
      evt.preventDefault();
      evt.stopPropagation();
      return false;
    } else if (evt.key === 'ArrowDown') {
      // down arrow pressed
      evt.preventDefault();
      evt.stopPropagation();
      return false;
    }
    // propagate event
    return true;
  }

  /*
 * Modes:
    - clipboard: (no focus, selecting a snippet will copy to clipboard)
    - inline: (user is doing an inline search. no search bar shown)
    - insert / undefined: ('regular' mode. search bar is shown)
 */
  setSnippetFinderMode(nullMode) {
    let mode = nullMode || 'insert';
    this.previousQueryTerms = null;

    this.snippetTable.removeClass('clipboard-mode inline-mode');
    if (mode === 'clipboard') {
      this.snippetTable.addClass('clipboard-mode');
      this.snippetStatus.text('copy to clipboard');
      this.snippetStatus.show();
    } else if (mode === 'inline') {
      this.snippetTable.addClass('inline-mode');
      this.snippetStatus.text('Inline search');
      this.snippetStatus.show();
      if (this.defaultSnippets.length) {
        this.displayedSnippets = this.defaultSnippets;
        this.drawRows();
        this.previousQueryTerms = '';
      }
    } else {
      this.snippetStatus.text('');
      this.snippetStatus.hide();
    }

    if (this.snippetLaunched) {
      if (this.launchCoordinates) {
        this.snippetTable.css(this.launchCoordinates);
      }
      // show the snippet table
      $('sapling-snippet-controls').show();
      if (mode !== 'inline') {
        this.snippetTable.css({ top: '50px', bottom: '' });
        this.snippetInput.focus().select();
      }
      let eventMode = mode || 'insert';
      sendEvent('extension_command', { command: 'snippet-control', mode: eventMode });
      if (mode === 'inline') {
        // inline snippet search may pipe events directly
        window.addEventListener('keydown', this.snippetControlsKeydownHandler, true);
      } else {
        window.addEventListener('keyup', this.snippetControlsKeydownHandler, true);
      }
    }
  }

  maybeScrollActiveElementIntoView(rowNumber) {
    // check if active row is in viewport, if not, scroll it into view
    let activeElement = $('#sapling-table-body > div', this.shadowRoot)[rowNumber];
    if (!activeElement) {
      return;
    }
    let activeElementJq = $(activeElement);

    let contHeight = this.snippetTableBody.height();
    let elemTop = activeElementJq.offset().top - this.snippetTableBody.offset().top;
    let elemBottom = elemTop + activeElementJq.height();

    if (elemTop < 0) {
      // align to top
      activeElement.scrollIntoView({ behavior: 'smooth', block: 'start', inline: 'nearest' });
    } else if (elemBottom > contHeight) {
      // align to bottom
      activeElement.scrollIntoView({ behavior: 'smooth', block: 'end', inline: 'nearest' });
    }
  }

  drawRows() {
    // This to updates the table UI with any new snippets returned from search
    let tbodyHTML = '';
    for (let idx = 0; idx < this.displayedSnippets.length; idx++) {
      let rowData = this.displayedSnippets[idx];

      // A highlight has <em> tags around terms matching the user query
      // If a highlight is specificed, display that
      let rowTitleDisplayStr;
      let bodyDisplayStr;
      let shortcutStr;

      if (!rowData.plain_text.trim()) continue;

      if (rowData.title_hl) {
        rowTitleDisplayStr = rowData.title_hl;
      } else {
        rowTitleDisplayStr = rowData.title;
      }

      if (rowData.plain_text_hl) {
        bodyDisplayStr = rowData.plain_text_hl;
      } else if (rowData.plain_text.length > 250) {
        bodyDisplayStr = `${rowData.plain_text.substring(0, 250)}...`;
      } else {
        bodyDisplayStr = rowData.plain_text;
      }

      if (rowData.shortcut_hl) {
        shortcutStr = rowData.shortcut_hl;
      } else {
        shortcutStr = rowData.shortcut;
      }

      let rowTitle = '';
      let rowShortcut = '';
      if (rowTitleDisplayStr) {
        rowTitle = `<span class="sapling-snippet-title">${rowTitleDisplayStr}</span>`;
      }
      if (shortcutStr) {
        rowShortcut = `<span class="sapling-snippet-shortcut">${shortcutStr}</span>`;
      }
      let rowBody = `<span class="sapling-snippet-body">${bodyDisplayStr}</span>`;
      let rowStr = `<div class='sapling-clickable-row'>${rowShortcut}${rowTitle}${rowBody}</div>`;
      tbodyHTML += rowStr;
    }

    this.snippetTableBody.html(tbodyHTML);

    // highlight first row
    this.updateActiveRow(0);

    // remove existing mouseover callbacks
    for (let idx = 0; idx < this.displayedSnippets.length; idx++) {
      let row = $('#sapling-table-body > div', this.shadowRoot)[idx];
      $(row).off('mouseover');
    }

    // on mouse motion, add updater to match mouse to row selection
    this.snippetTableBody.one('mousemove', () => {
      for (let idx = 0; idx < this.displayedSnippets.length; idx++) {
        let row = $('#sapling-table-body > div', this.shadowRoot)[idx];
        $(row).on('mouseover', () => {
          this.updateActiveRow(idx);
        });
      }
    });
  }
}
