/* eslint-disable max-classes-per-file */
/* eslint-disable class-methods-use-this */
import { getTextArea } from '../highlight/textarea';
import {
  areSnippetsEnabled,
  areSuggestionsEnabled,
  areAdvancedEditsEnabled,
  isBadgePowerButtonEnabled,
  isEnabledOnSite,
  isSubscription,
  isUserAnonymous,
  isToneEnabled,
} from '../settings';
import { showDisableTooltip } from '../tooltips';
import { sendMessage } from '../../utils/chrome-adapter';
import { isPopupEnvironment } from '../../utils/extension';
import { getTextAreaId } from '../../utils/html-utils';
import { getTopFrameHostname } from '../../utils/location';
import { SAPLING_ENV } from '../../globals';

const CUSTOM_STYLES = {
  tooltip: (() => {
    if (SAPLING_ENV.MODE !== 'SDK' || !Sapling.customStyles) {
      return '';
    }

    if (Sapling.customStyles.badgeTooltipLeft) {
      return 'tooltiptext-left';
    }

    return '';
  }),
};

class BadgeButton {
  constructor(badgeDashboard) {
    this.elem = null;
    this.badgeDashboard = badgeDashboard;
  }

  shouldShow() {
    return true;
  }

  refreshState() {
    if (this.shouldShow()) {
      this.elem.show();
    } else {
      this.elem.hide();
    }
  }
}

class EditCountButton extends BadgeButton {
  getName() {
    return 'EditCountButton';
  }

  shouldShow() {
    return SAPLING_ENV.MODE !== 'SDK';
  }

  setEditCount(count) {
    let badgeCount = $('.sapling-button-count', this.elem);
    let badgeLogo = $('.sapling-button-logo', this.elem);
    if (count === 0) {
      badgeCount.text('');
      this.setToolTipText('Sapling.ai');
      badgeCount.hide();
      badgeLogo.show();
    } else {
      badgeCount.text(count.toString());
      let tooltiptext;
      if (count === 1) {
        tooltiptext = '1 edit found';
      } else {
        tooltiptext = `${count} edits found`;
      }
      this.setToolTipText(tooltiptext);
      badgeCount.show();
      badgeLogo.hide();
    }
  }

  setToolTipText(text) {
    let tooltip = $('.sapling-button-edit-count > .tooltiptext', this.elem);
    tooltip.text(text);
  }

  createElement() {
    this.elem = $(`<div class="sapling-dashboard-icon sapling-button-edit-count">
      <span id="tooltiptext-right" class="tooltiptext caret-right">sapling.ai</span>
      <div class="sapling-button-count" style="display: none;"></div>
      <a target="_blank" href="${SAPLING_ENV.WEBSITE_URL}/user_settings">
        <div class="sapling-button-logo"></div>
      </a>
    </div>`);
    return this.elem;
  }
}

class SignInButton extends BadgeButton {
  getName() {
    return 'SignInButton';
  }

  shouldShow() {
    if (SAPLING_ENV.MODE === 'SDK') {
      return false;
    }
    return isUserAnonymous();
  }

  createElement() {
    this.elem = $(`<a target="_blank" href="${SAPLING_ENV.WEBSITE_URL}/user/sign-in">
      <div class="sapling-dashboard-icon sapling-button-profile">
          <span class="tooltiptext ${CUSTOM_STYLES['tooltip']()} caret-mid">Sign in</span>
      </div>
    </a>`);
    return this.elem;
  }
}

class SearchSnippetButton extends BadgeButton {
  getName() {
    return 'SearchSnippetButton';
  }

  shouldShow() {
    if (SAPLING_ENV.MODE === 'SDK') {
      return false;
    } else if (isPopupEnvironment()) {
      return false;
    } else if (isUserAnonymous()) {
      return false;
    }
    return areSnippetsEnabled();
  }

  createElement() {
    this.elem = $(`<div class="sapling-dashboard-icon sapling-button-search">
      <span class="tooltiptext ${CUSTOM_STYLES['tooltip']()} caret-mid">Search Snippets</span>
    </div>`);

    this.elem.on('mousedown', (event) => {
      if (event.which !== 1) {
        return;
      }
      event.preventDefault();
      event.stopPropagation();

      let { parentContainer } = this.badgeDashboard;
      let focusElement = parentContainer;
      let textAreaId = getTextAreaId(parentContainer);
      if (textAreaId) {
        // the badge is on an overlay sapling created for a textarea
        // focus the text area, not the overlay
        focusElement = getTextArea(textAreaId);
      }
      focusElement.focus();

      sendMessage({ action: 'snippet-control', data: { mode: 'insert' } });
    });

    return this.elem;
  }
}

class AddSnippetButton extends BadgeButton {
  getName() {
    return 'AddSnippetButton';
  }

  shouldShow() {
    if (SAPLING_ENV.MODE === 'SDK') {
      return false;
    }
    return !isUserAnonymous() && areSnippetsEnabled();
  }

  createElement() {
    this.elem = $(`<div class="sapling-dashboard-icon sapling-button-snippets">
      <span class="tooltiptext ${CUSTOM_STYLES['tooltip']()} caret-mid">Add Snippet</span>
    </div>`);

    this.elem.on('mousedown', (event) => {
      if (event.which !== 1) {
        return;
      }
      event.preventDefault();
      event.stopPropagation();
      let snippetString = this.badgeDashboard.parentContainer.textContent;
      // base364 encode html to pass into the snippet page
      snippetString = btoa(unescape(encodeURIComponent(snippetString)));
      let params = $.param({ preload: snippetString });
      let newSnippetUrl = `${SAPLING_ENV.WEBSITE_URL}/snippets/new?${params}`;
      window.open(newSnippetUrl);
    });

    return this.elem;
  }
}

class AddSuggestionButton extends BadgeButton {
  getName() {
    return 'AddSuggestionButton';
  }

  shouldShow() {
    if (SAPLING_ENV.MODE === 'SDK') {
      return false;
    } else if (isUserAnonymous) {
      return false;
    } else if (!isSubscription()) {
      return false;
    }
    return areSuggestionsEnabled();
  }

  createElement() {
    this.elem = $(`<div class="sapling-dashboard-icon sapling-button-suggest">
      <span class="tooltiptext ${CUSTOM_STYLES['tooltip']()} caret-mid">Add Suggestion</span>
    </div>`);

    this.elem.on('mousedown', (event) => {
      if (event.which !== 1) {
        return;
      }
      event.preventDefault();
      event.stopPropagation();
      let suggestString = $(this.badgeDashboard.parentContainer).text().trim();
      // base364 encode html
      suggestString = btoa(unescape(encodeURIComponent(suggestString)));
      let params = $.param({ preload: suggestString });
      let newSuggestUrl = `${SAPLING_ENV.WEBSITE_URL}/suggest/new?${params}`;
      window.open(newSuggestUrl);
    });
    return this.elem;
  }
}

class AnnotationsButton extends BadgeButton {
  getName() {
    return 'AnnotationsButton';
  }

  shouldShow() {
    if (SAPLING_ENV.MODE === 'SDK') {
      return areAdvancedEditsEnabled();
    } else if (isPopupEnvironment()) {
      return false;
    } else if (isUserAnonymous()) {
      return false;
    }
    return areAdvancedEditsEnabled();
  }

  updateIcon() {
    let tooltip = 'Show Annotations';
    if (this.badgeDashboard.containerInfo &&
        this.badgeDashboard.containerInfo.annotationsOverlay &&
        this.badgeDashboard.containerInfo.annotationsOverlay.summaryAnnotations &&
        this.badgeDashboard.containerInfo.annotationsOverlay.summaryAnnotations.summaryVisible()) {
      tooltip = 'Hide Annotations';
    }
    $(this.elem).find('.tooltiptext').html(tooltip);
  }

  createElement() {
    this.elem = $(`<div class="sapling-dashboard-icon sapling-button-annotations">
      <span class="tooltiptext ${CUSTOM_STYLES['tooltip']()} caret-mid">Show Annotations</span>
    </div>`);

    this.elem.on('mousedown', (event) => {
      if (event.which !== 1) {
        return;
      }
      event.preventDefault();
      event.stopPropagation();

      this.badgeDashboard.containerInfo.annotationsOverlay.toggleSummaryAnnotations();
      this.updateIcon();
    });

    return this.elem;
  }
}

class ToneButton extends BadgeButton {
  getName() {
    return 'ToneButton';
  }

  shouldShow() {
    return isToneEnabled();
  }

  updateIcon() {
    const { toneOverlay } = this.badgeDashboard.containerInfo;
    if (!toneOverlay) {
      return;
    }

    const topTone = toneOverlay.getTopTone();
    let tooltip = 'Show Tone';
    if ($(toneOverlay.toneOverlay).is('.visible')) {
      tooltip = 'Hide Tone';
    } else if (topTone) {
      $(this.elem).find('.top-tone-emoji').html(topTone[2]);
      tooltip = `${topTone[1]} tone<br/>See More`;
      $(this.elem).css({ backgroundSize: 0 });
    }
    $(this.elem).find('.tooltiptext').html(tooltip);
  }

  createElement() {
    this.elem = $(`<div class="sapling-dashboard-icon sapling-button-tone">
      <span class="top-tone-emoji">😐</span>
      <span class="tooltiptext ${CUSTOM_STYLES['tooltip']()} caret-mid">Show Tone</span>
    </div>`);

    this.elem.on('mousedown', (event) => {
      if (event.which !== 1) {
        return;
      }
      event.preventDefault();
      event.stopPropagation();

      if (this.badgeDashboard.containerInfo.toneOverlay) {
        this.badgeDashboard.containerInfo.toneOverlay.toggleVisibility();
      }
      this.updateIcon();
    });

    return this.elem;
  }
}

