class PowerButton extends BadgeButton {
  getName() {
    return 'PowerButton';
  }

  shouldShow() {
    if (SAPLING_ENV.MODE === 'SDK') {
      return Sapling.userToggle;
    }
    return isBadgePowerButtonEnabled();
  }

  refreshState() {
    const hostname = getTopFrameHostname();
    let toggle = 'off';
    let tooltiptext;
    if (SAPLING_ENV.MODE === 'SDK') {
      if (Sapling.userToggleEnabled) {
        toggle = 'off';
        tooltiptext = 'Disable grammar checking';
      } else {
        toggle = 'on';
        tooltiptext = 'Enable grammar checking';
      }
    } else {
      tooltiptext = `Turn ${toggle} Sapling for ${hostname}`;
    }
    let tooltip = $(this.elem).find('.tooltiptext').html(tooltip);
    tooltip.text(tooltiptext);
    super.refreshState();
  }

  createElement() {
    const hostname = getTopFrameHostname();
    this.elem = $(`<div class="sapling-dashboard-icon sapling-button-power">
      <span class="tooltiptext ${CUSTOM_STYLES['tooltip']()} caret-mid">Turn off Sapling for ${hostname}</span>
    </div>`);

    this.elem.on('mousedown', (event) => {
      if (event.which !== 1) {
        return;
      }
      event.preventDefault();
      event.stopPropagation();
      const offset = this.elem.offset();
      this.badgeDashboard.hide();
      const currentlyEnabled = SAPLING_ENV.MODE === 'SDK' ? Sapling.userToggleEnabled : isEnabledOnSite();
      showDisableTooltip(currentlyEnabled, offset.top - 60, offset.left - 110);
    });
    return this.elem;
  }
}

