import {
  getEdits,
  getCompletion,
  getSuggest,
  getMatchSuggest,
  sendEvent,
} from './index';
import {
  cacheEditsResponse,
  isInLoadingState,
  requestQueuedCalls,
  setLoadingState,
} from './cache';
import {
  maybeEmbedSaplingComplete,
  clearAndHideComplete,
  completeMidLine,
  getCompleteQueryText,
  showComplete,
} from '../ui/complete';
import {
  getEditCountForOverlay,
  showBadgeCountForOverlay,
  showBadgeErrorForOverlay,
  showBadgeLoadingForOverlay,
  showBadgeThrottledForOverlay,
  updateAnnotations,
  updateAnnotationSummary,
  updateTone,
} from '../ui/highlight/overlay';
import {
  getConnectionEstablished,
  makeToolbarIconActive,
  makeToolbarIconLoading,
  makeToolbarIconThrottled,
  setConnectionEstablished,
  updateToolbarIconDisconnected,
  updateToolbarIconEditCount,
} from '../ui/toolbar';
import { maybeShowLoginTooltip } from '../ui/tooltips';
import { updateSaplingEmbedded } from '../ui/popup';

const SAPLING_EDITS_APPLIED_IDS_SENT = new Set();

export default function getAndApplyEditsForContainer(
  innerHtml,
  htmlHash,
  parentContainer,
  containerId,
) {
  // initialize network call and handle button states.
  if (isInLoadingState()) {
    showBadgeLoadingForOverlay(containerId);
  }
  makeToolbarIconLoading();
  updateAnnotations(containerId);
  return getEdits(innerHtml, containerId, async (data) => {
    const { edits } = data;
    if (edits.includes('throttled')) {
      maybeShowLoginTooltip();
      makeToolbarIconThrottled();
      showBadgeThrottledForOverlay(containerId);
      if (parentContainer.id === 'sapling-embedded-editable') {
        updateSaplingEmbedded(true);
      }
      return;
    }

    setLoadingState(containerId, htmlHash);
    requestQueuedCalls();

    let count = 0;
    await cacheEditsResponse(
      parentContainer,
      containerId,
      htmlHash,
      edits,
    );
    count = getEditCountForOverlay(parentContainer);
    setConnectionEstablished(true);
    if (count > 0 && !SAPLING_EDITS_APPLIED_IDS_SENT.has(containerId)) {
      const properties = {
        num_edits: count,
      };
      sendEvent('edits_applied', properties, containerId);
      SAPLING_EDITS_APPLIED_IDS_SENT.add(containerId);
    }

    if (getConnectionEstablished()) {
      if (parentContainer.id === 'sapling-embedded-editable') {
        makeToolbarIconActive(); // Current behavior: do not display count for popup window edits
      } else {
        updateToolbarIconEditCount(count);
      }
    }
    showBadgeCountForOverlay(containerId);
    updateTone(containerId);
    updateAnnotationSummary(containerId);
  }, (resp) => {
    setConnectionEstablished(false);
    updateToolbarIconDisconnected();
    showBadgeCountForOverlay(containerId);
    showBadgeErrorForOverlay(containerId);
  });
}

export function getAndDisplayCompletion(editable, containerId) {
  maybeEmbedSaplingComplete();
  clearAndHideComplete();
  editable = $(editable)[0];
  if (completeMidLine(editable)) {
    return;
  }
  let queryText = getCompleteQueryText(editable);

  if (!queryText || !queryText.trim()) return;

  getCompletion(queryText, containerId, (data) => {
    if (getCompleteQueryText(editable) !== queryText) {
      clearAndHideComplete();
      return;
    }
    const { completion } = data;
    if (!completion || !completion.output || !completion.output.trim()) return;
    showComplete(editable, completion.output, completion);
  }, () => {
    setConnectionEstablished(false);
    updateToolbarIconDisconnected();
  });
}


export function getAndDisplaySuggest(query, multiquery, showFn, moreContext) {
  let isHidden = document.hidden;
  let context = { hidden: isHidden };
  Object.assign(context, moreContext);

  return getSuggest(
    query,
    multiquery,
    (data) => { showFn(data); },
    () => {},
    context,
  );
}

export function matchAndDisplaySuggest(inp, showFn, context) {
  getMatchSuggest(
    inp,
    (data) => { showFn(data); },
    () => {},
    context,
  );
}
