import { getAssetURL } from '../../utils/chrome-adapter';
import { initOrUpdateContainerOverlay } from '../highlight/overlay';
import { onUpdateTagForOverlayFormatPerContainer } from '../../ui/highlight/overlay';
import { getTopFrameHostname } from '../../utils/location';

let figmaTextNodes = {};
let figmaViewport = {};
let fontsImported = {};

let _initializeObserversPerEditableBlock;
let _onTextChangeDebounced;

export function initializeFigmaObserver(
  initializeObserversPerEditableBlock,
  onTextChangeDebounced,
) {
  _initializeObserversPerEditableBlock = initializeObserversPerEditableBlock;
  _onTextChangeDebounced = onTextChangeDebounced;

  if (!getTopFrameHostname().includes('figma.com')) {
    return;
  }

  $(() => {
    $('div[name="propertiesPanelContainer"]').css('z-index', 1);
  });

  // Emitted whenever any text property changes
  // This should include text content changes, but also
  // text element repositioning, size/font changes
  window.addEventListener(
    'sapling-figma-text-nodes-updated',
    e => {
      handleFigmaTextNodesUpdated(e.detail.figmaTextNodes);
    },
  );

  // Emitted on canvas repositioning, zooming etc
  window.addEventListener(
    'sapling-figma-viewport-updated',
    e => {
      handleFigmaViewportUpdated(
        e.detail.figmaViewport,
        e.detail.figmaTextNodes,
      );
    },
  );
}

function handleFigmaTextNodesUpdated(textNodes) {
  // Need this to position the overlays
  if (!figmaViewport.viewportBounds || !figmaViewport.zoom || !textNodes) {
    return;
  }

  // Remove old nodes first
  Object.keys(figmaTextNodes).filter(figmaId => {
    const matchingActiveNodes = textNodes.filter(node => node.figmaId === figmaId);
    if (matchingActiveNodes.length === 0) {
      figmaTextNodes[figmaId].overlayDomElement.remove();
      delete figmaTextNodes[figmaId];
    }
  });

  textNodes.forEach(textNode => handleFigmaTextNodeUpdated(textNode));
}

function handleFigmaTextNodeUpdated(textNode) {
  const { figmaId } = textNode;

  if (!figmaTextNodes.hasOwnProperty(figmaId)) {
    figmaTextNodes[figmaId] = { ...textNode };
  }
  const editable = initOrUpdateFigmaTextOverlay(textNode);
  _onTextChangeDebounced({
    saplingId: $(editable).attr('sapling-id'),
    editable,
  });
}

function initOrUpdateFigmaTextOverlay(textNode) {
  const { figmaId, characters, textBounds, style } = textNode;

  if (!figmaTextNodes.hasOwnProperty(figmaId)) {
    // not sure how we got here, but ditch
    return;
  }

  let { overlayDomElement } = figmaTextNodes[figmaId];
  if (!overlayDomElement) {
    overlayDomElement = document.createElement('div');
    overlayDomElement.setAttribute('contenteditable', true);
    $(overlayDomElement).attr('id', `sapling-figma-text-${figmaId}`);
    $(overlayDomElement).attr('sapling-figma-text-id', figmaId);
    $(overlayDomElement).data('sapling-figma-text-id', figmaId);

    const bodyEl = document.getElementsByTagName('body')[0];
    bodyEl.appendChild(overlayDomElement);

    figmaTextNodes[figmaId].overlayDomElement = overlayDomElement;
    // _initializeObserversPerEditableBlock(overlayDomElement);
    // Don't call this here - wait till after innerHTML is set

    overlayDomElement.addEventListener('input', e => {
      window.dispatchEvent(new CustomEvent(
        'sapling-figma-edit-accepted',
        {
          detail: {
            figmaId,
            updatedText: htmlToFigmaCharacters(overlayDomElement.innerHTML),
          },
        },
      ));
    });
  }

  const canvasTop = figmaViewport.canvasRect.top;
  const canvasLeft = figmaViewport.canvasRect.left;
  const viewportTop = figmaViewport.viewportBounds.y;
  const viewportLeft = figmaViewport.viewportBounds.x;

  let zoom = figmaViewport.zoom;
  $(overlayDomElement).data('figma-zoom', zoom);

  const textNodeTop = textBounds.y;
  const textNodeLeft = textBounds.x;
  const textWidth = textBounds.width;
  const textHeight = textBounds.height;

  const computedLeft = canvasLeft + ((textNodeLeft - viewportLeft) * zoom);
  const computedTop = canvasTop + ((textNodeTop - viewportTop) * zoom);
  const computedWidth = textWidth * zoom;
  const computedHeight = textHeight * zoom;

  // TODO - support rotation

  const {
    textAlignHorizontal,
    textAlignVertical,
    paragraphSpacing,
    paragraphIndent,
    listSpacing,
    textSegments,
  } = style;

  const computedParagraphSpacing = paragraphSpacing;
  const computedListSpacing = listSpacing;

  overlayDomElement.innerHTML = '';
  let containerSpan = document.createElement('span');
  $(containerSpan).css({ zoom });
  onUpdateTagForOverlayFormatPerContainer($(overlayDomElement).attr('sapling-id'));

  function splitStringOnMultipleDelimiters(text, delimiters) {
    const regex = new RegExp(`[${delimiters.join('')}]`, 'g');
    return text.split(regex);
  }
  const paragraphSeparator = String.fromCodePoint(8232);
  const linesOfText = splitStringOnMultipleDelimiters(
    characters.trim(),
    ['\n', paragraphSeparator],
  );

  let cursorIndex = 0;
  let currentSegmentIndex = 0;
  let currentSegment;
  let isEmptyLine;

  // each line of text gets a div
  for (let lineOfText of linesOfText) {
    isEmptyLine = lineOfText.length === 0;
    const lineEl = document.createElement('div');

    currentSegment = textSegments[currentSegmentIndex];
    const isList = currentSegment.listOptions.type !== 'NONE';

    const styles = {};
    if (!isList) {
      styles['text-indent'] = `${paragraphIndent}px`;
    }

    if (cursorIndex === 0) {
      // This is the first line, no margin-top
    } else if (isList) {
      // we need to check if the previous segment was not a list
      // because the first list item gets paragraphSpacing,
      // the rest get list spacing
      if (textSegments[currentSegmentIndex - 1].listOptions.type !== 'NONE') {
        styles['margin-top'] = `${computedParagraphSpacing}px`;
      } else {
        styles['margin-top'] = `${computedListSpacing}px`;
      }
    } else {
      styles['margin-top'] = `${computedParagraphSpacing - 1}px`;
    }

    const { lineHeight } = currentSegment;
    let computedLineHeight = 'inherit';
    if (lineHeight.unit === 'PERCENT') {
      computedLineHeight = Math.trunc(lineHeight.value) / 100;
    } else if (lineHeight.unit === 'PIXELS') {
      computedLineHeight = `${lineHeight.value - 1}px`;
    } else if (lineHeight.unit === 'AUTO') {
      // Force a 1:1 ratio with font size to match Figma's rendering
      computedLineHeight = 1;
    }
    styles['line-height'] = computedLineHeight;

    $(lineEl).css(styles);
    if (isEmptyLine) {
      $(lineEl).attr('sapling-figma-empty-line', true);
    }

    const endOfLineIndex = cursorIndex + lineOfText.length;
    while (isEmptyLine || (cursorIndex < endOfLineIndex && currentSegment)) {
      let segmentEl = document.createElement('span');
      const {
        characters: segmentCharacters,
        start: segmentStart,
        end: segmentEnd,
        fontName,
        fontSize,
        fontWeight,
        letterSpacing,
        textCase,
      } = currentSegment;

      const formattedFontName = fontName.family.split(' ').join('+') + `:wght@${fontWeight}`;
      if (!fontsImported.hasOwnProperty(formattedFontName)) {
        document.getElementsByTagName('head')[0].innerHTML +=
          `<link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=${formattedFontName}" />`;
        fontsImported[formattedFontName] = 1;
      }

      const computedFontSize = fontSize;

      let computedTextCase = 'inherit';
      if (textCase === 'UPPER' || textCase === 'LOWER') {
        computedTextCase = textCase.toLowerCase() + 'case';
      } else if (textCase === 'TITLE') {
        computedTextCase = 'capitalize';
      }

      // TODO: Handle overflow

      let computedLetterSpacing = 'inherit';
      if (letterSpacing.unit === 'PERCENT') {
        computedLetterSpacing = `${Math.trunc(letterSpacing.value * 100) / 10000}em`;
      } else if (letterSpacing.unit === 'PIXELS') {
        computedLetterSpacing = `${letterSpacing.value}px`;
      }

      $(segmentEl).css({
        'font-family': fontName.family,
        'font-style': fontName.style,
        'font-size': `${computedFontSize}px`,
        'text-transform': computedTextCase,
        'letter-spacing': computedLetterSpacing,
        'font-weight': fontWeight,
      });

      const sliceStart = cursorIndex - segmentStart;
      const sliceLength = Math.min(segmentEnd, endOfLineIndex) - cursorIndex;
      const sliceEnd = sliceStart + sliceLength;
      segmentEl.textContent = segmentCharacters.slice(sliceStart, sliceEnd);
      if (isEmptyLine) {
        // Need to put placeholder content because otherwise
        // it'll just get skipped in the rendering
        segmentEl.textContent = '\u200B'; // zero-width space
      }
      lineEl.appendChild(segmentEl);

      cursorIndex = Math.min(endOfLineIndex, segmentEnd);
      if (endOfLineIndex >= segmentEnd) {
        currentSegmentIndex++;
      } else {
        // If we're in the same segment but moved to the next
        // line, that means we encountered a \n
        cursorIndex++;
      }
      currentSegment = textSegments[currentSegmentIndex];
      isEmptyLine = false;
    }
    containerSpan.appendChild(lineEl);
  }

  overlayDomElement.appendChild(containerSpan);

  // Ok you would think horizontal alignment would be easy
  // But of course not... _vertical_ alignment needs flex
  let computedJustifyContent = 'flex-start';
  let computedTextAlign = textAlignHorizontal.toLowerCase();
  if (textAlignHorizontal === 'CENTER') {
    computedJustifyContent = 'center';
  } else if (textAlignHorizontal === 'RIGHT') {
    computedJustifyContent = 'flex-end';
  } else if (textAlignHorizontal === 'JUSTIFIED') {
    computedTextAlign = 'justify';
  }

  let computedAlignItems = 'flex-start';
  if (textAlignVertical === 'CENTER') {
    computedAlignItems = 'center';
  } else if (textAlignVertical === 'BOTTOM') {
    computedAlignItems = 'flex-end';
  }

  $(overlayDomElement).css({
    spellcheck: false,
    'color': 'red',
    opacity: 0,
    'pointer-events': 'none',
    position: 'fixed',
    top: `${computedTop}px`,
    left: `${computedLeft}px`,
    height: `${computedHeight}px`,
    width: `${computedWidth}px`,
    'text-align': computedTextAlign,
    display: 'flex',
    'justify-content': computedJustifyContent,
    'align-items': computedAlignItems,
  });

  _initializeObserversPerEditableBlock(overlayDomElement);
  initOrUpdateContainerOverlay(overlayDomElement);

  return overlayDomElement;
}

function handleFigmaViewportUpdated(viewport, textNodes) {
  figmaViewport = viewport;
  handleFigmaTextNodesUpdated(textNodes);
}

function htmlToFigmaCharacters(htmlString) {
  const parser = new DOMParser();
  const doc = parser.parseFromString(htmlString, 'text/html');

  // DOMParser returns a DOM that starts with
  // (first child) HTML ->
  // head + (last child) body ->
  // (first child) actual content
  const containerSpan = doc.firstChild.lastChild.firstChild;

  let outputString = '';
  for (let child of containerSpan.children) {
    if (child.attributes.hasOwnProperty('sapling-figma-empty-line')) {
      outputString += '\n';
    } else {
      outputString += child.textContent + '\n';
    }
  }

  return outputString.trimEnd();
}
