const BUTTON_SIZE = 32;
const MAX_SELECTION_LENGTH = 250;  // Match to backend *_REPHRASE_CHAR_LENGTH

// NOTE Keep in mind we'll want to expose the interface here
// so that users can display elements

let rephraseControls = (typeof rephraseControls == 'undefined') ? null : rephraseControls;
let rephraseButton = (typeof rephraseButton == 'undefined') ? null : rephraseButton;

export function getActiveRange(editableOnly = true, visibleOnly = true) {
  if (visibleOnly && !document.activeElement.checkVisibility()) return false;
  if (editableOnly && !inEditable()) return false;
  const selection = getSelection();
  return selection.rangeCount && !selection.isCollapsed && selection.getRangeAt(0);
}

function validRephraseActiveRange(activeRange) {
  if (!activeRange || !activeRange.toString().trim() || activeRange.toString().length > MAX_SELECTION_LENGTH) {
    return false;
  }
  return true;
}

