export class RephraseButton {
  constructor(shadowHost) {
    this.shadowHost = shadowHost;
    this.rephraseButton = null;
    this.rephraseShortcut = null;
    this.rephraseSpinner = null;
    this.rephraseWand = null;
  }

  static positionButton() {
    let activeRange = getActiveRange();
    if (!validRephraseActiveRange(activeRange)) return;
    // Place the element's bottom left corner at the top right of the selected range
    // Check visible portion of editable.
    let editable = findTopmostContenteditable();
    if (!editable) {
      console.log("Couldn't find editable");
      return;
    }
    const editableBbox = editable.getBoundingClientRect();
    const bbox = activeRange.getBoundingClientRect();

    if (editableBbox.top > bbox.top - BUTTON_SIZE) {
      $('sapling-rephrase-button').css({
        left: bbox.x + bbox.width + 5 + window.scrollX,
        top: bbox.y + window.scrollY,
        position: 'absolute',
      });
    } else {
      $('sapling-rephrase-button').css({
        left: bbox.x + bbox.width + 5 + window.scrollX,
        top: bbox.y - 5 - BUTTON_SIZE + window.scrollY,
        position: 'absolute',
      });
    }
  }

  createUIElements() {
    if (!isRephraseEnabled()) {
      return;
    }
    if (this.rephraseButton) {
      // Should already be created
      return;
    }
    // Clean up stale element
    $(this.shadowHost.shadowRoot).find('.sapling-rephrase-button').remove();

    getRephraseShortcut((data) => {
      this.rephraseShortcut = data.shortcut;
      this.rephraseButton = $(`
          <div class="sapling-rephrase-button">
            ${rephraseButtonCss()}
            ${tooltipCss()}
            <div style="margin-left: -47px; margin-bottom: 3px;" class="tooltiptext caret-mid">
            Rephrase${this.rephraseShortcut ? '&nbsp;<span class="shortcut-key">' + this.rephraseShortcut + '</span>' : ''}
            </div>
            <img class="sapling-rephrase-wand" src="${getAssetURL('assets/fa-wand-magic-sparkles-solid.svg')}" />
            <img class="sapling-rephrase-spinner" src="${getAssetURL('assets/fa-spinner-solid-white.svg')}" />
          </div>
      `);
      this.rephraseWand = this.rephraseButton.find('.sapling-rephrase-wand').first();
      this.rephraseSpinner = this.rephraseButton.find('.sapling-rephrase-spinner').first();
      this.rephraseSpinner.hide()
      let { shadowRoot } = this.shadowHost;
      $(shadowRoot).append(this.rephraseButton);
      this.rephraseButton.get(0).addEventListener('mousedown', (event) => {
        if (event.which !== 1) {
          return;
        }
        rephraseControls.toggleControls();
        event.preventDefault();
        event.stopPropagation();
      });
      RephraseButton.positionButton();
    }, (e) => { console.log(e); }); // End getRephraseShortcut callback
  }

  show() {
    setTimeout(() => {
      let activeRange = getActiveRange();
      if (!validRephraseActiveRange(activeRange)) return;
      RephraseButton.positionButton();
      this.rephraseButton.fadeIn(50);
    }, 200);
  }

  hide() {
    if (this.rephraseButton) this.rephraseButton.hide();
  }
}

export class RephraseControls {
  constructor(shadowHost) {
    this.shadowHost = shadowHost;

    this.activeRange = null;
    this.rephraseContainer = null;
    this.rephraseCandidatesContainer = null;
    this.rephraseStatusMessage = null;
    this.rephraseType = 'paraphrase';
    this.toneMapping = 'straightforward';
  }

  setRephraseType(typeEl) {
    const rephraseType = $(typeEl).attr('data-rephrase-type');
    this.rephraseType = rephraseType;
    $(typeEl).parent().find('.sapling-rephrase-type-active').removeClass('sapling-rephrase-type-active');
    $(typeEl).addClass('sapling-rephrase-type-active');
    this.queryAndUpdate();
  }

  setToneMapping(typeEl) {
    const toneMapping = $(typeEl).attr('data-tone-mapping');
    this.toneMapping = toneMapping;
    $(typeEl).parent().find('.sapling-tone-mapping-active').removeClass('sapling-tone-mapping-active');
    $(typeEl).addClass('sapling-tone-mapping-active');
    this.queryAndUpdate();
  }

  createUIElements() {
    if (!isRephraseEnabled()) {
      return;
    }
    if (this.rephraseContainer) {
      // Should already be enabled
      return;
    }
    $(this.shadowHost.shadowRoot).find('.sapling-rephrase-container').remove();

    this.rephraseContainer = $(`
      <div class="sapling-rephrase-container" style="display: none;">
        ${rephraseCss()}
        ${tooltipCss()}
        <div class="sapling-rephrase-types">
          <div class="sapling-rephrase-type sapling-rephrase-type-paraphrase" data-rephrase-type="paraphrase" title="Paraphrase">
            <div style="margin-left: -176px" class="tooltiptext caret-mid">Paraphrase</div>
            <img src="${getAssetURL('assets/fa-rotate-solid.svg')}" />
          </div>
          <div class="sapling-rephrase-type sapling-rephrase-type-formal" data-rephrase-type="informal_to_formal" title="Formal">
            <img src="${getAssetURL('assets/fa-black-tie.svg')}" />
            <div style="margin-left: -141px" class="tooltiptext caret-mid">Make formal</div>
          </div>
          <!--<div class="sapling-rephrase-type sapling-rephrase-type-informal" data-rephrase-type="formal_to_informal" title="Informal">
            <img src="${getAssetURL('assets/fa-shirt-solid.svg')}" />
          </div>-->
          <div class="sapling-rephrase-type sapling-rephrase-type-split" data-rephrase-type="sentence_split" title="Split">
            <img src="${getAssetURL('assets/fa-scissors-solid.svg')}" />
            <div style="margin-left: -107px" class="tooltiptext caret-mid">Split</div>
          </div>
          <div class="sapling-rephrase-type sapling-rephrase-type-tone" data-rephrase-type="switch_tone" title="Tone">
            <div class="dropdown-toggle">
              <img src="${getAssetURL('assets/fa-smile-solid.svg')}" />
              <div style="margin-left: -74px" class="tooltiptext caret-mid">Switch Tone</div>
              <div class="dropdown-menu-wrapper">
                <ul class="dropdown-menu">
                  <li class="sapling-tone-mapping" data-tone-mapping="straightforward">Straightforward</li>
                  <li class="sapling-tone-mapping" data-tone-mapping="confident">Confident</li>
                  <li class="sapling-tone-mapping" data-tone-mapping="friendly">Friendly</li>
                  <li class="sapling-tone-mapping" data-tone-mapping="empathetic">Empathetic</li>
                </ul>
              </div>
            </div>
          </div>
        </div>
        <div class="sapling-rephrase-candidates">
        </div>
        <div class="sapling-rephrase-status-bar">
          <div style="display: flex"><img src="${getAssetURL('assets/sapling-logo-small-white.svg')}" style="height: 16px" /></div>
          <div class="sapling-rephrase-status-message"></div>
        </div>
      </div>
    `);
    let { shadowRoot } = this.shadowHost;
    $(shadowRoot).append(this.rephraseContainer);
    this.rephraseCandidatesContainer = this.rephraseContainer.find('.sapling-rephrase-candidates').first();
    this.rephraseStatusMessage = this.rephraseContainer.find('.sapling-rephrase-status-message').first();
    this.rephraseSpinner = this.rephraseContainer.find('.sapling-rephrase-spinner').first();

    rephraseControls = this;

    this.rephraseContainer.find('.sapling-rephrase-type').each((ind, el) => {
      if ($(el).attr('data-rephrase-type') === rephraseControls.rephraseType) {
        $(el).addClass('sapling-rephrase-type-active');
      } else {
        $(el).removeClass('sapling-rephrase-type-active');
      }
      let callback = (e) => {
        e.preventDefault();
        e.stopPropagation();
        rephraseControls.setRephraseType(e.data.el);
      };
      $(el).on('mousedown', { el }, callback);
    });

    this.rephraseContainer.find('.sapling-tone-mapping').each((ind, el) => {
      if ($(el).attr('data-tone-mapping') === rephraseControls.toneMapping) {
        $(el).addClass('sapling-tone-mapping-active');
      } else {
        $(el).removeClass('sapling-tone-mapping-active');
      }
      let callback = (e) => {
        e.preventDefault();
        e.stopPropagation();
        rephraseControls.setToneMapping(e.data.el);
      };
      $(el).on('mousedown', { el }, callback);
    });

    this.showControls();
  }

  positionControls() {
    if (!this.activeRange) {
      return;
    }

    // Place the element's top left corner at the bottom left of the selected range
    // if there's enough space (i.e., selected text not near bottom).
    // Otherwise put bottom left at the top left of selected range.
    const bbox = this.activeRange.getBoundingClientRect();
    const controlsHeight = $('sapling-rephrase-controls').height();
    // Also include 2nd condition because sometimes unable to scroll up in small iframes
    if (bbox.y < window.innerHeight - controlsHeight || bbox.y < controlsHeight / 2) {
      $('sapling-rephrase-controls').css({
        left: bbox.x + window.scrollX,
        top: bbox.y + bbox.height + window.scrollY,
        position: 'absolute',
      });
    } else {
      $('sapling-rephrase-controls').css({
        left: bbox.x + window.scrollX,
        top: bbox.y - controlsHeight + window.scrollY - 2,
        position: 'absolute',
      });
    }
  }

  showControls() {
    this.activeRange = getActiveRange();
    if (!validRephraseActiveRange(this.activeRange)) return;
    this.queryAndUpdate();
    this.rephraseContainer.show();
    this.positionControls();
  }

  hideControls() {
    this.activeRange = null;
    if (this.rephraseContainer) {
      this.rephraseContainer.hide();
    }
  }

  toggleControls() {
    if (!this.rephraseContainer) {
      return;
    }
    if (this.rephraseContainer.is(':visible')) {
      this.hideControls();
    } else {
      this.showControls();
    }
  }

  loadingOn() {
    this.setStatus('Loading suggestions...');
    this.rephraseCandidatesContainer.html('');
    if (rephraseButton?.rephraseWand?.length) {
      rephraseButton.rephraseWand.hide();
    }
    if (rephraseButton?.rephraseSpinner?.length) {
      rephraseButton.rephraseSpinner.show();
    }
  }

  loadingOff() {
    this.setStatus('Ready.');
    if (rephraseButton?.rephraseSpinner?.length) {
      rephraseButton.rephraseSpinner.hide();
    }
    if (rephraseButton?.rephraseWand?.length) {
      rephraseButton.rephraseWand.show();
    }
  }

  queryAndUpdate() {
    this.loadingOn();
    // TODO Get rephrase hash as session ID
    let text = this.activeRange.toString();
    getRephrase(text,
                this.rephraseType,
                'en',
                {tone_mapping: this.toneMapping},
                'TODO-SESSION-ID',
                (data) => {
      this.updateCandidates(data.rephrases.results);
      this.loadingOff();
    }, (error) => {
      this.loadingOff();
      //console.log(error.err);
      if (error && text.length > 250) {  // FIXME Should read error msg
        this.setStatus('Error: selected text too long');
      } else {
        this.setStatus('Unexpected error');
      }
    });
  }

  static copyCandidate(el, e) {
    e.preventDefault();
    e.stopPropagation();
    let html = el[0].querySelector('span').innerText;
    copyToClipboard(html)
    rephraseControls.setStatus('Text copied.');
  }

  updateCandidates(candidates) {
    // TODO There will be multiple categories of suggestions
    this.rephraseCandidatesContainer.html('');
    for (const candidate of candidates) {
      const el = $(`<div class="sapling-rephrase-candidate" data-candidate-hash="${candidate.hash}">
          <span>${candidate.replacement}</span>
          <img class="candidate-copy-icon" src="${getAssetURL('assets/fa-copy-regular.svg')}" title="Copy" />
        </div>`);
      el.find('.candidate-copy-icon').first().mousedown((e) => {
        RephraseControls.copyCandidate(el, e);
      });
      this.rephraseCandidatesContainer.append(el);
    }

    this.rephraseCandidatesContainer.find('.sapling-rephrase-candidate').each((ind, el) => {
      const text = el.innerText;
      el.addEventListener('mousedown', (e) => {
        rephraseControls.acceptCandidate(text, document.activeElement, $(el).attr('data-candidate-hash'));
        e.preventDefault();
        e.stopPropagation();
      });
    });

    this.positionControls();
  }

  // TODO rejectCandidate
  acceptCandidate(candidate, containerDomElement, candidateHash) {
    // Take active section and apply the selected selection
    if (!this.activeRange) {
      return;
    }

    const editRange = this.activeRange;
    const textAreaId = getTextAreaId(containerDomElement);
    const containerId = getContainerId(containerDomElement);
    // TODO Sometimes won't have this
    const sessionId = containerId || textAreaId;

    // TODO Post apply action event with candidateId
    if (textAreaId) {
      replaceTextAreaSelection(containerDomElement, editRange.startOffset, editRange.endOffset, candidate);
    } else {
      replaceContentEditableSelection(editRange, candidate, containerDomElement);
    }

    postRephrase(
      candidateHash,
      true,
      sessionId,
      {},
    );

    this.hideControls();
  }

  setStatus(statusMsg) {
    this.rephraseStatusMessage.text(statusMsg);
  }
}

export function getRephraseControls() {
  return [rephraseControls, rephraseButton];
}

export function clearAndHideRephrase() {
  if (rephraseControls) rephraseControls.hideControls();
  if (rephraseButton) rephraseButton.hide();
}

export function getOrCreateRephraseControls(host, buttonHost) {
  if (!rephraseButton) {
    rephraseButton = new RephraseButton(buttonHost);
    rephraseButton.createUIElements();
  }
  if (!rephraseControls) {
    rephraseControls = new RephraseControls(host);
    rephraseControls.createUIElements();
  }
  return [rephraseControls, rephraseButton];
}
