export class UtilityOverlayCommons {
    static WIDTH = 300;
    static HEIGHT = 50;
    static PADDING = 15;

    constructor(shadowHost, containerId, badge) {
        this.containerId = containerId;
        this.shadowHost = shadowHost;
        this.badge = badge;

        this.queryAndUpdate = _.debounce(() => this._queryAndUpdate(), 100);
        this.inDOM = document.documentElement.contains(this.shadowHost);

        this.overlayDragger = null;
        this.queryEl = null;
        this.hudEl = null;

        this.assetUrls = {
            'xmark-solid': getAssetURL('assets/xmark-solid.svg'),
            'spinner-solid': getAssetURL('assets/spinner-solid.svg'),
            'thumbs-up-regular': getAssetURL('assets/thumbs-up-regular.svg'),
            'thumbs-down-regular': getAssetURL('assets/thumbs-down-regular.svg'),
        };

        const utilityName = this.utilityName().toLowerCase().replace(/\s+/g, "-");
        if (!$(`sapling-${utilityName}-overlays-container`).length) {
            let shadowHost = document.createElement(`sapling-${utilityName}-overlays-container`);
            $('html').append($(shadowHost));
            shadowHost.attachShadow({ mode: 'open' });
            this.utilityContainerShadowRoot = $(shadowHost.shadowRoot);
            $(this.utilityContainerShadowRoot).append(`
                <style>${UTITLITY_OVERLAY_CSS}${this.utilityCSS()}</style>
            `);
        } else {
            let shadowHost = $(`sapling-${utilityName}-overlays-container`).first();
            this.utilityContainerShadowRoot = $(shadowHost[0].shadowRoot);
        }

        this._setupStyleMutationObserver();
        this._setupContainerRemovedObserver();
    }

    // ABSTRACT FUNCTIONS -- START
    // Please implement these functions for your specific utility

    utilityName() {
        throw new Error('Method not implemented.');
    }

    renderUtilityData() {
        throw new Error('Method not implemented');
    }

    utilityCSS() {
        return '';
    }

    isBeta() {
        return true;
    }

    isUtilityEnabled() {
        throw new Error('Method not implemented');
    }

    getUtilityData(queryText, lang, containerId, onSuccess, onError) {
        throw new Error('Method not implemented');
    }

    // ABSTRACT FUNCTIONS -- END

    updateHud({hudEmoji, hudWarning, hudTitle}) {
        if (hudEmoji != null || hudWarning != null) {
            if (this.hudEl == null) {
                this.hudEl = document.createElement('div');
                $(this.hudEl).addClass('sapling-tone-hud');
                $(this.hudEl).attr('style', 'opacity: 0');
            }
            if (hudTitle) {
                $(this.hudEl).attr('title', hudTitle);
            } else {
                $(this.hudEl).attr('title', '');
            }
            $(this.hudEl).html('');
            $(this.hudEl).append(hudEmoji);
            $(this.hudEl).append(hudWarning);
        } else {
            this.hudEl = null;
        }
        $(this.badge.headsUpContainer).html(this.hudEl);

        if (this.hudEl) {
            $(this.hudEl).on('click', () => {
                this.toggleVisibility();
            });

            const { height: hudHeight, width: hudWidth } = this.hudEl.getBoundingClientRect();
            const { width: badgeWidth } = this.badge.badge[0].getBoundingClientRect();
            $(this.badge.headsUpContainer).css({
                left: `${-12 - Math.max(badgeWidth, 8) - hudWidth}px`,
                top: `${-0.9 * hudHeight}px`,
            });
            $(this.hudEl).attr('style', 'opacity: 1');
        }
    }

    _setupStyleMutationObserver() {
        const observer = new MutationObserver((mutationLlist) => {
            this.renderUtilityData();
        });
        observer.observe(this.shadowHost, {
            attributes: true,
            attributeOldValue: true,
            attributeFilter: ['style'],
            childList: true,
            subtree: true,
        });
    }

    _setupContainerRemovedObserver() {
        const parentNode = $(this.shadowHost).parent();
        setInterval(() => {
            if (this.inDOM && !document.documentElement.contains(this.shadowHost)) {
                this.toggleVisibility();
            }
        }, 50);
    }

    createUIElements() {
        if (this.utilityOverlay) {
            return;
        }

        this.utilityOverlay = document.createElement('div');
        $(this.utilityOverlay).addClass('sapling-utility-overlay');
        $(this.utilityOverlay).addClass('sapling-utility-empty');
        $(this.utilityOverlay).attr('id', `utility-overlay-${this.containerId}`);

        this.cancelButton = document.createElement('div');
        $(this.cancelButton).html(`<img src="${this.assetUrls['xmark-solid']}" />`);
        $(this.cancelButton).addClass('sapling-utility-overlay-cancel');
        $(this.cancelButton).addClass('sapling-utility-header-button');
        $(this.cancelButton).on('click', () => {
            this.toggleVisibility();
        });

        this.loadingIndicator = document.createElement('div');
        $(this.loadingIndicator).html(`<img src="${this.assetUrls['spinner-solid']}" />`);
        $(this.loadingIndicator).addClass('sapling-utility-header-button');
        $(this.loadingIndicator).addClass('sapling-utility-overlay-spinner');

        this.overlayHeader = document.createElement('div');
        $(this.overlayHeader).addClass('utility-overlay-header');
        $(this.overlayHeader).html(`
            ${this.utilityName()}
            ${this.isBeta() ? `<span class="sapling-utility-beta">beta</span>` : ''}
        `);

        this.overlayDragger = new MakeViewPortDraggable(
            $(this.utilityOverlay),
            $(this.overlayHeader),
            null,
        );

        $(this.utilityOverlay).append(this.overlayHeader);
        $(this.utilityOverlay).append(this.loadingIndicator);
        $(this.utilityOverlay).append(this.cancelButton);
        $(this.utilityOverlay).append('<div class="sapling-utility-data"></div>');
        $(this.utilityOverlay).append(
            '<div class="sapling-utility-empty-message">Waiting for text...</div>',
        );

        $(this.utilityContainerShadowRoot).append(this.utilityOverlay);

        this.sentenceOverlays = document.createElement('div');
        $(this.sentenceOverlays).addClass('sapling-utility-sentence-overlays');
        $(this.sentenceOverlays).attr('id', `utility-sentence-overlay-${this.containerId}`);
        $(this.shadowHost.shadowRoot).append(`<style>${UTITLITY_OVERLAY_CSS}${this.utilityCSS()}</style>`);
        $(this.shadowHost.shadowRoot).append(this.sentenceOverlays);
    }

    updateOverlayPosition() {
        const { bottom, right } = this.shadowHost.getBoundingClientRect();
        const overlayTop = bottom - (this.constructor.HEIGHT * 2) - this.constructor.PADDING + window.scrollY;
        const overlayLeft = right - this.constructor.WIDTH - this.constructor.PADDING + window.scrollX;

        const zIndex = Math.max(getEffectiveZIndex(this.shadowHost.parentNode), 9999);
        $(this.utilityOverlay).css({ zIndex });

        const fontSize = getComputedStyle(this.shadowHost).fontSize;
        $(this.sentenceOverlays).css({ zIndex, fontSize });

        $(this.utilityOverlay).css({ top: overlayTop, left: overlayLeft, width: this.constructor.WIDTH, minHeight: this.constructor.HEIGHT });
        this.updateSentenceOverlayPosition();
    }

    updateSentenceOverlayPosition() {
        const shadowHostBox = this.shadowHost.getBoundingClientRect();
        $(this.sentenceOverlays).css({
            position: 'absolute',
            top: 0,
            left: 0,
            width: `${shadowHostBox.width}px`,
            height: `${shadowHostBox.height}px`,
            pointerEvents: 'none',
        });
    }

    toggleVisibility() {
        this.updateOverlayPosition();
        $(this.utilityOverlay).toggleClass('visible');
        $(this.sentenceOverlays).toggleClass('visible');
        this.inDOM = $(this.utilityOverlay).is('.visible');

        if ($(this.utilityOverlay).is('.visible')) {
            const utilityName = this.utilityName().toLowerCase().replace(/\s+/g, "_");
            sendEvent(`${utilityName}_overlay_visible`);
        }
    }

    initForCheckOnce() {
        this.showOverlay();
        this.hideOnTextChange();
    }

    showOverlay() {
        this.updateOverlayPosition();
        $(this.utilityOverlay).addClass('visible');
        $(this.sentenceOverlays).addClass('visible');
        this.inDOM = true;
    }

    /**
     * If we're not going to be checking the text
     * constantly, we should at least remove the sentence
     * overlays if the text changes.
     */
    hideOnTextChange() {
        this.textChangeCheckInterval = setInterval(() => {
            const queryText = this._getQueryText();
            if (queryText !== this.lastQueryText) {
                $(this.sentenceOverlays).html('');
                clearInterval(this.textChangeCheckInterval);
            }
        }, 500);
    }

    getTextNodes(node, res) {
        if (node.nodeType === Node.TEXT_NODE) {
            res.push({ node, text: node.data });
            return;
        }
        node.childNodes.forEach(child => this.getTextNodes(child, res));
    }

    _getQueryText() {
        this.queryEl = $(this.shadowHost).prevAll('[sapling-id],[sapling-textarea-id],[contenteditable]').first()[0];
        if (typeof this.queryEl === 'undefined' || !this.queryEl) {
            return null;
        }

        let queryText = this.queryEl.innerHTML;
        if (!this.queryEl.innerText.trim()) {
            this.resetUIElements();
            return null;
        }

        return queryText;
    }

    _queryAndUpdate() {
        let queryText = this._getQueryText();
        if (queryText == null) {
            return;
        }

        if (this.lastQueryText == queryText) {
            // Could have been called by external events like a
            // window re-size
            this.renderUtilityData();
            return;
        }

        if (!this.isUtilityEnabled()) {
            return;
        }

        this.lastQueryText = queryText;
        $(this.loadingIndicator).addClass('sapling-loading');
        $(this.sentenceOverlays).addClass('sapling-loading');

        this.getUtilityData(
            queryText,
            'en',
            this.containerId,
            (data) => {
                $(this.utilityOverlay).removeClass('sapling-utility-empty');
                this.renderUtilityData();
                $(this.loadingIndicator).removeClass('sapling-loading');
                $(this.sentenceOverlays).removeClass('sapling-loading');
            },
            (err) => {
                // TODO - sentry
                $(this.loadingIndicator).removeClass('sapling-loading');
                $(this.sentenceOverlays).removeClass('sapling-loading');
            }
        );
    }

    removeUIElements() {
        $(this.utilityOverlay).remove();
    }

    resetUIElements() {
        $(this.sentenceOverlays).html('');
        $(this.utilityOverlay).addClass('sapling-utility-empty');
        this.hudEl = null;
        $(this.badge.headsUpContainer).html(this.hudEl);
    }

    /*
     * These text nodes somehow comprise our sentences, but
     * one sentence could be spread across multiple nodes.
     */
    _getRanges(sents, textNodes) {
        let textIndex = 0, sentenceIndex = 0, cursor = 0;
        let ranges = [];

        while (sentenceIndex < sents.length && textIndex < textNodes.length) {
            const sentence = sents[sentenceIndex];
            let startingOffset = textNodes[textIndex].text.indexOf(sentence[0], cursor);
            while (startingOffset < 0) {
                cursor = 0;
                textIndex++;
                if (textIndex === textNodes.length) {
                    return [];
                }
                startingOffset = textNodes[textIndex].text.indexOf(sentence[0], cursor);
            }
            const startingTextIndex = textIndex;
            cursor = startingOffset;

            let remainingChars = Math.max(
                0,
                sentence.length - (textNodes[textIndex].text.length - cursor),
            );
            let endingOffset = cursor + sentence.length;

            while (remainingChars) {
                textIndex++;
                if (textIndex === textNodes.length) {
                    return [];
                }
                endingOffset = remainingChars;
                remainingChars = Math.max(0, remainingChars - textNodes[textIndex].text.length);
            }

            const endingTextIndex = textIndex;
            ranges.push({startingTextIndex, startingOffset, endingTextIndex, endingOffset, sentenceIndex});

            if (endingOffset < textNodes[textIndex].text.length-1) {
                cursor = endingOffset;
            } else {
                cursor = 0;
                textIndex++;
            }
            sentenceIndex++;
        }

        return ranges;
    }
}
