export class AIDetectSelectButton {
    constructor(shadowHost, contentShadowHost) {
        this.shadowHost = shadowHost;
        this.contentShadowHost = contentShadowHost;
        this.aiDetectSelectButton = null;
        this.aiDetectSelectContent = null;

        this.assetUrls = {
            'xmark-solid': getAssetURL('assets/xmark-solid.svg'),
            'spinner-solid': getAssetURL('assets/spinner-solid.svg'),
            'thumbs-up-regular': getAssetURL('assets/thumbs-up-regular.svg'),
            'thumbs-down-regular': getAssetURL('assets/thumbs-down-regular.svg'),
            'sapling-logo-horizontal': getAssetURL('assets/sapling-logo-horizontal.png'),
            'fa-hand-sparkles-solid': getAssetURL('assets/fa-hand-sparkles-solid.svg'),
        };
    }

    positionButton() {
        // Place the element's bottom left corner at the top right of the selected range
        const selection = window.getSelection();
        if (!selection || !selection.rangeCount || !selection.toString().trim()) {
            return;
        }

        const range = selection.getRangeAt(0);
        const rect = range.getBoundingClientRect();

        const rephrasePadding = isRephraseEnabled() ? 15 : 0;

        $(this.aiDetectSelectButton).css({
            left: Math.min(rect.right + 10 + rephrasePadding, window.innerWidth - 50),
            top: Math.max(rect.top - 10 + rephrasePadding, 50) + window.scrollY,
            background: '#e8eaf6',
            padding: '12px 10px 7px 10px',
            position: 'absolute',
            cursor: 'pointer',
            borderRadius: '35px',
            border: '2px solid #535f99',
            zIndex: 9998
        });
    }

    _getAIDetectionScores(selectedText, context) {
        $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-error')
            .addClass('hidden');

        if (!isAIDetectEnabled()) {
            $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-waiting')
                .addClass('hidden');
            $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-premium')
                .removeClass('hidden');
            return;
        }

        $(this.loadingIndicator).addClass('sapling-loading');
        selectedText = selectedText.trim();
        this.lastQueryText = selectedText;

        if (window.location.hostname == 'chat.openai.com') {
            context['openai_model'] = document.querySelectorAll('.items-center.sm\\:justify-center span')[0]?.innerText;
        }

        getAIDetectionScores(
            selectedText,
            'en',
            window.location.href,
            context,
            (data) => {
                $(this.loadingIndicator).removeClass('sapling-loading');
                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-waiting')
                    .addClass('hidden');
                let { score, sentence_scores, score_string, hash } = data.aidetect;
                score = score * 100;

                let overallMessage;
                if (score > 90) {
                    overallMessage = 'Highly likely composed by AI.';
                } else if (score > 70) {
                    overallMessage = 'Significant chance of AI authorship.';
                } else if (score > 50) {
                    overallMessage = 'Toss-up: might be AI-generated.';
                } else if (score > 25) {
                    overallMessage = 'Low likelihood of AI creation.';
                } else if (score > 10) {
                    overallMessage = 'Minimal signs of AI origin.';
                } else {
                    overallMessage = 'Unlikely AI-authored; appears human-written.';
                }

                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-overall')
                    .html(`
                        <b class="overall-score" style="color: ${percentToRGB(score)}">
                            ${score.toFixed(2)}%
                        </b>
                        <div class="overall-message">${overallMessage}</div>
                        <div>
                            <a href="https://sapling.ai/ai-content-detector/${hash}" target="__blank" style="color: #535f99;" title="Use to share a detailed link to this AI Detection analysis. Link will expire in 3 days.">
                            Sapling AI Detection certificate</a>
                        </div>
                    `);

                // Just adding sapling-ignore to the parent isnt working
                let tempDiv = document.createElement('div');
                tempDiv.innerHTML = score_string;
                let spans = tempDiv.querySelectorAll('span');
                spans.forEach(span => {
                    span.setAttribute('sapling-ignore', 'true');
                });
                score_string = tempDiv.innerHTML;

                $(this.aiDetectSelectContent)
                    .find('.sapling-ai-detect-select-score-string .score-strings')
                    .addClass('has-backend-response')
                    .attr('sapling-ignore', 'true')
                    .html(`${score_string}`);

                const range = document.createRange(); //Create a range (a range is a like the selection but invisible)
                range.selectNodeContents(this.scoreStrings); //Select the entire contents of the element with the range
                range.collapse(false); //collapse the range to the end point. false means collapse to end rather than the start
                const selection = window.getSelection(); //get the selection object (allows you to change selection)
                selection.removeAllRanges(); //remove any selections already made
                selection.addRange(range); //make the range you have just created the visible selection

                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-sentences').html(``);
                sentence_scores.forEach(sentence_score => {
                    let { score, sentence } = sentence_score;

                    score = score * 100;
                    const scoreString = score >= 0 ? `${score.toFixed(2)}%` : 'n/a';

                    $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-sentences')
                        .append(`
                            <div class="sentence-row">
                                <div class="sentence-text">${sentence}</div>
                                <div class="sentence-score" style="color: ${percentToRGB(score)}">${scoreString}</div>
                            </div>
                        `);
                });

                sendEvent(`ai_detect_select_processed_${context.source.toLowerCase().replace(/\s+/g, "_")}`);
            },
            (err) => {
                $(this.loadingIndicator).removeClass('sapling-loading');
                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-error')
                    .removeClass('hidden');
                console.log({err});
            }
        );
    }

    createUIElements() {
        if (this.aiDetectSelectButton) {
            // Should already be created
            return;
        }

        // Clean up stale element
        $(this.shadowHost.shadowRoot).find('.sapling-ai-detect-select-button').remove();
        this.aiDetectSelectButton = $(`
            <div class="sapling-ai-detect-select-button">
                <img src="${this.assetUrls['fa-hand-sparkles-solid']}" style="height: 20px" />
            </div>
        `);
        this.aiDetectSelectButton.hide();
        $(this.shadowHost.shadowRoot).append(AI_DETECT_SELECT_STYLES);
        $(this.shadowHost.shadowRoot).append(this.aiDetectSelectButton);

        $(this.contentShadowHost.shadowRoot).append(AI_DETECT_SELECT_STYLES);

        this.aiDetectSelectContent = $(`
            <div class="sapling-ai-detect-select-content">
                <div class="sapling-ai-detect-select-content-header">
                    <div class="left">
                        <img src="${this.assetUrls['sapling-logo-horizontal']}" style="height: 20px" />
                        <span style="margin-right: 10px;">AI Detector</span>
                        <span class="sapling-ai-detect-select-analysis-mode" id="sapling-ai-detect-select-overall-analysis">
                            Overall Analysis
                        </span>
                        <span class="sapling-ai-detect-select-analysis-mode inactive" id="sapling-ai-detect-select-sentence-analysis">
                            Sentence-level Analysis
                        </span>
                        <span id="subscription-banner"></span>
                    </div>
                    <div class="right"></div>
                </div>
                <div class="sapling-ai-detect-select-content-body">
                    <div class="sapling-ai-detect-select-overall">
                    </div>
                    <div class="sapling-ai-detect-select-score-string">
                        <button class="sapling-ai-detect-select-edit-recheck">
                            Re-check edited text
                        </button>
                    </div>
                    <div class="sapling-ai-detect-select-sentences hidden">
                    </div>
                    <div class="sapling-ai-detect-select-error hidden">
                        An unknown error has occurred.<br/>Please try again in some time, or contact support@sapling.ai
                    </div>
                    <div class="sapling-ai-detect-select-premium hidden">
                        Please <a href="https://sapling.ai/pricing" target="_blank">subscribe</a> to access the AI Detection feature.
                    </div>
                    <div class="sapling-ai-detect-select-waiting">
                        Processing your text, please wait...
                    </div>
                </div>
            </div>
        `);
        this.aiDetectSelectContent.hide();
        $(this.contentShadowHost.shadowRoot).append(this.aiDetectSelectContent);
        this.aiDetectSelectContent[0].addEventListener("mousedown", (event) => {
            // Don't cancel the selection
            event.stopPropagation();
        });
        this.aiDetectSelectContent[0].addEventListener("contextmenu", (event) => {
            // Don't cancel the selection
            event.stopPropagation();
        });

        this.loadingIndicator = document.createElement('div');
        $(this.loadingIndicator).html(`<img src="${this.assetUrls['spinner-solid']}" />`);
        $(this.loadingIndicator).addClass('sapling-ai-detect-select-spinner');
        $(this.loadingIndicator).addClass('sapling-ai-detect-select-header-button');
        $(this.aiDetectSelectContent).find('.right').append(this.loadingIndicator);

        this.cancelButton = document.createElement('div');
        $(this.cancelButton).html(`<img src="${this.assetUrls['xmark-solid']}" />`);
        $(this.cancelButton).addClass('sapling-ai-detect-select-cancel');
        $(this.cancelButton).addClass('sapling-ai-detect-select-header-button');
        $(this.cancelButton).on('click', () => {
            this.hide();
        });
        $(this.aiDetectSelectContent).find('.right').append(this.cancelButton);

        $(document).keyup(e => {
            if (e.key === "Escape") {
                this.hide();
           }
       });

        this.scoreStrings = document.createElement('div');
        $(this.scoreStrings).addClass('score-strings');
        $(this.scoreStrings).attr('sapling-ignore', 'true');
        $(this.scoreStrings).attr('contenteditable', 'true');
        this.scoreStringsObserver = new MutationObserver((mutationList, observer) => {
            if ($(this.scoreStrings).is('.has-backend-response')) {
                $(this.scoreStrings).removeClass('has-backend-response');
                return;
            }

            const currentText = $(this.aiDetectSelectContent).find('.score-strings')[0].innerText.replace(/\n+/g, "\n\n");
            if (currentText == this.lastQueryText) {
                return;
            }

            $(this.scoreStrings).find('span').css('background-color', 'white');
        });
        this.scoreStringsObserver.observe(this.scoreStrings, { attributes: true, childList: true, subtree: true, characterData: true });
        $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-score-string').append(this.scoreStrings);

        this.aiDetectSelectButton[0].addEventListener("mousedown", (event) => {
            event.preventDefault();
            $(this.aiDetectSelectContent).fadeIn(50);
            this._getAIDetectionScores(this._getSelectedText(), {source: 'selected text'});
            sendEvent('ai_detect_select_overlay_visible_selected_text');
        });

        $(this.aiDetectSelectContent).on('click', '.sapling-ai-detect-select-edit-recheck', (e) => {
            this._getAIDetectionScores(
                $(this.aiDetectSelectContent).find('.score-strings')[0].innerText.replace(/\n+/g, "\n\n"),
                {source: 'edited text'},
            );
        });

        $(this.aiDetectSelectContent).on('click', '.sapling-ai-detect-select-analysis-mode', (e) => {
            $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-analysis-mode')
                .addClass('inactive');
            $(e.target).removeClass('inactive');
            if ($(e.target).is('#sapling-ai-detect-select-overall-analysis')) {
                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-overall').removeClass('hidden');
                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-score-string').removeClass('hidden');
                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-sentences').addClass('hidden');
            } else {
                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-overall').addClass('hidden');
                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-score-string').addClass('hidden');
                $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-sentences').removeClass('hidden');
            }
        });

        showSubscriptionBanner($(this.aiDetectSelectContent).find('#subscription-banner'));
    }

    _getSelectedText() {
        return document.getSelection().toString().replace(/\n+/g, "\n\n");
    }

    showContent(text, source) {
        $(this.aiDetectSelectContent).fadeIn(50);
        $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-waiting')
            .removeClass('hidden');
        this._getAIDetectionScores(text.replace(/\n+/g, "\n\n").trim(), { source });
        sendEvent(`ai_detect_select_overlay_visible_${source.toLowerCase().replace(/\s+/g, "_")}`);
    }

    show() {
        const selectedText = this._getSelectedText().trim();
        if (!selectedText || selectedText.split(' ').length < 50) {
            return;
        }

        setTimeout(() => {
            this.positionButton();
            this.aiDetectSelectButton.fadeIn(50);
        }, 200);
    }

    hide(buttonOnly = false) {
        if (this.aiDetectSelectButton) {
            setTimeout(() => {
                this.aiDetectSelectButton.hide();
                if (!buttonOnly) {
                    this.aiDetectSelectContent.fadeOut(250);
                    $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-waiting')
                        .removeClass('hidden');
                    $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-overall').html('');
                    $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-sentences').html('');
                    $(this.aiDetectSelectContent).find('.sapling-ai-detect-select-score-string .score-strings').html('');
                }
            }, 200);
        }
    }
}

export function getOrCreateAIDetectControls(host, buttonHost) {
    // if (!aiDetectControls) {
    //     aiDetectControls = new AIDetectControls(host);
    //     aiDetectControls.createUIElements();
    // }
    if (!aiDetectButton) {
        aiDetectButton = new AIDetectButton(buttonHost);
        aiDetectButton.createUIElements();
    }
    return [null, aiDetectButton];
}

export function maybeEmbedAIDetectOnHost() {
    if (!isAIDetectEnabled()) {
        return;
    }

    const { aiDetectSelectButton } = initAIDetectSelection();
    if (!aiDetectSelectButton) {
        return;
    }

    const hostname = window.location.hostname;
    if (hostname === 'chat.openai.com' || hostname === 'chatgpt.com') {
        initOpenAIObserver(aiDetectSelectButton);
    }

    if (hostname === 'claude.ai') {
        initDomainObserver({
            aiDetectSelectButton,
            domain: 'claude.ai',
            textNodesSelector: '.font-claude-message',
            customCss: `
            .sapling-run-ai-detection-button {
                bottom: -32px;
                width: 50%;
            }

            [data-mode="dark"] .sapling-run-ai-detection-button {
                color: white;
                background: #535f99;
            }
            `,
            textExtractor: (node) => node.querySelector('div').innerText,
        });
    }
}

const textNodesMap = new WeakMap();

function initOpenAIObserver(aiDetectSelectButton) {
    $(document.body).append(`
        <style>
            .sapling-run-ai-detection-button {
                position: absolute;
                border: 2px solid #535f99;
                border-radius: 5px;
                width: 100%;
                font-size: 10pt;
                text-align: center;
                color: #535f99;
                bottom: -20px;
                background: white;
                cursor: pointer;
                transition: all 0.25s;
            }

            .sapling-run-ai-detection-button:hover, .dark .sapling-run-ai-detection-button {
                color: white;
                background: #535f99;
            }
        </style>
    `);
    setInterval(() => {
        const textNodes = document.querySelectorAll('.text-message[data-message-author-role="assistant"]');
        textNodes.forEach(node => {
            if (
                !node.querySelectorAll('.text-gray-400.flex button.rounded-md')
                || textNodesMap.get(node)
            ) {
                return;
            }

            let text = node.innerText.replace(/^chatgpt\s+/i, '');
            if (text.trim().split(' ').length < 50) {
                return;
            }

            textNodesMap.set(node, text);
            const container = node;
            $(container).append(`
                <div class="sapling-run-ai-detection-button">Detect AI</div>
            `);

            const button = document.createElement('div');
            $(button).html(`Detect AI`);
            $(button).addClass('sapling-run-ai-detection-button');
            $(button).on('click', () => {
                text = node.querySelector('.markdown').innerText.replace(/^chatgpt\s+/i, '');
                aiDetectSelectButton.showContent(text, 'chat.openai.com generated');
            });

            $(container).append(button);
        });
    }, 1000);
}

function initDomainObserver({domain, textNodesSelector, customCss, aiDetectSelectButton, textExtractor}) {
    $(document.body).append(`
        <style>
            .sapling-run-ai-detection-button {
                position: absolute;
                border: 2px solid #535f99;
                border-radius: 5px;
                width: 100%;
                font-size: 10pt;
                text-align: center;
                color: #535f99;
                bottom: -20px;
                background: white;
                cursor: pointer;
                transition: all 0.25s;
            }

            .sapling-run-ai-detection-button:hover, .dark .sapling-run-ai-detection-button {
                color: white;
                background: #535f99;
            }

            ${customCss}
        </style>
    `);
    setInterval(() => {
        const textNodes = document.querySelectorAll(textNodesSelector);
        textNodes.forEach(node => {
            if (textNodesMap.get(node)) {
                return;
            }

            let text = textExtractor(node);
            if (text.trim().split(' ').length < 50) {
                return;
            }

            textNodesMap.set(node, text);
            const container = node;
            $(container).append(`
                <div class="sapling-run-ai-detection-button">Detect AI</div>
            `);

            const button = document.createElement('div');
            $(button).html(`Detect AI`);
            $(button).addClass('sapling-run-ai-detection-button');
            $(button).on('click', () => {
                text = textExtractor(node);
                aiDetectSelectButton.showContent(text, `${domain} generated`);
            });

            $(container).append(button);
        });
    }, 1000);
}
export function initAIDetectSelection() {
    let aiDetectHost, buttonHost, aiDetectSelectButton
  if ($('sapling-ai-detect-controls').length) {
    aiDetectHost = $('sapling-ai-detect-controls')[0];
    buttonHost = $('sapling-ai-detect-button')[0];
    aiDetectSelectButton = weakmap.get(aiDetectHost);
  } else {
    aiDetectHost = $('<sapling-ai-detect-controls></sapling-ai-detect-controls>')[0];
    buttonHost = $('<sapling-ai-detect-button></sapling-ai-detect-button>')[0];

    try {
        aiDetectHost.attachShadow({ mode: 'open' });
        buttonHost.attachShadow({ mode: 'open' });
    } catch (_) {
        return {aiDetectHost: null, buttonHost: null, aiDetectSelectButton: null};
    }

    $('html').append(aiDetectHost);
    $('html').append(buttonHost);

    aiDetectSelectButton = new AIDetectSelectButton(buttonHost, aiDetectHost);
    weakmap.set(aiDetectHost, aiDetectSelectButton);
    aiDetectSelectButton.createUIElements();
  }

  return {aiDetectHost, buttonHost, aiDetectSelectButton};
}
