export function getToneSign(tone) {
    switch (tone) {
        case 'angry':
        case 'annoyed':
        case 'disappointed':
        case 'disapproving':
        case 'embarassed':
        case 'fearful':
        case 'mournful':
        case 'remorseful':
        case 'repulsed':
        case 'sad':
        case 'worried':
            return -1;

        case 'aware':
        case 'confused':
        case 'curious':
        case 'neutral':
        case 'surprised':
        case 'sympathetic':
            return 0;

        case 'admiring':
        case 'amused':
        case 'approving':
        case 'confident':
        case 'eager':
        case 'excited':
        case 'grateful':
        case 'joyful':
        case 'loving':
        case 'optimistic':
        case 'relieved':
            return 1;
    }

    return 0;
}

export function getEkmanTone(tone) {
    switch (tone) {
        case 'admiring':
        case 'amused':
        case 'approving':
        case 'confident':
        case 'eager':
        case 'excited':
        case 'grateful':
        case 'joyful':
        case 'loving':
        case 'optimistic':
        case 'relieved':
            return 'joy';

        case 'angry':
        case 'annoyed':
        case 'repulsed':
        case 'disappointed':
        case 'disapproving':
            return 'anger';

        case 'aware':
        case 'neutral':
        case 'sympathetic':
            return 'neutral';

        case 'confused':
        case 'curious':
        case 'surprised':
            return 'surprise';

        case 'fearful':
            return 'fear';

        case 'embarassed':
        case 'mournful':
        case 'remorseful':
        case 'sad':
        case 'worried':
            return 'sadness';
    }

    return 'neutral';
}

export function getToneColor(tone) {
    const ekmanTone = getEkmanTone(tone);

    switch (ekmanTone) {
        case 'joy':
        case 'neutral':
        case 'surprise':
        case 'fear':
        case 'sadness':
            return '#535f99';

        case 'anger':
            return 'red';
    }
}
