window.log_last_mutated = (typeof window.log_last_mutated === 'undefined') ? new Date() : window.log_last_mutated;
window.sendEvent = sendEvent;

// the following functions are platform dependant
let PLUGIN_GET_MESSAGES_FUNC = null;
let PLUGIN_INJECT_RESPONSE_FUNC = null;
let PLUGIN_EDIT_RESPONSE_FUNC = null;
let PLUGIN_GET_CONTEXT_FUNC = null;
let PLUGIN_GET_HELPER_RESPONSES = null;
let PLUGIN_INJECT_CHAT_UI = null;
let HELPER_INTERVAL_MS = 3000;
let PLUGIN_GET_RESPONSE_TIME = null;
let PLUGIN_GET_RESPONSE_WRAPPER = null;
let PLUGIN_GET_INP_FUNC = null;
let KEEP_HIDDEN = false;

// Okay to declare, we clear before re-declaring
let HELPER_INTERVAL;

let suggestChatObserver = (typeof suggestChatObserver === 'undefined') ? null : suggestChatObserver;
let lastSuggestQuery = (typeof lastSuggestQuery === 'undefined') ? '' : lastSuggestQuery;
let lastInp = (typeof lastInp === 'undefined') ? '' : lastInp;
let currentSuggestionId = (typeof currentSuggestionId === 'undefined') ? null : currentSuggestionId; // track suggest if one is clicked for editing
let clickQuery = (typeof clickQuery === 'undefined') ? false : clickQuery;
let lastSelectedSuggestInfo = (typeof lastSelectedSuggestInfo === 'undefined') ? null : lastSelectedSuggestInfo;
// lastSelectedSuggestInfo keys:
//   - suggestion_id
//   - index
//   - helper
//   - suggest_text
//   - confidence
//   - send

window.lastResponseTimestamp = (typeof lastResponseTimestamp === 'undefined') ? null : lastResponseTimestamp;

const NGRAM_SIZE = 3;

function stringToNgram(s) {
  let words = s.split(' ');
  let ngrams = new Set();
  for (let idx = 0; idx <= words.length; idx++) {
    ngrams.add(words.slice(idx, idx + NGRAM_SIZE).join(' '));
    if (idx + NGRAM_SIZE >= words.length) {
      break;
    }
  }
  return ngrams;
}

function getHelperResponses() {
  let helperResponses = [];

  let d = new Date();
  if (d - log_last_mutated > 60 * 1000) {
    helperResponses.push({'id': 'helper-still-connected', 'doc': 'Are we still connected?', 'confidence': null});
  }

  return helperResponses;
}

function onChatLogMutation(mutationsList) {
  log_last_mutated = new Date();

  for (const mutation of mutationsList) {
    if (mutation.type === 'childList') {
      let shouldUpdate = true;
      // for (const addedNode of mutation.addedNodes) {
      //   // FIXME Can check if should update or not
      // }
      if (shouldUpdate) {
        debouncedUpdateSuggestedResponses();
        debouncedGetResponseTime();
        // Can stop here
        return;
      }
    }
    else if (mutation.type === 'attributes') {
      if (mutation.attributeName === 'disabled') {
        hideSuggestedChatResponses();
        return;
      }
    }
  }
}

function processSendEvent(lastAgentMessage) {
  if (!lastSelectedSuggestInfo) {
    return;
  }
  lastSelectedSuggestInfo.agent_message = lastAgentMessage;
  sendMessageEvent(lastSelectedSuggestInfo, false);
}

function sendMessageEvent(suggestEventInfo) {
  const {
    suggestion_id,
    index,
    helper,
    suggest_text,
    agent_message,
    confidence,
    quick_send,
  } = suggestEventInfo;

  let originalNGrams = stringToNgram(suggest_text);
  let sentNGrams = stringToNgram(agent_message);
  let overlapNGrams = new Set([...originalNGrams].filter(x => sentNGrams.has(x)));

  let moreContext = PLUGIN_GET_CONTEXT_FUNC();
  const context = {
    hostname: getTopFrameHostname(),
    pathname: getTopFramePathname(),
    suggest_index: index,
    confidence,
    frame_hostname: window.location.hostname,
    frame_pathname: window.location.pathname,
    ng_size: NGRAM_SIZE,
    ng_select: originalNGrams.size,
    ng_sent: sentNGrams.size,
    ng_overlap: overlapNGrams.size,
    quick_send,
    click_query: clickQuery,
  };
  Object.assign(context, moreContext);

  postSuggestionEvent({
    context,
    suggestion_id,
    action: 'send',
  });
  lastSelectedSuggestInfo = null;
  clickQuery = false;
}

function acceptSuggestionEvent(suggestEventInfo) {
  const {
    suggestion_id,
    index,
    helper,
    confidence,
    quick_send,
  } = suggestEventInfo;

  let moreContext = PLUGIN_GET_CONTEXT_FUNC();
  const context = {
    hostname: getTopFrameHostname(),
    pathname: getTopFramePathname(),
    suggest_index: index,
    confidence,
    frame_hostname: window.location.hostname,
    frame_pathname: window.location.pathname,
    quick_send,
    click_query: clickQuery,
    helper,
  };
  Object.assign(context, moreContext);
  postSuggestionSelect(suggestion_id, context);
  if (!quick_send) {
    lastSelectedSuggestInfo = suggestEventInfo;
  } else {
    lastSelectedSuggestInfo = null;
    clickQuery = false;
  }
}

function _getSecondsFromTimestamp(ts) {
  let parts = ts.split(':');
  let seconds = parseInt(parts[0]) * 3600 + parseInt(parts[1]) * 60 + parseInt(parts[2]);
  return seconds;
}

// TODO Override
const debouncedGetResponseTime = _.debounce(getResponseTime, 300);
function getResponseTime() {
  PLUGIN_GET_RESPONSE_TIME(postChatEvent);
}

function getInp() {
  let inpEl = null;
  let inp = '';
  return {inpEl, inp};
}

function getResponseTimeHelper(postChatEventFunc) {
  let lastTurn = null;
  let lastTimestamp = null;
  let penultimateTurn = null;
  let penultimateTimestamp = null;

  let messages = $('#chatLog div');
  for (let i = 0; i < messages.length; i += 1) {
    let messageNode = $(messages[i]);
    if (messageNode.hasClass('agentMessage')) {
      penultimateTurn = lastTurn;
      lastTurn = 'agent';
      penultimateTimestamp = lastTimestamp;
      lastTimestamp = $('.timestamp', messageNode).text();
    } else if (messageNode.hasClass('chasitorMessage')) {
      penultimateTurn = lastTurn;
      lastTurn = 'visitor';
      penultimateTimestamp = lastTimestamp;
      lastTimestamp = $('.timestamp', messageNode).text();
    }
  }

  if (lastTimestamp === lastResponseTimestamp) {
    // Mutation events get messy
    return;
  }
  lastResponseTimestamp = lastTimestamp;

  if (lastTurn === 'agent' && penultimateTurn === 'visitor') {
    let responseTime = _getSecondsFromTimestamp(lastTimestamp) - _getSecondsFromTimestamp(penultimateTimestamp);

    let moreContext = PLUGIN_GET_CONTEXT_FUNC();
    const context = {
      hostname: getTopFrameHostname(),
      pathname: getTopFramePathname(),
      frame_hostname: window.location.hostname,
      frame_pathname: window.location.pathname,
      response_time: responseTime,
      action: 'agent_response',
    };
    Object.assign(context, moreContext);
    sendEvent('chat_event', context, '');
    postChatEventFunc(context);
  }
}

function updateSuggestedResponses() {
  let context = PLUGIN_GET_CONTEXT_FUNC();
  let queryMessages = PLUGIN_GET_MESSAGES_FUNC(
    (msg) => {
      clickQuery = true;
      getAndDisplaySuggest(msg, null, showSuggestedChatResponses, context);
    },
    postChatTurn
  );
  let query = queryMessages[queryMessages.length - 1];
  if (!queryMessages) return;
  if (!query || query === lastSuggestQuery) {
    return;
  }
  lastSuggestQuery = query;
  hideSuggestedChatResponses();
  KEEP_HIDDEN = false;
  showHelperResponses();
  clickQuery = false;
  getAndDisplaySuggest(query, queryMessages, showSuggestedChatResponses, context);
}
const debouncedUpdateSuggestedResponses = _.debounce(updateSuggestedResponses, 200);

function matchResponses() {
  let context = PLUGIN_GET_CONTEXT_FUNC();
  let { inpEl, inp } = PLUGIN_GET_INP_FUNC();
  if (!inp) return;
  if (inp === lastInp) {
    return;
  }
  lastInp = inp;
  KEEP_HIDDEN = false;
  clickQuery = false;
  matchAndDisplaySuggest(inp, showSuggestedChatResponses, context);
}
const debouncedMatchResponses = _.debounce(matchResponses, 200);

function appendSuggestedChatResponse(response, index, helper) {
  const suggest_text = response.doc;
  const suggestion_id = response.id;
  if (suggestion_id === currentSuggestionId) {
    // don't show same suggestion as one currently being edited
    currentSuggestionId = null;
    return;
  }
  let responseWrapper = PLUGIN_GET_RESPONSE_WRAPPER();
  let shadowRoot = responseWrapper.shadowRoot;
  let newNode = $(`<div class='sapling-chat-suggestion'>${suggest_text}</div>`);

  if ('confidence' in response && response.confidence !== null) {
    let conf = response.confidence.toFixed(2);
    let confClass = 'low';
    if (conf > 0.25) confClass = 'med';
    if (conf > 0.75) confClass = 'high';
    let confNode = $(`<div class="sapling-suggestion-conf sapling-conf-${confClass}">${conf}</div>`);
    newNode.append(confNode);
  }

  if (helper) {
    $('.sapling-helper-container', shadowRoot).append(newNode);
  } else {
    $('.sapling-chat-container', shadowRoot).append(newNode);
  }

  newNode.on('mousedown', (event) => {
    if (event.which !== 1) {
      return;
    }
    log_last_mutated = new Date();

    currentSuggestionId = suggestion_id;
    hideSuggestedChatResponses();
    PLUGIN_EDIT_RESPONSE_FUNC(suggest_text);
    let suggestEventInfo = {
      suggestion_id,
      index,
      helper,
      suggest_text,
      agent_message: suggest_text,
      confidence: response['confidence'],
      quick_send: false,
    };
    acceptSuggestionEvent(suggestEventInfo);
  });
}

function dedupeResponses(responses) {
  let seen = new Set();
  let new_responses = [];
  for (let k=0; k < responses.length; k++) {
    if (seen.has(responses[k]['doc'])) continue;
    seen.add(responses[k]['doc']);
    new_responses.push(responses[k]);
  }
  return new_responses;
}

function showHelperResponses() {
  if (KEEP_HIDDEN) return;
  let responseWrapper = PLUGIN_GET_RESPONSE_WRAPPER();
  if (responseWrapper === null) PLUGIN_INJECT_CHAT_UI();
  responseWrapper = PLUGIN_GET_RESPONSE_WRAPPER();
  if (responseWrapper === null) return;
  let helper_responses = PLUGIN_GET_HELPER_RESPONSES();
  if (!helper_responses.length) return;

  let shadowRoot = responseWrapper.shadowRoot;
  if ($('.sapling-response-wrapper-close', shadowRoot).length === 0)
    $(".sapling-response-wrapper", shadowRoot).prepend('<div class="sapling-response-wrapper-close">&times;</div>');
  $('.sapling-response-wrapper-close', shadowRoot).click(hideSuggestedChatResponses);
  $('.sapling-helper-container', shadowRoot).html('');

  helper_responses = dedupeResponses(helper_responses);
  for (let i = 0; i < helper_responses.length; i++) {
    appendSuggestedChatResponse(helper_responses[i], i, true);
  }
}

function getResponseWrapper() {
  let wrapper = $('sapling-chat-controls');
  if (!wrapper.length) return null;
  return wrapper[0];
}

function showSuggestedChatResponses(responses) {
  if (!responses.length) {
    return;
  }

  let MAX_RESPONSES = 3;
  let responseWrapper = PLUGIN_GET_RESPONSE_WRAPPER();
  let shadowRoot = responseWrapper.shadowRoot;

  if ($('.sapling-response-wrapper-close', shadowRoot).length === 0)
    $(".sapling-response-wrapper", shadowRoot).prepend('<div class="sapling-response-wrapper-close">&times;</div>');
  $('.sapling-response-wrapper-close', shadowRoot).click(hideSuggestedChatResponses);
  $(".sapling-chat-container", shadowRoot).html('');

  responses = dedupeResponses(responses);
  for (let i = 0; i < Math.min(MAX_RESPONSES, responses.length); i += 1) {
    appendSuggestedChatResponse(responses[i], i, false);
  }

  let context = {num_responses: responses.length, hidden: document.hidden };
  let moreContext = PLUGIN_GET_CONTEXT_FUNC();
  Object.assign(context, moreContext);
  sendEvent('show_suggest_responses', context, '');
}

function hideSuggestedChatResponses() {
  KEEP_HIDDEN = true;
  let responseWrapper = PLUGIN_GET_RESPONSE_WRAPPER();
  if (responseWrapper === null) return;
  let shadowRoot = responseWrapper.shadowRoot;
  $(".sapling-chat-suggestion", shadowRoot).remove();
  $(".sapling-response-wrapper-close", shadowRoot).remove();
}

