import * as Sentry from '@sentry/browser';

import { initializeCommandObserver } from './observers/messages';
import { initializeObservers } from './observers/observers';
import { disconnectAllObservers } from './observers/teardown';
import { sendMessageHandler } from './send-message';
import { initToolbar } from './toolbar';
import initializeSaplingEmbedded from './popup';
import { maybeShowGSuiteTooltip, maybeShowConnectivityTooltip } from './tooltips';
import {
  fetchGrammarAndCompleteEnableSettings,
  getUserPromise,
  setSiteSettings,
} from './settings';
import { setCustomEndpointsPromise } from '../utils/endpoints';
import { setTopFrameUrl, getTopFrameHostname, getTopFramePathname } from '../utils/location';
import { getAssetURL, getManifestVersion, initChromeCommandListener } from '../utils/chrome-adapter';
import { isPopupEnvironment } from '../utils/extension';
import { getSettings } from '../requests/index';
import { SAPLING_ENV } from '../globals';

let SAPLING_INITIALIZED = false;

const IGNORE_ERRORS = [
  '$ is not defined',
  'Attempting to use a disconnected port object',
  'Extension context invalidated.',
  'No frame with id',
  'ResizeObserver loop limit exceeded',
  'ResizeObserver loop completed with undelivered notifications.',
  'ResizeObserver loop',
  'The frame was removed',
  'Non-Error promise rejection captured with keys: currentTarget, isTrusted, target, type',
  'Corruption: not an sstable (bad magic number)',
  'Uncaught RuntimeError: memory access out of bounds',
  // Slack CustomEvent objects thrown as promise rejections (plain object form)
  'Non-Error promise rejection captured with keys: bubbles, cancelBubble, cancelable, composed, currentTarget, defaultPrevented, detail, eventPhase, isTrusted, returnValue, srcElement, target, timeStamp, type',
  // Other CustomEvent promise rejections from Slack with different property order
  'Non-Error promise rejection captured with keys: type, target, currentTarget, eventPhase, bubbles, cancelable, defaultPrevented, composed, timeStamp, srcElement, returnValue, cancelBubble, detail, isTrusted',
  // Slack CustomEvent instances thrown as unhandled rejections (Sentry formats these differently from plain objects)
  'Event `CustomEvent` (type=unhandledrejection) captured as promise rejection',
  // Microsoft Teams internal web worker noise — not Sapling code
  'AsyncIterableObserver buffer is full',
  // Microsoft Teams wraps unhandled rejections as synchronous errors with this prefix
  'UPR: ',
  // Chrome IndexedDB / LevelDB internal errors — not from Sapling code, not actionable
  'IO error:',
];

if (SAPLING_ENV.SENTRY_DSN) {
  const version = getManifestVersion();
  try {
    Sentry.init({
      dsn: SAPLING_ENV.SENTRY_DSN,
      sampleRate: 0.0001,
      release: version,
      ignoreErrors: IGNORE_ERRORS,
      denyUrls: [
        // Microsoft Teams internal web worker scripts
        /teams-modular-packages/,
        // Microsoft Teams precompiled web worker scripts (source of UPR-prefixed errors)
        /\/v2\/worker\//,
        // Wix's bundled app code on Wix-hosted pages — errors from Wix's own runtime, not Sapling
        /wix_thunderbolt_app/,
        // Blob URL scripts (e.g. bsky.app dynamic workers) — third-party code, not Sapling
        /^blob:/,
      ],
      beforeSend(event, hint) {
        const matchesIgnore = (value) => IGNORE_ERRORS.some(pattern => {
          if (pattern instanceof RegExp) {
            return pattern.test(value);
          }
          return value.includes(pattern);
        });
        const error = hint.originalException;
        if (error && error.message) {
          if (matchesIgnore(error.message)) {
            return null;
          }
        }
        // Fallback: check the processed exception value for errors where originalException
        // is null (e.g. web-worker errors propagated to window.onerror without an Error object)
        const eventExceptionValue = event.exception?.values?.[0]?.value;
        if (eventExceptionValue) {
          if (matchesIgnore(eventExceptionValue)) {
            return null;
          }
        }
        return event;
      },
    });
    Sentry.configureScope((scope) => {
      scope.setTag('version', version);
      scope.setTag('background', false);
    });
  } catch (e) {
    // TODO: throws TypeError: ""addEventListener" is read-only" on firefox
  }
}

// This is safe: https://developer.chrome.com/extensions/content_scripts#run_time
// used for determining when we should display "install" button on our site
if (document.body && !window.location.hostname.includes('force.com')) { // Don't think getTopFrameHostname works yet
  document.body.setAttribute('sapling-installed', true);
}

function initApp() {
  // Programmatic stylesheet injection
  // Chrome's default injection mechanisms don't always work in iframes
  if (SAPLING_ENV.MODE !== 'SDK') {
    let elem = document.createElement('link');
    elem.rel = 'stylesheet';
    elem.setAttribute('href', getAssetURL('generated/icomoon.css'));
    // Sometimes document is just an SVG or other document w/o head
    if (document.head) document.head.appendChild(elem);
  }

  let isPopup = isPopupEnvironment();
  initializeCommandObserver(isPopup);
  initializeObservers();
  initToolbar();
  if (isPopup) {
    initializeSaplingEmbedded();
  }
  maybeShowGSuiteTooltip();
}

function getStoragePromise() {
  return new Promise((resolve) => {
    fetchGrammarAndCompleteEnableSettings(resolve);
  });
}

function getSettingsPromise() {
  return new Promise((resolve) => {
    getSettings(
      getTopFrameHostname(),
      getTopFramePathname(),
      (settings) => {
        setSiteSettings(settings);
        resolve();
      },
      (error) => {
        maybeShowConnectivityTooltip();
        resolve();
      },
    );
  });
}

function getAllPromises() {
  return Promise.all([getStoragePromise(), getSettingsPromise()]);
}

function setLocationPromise() {
  return new Promise((resolve) => {
    sendMessageHandler('init/GET_LOCATION', {}, (response) => {
      let ignoreCache = false;
      setTopFrameUrl(response.url);
      if (getTopFrameHostname() === SAPLING_ENV.WEBSITE_HOSTNAME &&
          ['/login_direct', '/user_settings', '/teams'].includes(getTopFramePathname())) {
        // refetch user cache after login
        ignoreCache = true;
      }
      resolve(ignoreCache);
    });
  });
}

function init(retry = 0) {
  initChromeCommandListener();

  // try waiting for jquery to load
  SAPLING_INITIALIZED = true;
  window.SAPLING_INITIALIZED = true;
  if (typeof $ !== 'function') {
    if (retry < 4) {
      setTimeout(() => {
        init(retry + 1);
      }, (2 ** retry) * 1000);
      return;
    }
    SAPLING_INITIALIZED = false;
    window.SAPLING_INITIALIZED = false;
  }
  try {
    setCustomEndpointsPromise().then(
      () => setLocationPromise(),
    ).then(
      (ignoreCache) => getUserPromise(ignoreCache),
    ).then(
      () => getAllPromises(),
    ).then(
      () => initApp(),
    );
  } catch (e) {
    SAPLING_INITIALIZED = false;
    window.SAPLING_INITIALIZED = false;
    Sentry.captureEvent(e);
    throw e;
  }
}

function isWindowLoaded() {
  return document.readyState === 'complete';
}

window.onload = () => {
  init();
};

window.onbeforeunload = () => {
  disconnectAllObservers();
};

if (isWindowLoaded() && !SAPLING_INITIALIZED && !window.SAPLING_INITIALIZED) {
  init();
}
