// existing observers:
//   1) onContentMutationForMutationObserver -> content mutation
//   2) initializeTextAreaObserver -> (textarea only) -> content mutation

//   3) 2x initEditableScrollObserver (contenteditable only) -> on scroll
//   4) 2x initTextAreaScrollObserver (textarea only) -> on scroll

//   5) initCursorMoveObserver (contenteditable only) -> click/key for cursor change
//   6) resizeObserverForEditableOrTextArea -> on resize

//   7) initializeFocusObservers (per frame) -> on focus
//   8) initializeMouseObserver (per frame) -> on focus

//   9) initializeHtmlObserver (optional, window, for wordpress.com) -> on all html change

//   10) initializeSaplingLoginLogoutObserver ->  sync extension and browser sessions

//   11) initializeSelectObservers ->  on range selection

// used to determine if container valid for content script
const SAPLING_CONTAINER_IDS = {}; // containerId: domElement
const SAPLING_TEXTAREA_IDS = {}; // textAreaId: domElement

let IS_UPDATING_CACHE = {}; // containerId -> boolean

async function onTextChange(obj) {
  // debounced function that gets called every QUERY_WAIT_IN_MILLISECONDS.
  const { saplingId, editable, useVisibleText } = obj;

  if (SAPLING_ENV.MODE === 'SDK') {
    if (!Sapling.userToggleEnabled) {
      return;
    }
  } else if (!isEnabledOnElement(editable) && editable.id !== 'sapling-embedded-editable') {
    return;
  }

  const containerId = getContainerId(editable);
  if (!containerId) {
    return;
  }

  updateTone(containerId);

  if (IS_UPDATING_CACHE[saplingId]) {
    return;
  }

  IS_UPDATING_CACHE[saplingId] = true;
  await updateCache(editable, useVisibleText || false);
  requestQueuedCalls(saplingId);
  delete IS_UPDATING_CACHE[saplingId];
}

function onCompleteChange(obj) {
  // debounced function that gets called every COMPLETE_WAIT_IN_MILLISECONDS.
  if (!isCompleteEnabledOnElement(obj.editable)) {
    return;
  }
  if (obj.hasOwnProperty('saplingId')) {
    getAndDisplayCompletion(obj.editable, obj.saplingId);
  } else {
    getAndDisplayCompletion(obj.editable, obj.textAreaId);
  }
}

// debounce and filtered so it only gets called per container and every 250ms.
const QUERY_WAIT_IN_MILLISECONDS = 250;
const onTextChangeDebounced = _.wrap(_.memoize(() => _.debounce(
  onTextChange,
  QUERY_WAIT_IN_MILLISECONDS,
  {
    leading: false,
    trailing: true,
  },
), _.property('id')), (func, obj) => func(obj)(obj));

// debounce and filtered so it only gets called per container and every 100ms.
const COMPLETE_WAIT_IN_MILLISECONDS = 50;
const onCompleteChangeDebounced = _.wrap(_.memoize(() => _.debounce(
  onCompleteChange,
  COMPLETE_WAIT_IN_MILLISECONDS,
  {
    leading: false,
    trailing: true,
  },
), _.property('id')), (func, obj) => func(obj)(obj));

// debounce and filtered so it only gets called per container and every 100ms.
const CURSOR_MOVE_WAIT_IN_MILLISECONDS = 20;
const onCursorMoveDebounced = _.wrap(_.memoize(() => _.debounce(
  onCursorMoveWithOverlayFormat,
  CURSOR_MOVE_WAIT_IN_MILLISECONDS,
  {
    leading: false,
    trailing: true,
  },
), _.property('id')), (func, obj) => func(obj)(obj));

function mutationAgreesWithCompletion(mutation) {
  if (mutation.type !== 'characterData') return false;

  // Non-breaking spaces
  const newText = mutation.target.data.replace(/\u00A0/g, ' ');
  const oldText = mutation.oldValue.replace(/\u00A0/g, ' ');

  if (!newText.startsWith(oldText)) return false;

  const delta = newText.substring(oldText.length);
  const compStr = getCompletionString();
  if (compStr.startsWith(delta)) return true;

  return false;
}

function inputAgreesWithCompletion(delta) {
  const compStr = getCompletionString();
  // in sdk environments sometimes input events have no delta
  if (delta && compStr.startsWith(delta)) {
    return true;
  }
  return false;
}

const contentMutationUpdateTagsDebounced = _.wrap(_.memoize(() => _.debounce(
  (saplingId) => {
    validateTagWithOverlayFormat(saplingId);
    onUpdateTagForOverlayFormatPerContainer(saplingId);
    hideEditControlsImmediatelyIfNoActiveEdit();
  },
  50,
  {
    leading: false,
    trailing: true,
  },
)), (func, obj) => func(obj)(obj));

function onContentMutationForMutationObserver(editable, saplingId, mutationsList) {
  let characterDataHandled = false; // Sometimes see multiple mutations for same change
  for (let k = 0; k < mutationsList.length; k += 1) {
    const mutation = mutationsList[k];
    onTextChangeDebounced({ saplingId, editable });
    if (mutation.type === 'characterData' && !characterDataHandled) {
      updateRangeForOverlayFormatForCharacterData(saplingId, mutation);

      if (getTextAreaId(editable)) {
        // Mutations mirroring textarea mutations, ignore
      } else if (!mutationAgreesWithCompletion(mutation)) {
        clearAndHideComplete();
        onCompleteChangeDebounced({ saplingId, editable });
      } else {
        shiftCompletion(editable);
      }

      characterDataHandled = true;
    } else if (mutation.type === 'childList') {
      updateRangeForOverlayFormatForChildList(saplingId, mutation);
      if (getTextAreaId(editable)) {
        // Mutations mirroring textarea mutations, ignore
      } else if (!mutationAgreesWithCompletion(mutation)) {
        // FIXME Currently mutation never agrees with completion
        // since we're handling childList mutations that aren't deltas
        // and so we never end up with shiftCompletion
        clearAndHideComplete();
        onCompleteChangeDebounced({ saplingId, editable });
      } else {
        shiftCompletion(editable);
      }
    } else if (mutation.type === 'attributes' && mutation.attributeName === 'contenteditable') {
      const ceAttr = editable.getAttribute('contenteditable');
      if (editable.tagName === 'DIV' &&
            !getTextAreaId(editable) &&
            ceAttr !== 'true' &&
            ceAttr !== '' &&
            ceAttr !== 'plaintext-only') {
        deactivateContainer(editable, false);
      }
    }
  }
  contentMutationUpdateTagsDebounced(saplingId);
}

function initCursorMoveObserver(editable, saplingId) {
  $(editable).on('focus click keyup', (e) => {
    if (e.type === 'keyup') {
      if (e.key === 'ArrowLeft' ||
        e.key === 'ArrowRight' ||
        e.key === 'ArrowUp' ||
        e.key === 'ArrowDown') {
        onTextChangeDebounced({ saplingId, editable });
      }
    } else {
      onTextChangeDebounced({ saplingId, editable });
      if (e.type === 'focus') {
        syncSnippetAutoExpander();
      }
    }
  });

  saveObservers(saplingId, editable, false, 'jqueryObservers', editable);
}

function initEditableScrollObserver(editable, saplingId) {
  const scrollables = getScrollableParents(editable);
  for (let i = 0; i < scrollables.length; i += 1) {
    let scrollable = scrollables[i];
    $(scrollable).on('scroll', () => {
      onUpdateTagForOverlayFormatPerContainer(saplingId);
      onTextChangeDebounced({
        saplingId,
        editable,
        useVisibleText: true,
      });
      hideEditControls();
    });
    saveObservers(saplingId, editable, false, 'jqueryObservers', scrollable);
  }
}

function initializeMutationObserver(block, containerId) {
  const contentMutationCfg = {
    attributes: true,
    childList: true, // primarily for copy-paste in empty textbox.
    characterData: true,
    subtree: true,
    characterDataOldValue: true,
  };
  const contentObserver = new MutationObserver((mutationsList) => {
    onContentMutationForMutationObserver(block, containerId, mutationsList);
  });
  contentObserver.observe(block, contentMutationCfg);

  saveObservers(containerId, block, false, 'mutationObservers', contentObserver);
}

export function deactivateContainer(container, isTextArea) {
  const inputId = container.getAttribute('sapling-input-id');
  if (inputId) {
    removeOverlay(inputId);
    disableObserver(inputId, isTextArea);
  }
  const containerId = getContainerId(container);
  removeOverlay(containerId);
  if (isTextArea) {
    const textAreaId = getTextAreaId(container);
    if (textAreaId) {
      //removeOverlay(textAreaId);  // TODO Would want to remove assoc. div
      disableObserver(textAreaId, isTextArea);
      removeTextAreaFromParentContainer(container);
    }
    delete SAPLING_TEXTAREA_IDS[textAreaId];
  } else {
    if (containerId) {
      disableObserver(containerId, isTextArea);
      removeContainerIdForOverlayFormat(containerId);
      clearCacheForContainer(containerId);
    }
    delete SAPLING_CONTAINER_IDS[containerId];
  }
  if (isHoveredElementInContainer(containerId)) {
    hideEditControls();
  }
  clearAndHideRephrase();
}

function onResizeObserverForEditableOrTextArea(entries) {
  Object.keys(SAPLING_CONTAINER_IDS).forEach((saplingId) => {
    let el = SAPLING_CONTAINER_IDS[saplingId];
    if (el !== undefined && !el.classList.contains('wysihtml5-editor')) {
      if (documentContains(el)) {
        onResizeOverlayFormatPerContainer(el);
        if (document.activeElement === el) {
          if (getCompletionString()) showComplete(el, getCompletionString());
        }
      } else {
        deactivateContainer(el, true);
      }
    }
  });
  Object.keys(SAPLING_TEXTAREA_IDS).forEach((textareaId) => {
    let el = SAPLING_TEXTAREA_IDS[textareaId];
    if (el !== undefined) {
      if (documentContains(el)) {
        let editableOverlay = initOrUpdateTextAreaOverlay(el);
        initOrUpdateContainerOverlay(editableOverlay)
      } else {
        deactivateContainer(el, true);
      }
    }
  });
}

const onResizeObserverForEditableOrTextAreaThrottled = _.throttle(
  onResizeObserverForEditableOrTextArea,
  30,
  { leading: false, trailing: true },
);

// throttle resize events to roughly 30 fps
let resizeObserverForEditableOrTextArea = new ResizeObserver(
  (entries) => {
    requestAnimationFrame(() => {
      onResizeObserverForEditableOrTextAreaThrottled(entries);
    });
  },
);

function onContentMutationForTextAreaObserver(event) {
  const editable = getDeepTarget(event);
  if (editable === undefined) {
    return;
  }

  const textAreaId = getTextAreaId(editable);
  if (!textAreaId) {
    return;
  }

  updateTextAreaOverlayWithText(textAreaId, editable.value);

  if (event.type === 'input') {
    if (!inputAgreesWithCompletion(event.data)) {
      clearAndHideComplete();
      onCompleteChangeDebounced({ textAreaId, editable });
    } else {
      shiftCompletion(editable);
    }
  }
}

function initializeTextAreaObserver(textArea) {
  const textAreaId = getTextAreaId(textArea);
  // passive is to improve scrolling perf
  const options = { passive: true, once: false };
  textArea.addEventListener('input', onContentMutationForTextAreaObserver, options);
  saveObservers(textAreaId, textArea, true, 'eventListeners', {
    element: textArea,
    event: 'input',
    handler: onContentMutationForTextAreaObserver,
    options,
  });

  textArea.addEventListener('keyup', onContentMutationForTextAreaObserver, options);
  saveObservers(textAreaId, textArea, true, 'eventListeners', {
    element: textArea,
    event: 'keyup',
    handler: onContentMutationForTextAreaObserver,
    options,
  });
}

function initTextAreaScrollObserver(textArea, textAreaId) {
  const scrollables = getScrollableParents(textArea);
  for (let i = 0; i < scrollables.length; i += 1) {
    let scrollable = scrollables[i];
    if (getTextAreaId(scrollable) === textAreaId) {
      $(scrollable).on('scroll', () => {
        updateTextAreaScroll(textAreaId);
      });
    } else {
      $(scrollable).on('scroll', () => {
        updateTextAreaInScrollable(textAreaId);
      });
    }
    saveObservers(textAreaId, textArea, true, 'jqueryObservers', scrollable);
  }
}

const SELECTCHANGE_WAIT_IN_MILLISECONDS = 100;
const onSelectionChangeHideRephrase = () => {
  setTimeout(hideRephraseControls, SELECTCHANGE_WAIT_IN_MILLISECONDS);
};

export function initializeObserversPerEditableBlock(block) {
  if (SAPLING_ENV.MODE !== 'SDK' &&
      !isEnabledOnElement(block) &&
      !isCompleteEnabledOnElement(block) &&
      block.id !== 'sapling-embedded-editable') {
    return;
  }

  // add unique id to each editable container.
  const currentContainerId = getContainerId(block);
  if (!currentContainerId || !(currentContainerId in SAPLING_CONTAINER_IDS)) {
    const containerId = setContainerId(block, currentContainerId);
    SAPLING_CONTAINER_IDS[containerId] = block;
    // for overlay format
    initOrUpdateContainerOverlay(block);
    initializeMutationObserver(block, containerId);
    resizeObserverForEditableOrTextArea.observe(block);
    saveObservers(containerId, block, false, 'resizeObservers', {
      container: block,
      observer: resizeObserverForEditableOrTextArea,
    });

    initKeypressObservers(containerId, block, false);
    initCursorMoveObserver(block, containerId);
    initClickObservers(containerId, block, false);
    initEditableScrollObserver(block, containerId);
    initializeDirectIFrameResources(block);

    // make initial edit
    onTextChange({
      saplingId: containerId,
      editable: block,
      useVisibleText: false,
    });
  }
}

function initKeypressObservers(blockId, block, isTextArea) {
  $(block).on('keypress', (e) => {
    let expansion = handleKeyPress(block, e.key);
    if (expansion) {
      return false;
    }
  });

  const isCompleteEnabled = isCompleteEnabledOnElement(block);
  $(block).on('keydown', (e) => {
    if (e.key === 'Tab') {
      const focused = maybeTabIntoEditControls();
      if (focused) {
        return false;
      }
    } else {
      const propagateEvent = handleKeyDown(block, e.key);
      if (!propagateEvent) {
        return false;
      }
      onCursorMoveDebounced(block);
    }
    if (isCompleteEnabled) {
      if (isSlateElement(block)) {
        // Hack to handle slate; adds pause
        tabComplete(e, block);
      } else {
        tabComplete(e, block);
      }
    }
    if (isRephraseEnabled()) {
      onSelectionChangeHideRephrase();
    }
  });

  saveObservers(blockId, block, isTextArea, 'jqueryObservers', block);
}

function initClickObservers(blockId, block, isTextArea) {
  $(block).on('click', (e) => {
    onClickWithOverlayFormat(block);
  });

  saveObservers(blockId, block, isTextArea, 'eventListeners', {
    element: block,
    event: 'click',
    handler: onClickWithOverlayFormat,
  });
}

export function initializeObserversPerTextArea(textArea) {
  if (!isEnabledOnElement(textArea) && !isCompleteEnabledOnElement(textArea)) {
    return;
  }

  let onfocus = $(textArea).attr('onfocus');
  if (onfocus && onfocus.includes('(this).hide()')) {
    // fake textarea. used by freshservice domains
    // adding an overlay to this prevents the element from re-showing down the line
    // this causes the UI to look like it's losing form fields
    return;
  }

  const textAreaId = getTextAreaId(textArea);
  if (!textAreaId || !(textAreaId in SAPLING_TEXTAREA_IDS)) {
    const newTextAreaId = setTextAreaId(textArea);
    SAPLING_TEXTAREA_IDS[newTextAreaId] = textArea;

    const editableOverlay = initOrUpdateTextAreaOverlay(textArea);
    initializeTextAreaObserver(textArea);
    resizeObserverForEditableOrTextArea.observe(textArea);
    saveObservers(newTextAreaId, textArea, true, 'resizeObservers', {
      container: textArea,
      observer: resizeObserverForEditableOrTextArea,
    });
    initTextAreaScrollObserver(textArea, newTextAreaId);

    initKeypressObservers(textAreaId, textArea, true);
    initClickObservers(textAreaId, textArea, true);

    // make initial edit.
    updateTextAreaOverlayWithText(newTextAreaId, textArea.value);
    updateTextAreaScroll(newTextAreaId);

    // need to force observing, cause we don't focusin.
    initializeObserversPerEditableBlock(editableOverlay);

    // tag textarea with containerId of the new content editable
    const containerId = getContainerId(editableOverlay);
    setContainerId(textArea, containerId);
  } else {
    // sync existing text area
    updateTextAreaOverlayWithText(textAreaId, textArea.value);
  }
}

// debounce so it only gets called every 100ms.
const MOUSE_WAIT_IN_MILLISECONDS = 100;
const onMouseMoveThrottled = _.throttle(
  onMouseMoveWithOverlayFormat,
  MOUSE_WAIT_IN_MILLISECONDS,
  {
    leading: false,
    trailing: true,
  },
);

function containsElement(path, elementId) {
  for (let k = 0; k < path.length; k += 1) {
    const p = path[k];
    if (p.id === elementId) {
      return true;
    }
  }

  return false;
}

function onMouseDown(event) {
  const { path } = event;
  if (!path) {
    return;
  }

  const snippetInteraction = containsElement(path, 'sapling-snippet-controls');
  clearKeyPressBuffer(snippetInteraction);

  if (containsElement(path, 'accept-button') ||
    containsElement(path, 'ignore-button') ||
    containsElement(path, 'explanations')) {
    event.preventDefault();
  }
}

function initializeDirectIFrameResources(elem) {
  // In the browser extension, content scripts are injected into every iFrame
  // For the SDK, users most likely only only load in the parent frame.
  // Additional resources need to be injected into iFrames in SDK mode.
  if (document === elem.ownerDocument) {
    return;
  } else if (SAPLING_ENV.MODE !== 'SDK') {
    return;
  }

  Sapling.injectCSS(elem.ownerDocument);
  const options = { passive: true };
  elem.ownerDocument.addEventListener('mousemove', onMouseMoveThrottled, options);
  saveEventListener({
    element: document,
    event: 'mousemove',
    handler: onMouseMoveThrottled,
    options,
  });

  // we need to below for web.whatsapp.com where
  // a mousedown event blocks click from propagating
  elem.ownerDocument.addEventListener('mousedown', onMouseDown, {});
  saveEventListener({
    element: document,
    event: 'mousedown',
    handler: onMouseDown,
    options: {},
  });
}

function initializeMouseObserver() {
  const options = { passive: true };
  document.addEventListener('mousemove', onMouseMoveThrottled, options);
  saveEventListener({
    element: document,
    event: 'mousemove',
    handler: onMouseMoveThrottled,
    options,
  });

  // we need to below for web.whatsapp.com where
  // a mousedown event blocks click from propagating
  document.addEventListener('mousedown', onMouseDown, {});
  saveEventListener({
    element: document,
    event: 'mousedown',
    handler: onMouseDown,
    options: {},
  });
}

function onFocusBlock(event) {
  clearKeyPressBuffer();
  const target = getDeepTarget(event);
  if (target.getAttribute('contenteditable') === 'true' ||
    target.getAttribute('contenteditable') === '' ||
    target.getAttribute('contenteditable') === 'plaintext-only') {
    initializeObserversPerEditableBlock(target);
  } else if (isCheckableTextElement(target)) {
    initializeObserversPerTextArea(target);
  }
  checkAndDisableInactiveObservers();
}

function initializeFocusObservers() {
  const options = { passive: true };
  document.addEventListener('focusin', onFocusBlock, options);
  saveEventListener({
    element: document,
    event: 'focusin',
    handler: onFocusBlock,
    options,
  });
  document.addEventListener('focusout', clearAndHideComplete, options);
  saveEventListener({
    element: document,
    event: 'focusout',
    handler: clearAndHideComplete,
    options,
  });
  document.addEventListener('focusout', clearAndHideRephrase, options);
  saveEventListener({
    element: document,
    event: 'focusout',
    handler: clearAndHideRephrase,
    options,
  });
}

function initializeSelectObservers() {
  const options = { passive: true };

  if (AI_DETECT_ANYWHERE_EXTENSION) {
    document.addEventListener('selectionchange', onSelectionChangeToggleAIDetect, options);
    saveEventListener({
      element: document,
      event: 'selectionchange',
      handler: onSelectionChangeToggleAIDetect,
      options,
    });

    return;
  }

  document.addEventListener('selectionchange', onSelectionChangeHideRephrase, options);
  saveEventListener({
    element: document,
    event: 'selectionchange',
    handler: onSelectionChangeHideRephrase,
    options,
  });

  document.addEventListener('selectionchange', maybeShowRephraseButton, options);
  saveEventListener({
    element: document,
    event: 'selectionchange',
    handler: maybeShowRephraseButton,
    options,
  });
}

function shouldInitializeObserver(node) {
  if (!$(node).is(':focus')) {
    if (node.textContent === '' || !$(node).is(':visible')) {
      return false;
    }
  }
  return true;
}

export function initializeObserversPerInput() {
  let selector = 'textarea';
  if (isCheckInputsEnabled()) selector = 'textarea,input[type="text"]';
  $(selector).each((ind, textArea) => {
    if (shouldInitializeObserver(textArea)) {
      initializeObserversPerTextArea(textArea);
    }
  });

  $('[contenteditable=true], [contenteditable=plaintext-only]').each((ind, block) => {
    if (shouldInitializeObserver(block)) {
      initializeObserversPerEditableBlock(block);
    }
  });

  let shadowTextAreas = shadowQuery(el => elIsTextArea(el, isCheckInputsEnabled()));
  $(shadowTextAreas).each((ind, textArea) => {
    if (shouldInitializeObserver(textArea)) {
      initializeObserversPerTextArea(textArea);
    }
  });

  let shadowContentEditables = shadowQuery(elIsContentEditable);
  $(shadowContentEditables).each((ind, block) => {
    if (shouldInitializeObserver(block)) {
      initializeObserversPerEditableBlock(block);
    }
  });
}

function onHtmlMutation(mutationsList) {
  for (let k = 0; k < mutationsList.length; k += 1) {
    const mutation = mutationsList[k];
    if (mutation.type === 'childList') {
      for (let j = 0; j < mutation.addedNodes.length; j += 1) {
        const addedNode = mutation.addedNodes[j];
        if (addedNode.tagName === 'IFRAME') {
          onIframeReady($(addedNode), () => {
            sendMessageHandler('init/NEW_IFRAME_LOADED');
          });
        } else {
          // find only applies to children
          $('iframe', addedNode).each((index, elem) => {
            onIframeReady($(elem), () => {
              sendMessageHandler('init/NEW_IFRAME_LOADED');
            });
          });
        }
      }
      for (let j = 0; j < mutation.removedNodes.length; j += 1) {
        const removedNode = mutation.removedNodes[j];
        if (removedNode.nodeType === Node.ELEMENT_NODE &&
            (elIsContentEditable(removedNode) || isCheckableTextElement(removedNode))) {
          const isTextArea = isCheckableTextElement(removedNode);
          deactivateContainer(removedNode, isTextArea);
        }
      }
    }
  }
}

function initializeHtmlObserver() {
  if (SAPLING_ENV.MODE !== 'SDK') {
    // hook into exsiting iframes
   const hostname = getTopFrameHostname();
    $('iframe').each((idx, elem) => {
      try {
        onIframeReady($(elem), () => sendMessageHandler('init/NEW_IFRAME_LOADED'));
      } catch (e) {
        // sometimes blocked from accessing a cross-origin frame.
      }
    });
  }

  const { body } = document;
  if (body) {
    if (SAPLING_ENV.MODE !== 'SDK') {
      // observer to detect new iframe.
      const mutationCfg = { attributes: false, childList: true, subtree: true };
      const observer = new MutationObserver(onHtmlMutation);
      observer.observe(body, mutationCfg);
      saveDocumentObserver(observer);
    }

    // observer to detect window resize
    resizeObserverForEditableOrTextArea.observe(body);
    saveDocumentObserver(resizeObserverForEditableOrTextArea);
  }
}

function initializeSaplingLoginLogoutObserver() {
  const hostname = getTopFrameHostname();
  if (!hostname.includes(SAPLING_ENV.WEBSITE_HOSTNAME)) {
    return;
  }

  const logoutButton = document.getElementById('logout-button');
  if (logoutButton) {
    logoutButton.addEventListener('click', () => {
      logoutUser(() => {
        getUserPromise(true);
      }, () => {
        getUserPromise(true);
      });
    });
  }

  const loginButton = document.getElementById('login-button');
  if (loginButton) {
    loginButton.addEventListener('click', () => {
      clearUser();
    });
  }
}

export function initializeObservers() {
  if (SAPLING_ENV.AI_DETECT_ANYWHERE_EXTENSION) {
    maybeEmbedAIDetectOnHost();
    initializeSelectObservers();
    return;
  }
  initializeHtmlObserver();
  initializeMouseObserver();
  if (SAPLING_ENV.MODE === 'SDK') {
    return;
  }
  initializeSaplingLoginLogoutObserver();
  initializeFocusObservers();
  initializeSelectObservers();
  initializeObserversPerInput();
  initializeFigmaObserver(
    initializeObserversPerEditableBlock,
    onTextChange,
  );
  syncSnippetAutoExpander();
  try {
    maybeInitializeSuggestionObserver(updateTextAreaOverlayWithText);
  } catch (e) {
    console.log('maybeInitializeSuggestionObserver error: ', e);
  }
}

export function checkOnceForEditableBlock(block) {
  let containerId = getContainerId(block);
  if (!containerId || !(containerId in SAPLING_CONTAINER_IDS)) {
    containerId = setContainerId(block);
    SAPLING_CONTAINER_IDS[containerId] = block;
    // initializeMutationObserver(block, containerId);
    resizeObserverForEditableOrTextArea.observe(block);
    saveObservers(containerId, block, false, 'resizeObservers', {
      container: block,
      observer: resizeObserverForEditableOrTextArea,
    });

    // initKeypressObservers(containerId, block, false);
    initCursorMoveObserver(block, containerId);
    initClickObservers(containerId, block, false);
    initEditableScrollObserver(block, containerId);
    initializeDirectIFrameResources(block);
  }
  initOrUpdateContainerOverlay(block);
  // make initial edit
  onTextChange({
    saplingId: containerId,
    editable: block,
    useVisibleText: false,
  });
}

export function checkOnceForTextArea(textArea) {
  let textAreaId = getTextAreaId(textArea);
  let editableOverlay;
  if (!textAreaId || !(textAreaId in SAPLING_TEXTAREA_IDS)) {
    textAreaId = setTextAreaId(textArea);
    SAPLING_TEXTAREA_IDS[textAreaId] = textArea;
    initializeTextAreaObserver(textArea);
    resizeObserverForEditableOrTextArea.observe(textArea);
    saveObservers(textAreaId, textArea, true, 'resizeObservers', {
      container: textArea,
      observer: resizeObserverForEditableOrTextArea,
    });
    initTextAreaScrollObserver(textArea, textAreaId);
    initKeypressObservers(textAreaId, textArea, true);
    initClickObservers(textAreaId, textArea, true);
    updateTextAreaScroll(textAreaId);
  }

  // sync existing text area
  updateTextAreaOverlayWithText(textAreaId, textArea.value);
  editableOverlay = initOrUpdateTextAreaOverlay(textArea);
  checkOnceForEditableBlock(editableOverlay);
}

export function refreshEdits() {
  for (const [containerId, elem] of Object.entries(SAPLING_CONTAINER_IDS)) {
    onTextChange({
      saplingId: containerId,
      editable: elem,
      useVisibleText: false,
    });
  }
  for (const [textAreaId, elem] of Object.entries(SAPLING_TEXTAREA_IDS)) {
    console.log('elem: ', elem);
    updateTextAreaOverlayWithText(textAreaId, elem.value);
  }
}
