let TEXT_FORMAT_PROPS = [
  'fontStyle',
  'fontVariant',
  'fontWeight',
  'fontStretch',
  'fontSize',
  'fontSizeAdjust',
  'fontFamily',
  'textAlign',
  'textTransform',
  'letterSpacing',
  'wordSpacing',
  'tabSize',
];

export function copyTextFormat(src, tgt) {
  var computed = getComputedStyle(src);
  $(TEXT_FORMAT_PROPS).each((ind, prop) => {
    tgt.style[prop] = computed[prop];
  });
}
