import {
  applySingleRange,
  replaceContentEditableSelection,
  replaceTextAreaSelection,
} from './textarea';
import {
  isCheckableTextElement,
  isMultiFillinEnabled,
} from '../settings';
import {
  getLocationFromOffset,
  getRangeAsOffsets,
} from '../../utils/html-utils';

let multiFillinfirstEdit = true;
let multiFillinNode = null;
let multiFillinCopyOffsets = [];
let multiFillinOffset = null;
let handlingPaste = false;

function resetMultiFillinEditMode() {
  if (multiFillinNode) {
    multiFillinNode.removeEventListener('keydown', handleMultiSelectKeyDown);
    multiFillinNode.removeEventListener('paste', handlePaste);
    multiFillinNode = null;
  }
  multiFillinCopyOffsets = [];
  multiFillinOffset = null;
  handlingPaste = false;
  document.removeEventListener('selectionchange', handleSelectionChange);
}

function startMultiFillinEditMode(block, editRange, fillinRanges) {
  multiFillinNode = block;
  multiFillinfirstEdit = true;
  handlingPaste = false;
  multiFillinCopyOffsets = [];
  if (isCheckableTextElement(multiFillinNode)) {
    multiFillinOffset = [editRange.startOffset, editRange.endOffset];
    for (let copyRange of fillinRanges) {
      multiFillinCopyOffsets.push([copyRange.startOffset, copyRange.endOffset]);
    }
  } else {
    multiFillinOffset = getRangeAsOffsets(multiFillinNode, editRange);
    if (multiFillinOffset === null) {
      // won't be able to track this multi fillin properly so break early
      multiFillinNode = null;
      return;
    }
    for (let copyRange of fillinRanges) {
      let rangeOffset = getRangeAsOffsets(multiFillinNode, copyRange);
      if (rangeOffset !== null) {
        multiFillinCopyOffsets.push(rangeOffset);
      }
    }
  }

  // sort back to front
  multiFillinCopyOffsets.sort((a, b) => b[0] - a[0]);
  multiFillinNode.addEventListener('keydown', handleMultiSelectKeyDown);
  multiFillinNode.addEventListener('paste', handlePaste);
  document.addEventListener('selectionchange', handleSelectionChange);
}

export function maybeStartMultiFillinEditMode(block, activeEditInfo, editInfos) {
  // do a quick search, select all fillins with the same originalText
  resetMultiFillinEditMode();
  if (!isMultiFillinEnabled()) {
    return;
  }
  let fillinRanges = [];
  for (const matchingEditInfo of Object.values(editInfos)) {
    if (activeEditInfo.edit.originalText === matchingEditInfo.edit.originalText &&
        activeEditInfo.edit.editId !== matchingEditInfo.edit.editId) {
      fillinRanges.push(matchingEditInfo.editRange);
    }
  }
  if (fillinRanges.length) {
    startMultiFillinEditMode(block, activeEditInfo.editRange, fillinRanges);
  }
}

function handleSelectionChange(event) {
  if (isCheckableTextElement(multiFillinNode)) {
    let multiFillinStart = multiFillinOffset[0];
    let multiFillinEnd = multiFillinOffset[1];
    multiFillinEnd++;
    let { selectionStart, selectionEnd } = multiFillinNode;
    if (((multiFillinStart <= selectionStart) && (selectionStart <= multiFillinEnd)) ||
        ((multiFillinStart <= selectionEnd) && (selectionEnd <= multiFillinEnd))) {
      // sill in multi edit mode
      return;
    }
  } else {
    const sel = window.getSelection();
    if (sel) {
      const selectedRange = sel.getRangeAt(0);

      let multiFillinStart = multiFillinOffset[0];
      let multiFillinEnd = multiFillinOffset[1];
      multiFillinEnd++;

      let selectedOffset = getRangeAsOffsets(multiFillinNode, selectedRange);
      if (((multiFillinStart <= selectedOffset[0]) && (selectedOffset[0] <= multiFillinEnd)) ||
          ((multiFillinStart <= selectedOffset[1]) && (selectedOffset[1] <= multiFillinEnd))) {
        // sill in multi edit mode
        return;
      }
    }
  }

  resetMultiFillinEditMode();
}

function postKeyDownEvent(inputValue, isBackspace) {
  const inputLength = inputValue.length;
  let charactersRemoved = multiFillinOffset[1] - multiFillinOffset[0];

  // update offsets from keyboard input
  for (let idx = 0; idx < multiFillinCopyOffsets.length; idx++) {
    if (multiFillinOffset[0] <= multiFillinCopyOffsets[idx][0]) {
      if (multiFillinfirstEdit) {
        // TODO: this doesn't account for whitespace around the multiFillinOffset
        // that sometimes also gets removed
        multiFillinCopyOffsets[idx][0] -= charactersRemoved;
        multiFillinCopyOffsets[idx][1] -= charactersRemoved;
        if (!isBackspace) {
          multiFillinCopyOffsets[idx][0] += inputLength;
          multiFillinCopyOffsets[idx][1] += inputLength;
        }
      } else if (isBackspace) {
        multiFillinCopyOffsets[idx][0]--;
        multiFillinCopyOffsets[idx][1]--;
      } else {
        multiFillinCopyOffsets[idx][0] += inputLength;
        multiFillinCopyOffsets[idx][1] += inputLength;
      }
    }
  }
  // at this point, the offsets are correct
  // make updates to fillins, which requires all offsets be updated again
  for (let i = 0; i < multiFillinCopyOffsets.length; i++) {
    let copyOffset = multiFillinCopyOffsets[i];
    let [startOffset, endOffset] = copyOffset;

    let range;
    if (!isCheckableTextElement(multiFillinNode)) {
      range = document.createRange();
      const startLocation = getLocationFromOffset(multiFillinNode, 0, startOffset, multiFillinNode);
      const endLocation = getLocationFromOffset(multiFillinNode, 0, endOffset, multiFillinNode);
      range.setStart(startLocation.domElement, startLocation.domOffset);
      range.setEnd(endLocation.domElement, endLocation.domOffset);
    }

    if (multiFillinfirstEdit) {
      let newString = '';
      let characterDiff = -charactersRemoved;
      if (!isBackspace) {
        newString = inputValue;
        characterDiff += newString.length;
      }

      if (isCheckableTextElement(multiFillinNode)) {
        replaceTextAreaSelection(multiFillinNode, startOffset, endOffset, newString);
      } else {
        replaceContentEditableSelection(range, newString, multiFillinNode);
      }
      multiFillinCopyOffsets[i][1] += characterDiff;
      // update all previous offsets, due to clearing this fillin
      if (multiFillinOffset[0] > startOffset) {
        multiFillinOffset[0] += characterDiff;
        multiFillinOffset[1] += characterDiff;
      }
      for (let j = 0; j < i; j++) {
        multiFillinCopyOffsets[j][0] += characterDiff;
        multiFillinCopyOffsets[j][1] += characterDiff;
      }
    } else {
      if (isBackspace) {
        if (isCheckableTextElement(multiFillinNode) && endOffset > startOffset) {
          replaceTextAreaSelection(multiFillinNode, endOffset - 1, endOffset, '');
          multiFillinCopyOffsets[i][1]--;
        } else if (range.toString().length) {
          const lastCharLocation = getLocationFromOffset(multiFillinNode, 0, endOffset - 1, multiFillinNode);
          range.setStart(lastCharLocation.domElement, lastCharLocation.domOffset);
          replaceContentEditableSelection(range, '', multiFillinNode);
          multiFillinCopyOffsets[i][1]--;
        }

        // update other copy offsets that shifted because of latest change
        for (let j = 0; j < i; j++) {
          multiFillinCopyOffsets[j][0]--;
          multiFillinCopyOffsets[j][1]--;
        }
      } else {
        if (isCheckableTextElement(multiFillinNode)) {
          replaceTextAreaSelection(multiFillinNode, endOffset, endOffset, inputValue);
        } else {
          range.collapse();
          replaceContentEditableSelection(range, inputValue, multiFillinNode);
        }
        multiFillinCopyOffsets[i][1] += inputLength;
        for (let j = 0; j < i; j++) {
          multiFillinCopyOffsets[j][0] += inputLength;
          multiFillinCopyOffsets[j][1] += inputLength;
        }
      }

      // update multiFillinOffset based on latest change
      if (multiFillinOffset[0] > multiFillinCopyOffsets[i][0]) {
        if (isBackspace) {
          multiFillinOffset[0]--;
          multiFillinOffset[1]--;
        } else {
          multiFillinOffset[0] += inputLength;
          multiFillinOffset[1] += inputLength;
        }
      }
    }
  }

  // Update multiFillinRange too, to detect when to break out of mode properly
  // Let key event propagate first
  if (multiFillinfirstEdit) {
    multiFillinfirstEdit = false;
    multiFillinOffset[1] = multiFillinOffset[0];
  }

  if (isBackspace) {
    multiFillinOffset[1]--;
  } else {
    multiFillinOffset[1] += inputLength;
  }

  // focus
  if (isCheckableTextElement(multiFillinNode)) {
    multiFillinNode.selectionStart = multiFillinOffset[1];
    multiFillinNode.selectionEnd = multiFillinOffset[1];
  } else {
    let multiFillinRange = document.createRange();
    const startLocationMF = getLocationFromOffset(multiFillinNode, 0, multiFillinOffset[0], multiFillinNode);
    const endLocationMF = getLocationFromOffset(multiFillinNode, 0, multiFillinOffset[1], multiFillinNode);
    multiFillinRange.setStart(startLocationMF.domElement, startLocationMF.domOffset);
    multiFillinRange.setEnd(endLocationMF.domElement, endLocationMF.domOffset);
    applySingleRange(multiFillinRange);
  }
  setTimeout(() => document.addEventListener('selectionchange', handleSelectionChange), 0);
}

function handleMultiSelectKeyDown(event) {
  const inputValue = event.key;
  if (inputValue.length !== 1 && inputValue !== 'Backspace') {
    return;
  }
  // selectionchange listener added back after postKeyDownEvent complete
  document.removeEventListener('selectionchange', handleSelectionChange);
  const isBackspace = inputValue === 'Backspace';
  // wait for dom modifications to apply before deuplicating across other fillins
  setTimeout(() => {
    if (handlingPaste) {
      return; // drops keyboard presses around copy-paste
    }
    postKeyDownEvent(inputValue, isBackspace);
  }, 10);
}

function handlePaste(event) {
  handlingPaste = true;
  // selectionchange listener added back after postKeyDownEvent complete
  document.removeEventListener('selectionchange', handleSelectionChange);
  let data = (event.clipboardData || window.clipboardData).getData('text');
  // wait for dom modifications to apply before deuplicating across other fillins
  setTimeout(() => {
    postKeyDownEvent(data, false);
    handlingPaste = false;
  }, 10);
}
