/**
 * getSuggest
 * ---------
 * Makes a call to the suggestion server on given query.
 */
export function getSuggest(query, multiquery, onSuccess, onFailure, moreContext={}) {
  // FIXME -300 should be param
  let context = getContextProperties();
  Object.assign(context, moreContext);
  sendMessageHandler('request/GET_SUGGEST', {
    query: query.slice(-300),
    multiquery,
    context,
  }, onSuccess, onFailure);
}


