import { initializeObserversPerInput } from '../ui/observers/observers';

let SNIPPETS_CACHE = null;

function getContextProperties() {
  return {
    version: 'TODO',
    source: 'SDK',
  };
}

function unformatEdit(edit) {
  let originalText = edit.sentence.substring(edit.start, edit.end);
  let start = {
    offset: edit.start + edit.sentence_start,
    text: originalText,
  };
  let end = {
    offset: edit.end + edit.sentence_start,
    text: originalText,
  };

  let newEdit = edit;
  newEdit.replacement_text = edit.replacement;
  newEdit.original_text = originalText;
  newEdit.start = start;
  newEdit.end = end;
  newEdit.replacement_text = edit.replacement;
  if (edit.general_error_type === 'Advanced Edit') {
    newEdit.category = edit.error_type; // eslint-disable-line no-param-reassign
  }
  return newEdit;
}

/**
 * Edits endpoints return different formats depending on the noformat flag.
 * If SDK users are passing results from an API call without the noformat flag, we convert it
 * to a usable format silently instead of failing.
 */
function editCompatibilityConversion(edits) {
  let newEdits = [];
  for (let i = 0; i < edits.length; i++) {
    let newEdit = unformatEdit(edits[i]);
    newEdits.push(newEdit);
  }
  return newEdits;
}

function telemetryWrapper({
  type,
  url,
  contentType,
  dataType,
  data,
  xhrFields,
  success,
  error,
}) {
  const startTime = Date.now();
  $.ajax({
    type,
    url,
    contentType: contentType || 'application/json',
    dataType: dataType || 'json',
    data,
    xhrFields: xhrFields || {},
    success: success || (() => {}),
    error: error || (() => {}),
    complete: (jqXHR) => callTelemetryEndpoint({
      startTime,
      status: jqXHR.status,
      url,
      data,
    }),
  });
}

function callTelemetryEndpoint({
  startTime,
  status,
  url,
}) {
  if (!Sapling.telemetryEndpoint) {
    return;
  }

  const telemetry = {
    status,
    latency: Date.now() - startTime,
    url,
  };

  try {
    $.ajax({
      type: 'post',
      url: Sapling.telemetryEndpoint,
      contentType: 'application/json',
      dataType: 'json',
      data: JSON.stringify(telemetry),
    });
  } catch (e) {
  }
}

export function sendEvent(name) {
  if (!Sapling.key) {
    return; // skip sdk events when initialized with no key
  }
  let context = getContextProperties();
  context.hostname = getTopFrameHostname();
  context.pathname = getTopFramePathname();
  let data = {
    name,
    key: Sapling.key,
    event_properties: context,
  };
  let url = `${Sapling.endpointHostname}${Sapling.saplingPathPrefix}/api/v1/events`;
  try {
    telemetryWrapper({
      type: 'post',
      url,
      contentType: 'application/json',
      dataType: 'json',
      data: JSON.stringify(data),
    });
  } catch (e) {
  }
}

function getAIDetectionScores(innerHTML, context, onSuccess, onFailure) {
  const data = {
    text: innerHTML,
    context,
    session_id: Sapling.sessionId,
    user_id: Sapling.userId,
    is_anon_user: Sapling.isAnonUser,
    lang: 'en',
    key: Sapling.key,
  };
  let url = `${Sapling.endpointHostname}${Sapling.saplingPathPrefix}${Sapling.aiDetectPathname}`;

  telemetryWrapper({
    type: 'post',
    url,
    contentType: 'application/json',
    dataType: 'json',
    data: JSON.stringify(data),
    success: (aidetect) => {
      onSuccess({ data: { aidetect }, status: true, success: true });
    },
    error: (resp) => {
      onFailure(resp.responseJSON);
    },
  });
}

