function getUser() {
  let withCredentials = true;
  let url = `${Sapling.endpointHostname}${Sapling.saplingPathPrefix}/users/me`;

  telemetryWrapper({
    type: 'get',
    url,
    contentType: 'application/json',
    xhrFields: {
      withCredentials,
    },
    success: (user) => {
      setUserProperties(user);
      Sapling.userPropertiesLoaded = true;
    },
    error: (resp) => {
      // do nothing
    },
  });
}

function getEdits(innerHtml, context, onSuccess, onFailure) {
  let hostname = getTopFrameHostname();
  let withCredentials;
  let url = `${Sapling.endpointHostname}${Sapling.saplingPathPrefix}${Sapling.editPathname}`;
  if (Sapling.freemium || hostname === SAPLING_ENV.WEBSITE_HOSTNAME) {
    withCredentials = true;
  } else {
    withCredentials = false;
  }

  let data = {
    key: Sapling.key,
    session_id: Sapling.sessionId,
    user_id: Sapling.userId,
    is_anon_user: Sapling.isAnonUser,
    text: innerHtml,
    noformat: true,
    lang: Sapling.lang,
    variety: Sapling.variety,
    advanced_edits: Sapling.advancedEdits,
    operations: Sapling.operations,
    freemium: Sapling.freemium,
    context,
  };
  if (!Sapling.appearance.compact) {
    data.sdk_extended = true;
  }
  if (Sapling.addToDictionary) {
    data.sdk_dictionary = true;
  }

  if (Sapling.freemium && Sapling.userPropertiesLoaded && !isAccountPremium()) {
    delete data.advanced_edits;
  }

  if (Sapling.userData !== null) {
    data.userData = Sapling.userData;
  }
  if (Sapling.neuralSpellcheck !== null) {
    data.neural_spellcheck = Sapling.neuralSpellcheck;
  }
  if (Sapling.minLength !== null) {
    data.min_length = Sapling.minLength;
  }
  if (Sapling.medical !== null) {
    data.medical = Sapling.medical;
  }

  telemetryWrapper({
    type: 'post',
    url,
    contentType: 'application/json',
    dataType: 'json',
    data: JSON.stringify(data),
    xhrFields: {
      withCredentials,
    },
    success: (returnEdits) => {
      let edits;
      if (returnEdits.edits && returnEdits.edits[0] && returnEdits.edits[0].error_type) {
        edits = editCompatibilityConversion(returnEdits.edits);
      } else {
        edits = returnEdits;
      }
      onSuccess({ data: { edits }, status: true, success: true });
    },
    error: (resp) => {
      onFailure(resp.responseJSON);
    },
  });
}

