function getShortcutSnippets(onSuccess, onFailure) {
  if (SNIPPETS_CACHE) {
    onSuccess({ data: SNIPPETS_CACHE, status: true, success: true });
    return;
  }
  const currentDate = new Date();
  const timeZoneOffset = currentDate.getTimezoneOffset();
  let url = `${Sapling.endpointHostname}${Sapling.saplingPathPrefix}/snippets/shortcut_snippets?timeZoneOffset=${timeZoneOffset}`;

  telemetryWrapper({
    type: 'get',
    url,
    contentType: 'application/json',
    xhrFields: {
      withCredentials: true,
    },
    success: (resp) => {
      SNIPPETS_CACHE = resp.snippets;
      console.log('SNIPPETS_CACHE: ', SNIPPETS_CACHE);
      onSuccess({ data: SNIPPETS_CACHE, status: true, success: true });
    },
    error: (resp) => {
      onFailure(resp.responseJSON);
    },
  });
}

