function postEdit(editHash, action, context) {
  if (action !== 'accept' && action !== 'reject') {
    return;
  }
  const data = {
    context,
    session_id: Sapling.sessionId,
    user_id: Sapling.userId,
    is_anon_user: Sapling.isAnonUser,
    key: Sapling.key,
    freemium: Sapling.freemium,
  };

  let withCredentials = Sapling.freemium;

  let url = `${Sapling.endpointHostname}${Sapling.saplingPathPrefix}/api/v1/edits/${editHash}/${action}`;
  telemetryWrapper({
    type: 'post',
    url,
    contentType: 'application/json',
    dataType: 'json',
    data: JSON.stringify(data),
    xhrFields: { withCredentials },
  });
}

