export function getManifestVersion() {
  if (SAPLING_ENV.MODE !== 'SDK') {
    const { version } = chrome.runtime.getManifest();
    return version;
  }
  return '';
}

export function sendMessage(message, onSuccess = null, onFailure = null) {
  if (SAPLING_ENV.MODE !== 'SDK') {
    chrome.runtime.sendMessage(
      message,
      (response) => {
        if (chrome.runtime.lastError && onFailure) {
          onFailure({ message: chrome.runtime.lastError });
        }
        if (onSuccess) {
          onSuccess(response);
        }
      },
    );
    return;
  }
  const { data, action } = message;
  const defaultContextProperties = getContextProperties();
  const context = { ...defaultContextProperties, ...data.context };
  if (action === 'request/GET_EDITS') {
    getEdits(data.html, context, onSuccess, onFailure);
  } else if (action === 'request/GET_COMPLETION') {
    getCompletion(data.query, context, onSuccess, onFailure);
  } else if (action === 'request/GET_SHORTCUT_SNIPPETS' && Sapling.snippets) {
    getShortcutSnippets(onSuccess, onFailure);
  } else if (action === 'request/GET_STATISTICS') {
    getStatistics(data.html, context, onSuccess, onFailure);
  } else if (action === 'request/POST_EDIT') {
    postEdit(data.editHash, data.action, context);
  } else if (action === 'request/GET_AI_DETECTION_SCORES') {
    getAIDetectionScores(data.html, context, onSuccess, onFailure);
  } else if (action === 'request/GET_TONE') {
    getTone(data.html, context, onSuccess, onFailure);
  } else if (action === 'request/POST_TONE_FEEDBACK') {
    postToneFeedback(data.html, data.toneData, data.textType, data.score, context, onSuccess, onFailure);
  } else if (action === 'request/GET_USER') {
    getUser();
  } else if (action === 'request/POST_DICTIONARY') {
    postDictionary(data.entry);
  }
}

export function sendMessageAsync(message) {
  return new Promise((resolve, reject) => {
    sendMessage(
      message,
      (result) => {
        resolve(result);
      },
      (error) => {
        reject(error);
      },
    );
  });
}

// used to determine if content script has been loaded properly.
// non-response means content script not loaded, and background script
// will attempt to re-inject content script.

function loadSuggestPlugin(plugin) {
  // Messages are JSON-serialized, so plugin will never be a function
  const pluginSrc = typeof plugin === 'string' ? plugin : plugin?.src;
  if (!pluginSrc) {
    return;
  }

  // Try to parse as URL first (without base URL to enforce absolute URLs)
  try {
    const parsed = new URL(pluginSrc);
    if (!['http:', 'https:'].includes(parsed.protocol)) {
      return;
    }
    // For URL-based plugins, we still need to inject as script tag
    // since we can't fetch and eval due to CSP
    const script = document.createElement('script');
    script.src = parsed.href;
    script.async = true;
    document.head.appendChild(script);
  } catch (e) {
    // If URL parsing fails, treat as code string
    // Inject as script tag with textContent to be CSP-compliant
    // This executes in the page context (Main World), not content script context
    const script = document.createElement('script');
    script.textContent = pluginSrc;
    script.async = true;
    // Execute and immediately remove to keep DOM clean
    document.head.appendChild(script);
    script.remove();
  }
}

export function initChromeCommandListener() {
  if (SAPLING_ENV.MODE === 'SDK') {
    return;
  }
  chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
    if (request.action === 'init/CONTENT_SCRIPT_LOADED') {
      initializeObserversPerInput(); // this catches elements that don't bubble focusin events
      sendResponse({ status: true, success: true });
      return false;
    } else if (request.action === 'init/SUGGEST_PLUGIN') {
      // load plugin
      loadSuggestPlugin(request.plugin);
      return false;
    } else if (request.action === 'get-session-id') {
      // Most cases this isn't going to work
      const tabs = $('.sd_primary_tabstrip .x-tab-strip-active .tabText');
      if (tabs.length && !tabs[0].textContent.trim().includes(' ')) {
        sendResponse({ status: true, success: true, sessionId: tabs[0].textContent });
      } else if (document.title.includes('Case: ') && document.title.includes('Console')) {
        sendResponse({ status: true, success: true, sessionId: document.title.split(': ')[1].split(' -')[0] });
      } else {
        sendResponse({ status: true, success: true, sessionId: '' });
      }
      return false;
    }
    return false;
  });
}

export function initKeyboardShortcutMessageListener(listener) {
  if (SAPLING_ENV.MODE === 'SDK') {
    return;
  }
  chrome.runtime.onMessage.addListener(listener);
}
