import _ from 'lodash';
import { getTopFrameHostname } from '../../utils/location';
import { getTone, postToneFeedback } from "../../requests";
import { isToneEnabled } from '../settings';
import { UtilityOverlayCommons } from './utility-overlay-commons';

import { getEkmanTone, getToneColor } from './tone-utils';
import { SAPLING_ENV } from '../../globals';

const TONE_OVERLAY_CSS = `
    .sapling-utility-data-row .tone-feedback {
        display: flex;
        justify-content: space-between;
        width: 60px;
        height: 20px;
    }

    .sapling-utility-data-row.hide-feedback-buttons .tone-feedback {
        display: none;
    }

    .sapling-utility-data-row .tone-feedback.feedback-recorded {
        font-size: 8px;
        text-transform: uppercase;
        text-align: center;
        color: #999;
        line-height: 10px;
    }

    .tone-feedback-button img:hover, .tone-feedback-button img.selected {
        opacity: 0.5;
    }

    .tone-feedback-button img:active {
        opacity: 1;
    }

    .sapling-utility-data-row .tone-name {
        text-transform: capitalize;
    }

    .tone-sentence-feedback.feedback-recorded {
        display: none !important;
    }

    .tone-sentence-feedback {
        right: -4.75em;
        top: 0px;
        display: none;
        width: 74px;
        height: 38px;
        justify-content: space-between;
        background: white;
        padding: 5px;
        border: 2px solid #535f99;
        border-radius: 5px;
        align-items: center;
        box-sizing: border-box;
        flex-direction: column;
        margin-left: 4px;
        padding-top: 3px;
    }

    .tone-sentence-feedback:before {
        content: "";
        position: absolute;
        top: 4px;
        left: 0.9em;
        border-top: 6px solid transparent;
        border-bottom: 6px solid transparent;
        border-right: 6px solid #535f99;
    }

    .tone-sentence-feedback.hide-feedback-buttons {
        justify-content: center;
    }

    .tone-sentence-feedback-title {
        text-transform: uppercase;
        font-size: 8px;
        width: 74px;
        text-align: center;
    }

    .tone-sentence-feedback-button-container {
        display: flex;
        width: 100%;
        justify-content: space-around;
    }

    .hide-feedback-buttons .tone-sentence-feedback-button-container {
        display: none;
    }

    .tone-feedback-button {
        display: flex;
        align-items: center;
    }

    .tone-feedback-button img {
        width: 15px;
        opacity: 0.25;
        cursor: pointer;
        padding: 1px;
    }

    .tone-feedback-button img:hover, .tone-feedback-button img.selected {
        opacity: 0.5;
    }

    .tone-feedback-button img:active {
        opacity: 1;
    }
`

export class ToneOverlay extends UtilityOverlayCommons {
    constructor(shadowHost, containerId, badge) {
        super(shadowHost, containerId, badge);
        this.topTone = null;
        this.toneData = null;
        this.feedbackDisplayClass = SAPLING_ENV.MODE === 'SDK' && !Sapling.toneFeedbackEnabled
            ? 'hide-feedback-buttons'
            : '';
    }

    utilityName() {
        return 'Tone';
    }

    utilityCSS() {
        return `${TONE_OVERLAY_CSS}`;
    }

    isBeta() {
        return false;
    }

    isUtilityEnabled() {
        return isToneEnabled();
    }

    getUtilityData(queryText, lang, containerId, onSuccess, onError) {
        getTone(
            queryText,
            lang,
            containerId,
            (data) => {
                this.toneData = data.tone;
                onSuccess(data);
            },
            (err) => {
                onError(err);
            }
        );
    }

    _updateToneHud(overallTones, results) {
        let hudEmoji = null, hudWarning = null, hudTitle;

        if (overallTones.length > 0) {
            this.topTone = overallTones[0];

            if (this.topTone[1].toLowerCase() !== 'neutral') {
                hudEmoji = `<span style="padding-top: 0.1rem;">${this.topTone[2]}</span>`;
            }
        }

        for (let sentenceTones of results) {
            const topSentenceTone = sentenceTones[0];
            if (getEkmanTone(topSentenceTone[1]) === 'anger') {
                hudTitle = "Angry sentence detected";
                hudWarning = `
                    <div style="margin-left: 3px; transform: rotate(10deg); padding-top: 0.15rem;">
                        <svg fill="red" height="1em" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 512"><!--! Font Awesome Pro 6.4.0 by @fontawesome - https://fontawesome.com License - https://fontawesome.com/license (Commercial License) Copyright 2023 Fonticons, Inc. --><path d="M64 64c0-17.7-14.3-32-32-32S0 46.3 0 64V320c0 17.7 14.3 32 32 32s32-14.3 32-32V64zM32 480a40 40 0 1 0 0-80 40 40 0 1 0 0 80z"/></svg>
                    </div>
                `;
            }
        }

        this.updateHud({hudEmoji, hudWarning, hudTitle});
    }

    createUIElements() {
        super.createUIElements();

        $(this.utilityOverlay).on('click', '.tone-feedback-button img', (event) => {
            const target = $(event.target);
            const isSelected = $(target).is('.selected');
            $(target).parents('.tone-feedback').find('img').removeClass('selected');
            if (!isSelected) {
                $(target).addClass('selected');
            }
            const toneDataRow = JSON.parse($(target).parents('.sapling-tone-data-row').attr('data-tone'));
            const score = $(target).is('.thumbs-up') ? 1 : -1;
            postToneFeedback(
                this.lastQueryText, toneDataRow, 'overall', score, this.containerId,
                (success) => {
                    $(target).parents('.tone-feedback')
                        .addClass('feedback-recorded')
                        .html('Feedback recorded');
                },
                (err) => {
                    $(target).parents('.tone-feedback')
                        .addClass('feedback-recorded')
                        .html('Feedback recorded');

                    // We should log an error, but lets not confuse the user
                },
            );
        });
    }

    renderUtilityData() {
        const tone = this.toneData;
        const contentEl = this.queryEl;

        if (!tone || !contentEl) {
            return;
        }

        const { overall, sents, results } = tone;
        if (!overall) {
            return;
        }

        // Don't show values below 5%
        const overallTones = overall.filter(toneData => toneData[0] > 0.05)
            .sort((a, b) => b[0] - a[0]);

        this._updateToneHud(overallTones, results);

        let htmlContent = '';
        for (let tone of overallTones) {
            const percentage = Math.round(tone[0] * 100 / 5) * 5;
            htmlContent += `
                <div class="sapling-utility-data-row ${this.feedbackDisplayClass}" data-tone='${JSON.stringify(tone)}'>
                    <div>
                        <span class="tone-emoji">${tone[2]}</span>
                        <span class="tone-name">${tone[1]} -</span>
                        <span class="tone-percentage">${percentage}%</span>
                    </div>
                    <div class="tone-feedback">
                        <span class="tone-feedback-button"><img class="thumbs-up" src="${this.assetUrls['thumbs-up-regular']}" /></span>
                        <span class="tone-feedback-button"><img class="thumbs-down" src="${this.assetUrls['thumbs-down-regular']}" /></span>
                    </div>
                </div>
            `;
        }
        $(this.utilityOverlay).find('.sapling-utility-data').html(htmlContent);

        // Render per-sentence results
        this.updateSentenceOverlayPosition();
        const shadowHostBox = this.shadowHost.getBoundingClientRect();
        const sentenceToneContainer = document.createElement('sapling-sentence-tones');

        const textNodes = [];
        this.getTextNodes(contentEl, textNodes);
        const ranges = this._getRanges(sents, textNodes);

        for (let i=0; i<ranges.length; i++) {
            const {
                startingTextIndex,
                startingOffset,
                endingTextIndex,
                endingOffset,
                sentenceIndex,
            } = ranges[i];

            const sentence = sents[sentenceIndex];

            const extraLeftPadding = sentence.slice(-1) === '.' ? 5 : 0;
            const lowerEmojiTop = getTopFrameHostname().includes('zendesk') ? 8 : 0;

            const range = document.createRange();
            range.setStart(textNodes[startingTextIndex].node, startingOffset);
            range.setEnd(textNodes[endingTextIndex].node, endingOffset);
            const rects = range.getClientRects();

            // Add the tone emoji to the top-right of the sentence
            const lastRect = rects.item(rects.length - 1);
            if (lastRect == null) {
                continue;
            }

            const toneEmoji = document.createElement('div');
            $(toneEmoji).css({
                position: 'absolute',
                pointerEvents: 'auto',
                left: `${lastRect.x - shadowHostBox.x + lastRect.width - extraLeftPadding}px`,
                top: `${lastRect.y - shadowHostBox.y - 10 + lowerEmojiTop}px`,
                width: `20px`,
                height: `20px`,
                cursor: 'pointer',
                opacity: 0.5,
                display: 'flex',
            });
            $(toneEmoji).attr('data-sentence', sentence);
            $(toneEmoji).attr('data-tone', JSON.stringify(results[i][0]));
            toneEmoji.innerHTML = `
                ${results[i][0][2]}
                <div class="tone-sentence-feedback ${this.feedbackDisplayClass}">
                    <div class="tone-sentence-feedback-title">${results[i][0][1]}</div>
                    <div class="tone-sentence-feedback-button-container">
                        <div class="tone-feedback-button"><img class="thumbs-up" src="${this.assetUrls['thumbs-up-regular']}" /></div>
                        <div class="tone-feedback-button"><img class="thumbs-down" src="${this.assetUrls['thumbs-down-regular']}" /></div>
                    </div>
                </div>
            `;
            toneEmoji.rects = [];

            // clientRects was giving duplicates,
            // haven't been able to root-cause why yet
            const seenRects = {};

            for (let rect of rects) {
                if (seenRects.hasOwnProperty(JSON.stringify(rect))) {
                    continue;
                }
                seenRects[JSON.stringify(rect)] = 1;

                const backgroundColor = getToneColor(results[i][0][1].toLowerCase());

                const div = document.createElement('div');
                $(div).css({
                    position: 'absolute',
                    left: `${rect.x - shadowHostBox.x - 1}px`,
                    top: `${rect.y - shadowHostBox.y - 1}px`,
                    width: `${rect.width + 2}px`,
                    height: `${rect.height + 2}px`,
                    backgroundColor,
                    border: '1px solid black',
                    borderRadius: '5px',
                    cursor: 'pointer',
                    opacity: 0.1,
                });
                $(sentenceToneContainer).append(div);
                toneEmoji.rects.push(div);
            }
            $(sentenceToneContainer).append(toneEmoji);
            toneEmoji.addEventListener('mouseenter', () => {
                $(toneEmoji).css({opacity: 1});
                $(toneEmoji).find('.tone-sentence-feedback').css({display: 'flex'});
                toneEmoji.rects.forEach(rect => rect.style.opacity = 0.25);
            });
            toneEmoji.addEventListener('mouseleave', () => {
                $(toneEmoji).css({opacity: 0.75});
                $(toneEmoji).find('.tone-sentence-feedback').css({display: 'none'});
                toneEmoji.rects.forEach(rect => rect.style.opacity = 0.1);
            });
            $(toneEmoji).on('click', '.tone-feedback-button img', (event) => {
                const target = $(event.target);
                const isSelected = $(target).is('.selected');
                $(target).parents('.tone-sentence-feedback').find('img').removeClass('selected');
                if (!isSelected) {
                    $(target).addClass('selected');
                }
                const toneDataRow = JSON.parse($(toneEmoji).attr('data-tone'));
                const score = $(target).is('.thumbs-up') ? 1 : -1;
                postToneFeedback(
                    sentence, toneDataRow, 'sentence', score, this.containerId,
                    (success) => {
                        $(target).parents('.tone-sentence-feedback').addClass('feedback-recorded');
                    },
                    (err) => {
                        $(target).parents('.tone-sentence-feedback').addClass('feedback-recorded');
                    },
                )
            });
        }

        $(this.sentenceOverlays).html(`<style>${TONE_OVERLAY_CSS}</style>`);
        $(this.sentenceOverlays).append(sentenceToneContainer);
    }

    getTopTone() {
        return this.topTone;
    }
}
