import { replaceTextAreaSelection } from '../../ui/highlight/textarea';
import {
  getTextAreaId,
} from '../../utils/html-utils';



// Defaults to SFDC settings

export function observeChatEvents(chatObserver, contentMutationCfg, callback) {
  chatObserver.observe($("#chatLog")[0], contentMutationCfg);
  chatObserver.observe($("#chatTextArea")[0], contentMutationCfg);
  if (callback) callback();
}

export function injectChatUI() {
  let shadowHost;
  if ($('sapling-chat-controls').length === 0) {
    shadowHost = document.createElement('sapling-chat-controls');
    shadowHost.attachShadow({mode: 'open'});

    $('#chatInput').after(shadowHost);

  } else {
    shadowHost = $('sapling-chat-controls')[0];
  }
  let shadowRoot = shadowHost.shadowRoot;

  if ($('.sapling-chat-container', shadowRoot)[0]) {
    return;
  }

  // inject css
  $(shadowRoot).prepend($(`
<style type="text/css">
.sapling-chat-container{
}
.sapling-chat-suggestion{
  width: 305px;
  margin: 5px;
  border: 1px solid rgba(82, 95, 153, 0.8);
  color: rgba(82, 95, 153, 0.8);
  background-color: #fff;
  border-radius: 5px;
  padding-left: 10px;
  padding-right: 10px;
  padding-top: 5px;
  padding-bottom: 5px;
  user-select: none;
  font-family: Helvetica, Arial, sans-serif;
  font-size: 12px;
  transition: all .15s ease;
}
.sapling-chat-suggestion:hover {
  transform: translateY(-1px);
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.32);
}
.sapling-chat-suggestion:active {
  transform: translateY(0px);
  background-color: rgba(82, 95, 153, 0.5);
}
.sapling-chat-suggestion .sapling-suggestion-send img {
  z-index: 10;
  width: 20px;
  height: 20px;
  position: absolute;
  top: 0px; right: 0px;
  padding-top: 5px; padding-right: 5px;
  color: rgba(82, 95, 153, 0.8);
  visibility: hidden;
}
.sapling-chat-suggestion:hover .sapling-suggestion-send img {
  visibility: visible;
}
</style>`));

  // inject html
  $(shadowRoot).append($(`
<div class='sapling-chat-container'>
</div>
`));
}

export function getLastClientChatMessages(updateFunc) {
  let messages = $('#chatLog div');
  let lastClientMessages = [];
  for (let i = 0; i < messages.length; i += 1) {
    let messageNode = $(messages[i]);
    if (messageNode.hasClass('agentMessage')) {
    } else if (messageNode.hasClass('chasitorMessage')){
      let messageText = $('.messageText', messageNode).text();
      if (!messageText) {
        // fallback on whole node (has timestamp)
        messageText = messageNode.text();
      }
      lastClientMessages.push(messageText);
      if (updateFunc) {
        $(messageNode).off('click');
        $(messageNode).css('cursor', 'pointer');
        $(messageNode).on('click', () => updateFunc(messageText))
      }
    }
  }
  return lastClientMessages;
}

export function injectChatResponse(text, textChangedCB) {
  replaceTextAreaSelection($('#chatTextArea')[0], 0, 0, text);
  try {
    $('#chatInputSend').click();
  } catch (e) {
  }

  // update textarea to prevent lingering edit tags
  let textAreaId = getTextAreaId($('#chatTextArea'));
  textChangedCB(textAreaId, $('#chatTextArea')[0].value);
}

export function editChatResponse(text) {
  replaceTextAreaSelection($('#chatTextArea')[0], 0, 0, text);
}

export function shouldInitializeChatObserver() {
  if (!location.hostname.endsWith('salesforce.com')) {
    return false;
  } else if (location.pathname !== '/liveagent/chatlog.apexp') {
    return false;
  } else if (!$("#chatLog")[0]) {
    return false;
  }
  return true;
}

export function getContext() {
  if (!$('#chatTextArea')[0]) return '';
  return { 'sessionId': getTextAreaId($('#chatTextArea')) };
}
