import regexCreator from 'emoji-regex';
import { v4 as uuid } from 'uuid';

import { getTopFrameHostname } from './location';

const EMOJI_REGEX = regexCreator();

function replacer(match) {
  // p1 is nondigits, p2 digits, and p3 non-alphanumerics
  return ' '.repeat(match.length);
}

export function cleanse(str) {
  // character code 160 is "non-breaking space" looks like whitespace
  const newStr = str.replace(/\u00A0/g, ' ')
    .replace(/\u200B/g, ' ')
    .replace(/\u00A9/g, ' ')
    .replace(/\u00AE/g, ' ')
    .replace(/&nbsp;/g, ' ');
  return newStr.replace(EMOJI_REGEX, replacer);
}

export function splitHTMLToSentences(str) {
  // This is a rough heuristic for splitting up html by sentence.
  return str.replace(/([.?!]+)/g, '$1|||').split('|||');
}

export function isScrollable(element) {
  return $(element).css('overflow-y') === 'scroll' ||
    $(element).css('overflow-y') === 'auto' ||
    $(element).is('textarea') ||
    getTextAreaId(element);
}

// Finds first scrollable parent
export function getScrollableParent(editable) {
  if (isScrollable(editable)) {
    return editable;
  }

  const parents = $(editable).parentsUntil('body');
  for (let k = 0; k < parents.length; k += 1) {
    const parent = parents[k];
    if (isScrollable(parent)) {
      return parent;
    }
  }
  return null;
}

// Finds all scrollable parents
export function getScrollableParents(editable) {
  let scrollableParents = [];

  // conservatively add scroll observer to editable even if it doesn't currently scroll
  scrollableParents.push(editable);

  const parents = $(editable).parentsUntil('body');
  for (let k = 0; k < parents.length; k += 1) {
    const parent = parents[k];
    if (isScrollable(parent)) {
      scrollableParents.push(parent);
      // return parent;
    }
  }
  return scrollableParents;
}

// Finds region of edit elem that is visible within scrolling window
export function getVisibleEditElem(el) {
  let visibleArea = el;
  const parents = $(el).parentsUntil('body');
  let minHeight = el.clientHeight;
  let minWidth = el.clientWidth;

  for (let k = 0; k < parents.length; k += 1) {
    const parent = parents[k];
    const width = parent.clientWidth;
    const height = parent.clientHeight;
    if (width === 0 || height === 0) {
      continue;
    }
    if (height < minHeight || width < minWidth) {
      minHeight = height;
      minWidth = width;
      visibleArea = parent;
    }
    const positionType = window.getComputedStyle(parent).position;
    if (positionType === 'absolute') {
      break;
    }
  }
  return visibleArea;
}

// Given element e, compute min(dim(e), dim(parent(e)), dim(parent(parent(e)))), etc.
export function getContainingDims(el) {
  return {
    height: el.clientHeight,
    width: el.clientWidth,
  };
}

export function getBounds(parentContainer) {
  const visibleEditElem = getVisibleEditElem(parentContainer);
  const dims = getContainingDims(visibleEditElem);
  const offset = $(visibleEditElem).offset();
  return {
    top: offset.top,
    bottom: offset.top + dims.height,
    left: offset.left,
    right: offset.left + dims.width,
  };
}

export function nextDomElement(domElement, parentContainer, includeChild = true) {
  // parentContainer = null means we don't consider bounds
  const retDomElement = domElement;
  if (retDomElement.firstChild && includeChild) {
    return retDomElement.firstChild;
  }
  if (retDomElement.nextSibling) {
    return retDomElement.nextSibling;
  }

  // go back up to parent level and inspect sibling
  // guard against tempParent becoming null when reaching the document root (SAPLING-WEBSITE-2CA)
  let tempParent = retDomElement.parentNode;
  while (tempParent !== null && (parentContainer === null || tempParent !== parentContainer)) {
    if (tempParent.nextSibling) {
      return tempParent.nextSibling;
    }
    tempParent = tempParent.parentNode;
  }

  return null;
}

function excludeElementChild(domElement) {
  if (domElement.tagName) {
    return ['script', 'style', 'xml'].includes(domElement.tagName.toLowerCase());
  }

  return false;
}

export function getLocationFromOffset(
  startNode, startIndexSum, textOffset,
  endNode, includeBreaks = false, prioritizeLast = true,
) {
  // startNode = where we start crawling
  // startIndexSum = sum of length of text before startNode
  // offset we are searching for, from beginning of container
  // endNode = node at which we terminate searching
  // prioritizeLast = we prefer prioritizing the last dom element over the first if index on edge
  if (startIndexSum > textOffset) {
    return null;
  }
  let domElement = startNode;
  let indexSum = startIndexSum;
  while (domElement !== null) {
    if (includeBreaks && $(domElement).is('br')) {
      if (textOffset === indexSum) {
        return {
          domElement,
          indexSum,
          domOffset: indexSum,
        };
      }
    } else if (domElement.nodeType === Node.TEXT_NODE) {
      const domLength = domElement.data.length;
      const domOffset = textOffset - indexSum;
      if (domOffset < domLength || (prioritizeLast && domOffset === domLength)) {
        return {
          domElement,
          domOffset,
          indexSum,
        };
      }
      indexSum += domLength;
    }

    domElement = nextDomElement(domElement, endNode, !excludeElementChild(domElement));
  }

  return null;
}

export function getOffsetfromLocation(parent, node, offset) {
  let domElement = parent;
  let indexSum = 0;
  while (domElement !== null) {
    if (domElement === node) {
      return indexSum + offset;
    } else if (domElement.nodeType === Node.TEXT_NODE) {
      const domLength = domElement.data.length;
      indexSum += domLength;
    }
    domElement = nextDomElement(domElement, parent, !excludeElementChild(domElement));
  }
  return null;
}

export function getRangeAsOffsets(parent, range) {
  if (!range) {
    return null;
  }
  let startOffset = getOffsetfromLocation(parent, range.startContainer, range.startOffset);
  let endOffset = getOffsetfromLocation(parent, range.endContainer, range.endOffset);
  if (startOffset === null || endOffset === null) {
    return null;
  }
  return [startOffset, endOffset];
}

function getFirstParentNotStatic(domElement) {
  let parentElementTemp = domElement.parentElement;
  while (parentElementTemp !== null) {
    if (getComputedStyle(parentElementTemp).position !== 'static') {
      return parentElementTemp;
    }
    parentElementTemp = parentElementTemp.parentElement;
  }

  return null;
}

export function getCSSOverlayForElement(domElement) {
  const { position, top, left, height, width } = getComputedStyle(domElement);
  // This is more robust and won't return something like top: auto
  const coords = domElement.getBoundingClientRect();
  let frameDimensions = {
    position,
    left: coords.left,
    top: coords.top,
    height: coords.height,
    width: coords.width,
  };
  if (position === 'static' || position === 'relative') {
    frameDimensions.position = 'absolute';
  }

  if (position === 'absolute') {
    frameDimensions = {
      position,
      top: parseInt(top, 10),
      left: parseInt(left, 10),
      height: parseInt(height, 10),
      width: parseInt(width, 10),
    };
  }

  // hack: some websites get a scrollbar from the sapling overlay.
  // is the bounding client rect wrong?
  // TODO Unsure this is necessary anymore
  const hostname = getTopFrameHostname();
  if (hostname.endsWith('messenger.com') ||
      hostname.endsWith('twitter.com') ||
      hostname.endsWith('workplaceoptions.com')) {
    frameDimensions.left -= 1;
  }

  const nonstaticParent = getFirstParentNotStatic(domElement);
  if (position === 'absolute') {
    return { frameDimensions, nonstaticParent };
  }

  if (nonstaticParent) {
    const nonstaticParentRect = nonstaticParent.getBoundingClientRect();
    frameDimensions.left -= (nonstaticParentRect.left - (nonstaticParent.scrollLeft || 0));
    frameDimensions.top -= (nonstaticParentRect.top - (nonstaticParent.scrollTop || 0));
  } else {
    // need to handle whole page scroll
    let doc = domElement.ownerDocument;
    let elementWindow = doc.defaultView || doc.parentWindow;
    const { pageXOffset, pageYOffset } = elementWindow;
    if (pageXOffset !== undefined) {
      frameDimensions.top += pageYOffset;
    }
    if (pageYOffset !== undefined) {
      frameDimensions.top += pageXOffset;
    }
  }

  return { frameDimensions, nonstaticParent };
}

export function isPSPDFKitElement(el) {
  return $(el).is('[class*="PSPDFKit"]');
}
export function isTinyMCEElement(el) {
  return $(el).is('[class*="mce-content-body"]');
}

export function isSlateElement(el) {
  const hostname = getTopFrameHostname();
  if (hostname.includes('gladly.')) {
    return false;
  }
  let res = el.getAttribute('data-slate-editor') === 'true' ||
    $('[data-slate-leaf]', el).length > 0;
  return res;
}

export function isCKElement(el) {
  if (el.className.includes('ck-editor')) return true;
  return false;
}

export function isDraftJSElement(el) {
  let attributeClasses = el.getAttribute('class');
  if (attributeClasses && attributeClasses.includes('DraftEditor')) {
    return true;
  }
  return false;
}

export function isLexicalElement(el) {
  let lexicalAttribute = el.getAttribute('data-lexical-editor');
  if (lexicalAttribute) {
    return true;
  }
  return false;
}

export function isQuillJSEditor(el) {
  let attributeClasses = el.getAttribute('class');
  return attributeClasses && attributeClasses.includes('ql-editor');
}

export function isCodeMirrorElement(textarea) {
  if (!textarea || !textarea.parentElement || !textarea.parentElement.parentElement) {
    return false;
  }
  return textarea.parentElement.parentElement.classList.contains('CodeMirror');
}

export function isTextInput(el) {
  const tagName = el.tagName.toLowerCase();
  return (tagName === 'input' || tagName === 'lightning-input-field') &&
    el.getAttribute('type').toLowerCase() === 'text';
}

export function getContainerId(elem) {
  return $(elem).attr('sapling-id') || $(elem).data('sapling-id');
}

export function setContainerId(elem, containerId) {
  if (!containerId) {
    containerId = uuid();
  }
  $(elem).attr('sapling-id', containerId);
  $(elem).data('sapling-id', containerId);
  return containerId;
}

export function getTextAreaId(elem) {
  return $(elem).attr('sapling-textarea-id') || $(elem).data('sapling-textarea-id');
}

export function setTextAreaId(elem, textAreaId) {
  if (!textAreaId) {
    textAreaId = uuid();
  }
  $(elem).attr('sapling-textarea-id', textAreaId);
  $(elem).data('sapling-textarea-id', textAreaId);
  return textAreaId;
}

export function getEffectiveZIndex(node) {
  try {
    let zIndex = getComputedStyle(node).zIndex;

    // If the computed z-index is "auto", get the parent element's z-index
    if (isNaN(zIndex)) {
      return getEffectiveZIndex(node.parentElement);
    }

    return parseInt(zIndex);
  } catch (_) {
    return 0;
  }
}

export function percentToRGB(percent) {
  if (percent < 0) {
    return "rgb(0,0,0)";
  }

  let red, green;
  if (percent <= 50) {
      red = Math.floor(225 * percent / 50);
      green = 225;
  } else {
      red = 225;
      green = Math.floor(225 * (100 - percent) / 50);
  }
  return "rgb(" + red + "," + green + ",0)";
}

export function copyToClipboard(s) {
  function listener(e) {
    e.clipboardData.setData("text/html", s);
    e.clipboardData.setData("text/plain", s);
    e.preventDefault();
  }
  document.addEventListener("copy", listener);
  document.execCommand("copy");
  document.removeEventListener("copy", listener);
}
