import { SAPLING_ENV } from '../globals';

const Url = require('url-parse');

let AUTH_TOKENS = null;
let IS_FETCHING_TOKEN = false;
let TOKEN_SUCCESS_CALLBACKS = [];
let TOKEN_FAILURE_CALLBACKS = [];
let IS_FETCHING_AUTH_TOKEN = false;
let AUTH_TOKEN_CALLBACKS = [];

export function queryParams(params) {
  let array = [];
  for (const [key, value] of Object.entries(params)) {
    array.push(`${encodeURIComponent(key)}=${encodeURIComponent(value)}`);
  }
  return array.join('&');
}

export function setCustomEndpointsPromise() {
  return new Promise((resolve) => {
    if (SAPLING_CONFIGURABLE_ENDPOINT) {
      chrome.storage.local.get(['apiURL', 'websiteURL'], (obj) => {
        const { apiURL, websiteURL } = obj;
        if (apiURL) {
          SAPLING_ENV.API_URL = apiURL;
          let parsedApiURL = new Url(apiURL);
          SAPLING_ENV.API_HOSTNAME = parsedApiURL.hostname;
        }
        if (websiteURL) {
          let parsedWebsiteURL = new Url(websiteURL);
          SAPLING_ENV.WEBSITE_URL = websiteURL;
          SAPLING_ENV.WEBSITE_HOSTNAME = parsedWebsiteURL.hostname;
        }
        resolve();
      });
    } else {
      resolve();
    }
  });
}

export function sendBackendRequest(
  path,
  type,
  requestData = {},
  headers = {},
  onSuccess = null,
  onFailure = null,
  timeout = null,
) {
  // path: /users
  // type: POST

  let initOptions = {
    method: type,
    credentials: 'include',
    headers,
  };

  if (timeout) {
    initOptions.signal = AbortSignal.timeout(timeout);
  }

  if (Object.keys(requestData).length !== 0 || type !== 'get') {
    initOptions.headers['Content-Type'] = 'application/json';
    initOptions.body = JSON.stringify(requestData);
  }
  fetch(
    `${SAPLING_ENV.API_URL}${path}`,
    initOptions,
  ).then((response) => {
    if (!response.ok && onFailure) {
      onFailure(response);
      return null;
    }
    return response.json();
  }).then((data) => {
    if (!data) {
      return;
    }
    if (onSuccess) {
      onSuccess(data);
    }
  }).catch((error) => {
    console.log('error: ', error);
    if (onFailure) {
      onFailure(error);
    }
  });
}

export function setRefreshToken(authTokens) {
  AUTH_TOKENS = authTokens;
  chrome.storage.local.set({ authTokens });
}

function refetchAccessToken() {
  if (IS_FETCHING_TOKEN) {
    return;
  }
  IS_FETCHING_TOKEN = true;
  sendBackendRequest(
    '/auth/login',
    'post',
    {},
    {},
    (authData) => {
      IS_FETCHING_TOKEN = false;
      const authTokens = {
        refreshToken: authData.refresh_token,
        accessToken: authData.access_token,
      };
      setRefreshToken(authTokens);
      for (let idx = 0; idx < TOKEN_SUCCESS_CALLBACKS.length; idx += 1) {
        const callback = TOKEN_SUCCESS_CALLBACKS[idx];
        callback(authTokens.accessToken);
      }
      TOKEN_SUCCESS_CALLBACKS = [];
    },
    (error) => {
      IS_FETCHING_TOKEN = false;
      for (let idx = 0; idx < TOKEN_FAILURE_CALLBACKS.length; idx += 1) {
        const callback = TOKEN_FAILURE_CALLBACKS[idx];
        callback(error);
      }
      TOKEN_FAILURE_CALLBACKS = [];
    },
  );
}

function fetchAccessToken(onSuccess, onFailure) {
  if (AUTH_TOKENS) {
    onSuccess(AUTH_TOKENS.accessToken);
    return;
  }
  chrome.storage.local.get('authTokens', (data) => {
    if (data && data.authTokens) {
      AUTH_TOKENS = data.authTokens;
      onSuccess(AUTH_TOKENS.accessToken);
      return;
    }

    TOKEN_SUCCESS_CALLBACKS.push(onSuccess);
    TOKEN_FAILURE_CALLBACKS.push(onFailure);
    refetchAccessToken();
  });
}

function getRefreshToken() {
  if (AUTH_TOKENS) {
    return AUTH_TOKENS.refreshToken;
  }

  return null;
}

export function clearRefreshToken() {
  chrome.storage.local.remove('authTokens');
  if (AUTH_TOKENS) {
    AUTH_TOKENS = null;
  }
}

export function sendAuthenticatedBackendRequest(
  path,
  type,
  requestData = {},
  onSuccess = null,
  onFailure = null,
  fetchNewRefreshToken = true,
  timeout = null,
) {
  fetchAccessToken((accessToken) => {
    const headers = {};
    headers.Authorization = `Bearer ${accessToken}`;
    sendBackendRequest(path, type, requestData, headers, onSuccess, (error) => {
      const refreshToken = getRefreshToken();
      if (error.status === 401 && refreshToken && fetchNewRefreshToken) {
        AUTH_TOKEN_CALLBACKS.push(() => {
          sendAuthenticatedBackendRequest(path, type, requestData, onSuccess, onFailure, false, timeout);
        });
        if (!IS_FETCHING_AUTH_TOKEN) {
          // try to get a new access token, then retry same request.
          const refreshHeaders = {
            Authorization: `Bearer ${refreshToken}`,
          };
          IS_FETCHING_AUTH_TOKEN = true;
          sendBackendRequest(
            '/auth/refresh',
            'post',
            {},
            refreshHeaders,
            (data) => {
              AUTH_TOKENS.accessToken = data.access_token;
              chrome.storage.local.set({ authTokens: AUTH_TOKENS });
              for (let idx = 0; idx < AUTH_TOKEN_CALLBACKS.length; idx += 1) {
                const callback = AUTH_TOKEN_CALLBACKS[idx];
                callback();
              }
              IS_FETCHING_AUTH_TOKEN = false;
              AUTH_TOKEN_CALLBACKS = [];
            },
            (err) => {
              IS_FETCHING_AUTH_TOKEN = false;
              if (err.status === 422 || err.status === 401) {
                clearRefreshToken();
                sendAuthenticatedBackendRequest(path, type, requestData, onSuccess, onFailure, false, timeout);
              } else {
                if (!onFailure) {
                  return;
                }
                onFailure(err);
              }
            },
            timeout,
          );
        }
      } else if (error.status === 422) {
        clearRefreshToken();
        sendAuthenticatedBackendRequest(path, type, requestData, onSuccess, onFailure, false, timeout);
      } else {
        if (!onFailure) {
          return;
        }
        onFailure(error);
      }
    }, timeout);
  }, (error) => {
    if (!onFailure) {
      return;
    }
    onFailure(error);
  });
}
