import {
  cacheFocus,
  focusEquals,
  getCaretCoord,
  insertTextAtCaret,
  insertTextAtCaret2,
} from '../utils/caret-utils';
import { copyTextFormat } from '../ui/format';
import { getCompleteShortcut } from '../ui/settings';
import { postCompletion } from '../requests/index';
import {
  getContainerId,
  getScrollableParent,
  isSlateElement,
  isCKElement,
} from '../utils/html-utils';
import { getTopFrameHostname } from '../utils/location';

let shadowDom = null;
let currentCompletionQuery = '';
let completionModelVersion = '';
let focusOnShowComplete = null;

export function maybeEmbedSaplingComplete() {
  if ($('sapling-complete').length) {
    return;
  }
  let saplingComplete = $('<sapling-complete></sapling-complete>');
  saplingComplete.css({display:'inline', width:0, height:0});
  let shadowHost = saplingComplete[0];
  shadowHost.attachShadow({ mode: 'open' });
  shadowDom = shadowHost.shadowRoot;
  $('html').append(saplingComplete);
}

export function clearAndHideComplete() {
  if (!$('sapling-complete').length) return;
  // Thinking will be less disruptive than display
  shadowDom = $('sapling-complete')[0].shadowRoot;
  $('#sapling-complete-div-box', shadowDom).css('visibility', 'hidden');
  $(shadowDom).text('');
  focusOnShowComplete = null;
}

function getLinesAndOffset(editable) {
  let lines = [];
  let offset = 0;
  if (editable.nodeName === 'TEXTAREA') {
    lines = editable.value.split('\n');
    offset = editable.selectionEnd;
  } else {
    // Sometimes editable no longer editable
    if (typeof editable.getRootNode().getSelection !== 'function') return [lines, offset];
    // This only grabs current div/p
    let sel = editable.getRootNode().getSelection();
    let anchor = sel.anchorNode;
    if (!anchor) {
      return [lines, offset];
    }
    lines = anchor.textContent.split('\n');
    offset = sel.focusOffset;
  }
  return [lines, offset];
}

export function completeMidLine(editable) {
  const [lines, offset] = getLinesAndOffset(editable);
  let lineStart = 0;
  for (let k = 0; k < lines.length; k++) {
    let lineEnd = lineStart + lines[k].length;
    if (lineStart <= offset && lineEnd > offset) {
      return true;
    }
    lineStart = lineEnd + 1;
  }
  return false;
}

export function getCompleteQueryText(editable) {
  const LINE_DELIM = '   ';
  const [lines, offset] = getLinesAndOffset(editable);
  let start = 0;
  let queryText = '';
  for (let k = 0; k < lines.length; k++) {
    if (queryText !== '') {
      queryText += LINE_DELIM + lines[k];
    } else {
      queryText = lines[k];
    }
    if (start + lines[k].length >= offset) return queryText;
    start += lines[k].length + 1;
  }
  return '';
}

function getCompletionHash() {
  try {
    shadowDom = $('sapling-complete')[0].shadowRoot;
    return $(shadowDom).find('span').first().attr('completion-hash');
  } catch (err) {
    return '';
  }
}

function tempLockScroll(f, editable) {
  // Lock scroll while calling function f
  let scrollable = getScrollableParent(editable);
  if (scrollable === null) {
    f();
    return;
  }

  let hostname = getTopFrameHostname();

  const of = $(scrollable).css('overflow');
  $(scrollable).css('overflow', 'hidden');

  // TODO Unsure this is necessary anymore
  if (hostname === 'messenger.com' || hostname === 'facebook.com') {
    $('html').attr('style', 'overflow: hidden !important;');
  }

  f();
  $(scrollable).css('overflow', of);
  if (hostname === 'facebook.com') {
    $('html').attr('style', '');
  }
}

// This fn is called w/ and w/o completionData and so has to work with both
// Two cases when called w/o are shiftCompletion and onResize
export function showComplete(editable, text, completionData) {
  if (text === '') {
    clearAndHideComplete();
    return;
  }

  let completionHash = getCompletionHash();
  if (completionData && ('query' in completionData)) {
    currentCompletionQuery = completionData.query;
    completionModelVersion = completionData.model_version;
    completionHash = completionData.hash;
  }

  let saplingComplete = $('sapling-complete');
  shadowDom = saplingComplete[0].shadowRoot;

  const styling = `
  <style type="text/css">
  #sapling-complete-div {
    margin: 0;
    padding: 0;

    white-space: nowrap;
    text-overflow: ellipsis;
    overflow: hidden;

    color: #3f51b5;
    opacity: 0.5;

    -webkit-user-select: none; /* Safari */
    -moz-user-select: none; /* Firefox */
    -ms-user-select: none; /* IE10+/Edge */
    user-select: none; /* Standard */
  }
  #sapling-complete-div-box {
    z-index: 2147483647 !important;
    display: table;
    margin: 0;
    padding: 0;
  }
  </style>
  `;

  let completeShortcut = getCompleteShortcut();
  if (!completeShortcut) completeShortcut = '`';
  const reminder = `<span title="Hit the backtick or tab key to use Sapling\'s completion." style="margin-left: 1em; background: #ccc; font-weight: 500; border-radius: 0.2em; line-height: 0.6em; padding: 0 0.4em 0 0.3em;">${completeShortcut}</span>`;
  shadowDom.innerHTML = styling + `<div id="sapling-complete-div-box"><div id="sapling-complete-div"><span completion-hash="${completionHash}">${text.replace(' ', '&nbsp;')}</span>${reminder}</div></div>`;

  let saplingCompleteDiv = $('#sapling-complete-div', shadowDom);

  let coord = getCaretCoord(editable);
  if (coord === undefined) {
    return;
  }
  focusOnShowComplete = cacheFocus(editable);
  if (editable.nodeName === 'TEXTAREA') {
    copyTextFormat(editable, saplingCompleteDiv[0]);
  } else {
    let { anchorNode } = editable.getRootNode().getSelection();
    while (anchorNode.nodeType === Node.TEXT_NODE) {
      anchorNode = anchorNode.parentNode;
    }
    copyTextFormat(anchorNode, saplingCompleteDiv[0]);
  }

  let saplingCompleteDivBox = $('#sapling-complete-div-box', shadowDom);
  saplingCompleteDivBox.offset({ top: coord.top + window.scrollY, left: coord.left + window.scrollX });

  // Set max-width depending on size of editable
  let editableRect = editable.getBoundingClientRect();
  let overflow = saplingCompleteDivBox.offset().left + saplingCompleteDivBox.width() - (editableRect.left + editableRect.width);
  if (overflow > 0) {
    saplingCompleteDiv.css('max-width', saplingCompleteDivBox.width() - overflow);
  } else {
    saplingCompleteDiv.css('max-width', '');
  }

  tempLockScroll(() => { saplingCompleteDivBox.css('visibility', 'visible'); }, editable);
}

export function getCompletionString() {
  try {
    shadowDom = $('sapling-complete')[0].shadowRoot;
  } catch (err) {
    return '';
  }
  // Non-breaking spaces
  return $(shadowDom).find('span').first().text().replace(/\u00A0/g, ' ');
}

export function shiftCompletion(editable) {
  showComplete(editable, getCompletionString().substring(1));
}

export function tabComplete(e, block) {
  let { key } = e;

  let completeShortcut = getCompleteShortcut();
  if (key === 'Tab' // tab
    || key === 'ArrowRight'
    || (!completeShortcut && key === '`') // backtick
    || (completeShortcut && key === completeShortcut)) {
    // check current focus position
    // if it's not the same as the position when the completion was suggested, drop it
    let currentFocus = cacheFocus(block);
    if (!focusEquals(currentFocus, focusOnShowComplete)) {
      return;
    }

    let compStr = getCompletionString();
    // FIXME Don't have tab take focus off chat box
    if (compStr === '' && block.getAttribute('id') !== 'chatTextArea') return;
    e.preventDefault();

    if (isSlateElement(block)) {
      const inputEventInit = {
        inputType: 'insertText',
        data: compStr,
        bubbles: true,
        cancelable: false,
      };

      let range = window.getSelection().getRangeAt(0);
      setTimeout(() => {
        range.startContainer.dispatchEvent(new InputEvent('beforeinput', inputEventInit));
      }, 100);
    } else if (isCKElement(block)) {
      insertTextAtCaret2(compStr);
    } else {
      insertTextAtCaret(compStr);
    }

    const hash = getCompletionHash();
    const containerId = getContainerId(e.target);
    clearAndHideComplete();

    const properties = {
      query: currentCompletionQuery,
      completion: compStr,
      model_version: completionModelVersion,
    };
    postCompletion(
      hash,
      true,
      containerId,
      properties,
    );
  }
}
