import { getAssetURL } from '../../utils/chrome-adapter';

export function getBadgeStyling(
  containerBottom,
  badgeContainerMargin,
  badgeSize,
  badgeMargin,
  badgeColor,
  badgeErrorColor,
) {
  return `
<style type="text/css">
.sapling-badge-container {
  position: absolute;
  bottom: ${containerBottom};
  right: 0px;
  font-family: 'Helvetica', 'Arial', sans-serif;
}

.sapling-status-container {
  position: absolute;
  bottom: ${badgeContainerMargin}px;
  right: ${badgeContainerMargin}px;
}

.sapling-badge {
  position: absolute;
  width: ${badgeSize}px;
  height: ${badgeSize}px;
  bottom: ${badgeMargin}px;
  right: ${badgeMargin}px;
  text-align: center;
  border-radius: 50%;
}

.errors {
  background-color: ${badgeErrorColor};
}

.no-errors {
  background-color: ${badgeColor};
}

.connectivity-error .sapling-badge {
  background-color: ${badgeErrorColor};
}

.throttled-error .sapling-badge {
  background-color: orange;
}

.sapling-badge-spinner {
  position: absolute;
  width: ${badgeSize - 4}px;
  height: ${badgeSize - 4}px;
  border: ${Math.floor(badgeSize / 4)}px solid ${badgeColor};
  bottom: ${badgeMargin}px;
  right: ${badgeMargin}px;
  border-top: ${Math.floor(badgeSize / 4)}px solid rgba(0,0,0,0);
  border-radius: 50%;
  animation: rotation 2s infinite linear;
}

.connectivity-error .sapling-badge-spinner {
  border: 2px solid ${badgeErrorColor};
  border-top: 2px solid rgba(0,0,0,0);
}

.sapling-badge-hud {
  position: absolute;
  top: -22px;
  left: -42px;
  transition: all 0.25s;
}

.sapling-tone-hud {
  cursor: pointer;
  pointer-events: initial;
  display: flex;
  transition: all 0.25s;
}

@keyframes rotation {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}
</style>`;
}

