import { getAssetURL } from '../../utils/chrome-adapter';
import { summaryAnnotationsCSS, ANNOTATION_STYLES } from './style-elements';
import { MakeViewPortDraggable } from '../../utils/draggable';
import { isAccountPremium } from '../settings';
import { SAPLING_ENV } from '../../globals';

export class SummaryAnnotations {
  /**
   * Each textarea/content-editable has it's own SummaryAnnotations manager
   * However, there is only a single SummaryAnnotations DOM element per window
   */

  constructor(containerId, annotationsOverlay) {
    this.containerId = containerId;
    this.annotationsOverlay = annotationsOverlay;
    this.summaryWrapper = null;
    this.summaryList = null;
    this.annotationsSpinner = null;
    this.annotationsError = null;
    this.shadowRoot = null;
    this.summaryAnnotationsContainer = null;
    this.summaryDragger = null;
    this.annotationsCache = [];
    this.statisticsCache = {};
  }

  handleDismiss(event) {
    if (event.which === 1) {
      this.annotationsOverlay.hideSummaryAnnotations();
    }
  }

  maybeEmbedSaplingSummaryAnnotations() {
    let pageSummaryAnnotations = $('sapling-summary-annotations');
    if (pageSummaryAnnotations.length) {
      if (!this.summaryAnnotationsContainer) {
        this.summaryAnnotationsContainer = pageSummaryAnnotations.first();
        this.shadowRoot = this.summaryAnnotationsContainer[0].shadowRoot;
      }
    }
    if (!this.summaryAnnotationsContainer) {
      this.summaryAnnotationsContainer = $(`<sapling-summary-annotations>
        </sapling-summary-annotations>`);
      let summaryAnnotationsElements = `
        ${summaryAnnotationsCSS()}
        <div class="summary-annotations-wrapper">
        <span class="annotations-dismiss">×</span>
        <div class="dl-cols summary-annotations-statistics">
          <dl>
            <dt>Characters</dt>
            <dd class="summary-chars">-</dd>
            <dt >Words</dt>
            <dd class="summary-words">-</dd>
            <dt>Sentences</dt>
            <dd class="summary-sentences">-</dd>
          </dl>
          <dl>
            <dt>Readability (Grade)</dt>
            <dd class="summary-readability">-</dd>
            <dt>Reading Time (min)</dt>
            <dd class="summary-reading_time_min">- min</dd>
            <dt>&nbsp;</dt>
            <dd>&nbsp;</dd>
          </dl>
        </div>
        <div class="summary-annotations">
        </div>
        <div class="sapling-annotations-error"></div>
        <div class="sapling-annotations-spinner" style=""><img src="${getAssetURL('assets/fa-spinner-solid.svg')}" /></div>
        </div>`;

      this.summaryAnnotationsContainer[0].attachShadow({ mode: 'open' });
      this.shadowRoot = this.summaryAnnotationsContainer[0].shadowRoot;
      $(this.shadowRoot).html(summaryAnnotationsElements);
      $('html').append(this.summaryAnnotationsContainer);
    }
    this.summaryWrapper = $(this.shadowRoot).find('.summary-annotations-wrapper').first();
    this.summaryList = $(this.shadowRoot).find('.summary-annotations').first();
    this.annotationsSpinner = $(this.shadowRoot).find('.sapling-annotations-spinner').first();
    this.annotationsError = $(this.summaryWrapper).find('.sapling-annotations-error').first();
    $(this.summaryWrapper).find('.annotations-dismiss').on('mousedown', this.handleDismiss.bind(this));
    this.annotationsError.hide();

    this.summaryDragger = new MakeViewPortDraggable(
      this.summaryWrapper,
      this.summaryWrapper,
      null,
      false,
    );
  }

  summaryVisible() {
    // if the summary element is visible, and matches the current container we consider it visible.
    return this.summaryAnnotationsContainer.attr('container-id') === this.containerId;
  }

  showSummary(editsVisible) {
    if (!this.summaryAnnotationsContainer) {
      return;
    }
    this.updateAnnotationsDOM();
    this.summaryAnnotationsContainer.attr('container-id', this.containerId);
    this.updateToggle(editsVisible);
    this.summaryAnnotationsContainer.show();
  }

  hideSummary() {
    if (!this.summaryAnnotationsContainer) {
      return;
    }
    this.summaryAnnotationsContainer.hide();
    this.summaryAnnotationsContainer.attr('container-id', '');
  }

  buildSummaryElement(annotationType, annotationCount, annotationExplanation) {
    // Example: [5] sentences are hard to read
    let annotationStyle = ANNOTATION_STYLES[annotationType];
    let backgroundColor = annotationStyle['background-color'].replace('0.2)', '1.0)');
    let annotationClass = annotationType.replaceAll(' ', '-');
    let annotationLabel = annotationType.replaceAll('_', ' ');

    if (annotationLabel === 'dei') {
      annotationLabel = 'DEI';
    }
    return $(`
      <div class="sapling-summary-annotation">
        <span class="sapling-annotation-count">${annotationCount}</span>
        <span class="sapling-annotation-type ${annotationClass}" style="background-color: ${backgroundColor};">${annotationLabel}</span>
        <span class="sapling-annotation-explanation">
        ${annotationExplanation}
        </span>
      </div>
    `);
  }

  setSummaryAnnotations(annotations) {
    this.annotationsCache = annotations;
    if (this.summaryVisible()) {
      this.updateAnnotationsDOM();
    }
  }

  setStatistics(statistics) {
    this.statisticsCache = statistics;
    if (this.summaryVisible()) {
      this.updateAnnotationsDOM();
    }
  }

  updateAnnotationsDOM() {
    // update statistics
    if (this.summaryWrapper) {
      for (const [prop, val] of Object.entries(this.statisticsCache)) {
        this.summaryWrapper.find(`.summary-${prop}`).text(val);
      }
    }

    // update error counts by category
    this.clear();
    this.annotationsError.hide();
    for (const anno of this.annotationsCache) {
      // Add output of buildSummaryElement
      let summaryEl = this.buildSummaryElement(anno.type, anno.count, anno.explanation);
      this.summaryList.append(summaryEl);
    }

    // add edit toggle
    if (SAPLING_ENV.MODE !== 'SDK' || !Sapling.freemium || isAccountPremium()) {
      this.summaryList.append($(`
        <div>
          <label class="sapling-annotation-toggle-row">
            <div class="sapling-annotation-toggle switch">
              <input type="checkbox">
              <span class="slider"></span>
            </div>
            <span class="sapling-annotation-explanation">
              <span class="toggle-text">Hide Advanced Edits</span>
            </span>
          </label>
        </div>
      `));
      $('input', this.summaryList).change(this.editsToggled.bind(this));
    }
  }

  editsToggled(event) {
    let visible = event.currentTarget.checked;
    this.updateToggle(visible);
    if (visible) {
      this.annotationsOverlay.showEdits();
    } else {
      this.annotationsOverlay.hideEdits();
    }
  }

  updateToggle(visible) {
    $('input', this.summaryList).prop('checked', visible);
    if (visible) {
      $('.toggle-text', this.summaryList).text('Advanced Edits Shown');
    } else {
      $('.toggle-text', this.summaryList).text('Advanced Edits Hidden');
    }
  }

  clear() {
    if (!this.summaryList) {
      return;
    }
    this.summaryList.html('');
  }

  setErrorStatus(msg) {
    this.annotationsError.text(msg);
    this.annotationsError.show();
  }

  showSpinner() {
    if (!this.annotationsSpinner) {
      return;
    }
    this.annotationsSpinner.show();
  }

  hideSpinner() {
    if (!this.annotationsSpinner) {
      return;
    }
    this.annotationsSpinner.hide();
  }
}
