export function acceptCallbackForContainerAndEdit(containerId, edit, properties) {
  let { editId, replacementText } = edit;
  const containerInfo = getContainerInfo(containerId);
  if (!containerInfo) {
    return;
  }
  const { edits, textAreaId, containerDomElement } = containerInfo;
  if (edits) {
    const editObj = edits[editId];
    if (editObj) {
      const { editRange } = editObj;
      postEdit(
        edit.editHash,
        'accept',
        containerId,
        properties,
      );

      if (textAreaId) {
        acceptCallbackForTextArea(textAreaId, editRange, replacementText);
      } else {
        replaceContentEditableSelection(editRange, replacementText, containerDomElement);
      }
      clearTagForOverlayFormat(containerId, editId);
    }
  }
  hideEditControls();
  clearHoveredElement();
}

export function rejectCallbackForOverlayFormat(containerId, edit, properties) {
  const containerInfo = getContainerInfo(containerId);
  if (!containerInfo) {
    return;
  }
  postEdit(
    edit.editHash,
    'reject',
    containerId,
    properties,
  );
  removeCachedEdit(containerId, edit.editId);
  clearTagForOverlayFormat(containerId, edit.editId);
  hideEditControls();
  clearHoveredElement();
  showBadgeCountForOverlay(containerId); // update badge error count
}

export function hoverEventCallbackForOverlayFormat(containerId, edit, properties) {
  const containerInfo = getContainerInfo(containerId);
  if (!containerInfo) {
    return;
  }
  postEdit(
    edit.editHash,
    'hover',
    containerId,
    properties,
  );
}

export function addToDictionaryForContainerAndEdit(containerId, editId) {
  const containerInfo = getContainerInfo(containerId);
  if (!containerInfo) {
    return;
  }
  const { edits } = containerInfo;
  if (edits) {
    const editObj = edits[editId];
    if (editObj) {
      const { edit } = editObj;
      const { originalText } = edit;
      addToDictionary(originalText);
      removeCachedEdit(containerId, editId);
      clearTagForOverlayFormat(containerId, editId);
    }
  }
  hideEditControls();
  clearHoveredElement();
}

function animateAndApplyEdits(containerId, edits) {
  // This function mocks a hover affect over edits to animate them
  // briefly before applying the edit programmatically
  //
  //  edits: dictionary of editInfos from containerInfo
  for (let editId in edits) {
    let editInfos = edits[editId];
    applyTagCSS(editInfos, true);
  }
  setTimeout(() => {
    for (let editId in edits) {
      acceptCallbackForContainerAndEdit(containerId, edits[editId].edit);
    }
  }, 200);
}

// premium account feature
export function acceptAllEdits(block) {
  // the focused block can be a contenteditable with a sapling-id
  // or a textarea with a sapling-textarea-id
  let containerId = getContainerId(block);

  if (!containerId) {
    return; // focused element was not processed by sapling
  }
  const containerInfo = getContainerInfo(containerId);
  if (!containerInfo) {
    return;
  }

  animateAndApplyEdits(containerId, containerInfo.edits);
  if (Object.keys(containerInfo.edits).length !== 0) {
    sendEvent('extension_command', { command: 'accept-all-edits' });
  }
}

// premium account feature
export function acceptEditsInCurrentSentence(block) {
  // the focused block can be a contenteditable with a sapling-id
  // or a textarea with a sapling-textarea-id
  let containerId = getContainerId(block);
  const isTextArea = isCheckableTextElement(block);

  if (!containerId) {
    return; // focused element was not processed by sapling
  }
  const containerInfo = getContainerInfo(containerId);
  if (!containerInfo) {
    return;
  }

  // figure out the html character range of current sentence cursor is on
  let cursorOffset = getCursorTextOffset(block, isTextArea);
  let sentenceTextStartPos = 0;
  let sentenceTextEndPos = 0;

  // Note that textContent do not work properly for textarea
  let sentences = splitHTMLToSentences(isTextArea ? block.value : block.textContent);
  let sentence = null;
  for (sentence of sentences) {
    // we have hit the current sentence
    if (sentence.length + sentenceTextStartPos >= cursorOffset) {
      break;
    }
    // not yet at the current sentence
    sentenceTextStartPos += sentence.length;
  }
  sentenceTextEndPos = sentenceTextStartPos + ((sentence === null) ? 0 : sentence.length);

  // convert sentence character offsets to points and compare againt edit ranges
  // as the text + edit offset  may have changed
  const startLocation = getLocationFromOffset(block, 0, sentenceTextStartPos, null);
  const endLocation = getLocationFromOffset(block, 0, sentenceTextEndPos, null);

  let editsToApply = {};
  // go through the edits and apply ones with overlap with current sentence
  // eslint-disable-next-line guard-for-in
  for (let editId in containerInfo.edits) {
    let edit = containerInfo.edits[editId];
    let compareStart = edit.editRange.comparePoint(startLocation.domElement, startLocation.domOffset);
    let compareEnd = edit.editRange.comparePoint(endLocation.domElement, endLocation.domOffset);
    if (isTextArea) {
      compareStart = Math.sign(sentenceTextStartPos - edit.editRange.startOffset);
      compareEnd = Math.sign(sentenceTextEndPos - edit.editRange.endOffset);
    }
    if (compareStart === -1 && compareEnd === 1) {
      // The edit is contained in the sentence
      editsToApply[editId] = edit;
    } else if (compareStart === 0 || compareEnd === 0) {
      // The edit is partially contained in the sentence
      editsToApply[editId] = edit;
    }
  }

  animateAndApplyEdits(containerId, editsToApply);
  if (Object.keys(editsToApply).length !== 0) {
    sendEvent('extension_command', { command: 'accept-current-sentence' });
  }
}

function maybeEmbedSaplingRephraseControls() {
  if ($('sapling-rephrase-controls').length) {
    let rephraseHost = $('sapling-rephrase-controls')[0];
    let buttonHost = $('sapling-rephrase-button')[0];
    return [rephraseHost, buttonHost];
  }
  let rephraseJq = $('<sapling-rephrase-controls></sapling-rephrase-controls>')
  rephraseJq.css({
    zIndex: '2147483647',
    font: '11pt "Roboto", "Helvetica Neue", Helvetica, Arial, sans-serif',
    position: 'absolute',
  });
  let rephraseHost = rephraseJq[0];
  let buttonHost = $('<sapling-rephrase-button></sapling-rephrase-button>')[0];
  rephraseHost.attachShadow({ mode: 'open' });
  buttonHost.attachShadow({ mode: 'open' });
  $('html').append(rephraseHost);
  $('html').append(buttonHost);
  return [rephraseHost, buttonHost];
}

export function showRephraseControls() {
  if (!isRephraseEnabled()) return;
  const [rephraseHost, buttonHost] = maybeEmbedSaplingRephraseControls();
  let [rephraseControls, rephraseButton] = getOrCreateRephraseControls(rephraseHost, buttonHost);
  rephraseControls.showControls();
}

export function hideRephraseControls() {
  const rephraseHost = $('sapling-rephrase-controls')[0];
  const buttonHost = $('sapling-rephrase-button')[0];
  if (!rephraseHost || !buttonHost) return;
  if (!rephraseHost.shadowRoot || !buttonHost.shadowRoot) return;
  const [rephraseControls, rephraseButton] = getOrCreateRephraseControls(rephraseHost, buttonHost);
  rephraseControls.hideControls();
  const activeRange = getActiveRange();
  if (!activeRange) {
    rephraseButton.hide();
  }
}

export function maybeShowRephraseButton() {
  if (!isRephraseEnabled()) return;
  const [rephraseHost, buttonHost] = maybeEmbedSaplingRephraseControls();
  let rephraseButton = getOrCreateRephraseControls(rephraseHost, buttonHost)[1];
  if (!rephraseButton) {
    return;
  }
  if (!inEditable()) {
    rephraseButton.hide();
    return;
  }
  const activeRange = getActiveRange();
  if (!activeRange) {
    rephraseButton.hide();
    return;
  }
  rephraseButton.show();
}

export function onSelectionChangeToggleAIDetect() {
  if (!isAIDetectEnabled()) {
    return;
  }

  const { aiDetectSelectButton } = initAIDetectSelection();
  if (!aiDetectSelectButton) {
    return;
  }

  const activeRange = getActiveRange(
    false, // editableOnly
  );
  if (!activeRange) {
    aiDetectSelectButton.hide(
      true, /* button only */
    );
    return;
  }

  const popupEditable = document.getElementById('sapling-embedded-editable');
  if (popupEditable && popupEditable.contains(
    activeRange.commonAncestorContainer,
  )) {
    aiDetectSelectButton.hide(
      true, /* button only */
    );
    return;
  }

  aiDetectSelectButton.show();
}
