export class MakeViewPortDraggable {
  constructor(draggableJq, dragJq, ignoreJqSelector, ignoreScroll) {
    this.draggableJq = draggableJq;
    this.dragJq = dragJq || draggableJq;
    this.ignoreJqSelector = ignoreJqSelector;
    this.ignoreScroll = ignoreScroll;

    this.dragMove = this.dragMove.bind(this);
    this.dragMouseUp = this.dragMouseUp.bind(this);
    this.dragMouseDown = this.dragMouseDown.bind(this);

    this.posX = 0;
    this.posY = 0;

    this.dragJq.on('mousedown', this.dragMouseDown);

    window.addEventListener('mouseup', this.dragMouseUp, false);
  }

  dragMove(e) {
    let top = e.clientY + this.posY;
    let left = e.clientX + this.posX;
    if (!this.ignoreScroll) {
      top += window.scrollY;
      left += window.scrollX;
    }
    this.draggableJq.css({ top, left, bottom: '', right: '' });
  }

  dragMouseUp() {
    window.removeEventListener('mousemove', this.dragMove, true);
    this.dragJq.css({ cursor: 'grab' });
  }

  dragMouseDown(e) {
    if (this.ignoreJqSelector && $(e.target).is(this.ignoreJqSelector)) {
      return;
    }
    e.preventDefault();
    const rect = this.draggableJq[0].getBoundingClientRect();
    this.posX = rect.left - e.clientX;
    this.posY = rect.top - e.clientY;

    window.addEventListener('mousemove', this.dragMove, true);
    this.dragJq.css({ cursor: 'grabbing' });
  }
}
