import { SAPLING_ENV } from '../../globals';
import { getIframeBoundingRect } from '../../utils/iframe';

import { ButtonClasses } from './badge-buttons';
import { getDashStyling } from './style-elements';

export class BadgeDashboard {
  constructor() {
    this.parentContainer = null;
    this.popupControls = null;
    this.popupControlsJq = null;
    this.shadowRoot = null;
    this.shadowRootJq = null;

    this.containerId = null;
    this.containerInfo = null;
    this.badgeDashContainer = null;
    this.badgeDash = null;
    this.buttons = {};
  }

  createPopupContainer() {
    if (!this.popupControls) {
      let shadowHost;
      if ($('sapling-popup-controls').length === 0) {
        shadowHost = document.createElement('sapling-popup-controls');
        shadowHost.attachShadow({ mode: 'open' });
        $('html').append(shadowHost);
      } else {
        shadowHost = $('sapling-popup-controls')[0];
      }
      this.popupControls = shadowHost;
      this.popupControlsJq = $(shadowHost);
      this.shadowRoot = shadowHost.shadowRoot;
      this.shadowRootJq = $(this.shadowRoot);
    }
  }

  createDashboardContainer() {
    let { shadowRoot } = this.popupControls;
    if (!this.badgeDashContainer) {
      const dashStyleNode = $(getDashStyling());
      $(shadowRoot).prepend(dashStyleNode);

      this.badgeDashContainer = $('<div class="sapling-badge-dash-container" style="display: none;"></div>');
      this.badgeDash = $('<div class="sapling-badge-dash"></div>');
      this.badgeDashContainer.append(this.badgeDash);
      for (let ButtonClass of ButtonClasses) {
        let button = new ButtonClass(this);
        let elem = button.createElement();
        this.badgeDash.append(elem);
        this.buttons[button.getName()] = button;
        button.refreshState();
      }

      // hide dash when mouse leaves
      this.badgeDash.hover(
        null,
        () => { this.hide(); },
      );
      this.shadowRootJq.append(this.badgeDashContainer);
    }
  }

  createUIElements() {
    this.createPopupContainer();
    this.createDashboardContainer();
  }

  show(parentContainer, badge, containerId, containerInfo) {
    this.parentContainer = parentContainer;
    // bring to top
    if (!this.popupControlsJq.is(':last-child')) {
      this.popupControlsJq.appendTo('html');
    }

    if (containerId === this.containerId) {
      return;
    }
    this.containerId = containerId;
    this.containerInfo = containerInfo;
    this.badgeDashContainer.containerId = containerId;

    let noButtons = true;
    for (const button of Object.values(this.buttons)) {
      button.refreshState();
      if (button.shouldShow()) {
        noButtons = false;
      }
    }
    if (noButtons) {
      return;
    }

    // ensure dashboard is not clipped from top or left side
    let clientRect = badge.badge[0].getBoundingClientRect();
    let left = clientRect.right + window.scrollX - this.badgeDashContainer.width() + 6;
    let top = clientRect.bottom + window.scrollY - this.badgeDashContainer.height() + 6;

    if (SAPLING_ENV.MODE === 'SDK') {
      let iframeAdjustment = getIframeBoundingRect(parentContainer);
      left += iframeAdjustment.x;
      top += iframeAdjustment.y;
    }
    top = Math.max(top, 20);
    left = Math.max(left, 0);
    this.badgeDashContainer.css({
      left,
      top,
    });

    if (this.buttons.EditCountButton) {
      this.buttons.EditCountButton.setEditCount(badge.editCount);
    }

    // TODO: move to refreshState()
    if (this.buttons.ToneButton) {
      this.buttons.ToneButton.updateIcon();
    }
    if (this.buttons.AnnotationsButton) {
      this.buttons.AnnotationsButton.updateIcon();
    }

    this.badgeDashContainer.show();
  }

  hide() {
    if (!this.badgeDashContainer) {
      return;
    }
    this.badgeDashContainer.hide();
    this.containerId = null;
  }
}
