import { isBadgeEnabledOnSite } from '../settings';
import {
  getTopFrameHostname,
  getTopFramePathname,
} from '../../utils/location';
import { documentContains } from '../../utils/sdom';
import { SAPLING_ENV } from '../../globals';
import { getBadgeStyling } from './style-elements';
import { BadgeDashboard } from './badge-dashboard';

let badgeDashboard = null; // one dashboard per page, there can be multiple badges

export class Badge {
  constructor() {
    // jquery fade out/fade in dont work on firefox on initial load
    // 'requestAnimationFrame' called on an object that does not implement interface Window.
    if (EXTENSION_BROWSER === 'ff') {
      this.showSpinner = this.firefoxShowSpinner;
      this.hideSpinner = this.firefoxHideSpinner;
    } else {
      this.showSpinner = this.regularShowSpinner;
      this.hideSpinner = this.regularHideSpinner;
    }
    this.parentContainer = null;
    this.containerId = null;
    this.containerInfo = null;
    this.badgeShadowHost = null;
    this.badge = null;
    this.badgeSpinner = null;
    this.badgeContainer = null;
    this.hostname = getTopFrameHostname();
    this.pathname = getTopFramePathname();
    this.editCount = 0;
  }

  firefoxShowSpinner() {
    if (!this.isEnabled()) {
      return;
    }
    this.badge.hide();
    this.badgeSpinner.show();
  }

  firefoxHideSpinner() {
    if (!this.isEnabled()) {
      return;
    }
    this.badge.show();
    this.badgeSpinner.hide();
  }

  regularShowSpinner() {
    if (!this.isEnabled()) {
      return;
    }
    this.badge.stop().fadeOut(300);
    this.badgeSpinner.stop().fadeIn(300);
  }

  regularHideSpinner() {
    if (!this.isEnabled()) {
      return;
    }
    this.badge.stop().fadeIn(300);
    this.badgeSpinner.stop().fadeOut(300);
  }

  detectOverlappingElement(parentContainer, badgeRect) {
    if (!this.isEnabled()) {
      return null;
    }

    // Get all elements at the badge position
    //console.log('Checking for overlaps at badge position:', badgeRect);
    const elements = document.elementsFromPoint(
      badgeRect.right,
      badgeRect.bottom,
    );
    //console.log(elements);

    // Filter out Sapling's own elements and check for overlapping elements
    for (let elem of elements) {
      if (!elem) continue;

      // Skip if it's the parent container or Sapling overlay
      if (elem === parentContainer ||
          elem.getAttribute('is-sapling-overlay') ||
          $(elem).parents('[is-sapling-overlay]').length > 0) {
        continue;
      }

      // Check if element is visible and has dimensions
      const rect = elem.getBoundingClientRect();
      if (rect.width > 0 && rect.height > 0) {
        const computedStyle = window.getComputedStyle(elem);

        // Check if element is actually visible
        if (computedStyle.display !== 'none' &&
            computedStyle.visibility !== 'hidden' &&
            parseFloat(computedStyle.opacity) > 0) {
          // Check if it's a small icon or button that might overlap
          // (typically icons are less than 50px in both dimensions)
          if (rect.width < 50 && rect.height < 50) {
            // Return the element's rect to calculate shift distance
            return rect;
          }
        }
      }
    }

    // Return null if no overlap detected
    return null;
  }

  createUIElements(parentContainer, shadowHost, containerId, containerInfo) {
    if (!this.isEnabled()) {
      return;
    }
    this.parentContainer = parentContainer;
    this.containerId = containerId;
    this.containerInfo = containerInfo;
    if (this.hostname === 'outlook.live.com') {
      // custom formatting for outlook to keep badge in view
      if (this.badgeShadowHost && !documentContains(this.badgeShadowHost)) {
        this.badgeShadowHost.remove();
        this.badgeShadowHost = null;
      }
      if (!this.badgeShadowHost) {
        this.badgeShadowHost = document.createElement('div');
        this.badgeShadowHost.setAttribute('is-sapling-overlay', true);
        this.badgeShadowHost.attachShadow({ mode: 'open' });
        $(parentContainer.parentNode.parentNode).append(this.badgeShadowHost);
        $(this.badgeShadowHost).css({
          'pointer-events': 'none',
          position: 'sticky',
          bottom: '0px',
        });
      }
    } else {
      this.badgeShadowHost = shadowHost;
    }
    if (this.badgeContainer) {
      return;
    }

    let { shadowRoot } = this.badgeShadowHost;
    if (!badgeDashboard) {
      badgeDashboard = new BadgeDashboard();
      badgeDashboard.createUIElements();
    }

    let containerBottom = '2px';
    if (this.hostname === 'outlook.live.com') {
      // shadowRoot is position: sticky. we want badge above the footer toolbar
      containerBottom = '100px';
    }

    // for smaller text areas, shrink badge and move closer to corner
    let badgeContainerMargin = 2;
    let badgeSize = 8;
    let badgeMargin = 8;
    let badgeColor = '#3f51b5';
    let badgeErrorColor = '#990000';
    if ($(parentContainer).height() < 24 || $(parentContainer).width() < 140) {
      badgeSize = 6;
      badgeMargin = 4;
      badgeContainerMargin = 1;
    }

    if (SAPLING_ENV.MODE === 'SDK') {
      if (Sapling.appearance.customCSS) {
        const customCSSNode = $(`<style type="text/css">${Sapling.appearance.customCSS}</style>`);
        $(shadowRoot).prepend(customCSSNode);
      }
      if (Sapling.appearance.variables.badgeSize) {
        badgeSize = Sapling.appearance.variables.badgeSize;
      }
      if (Sapling.appearance.variables.badgeMargin) {
        badgeMargin = Sapling.appearance.variables.badgeMargin;
      }
      if (Sapling.appearance.variables.badgeColor) {
        badgeColor = Sapling.appearance.variables.badgeColor;
      }
      if (Sapling.appearance.variables.badgeErrorColor) {
        badgeErrorColor = Sapling.appearance.variables.badgeErrorColor;
      }
    }
    const badgeStyleNode = $(getBadgeStyling(
      containerBottom,
      badgeContainerMargin,
      badgeSize,
      badgeMargin,
      badgeColor,
      badgeErrorColor,
    ));
    $(shadowRoot).prepend(badgeStyleNode);

    this.badgeContainer = $('<div class="sapling-badge-container"></div>');
    let statusContainer = $('<div class="sapling-status-container"></div>');
    this.badge = $('<div class="sapling-badge no-errors"></div>');
    this.badgeSpinner = $('<div class="sapling-badge-spinner" style="display: none;"> </div>');
    this.headsUpContainer = $('<div class="sapling-badge-hud" style=""></div>');
    this.badgeContainer.append(statusContainer);

    statusContainer.append(this.headsUpContainer);
    statusContainer.append(this.badge);
    statusContainer.append(this.badgeSpinner);

    $(shadowRoot).append(this.badgeContainer);

    // Check for overlapping elements after a short delay to allow DOM to settle
    setTimeout(() => {
      this.adjustBadgePositionIfNeeded(parentContainer);
    }, 100);
  }

  adjustBadgePositionIfNeeded(parentContainer) {
    if (!this.badgeContainer || !this.isEnabled()) {
      return;
    }

    let totalShift = 0;
    const CUSHION = 10; // pixels of spacing between badge and overlapping element
    const MAX_ITERATIONS = 2; // Check twice for multiple overlapping elements

    // Run overlap detection up to MAX_ITERATIONS times
    for (let i = 0; i < MAX_ITERATIONS; i += 1) {
      // Get the badge container's current position
      const containerRect = this.badgeShadowHost.getBoundingClientRect();

      // Calculate badge position (bottom-right corner)
      const badgeRect = {
        right: containerRect.right - totalShift,
        bottom: containerRect.bottom,
      };

      // Check for overlapping elements
      const overlappingRect = this.detectOverlappingElement(parentContainer, badgeRect);
      if (overlappingRect) {
        // Calculate shift based on overlapping element's width + cushion
        const shift = overlappingRect.width + CUSHION;
        //console.log('Shifting badge by', shift, 'pixels to avoid overlap');
        totalShift += shift;
        // Apply the accumulated shift
        this.badgeContainer.css('right', `${totalShift}px`);
      } else {
        // No more overlaps, we're done
        break;
      }
    }
  }

  removeUIElements() {
    if (this.badgeShadowHost) {
      this.badgeShadowHost.remove();
    }
  }

  isEnabled() {
    let NO_BADGE_DOMAINS = ['notion.so', 'trello.com', 'canva.com'];
    if (!isBadgeEnabledOnSite()) {
      return false;
    }

    if (NO_BADGE_DOMAINS.includes(this.hostname) || this.pathname.includes('wp-admin')) {
      return false;
    }
    return true;
  }

  updateBadgeCount(count) {
    if (!this.isEnabled()) {
      return;
    }

    if (count === 0) {
      this.badge.removeClass('errors');
      this.badge.addClass('no-errors');
    } else {
      this.badge.removeClass('no-errors');
      this.badge.addClass('errors');
    }

    // count indicates successful fetch of edits
    if (!this.badgeContainer) {
      return;
    }
    this.badgeContainer.removeClass('connectivity-error');

    // transition spinner to edit count
    this.hideSpinner();
    this.editCount = count;
    // push update to dashboard if this is the active badge

    if (this.containerId === badgeDashboard.badgeDashContainer.containerId && badgeDashboard.buttons.EditCountButton) {
      badgeDashboard.buttons.EditCountButton.setEditCount(count);
    }
  }

  showErrorState() {
    if (this.badgeContainer) {
      this.badgeContainer.addClass('connectivity-error');
    }
    if (this.badgeDashboard && this.badgeDashboard.buttons && this.badgeDashboard.buttons.EditCountButton) {
      this.badgeDashboard.buttons.EditCountButton.setToolTipText('Check your internet and firewall settings.');
    }
  }

  showThrottledState() {
    this.hideSpinner();
    this.badgeContainer.addClass('throttled-error');
    if (badgeDashboard.buttons.ThrottleButton) {
      // Unclear under what conditions ThrottleButton is caught as undefined sometimes in Sentry
      // Under normal operations if badgeDashboard is instantiated so are the buttons
      badgeDashboard.buttons.ThrottleButton.isThrottled = true;
      badgeDashboard.buttons.ThrottleButton.refreshState();
    }
  }

  showBadgeDashboard() {
    badgeDashboard.show(this.parentContainer, this, this.containerId, this.containerInfo);
  }
}
