import { initializeObservers } from './observers';
import { disconnectAllObservers } from './teardown';

import {
  fetchGrammarAndCompleteEnableSettings,
  getUserPromise,
  isAccountPremium,
  isRephraseEnabled,
  isUserEmailConfirmed,
} from '../settings';
import {
  acceptAllEdits,
  acceptEditsInCurrentSentence,
  showRephraseControls,
} from '../highlight/edit-action';
import {
  updateTextAreaOverlayWithText,
} from '../highlight/textarea';
import {
  clearInlineSearchState,
  recursiveGetIframeBoundingRect,
  launchSnippetControl,
} from '../snippet/snippet-autoexpander';
import {
  addSnippet,
  cacheSnippetFocus,
  injectSnippet,
  resetSnippetFocus,
} from '../snippet/snippet-injector';
import { SnippetControl } from '../snippet/snippet-controls';
import { maybeInitializeSuggestionObserver } from '../suggest/suggest';
import { getTopFrameHostname } from '../../utils/location';
import { isInIframe } from '../../utils/iframe';
import { initKeyboardShortcutMessageListener } from '../../utils/chrome-adapter';
import { getDeepActiveElement } from '../../utils/sdom';

let IS_POPUP = false;
let snippetControl = new SnippetControl();

function commandListener(request, sender, sendResponse) {
  let command = request.action;
  if (command === 'event/NEW_USER') {
    getUserPromise(false);
  } else if (command === 'init/HISTORY_PUSHSTATE') {
    // Some elements may still be loaded dynamically
    maybeInitializeSuggestionObserver(updateTextAreaOverlayWithText);
  } else if (command === 'event/GRAMMAR_OR_COMPLETE_TOGGLED') {
    if (getTopFrameHostname() === request.hostname) {
      if (request.observersOff) {
        disconnectAllObservers();
      } else if (request.observersOn) {
        fetchGrammarAndCompleteEnableSettings(() => {
          disconnectAllObservers();
          initializeObservers();
        });
      }
    }
  }

  if (!isUserEmailConfirmed()) {
    return;
  }

  if (command === 'get-iframe-bounding-rect') {
    recursiveGetIframeBoundingRect(request);
  } else if (command === 'return-iframe-bounding-rect') {
    launchSnippetControl(request.x, request.y, request.windowHeight, request.caretY);
  } else if (command === 'toggle-snippet-controls' ||
      command === 'snippet-control') {
    // - Launch the snippet finder only on the root DOM
    // - Use the same DOM to find focus element for snippet injection
    // - In the special case of x-origin IFRAME, the IFRAME needs
    //   to do the injection itself. We use chrome.runtime to pass messages
    //   between the snippet finder -> background page -> x-origin iframe

    let focusedElement = getDeepActiveElement(document);
    if (!focusedElement) {
      return;
    }

    if (request.data && (
        request.data.query != null ||
        request.data.key != null ||
        request.data.show === false)) {
      snippetControl.handleSnippetControlCommand(request.data);
      return;
    }
    // figure out focus
    cacheSnippetFocus(focusedElement, request.data);

    // we only want to launch snippet controls from the main non-iframe window
    if (isInIframe()) {
      return;
    }
    const coordinates = request.data && request.data.coordinates;
    const show = request.data && request.data.show;
    snippetControl.toggleSnippetFinder(coordinates, show);
  } else if (command === 'snippet-selected') {
    injectSnippet(request.snippet, request.currentQueryTerms, request.queryCount);
  } else if (command === 'snippet-add') {
    addSnippet();
  } else if (command === 'hide-snippet-controls') {
    clearInlineSearchState();
    resetSnippetFocus();
  } else if (command === 'snippet-focus-found') {
    if (isInIframe()) {
      // iframes do not have snippet controls
      return;
    }
    snippetControl.setSnippetFinderMode(request.mode);
  } else if (command === 'toggle-rephrase-controls') {
    let focusedElement = getDeepActiveElement(document);
    if (focusedElement) {
      showRephraseControls();
    }
  }

  if (!isAccountPremium()) {
    return;
  }
  // everything below is a premium account feature

  if (command === 'accept-all-edits') {
    let focusedElement = getDeepActiveElement(document);
    if (focusedElement) {
      acceptAllEdits(focusedElement);
    }
  } else if (command === 'accept-all-edits-popup' && IS_POPUP) {
    let popupEditable = document.getElementById('sapling-embedded-editable');
    acceptAllEdits(popupEditable);
  } else if (command === 'accept-current-sentence-edits') {
    let focusedElement = getDeepActiveElement(document);
    if (focusedElement) {
      acceptEditsInCurrentSentence(focusedElement);
    }
  } else if (command === 'accept-current-sentence-edits-popup' && IS_POPUP) {
    let popupEditable = document.getElementById('sapling-embedded-editable');
    acceptEditsInCurrentSentence(popupEditable);
  }
}

export function initializeCommandObserver(isPopup) {
  initKeyboardShortcutMessageListener(commandListener);
  IS_POPUP = isPopup;
}
