import * as Sentry from '@sentry/browser';

export function isPopupEnvironment() {
  if (window.location.protocol === 'chrome-extension:') {
    if (window.location.hash === '#saplingpopup') {
      // defined in manifest: action.default_popup
      return true;
    }
  } else if (window.location.protocol === 'ms-browser-extension:') {
    return true;
  } else if (window.location.protocol === 'moz-extension:') {
    return true;
  }
  return false;
}
