import { SAPLING_ENV } from '../globals';
import { isInIframe } from '../utils/iframe';
import { sendEvent, getAssetURL, syncStorageGet, syncStorageSet } from '../utils/chrome-adapter';
import { getTopFrameHostname, getTopFramePathname } from '../utils/location';
import { isUserAnonymous, setGrammarAndCompleteEnabledSettings } from './settings';

// Tooltips for onboarding and other communication

let connectivityObserverId = null;
const CONNECTIVITY_ALERT_FREQUENCY = 24 * 60 * 60 * 1000; // If user dismisses, hide for a day
const LOGIN_PROMPT_ALERT_FREQUENCY = 24 * 60 * 60 * 1000; // If user dismisses, hide for a day

function stopConnectivityObserver() {
  // Call when the connectivity tooltip is dismissed
  if (connectivityObserverId) {
    clearInterval(connectivityObserverId);
    connectivityObserverId = null;
  }
}

function hideToolTip() {
  let shadowHost = $('sapling-popup-controls')[0];
  if (!shadowHost) {
    return;
  }
  let { shadowRoot } = shadowHost;
  $('.sapling-tooltip-container', shadowRoot).hide();
}

function showToolTip(
  tooltipPosition,
  showLogo,
  titleHtml,
  tooltipHtml,
  primaryButtonText,
  secondaryButtonText,
  primaryButtonCallback,
  secondaryButtonCallback,
  blurDismiss=false,
) {
  // Don't show tooltips in iframes
  if (isInIframe()) {
    return;
  }

  let shadowHost;
  let shadowHostJq = $('sapling-popup-controls');
  if (shadowHostJq.length === 0) {
    shadowHost = document.createElement('sapling-popup-controls');
    shadowHost.attachShadow({ mode: 'open' });
    $('html').append(shadowHost);
  } else {
    // bring to top
    if (!shadowHostJq.is(':last-child')) {
      shadowHostJq.appendTo('html');
    }
    shadowHost = shadowHostJq[0];
  }
  let { shadowRoot } = shadowHost;

  if (!$('.sapling-tooltip-container', shadowRoot)[0]) {
    setTopFrameUrl(shadowRoot);
  } else {
    $('.sapling-tooltip-button-primary', shadowRoot).off('mousedown');
    $('.sapling-tooltip-button-secondary', shadowRoot).off('mousedown');
    $('.sapling-tooltip-container', shadowRoot).off('blur');
  }

  const tooltipHeight = 190; // 160 + padding
  const tooltipWidth = 250; // 220 + padding
  let { top, left } = tooltipPosition;

  let effectiveWindowHeight = window.innerHeight + window.scrollY;
  let effectiveWindowWidth = window.innerWidth + window.scrollX;
  if (top !== null && top + tooltipHeight > effectiveWindowHeight) {
    top = effectiveWindowHeight - tooltipHeight;
    tooltipPosition.top = Math.max(top, 0);
  }

  if (left !== null && left + tooltipWidth > effectiveWindowWidth) {
    left = effectiveWindowWidth - tooltipWidth;
    tooltipPosition.left = Math.max(left, 0);
  }

  $('.sapling-tooltip', shadowRoot).css(tooltipPosition);
  if (showLogo) {
    $('.sapling-tooltip-icon', shadowRoot).show();
  } else {
    $('.sapling-tooltip-icon', shadowRoot).hide();
  }
  $('.sapling-tooltip-title', shadowRoot).html(titleHtml);
  $('.sapling-tooltip-body', shadowRoot).html(tooltipHtml);
  $('.sapling-tooltip-button-primary', shadowRoot).text(primaryButtonText);
  if (secondaryButtonText) {
    $('.sapling-tooltip-button-secondary', shadowRoot).text(secondaryButtonText);
  } else {
    $('.sapling-tooltip-button-secondary', shadowRoot).hide();
  }

  if (blurDismiss) {
    $('.sapling-tooltip-container', shadowRoot).attr('tabindex', -1).on('blur', function() {
      $(this).hide();
    });
  }

  $('.sapling-tooltip-button-primary', shadowRoot).on('mousedown', (event) => {
    if (event.which !== 1) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();

    $('.sapling-tooltip-container', shadowRoot).hide();
    if (primaryButtonCallback) {
      primaryButtonCallback();
    }
  });

  $('.sapling-tooltip-button-secondary', shadowRoot).on('mousedown', (event) => {
    if (event.which !== 1) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();

    $('.sapling-tooltip-container', shadowRoot).hide();
    if (secondaryButtonCallback) {
      secondaryButtonCallback();
    }
  });

  if (blurDismiss) {
    $('.sapling-tooltip-container', shadowRoot).show().focus();
  } else {
    $('.sapling-tooltip-container', shadowRoot).show();
  }
}

function GDocsShowToolTip() {
  showToolTip(
    { right: 72, bottom: 8, top: '', left: '' },
    true,
    'Sapling for Google Docs',
    'Get the <a href="https://gsuite.google.com/marketplace/app/sapling_grammar_checker_and_writing_assi/1078289388837" target="_blank">Sapling GSuite Add-on</a> to use Sapling in Google Docs.',
    'Install',
    'Dismiss',
    () => {
      syncStorageSet({ ToolTipGDocs: true });
      window.open(
        'https://gsuite.google.com/marketplace/app/sapling_grammar_checker_and_writing_assi/1078289388837',
        '_blank',
      );
    },
    () => {
      syncStorageSet({ ToolTipGDocs: true });
    },
  );
}

