export function maybeShowGSuiteTooltip() {
  const hostname = getTopFrameHostname();
  const pathname = getTopFramePathname();
  if (hostname !== 'docs.google.com') {
    return;
  }
  if (pathname.startsWith('/document/d')) {
    syncStorageGet(['ToolTipGDocs'], (result) => {
      if (!result.ToolTipGDocs) {
        GDocsShowToolTip();
      }
    });
  } else if (pathname.startsWith('/presentation/d')) {
    syncStorageGet(['ToolTipGSlides'], (result) => {
      if (!result.ToolTipGSlides) {
        GSlidesShowToolTip();
      }
    });
  }
}

export function showDisableTooltip(currentlyEnabled, top, left) {
  let title;
  let description;
  let primaryButton;
  let secondaryButton;
  let descriptionTail = 'Sapling';
  let toggle = 'Disable';
  let toggleOpposite = 'Keep Enabled';
  if (SAPLING_ENV.MODE === 'SDK') {
    descriptionTail = 'grammar checking';
  }
  if (!currentlyEnabled) {
    toggle = 'Enable';
    toggleOpposite = 'Keep Disabled';
  }
  showToolTip(
    { top, left, right: '', bottom: '' },
    false,
    `${toggle} ${descriptionTail}`,
    `${toggle} ${descriptionTail} on pages of site: <b>${getTopFrameHostname()}</b>?`,
    toggle,
    toggleOpposite,
    () => {
      if (SAPLING_ENV.MODE === 'SDK') {
        Sapling.setUserToggleEnabled(!currentlyEnabled);
        if (currentlyEnabled) {
          sendEvent('sdk-disable');
        } else {
          sendEvent('sdk-enable');
        }
      } else {
        setGrammarAndCompleteEnabledSettings(!currentlyEnabled, !currentlyEnabled);
      }
    },
    null,
    true,
  );
}

export function maybeShowConnectivityTooltip() {
  if (navigator.onLine) {
    return;
  }
  syncStorageGet(['ToolTipConnectivity'], (result) => {
    const currentTimeMs = new Date().getTime();
    const cutOff = currentTimeMs - CONNECTIVITY_ALERT_FREQUENCY;
    if (!result.ToolTipConnectivity || result.ToolTipConnectivity < cutOff) {
      showToolTip(
        // eslint-disable-next-line object-curly-newline
        { right: 8, bottom: 8, top: '', left: '' },
        true,
        'Are you offline?',
        'Sapling needs an Internet connection to make suggestions.',
        'OK',
        null,
        () => {
          stopConnectivityObserver();
          syncStorageSet({ ToolTipConnectivity: currentTimeMs });
        },
        null,
      );
      startConnectivityObserver();
    }
  });
}

export function maybeShowLoginTooltip() {
  if (!isUserAnonymous()) {
    return;
  }
  syncStorageGet(['ToolTipLogin'], (result) => {
    const currentTimeMs = new Date().getTime();
    const cutOff = currentTimeMs - LOGIN_PROMPT_ALERT_FREQUENCY;
    if (!result.ToolTipLogin || result.ToolTipLogin < cutOff) {
      showToolTip(
        { right: 8, bottom: 8, top: '', left: '' },
        true,
        'Are you signed in?',
        "For full access to Sapling, make sure you are on your team's enterprise plan.",
        'Sign in',
        'Cancel',
        () => {
          let signInUrl = `${SAPLING_ENV.WEBSITE_URL}/user/sign-in`;
          window.open(signInUrl);
          syncStorageSet({ ToolTipLogin: currentTimeMs });
        },
        () => {
          syncStorageSet({ ToolTipLogin: currentTimeMs });
        },
      );
    }
  });
}

function startConnectivityObserver() {
  // Call when the connectivity tooltip is shown.
  // If the user gains connectivity auto-dismiss the tooltip
  connectivityObserverId = setInterval(
    () => {
      if (navigator.onLine) {
        hideToolTip();
        stopConnectivityObserver();
      } else {
        syncStorageGet(['ToolTipConnectivity'], (result) => {
          const currentTimeMs = new Date().getTime();
          const cutOff = currentTimeMs - CONNECTIVITY_ALERT_FREQUENCY;
          if (result.ToolTipConnectivity && result.ToolTipConnectivity > cutOff) {
            hideToolTip();
            stopConnectivityObserver();
          }
        });
      }
    },
    5000,
  );
}

