import { firstRangeSubset, firstRangeFrontIntersect } from '../../utils/range';

function resolveTwoEdits(edit1, edit2) {
  let range1 = edit1.editRange;
  let range2 = edit2.editRange;
  // if one edit inside another, prioritize inside edit
  if (firstRangeSubset(range1, range2)) {
    return edit2;
  }
  if (firstRangeSubset(range2, range1)) {
    return edit1;
  }

  // if partial overlap, prioritize first
  if (firstRangeFrontIntersect(range1, range2)) {
    return edit1;
  }
  if (firstRangeFrontIntersect(range2, range1)) {
    return edit2;
  }

  return edit1;
}

export function resolveActiveEdits(edits) {
  let priorityEdit = edits[0];
  for (let i = 1; i < edits.length; i++) {
    priorityEdit = resolveTwoEdits(priorityEdit, edits[i]);
  }

  return priorityEdit;
}
