import { diffChars } from 'diff';

import { SAPLING_ENV } from '../../globals';
import { onUpdateTagForOverlayFormatPerContainer } from '../../ui/highlight/overlay';
import {
  getContainerId,
  getCSSOverlayForElement,
  getTextAreaId,
  isCodeMirrorElement,
  isDraftJSElement,
  isLexicalElement,
  isPSPDFKitElement,
  isQuillJSEditor,
  isSlateElement,
  isTinyMCEElement,
  setTextAreaId,
} from '../../utils/html-utils';
import { getTopFrameHostname } from '../../utils/location';
import { documentContains } from '../../utils/sdom';

// We cache results that should be shown and propagate the changes
// to the frontend overlay.
// {
//   saplingTextAreaId: {
//     textArea: (domElement),
//     overlayDomElement: (domElement),
//   }
// }
const saplingIdToTextAreaInfo = {};

export function initOrUpdateTextAreaOverlay(textArea) {
  const saplingTextAreaId = getTextAreaId(textArea);
  saplingIdToTextAreaInfo[saplingTextAreaId] = saplingIdToTextAreaInfo[saplingTextAreaId] || {};
  let { overlayDomElement } = saplingIdToTextAreaInfo[saplingTextAreaId];

  if (overlayDomElement && !documentContains(overlayDomElement)) {
    overlayDomElement.remove();
    overlayDomElement = null;
  }
  if (!overlayDomElement) {
    // remove if exists
    let { nextSibling } = textArea;
    while (nextSibling &&
        nextSibling.nodeType === Node.ELEMENT_NODE &&
        getTextAreaId(nextSibling)) {
      let nodeToRemove = nextSibling;
      nextSibling = nextSibling.nextSibling;
      nodeToRemove.remove();
    }

    overlayDomElement = document.createElement('div');
    overlayDomElement.setAttribute('contenteditable', true);
    if (SAPLING_ENV.MODE === 'SDK') {
      // prevent conflict with sapling browser extension
      overlayDomElement.setAttribute('sapling-ignore', true);
    }
    setTextAreaId(overlayDomElement, saplingTextAreaId);
    $(textArea).after(overlayDomElement);
    saplingIdToTextAreaInfo[saplingTextAreaId].overlayDomElement = overlayDomElement;
    saplingIdToTextAreaInfo[saplingTextAreaId].textArea = textArea;
  }

  const { frameDimensions } = getCSSOverlayForElement(textArea);
  let { width, height } = frameDimensions;
  if ($(textArea).css('box-sizing') === 'content-box') {
    // we need to subtract padding and border from width and height
    const paddingLeft = parseInt($(textArea).css('padding-left')) || 0;
    const paddingRight = parseInt($(textArea).css('padding-right')) || 0;
    const paddingTop = parseInt($(textArea).css('padding-top')) || 0;
    const paddingBottom = parseInt($(textArea).css('padding-bottom')) || 0;
    const borderLeft = parseInt($(textArea).css('border-left-width')) || 0;
    const borderRight = parseInt($(textArea).css('border-right-width')) || 0;
    const borderTop = parseInt($(textArea).css('border-top-width')) || 0;
    const borderBottom = parseInt($(textArea).css('border-bottom-width')) || 0;
    width = width - paddingLeft - paddingRight - borderLeft - borderRight;
    height = height - paddingTop - paddingBottom - borderTop - borderBottom;
  }

  let compStyle = document.defaultView.getComputedStyle(textArea);
  $(overlayDomElement).css({
    'z-index': compStyle.getPropertyValue('z-index'),
    spellcheck: false,
    'font-style': $(textArea).css('font-style'),
    'font-weight': $(textArea).css('font-weight'),
    'font-size': $(textArea).css('font-size'),
    'font-family': $(textArea).css('font-family'),
    'text-align': $(textArea).css('text-align'),
    'line-height': $(textArea).css('line-height'),
    'letter-spacing': $(textArea).css('letter-spacing'),
    'word-spacing': $(textArea).css('word-spacing'),
    color: 'transparent',
    opacity: 0,
    background: $(textArea).css('background'),
    'overflow-x': $(textArea).css('overflowX'),
    'overflow-y': $(textArea).css('overflowY'),
    'background-color': 'transparent',
    'white-space': $(textArea).css('whiteSpace'),
    'pointer-events': 'none',
    'border-top-width': $(textArea).css('border-top-width'),
    'border-top-style': $(textArea).css('border-top-style'),
    'border-top-color': 'transparent',
    'border-left-width': $(textArea).css('border-left-width'),
    'border-left-style': $(textArea).css('border-left-style'),
    'border-left-color': 'transparent',
    'box-sizing': $(textArea).css('boxSizing'),
    padding: $(textArea).css('padding'),
    'padding-top': $(textArea).css('padding-top'),
    'padding-left': $(textArea).css('padding-left'),
    overflow: $(textArea).css('overflow'),
    display: $(textArea).css('display'),
    position: frameDimensions.position,
    left: frameDimensions.left,
    top: frameDimensions.top,
    height,
    width,
  });
  if (EXTENSION_BROWSER === 'ff') {
    $(overlayDomElement).css({
      'overflow-x': 'auto',
      'overflow-y': 'auto',
      overflow: 'auto',
    });
  }
  if (textArea.nodeName.toLowerCase() === 'input') {
    $(overlayDomElement).css({
      'display': 'flex',
      'align-items': 'center',
      'white-space': 'nowrap',
      'overflow': 'hidden',
      'text-overflow': 'clip',
    });
  }

  /* Hack for sites where line-height doesn't match computed */
  const hostname = getTopFrameHostname();
  if (hostname === 'linkedin.com') {
    $(textArea).css({ 'line-height': compStyle.getPropertyValue('line-height') });
  }

  return overlayDomElement;
}

export function getTextArea(textAreaId) {
  if (textAreaId in saplingIdToTextAreaInfo) {
    return saplingIdToTextAreaInfo[textAreaId].textArea;
  }
  return null;
}

export function updateTextAreaOverlayWithText(textAreaId, value) {
  if (textAreaId in saplingIdToTextAreaInfo) {
    const { overlayDomElement } = saplingIdToTextAreaInfo[textAreaId];
    const { firstChild } = overlayDomElement;
    const oldValue = overlayDomElement.textContent;
    const newValue = `${value}\n`;
    if (oldValue !== newValue) {
      // if difference in text is really big, then just replace everything.
      if (Math.abs(newValue.length - oldValue.length) > 250) {
        overlayDomElement.textContent = newValue;
      } else if (firstChild && firstChild.nodeType === Node.TEXT_NODE) {
        const diffs = diffChars(oldValue, newValue);
        let runningOffset = 0;
        for (let idx = 0; idx < diffs.length; idx += 1) {
          const diff = diffs[idx];
          const valueLength = diff.value.length;
          const currentValue = overlayDomElement.textContent;
          if (diff.added) {
            firstChild.insertData(runningOffset, diff.value);
            runningOffset += valueLength;
          } else {
            // check value is correct
            if (diff.value !== currentValue.substr(runningOffset, valueLength)) {
              // if fail then just replace everything
              overlayDomElement.textContent = newValue;
              break;
            }
            if (diff.removed) {
              firstChild.deleteData(runningOffset, valueLength);
            } else {
              runningOffset += valueLength;
            }
          }
        }
      } else {
        overlayDomElement.textContent = newValue;
      }
    }
  }
}

export function acceptCallbackForTextArea(textAreaId, editRange, replacementText) {
  if (textAreaId in saplingIdToTextAreaInfo) {
    const { textArea } = saplingIdToTextAreaInfo[textAreaId];
    replaceTextAreaSelection(textArea, editRange.startOffset, editRange.endOffset, replacementText);
  }
}

export function updateTextAreaScroll(textAreaId) {
  if (textAreaId in saplingIdToTextAreaInfo) {
    const { textArea, overlayDomElement } = saplingIdToTextAreaInfo[textAreaId];
    overlayDomElement.scrollTop = textArea.scrollTop;
    overlayDomElement.scrollLeft = textArea.scrollLeft;

    // the below makes it far less laggy.
    const containerId = getContainerId(overlayDomElement);
    onUpdateTagForOverlayFormatPerContainer(containerId);
  }
}

export function updateTextAreaInScrollable(textAreaId) {
  if (textAreaId in saplingIdToTextAreaInfo) {
    const { textArea, overlayDomElement } = saplingIdToTextAreaInfo[textAreaId];
    const { frameDimensions } = getCSSOverlayForElement(textArea);
    $(overlayDomElement).css({
      left: frameDimensions.left,
      top: frameDimensions.top,
      height: frameDimensions.height,
      width: frameDimensions.width,
    });

    // the below makes it far less laggy.
    const containerId = getContainerId(overlayDomElement);
    onUpdateTagForOverlayFormatPerContainer(containerId);
  }
}

function removeTextAreaIdForOverlayFormat(saplingTextAreaId) {
  if (saplingTextAreaId in saplingIdToTextAreaInfo) {
    saplingIdToTextAreaInfo[saplingTextAreaId].overlayDomElement.remove();
    delete saplingIdToTextAreaInfo[saplingTextAreaId];
  }
}

export function removeTextAreaFromParentContainer(textArea) {
  const saplingTextAreaId = getTextAreaId(textArea);
  if (saplingTextAreaId) {
    removeTextAreaIdForOverlayFormat(saplingTextAreaId);
  }
}

function applySingleRangeSelection(range) {
  let sel = window.getSelection();
  sel.removeAllRanges();
  sel.addRange(range);

  const nativeSelection = window.getSelection();
  nativeSelection.setBaseAndExtent(
    range.startContainer,
    range.startOffset,
    range.endContainer,
    range.endOffset,
  );
}

export function replaceTextAreaSelection(textAreaDOM, startOffset, endOffset, replacementText) {
  textAreaDOM.focus();
  let val = textAreaDOM.value;
  textAreaDOM.selectionStart = startOffset;
  textAreaDOM.selectionEnd = endOffset;

  let newValue = val.slice(0, startOffset) + replacementText + val.slice(endOffset);
  const hostname = getTopFrameHostname();
  const isVinted = hostname.endsWith('vinted.net') || hostname.endsWith('vinted.com');
  try {
    if (!hostname.endsWith('overleaf.com') && !isVinted) {
      // causes double insertion on certain websites
      document.execCommand('insertText', false, replacementText);
    }
  } catch (e) {
  }

  if (!isCodeMirrorElement(textAreaDOM)) {
    // causes double insertion on certain websites
    if (textAreaDOM.value !== newValue) {
      if (isVinted) {
        // Vinted's controlled textarea can apply execCommand at its own cursor before this fallback runs.
        const nativeDesc = Object.getOwnPropertyDescriptor(Object.getPrototypeOf(textAreaDOM), 'value');
        const instanceDesc = Object.getOwnPropertyDescriptor(textAreaDOM, 'value');
        const setter = (nativeDesc && nativeDesc.set) || (instanceDesc && instanceDesc.set);
        if (setter) {
          setter.call(textAreaDOM, newValue);
        } else {
          textAreaDOM.value = newValue;
        }
      } else {
        textAreaDOM.value = newValue;
      }
    }
  }

  // collapse to the front
  textAreaDOM.selectionStart = startOffset;
  textAreaDOM.selectionEnd = startOffset;

  textAreaDOM.dispatchEvent(new Event('input', { bubbles: true, cancelable: false }));
  document.body.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true }));
}

export function pasteContentEditableSelectionWithHTML(range, plainText, htmlText, container, style) {
  if (isSlateElement(container)) {
    replaceContentEditableSelection_slatejs(range, plainText);
    return;
  }
  applySingleRangeSelection(range);

  const hostname = getTopFrameHostname();
  if (hostname.includes('gladly.')) {
    // not sure why, but applySingleRangeSelection doesn't work unless it is called twice
    // once async
    setTimeout(() => {
      applySingleRangeSelection(range);
    }, 10);
  }

  // Check if we're in a TinyMCE editor
  const isTinyMCE = isTinyMCEElement(container);

  // For TinyMCE editors, modify the HTML to preserve styling using spans
  let modifiedHtmlText = htmlText;
  if (isTinyMCE && htmlText) {
    const styleStr = Object.entries(style)
      .map(([key, value]) => `${key}: ${value};`)
      .join(' ');

    // Create a simple container for our HTML
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = htmlText;

    // Function to replace paragraph tags with double line breaks
    function replaceParagraphsWithBrs(element) {
      if (!element) return;

      // Convert the NodeList to an array for safe iteration during modifications
      const paragraphs = Array.from(element.querySelectorAll('p'));

      paragraphs.forEach(paragraph => {
        const content = paragraph.innerHTML;
        const span = document.createElement('span');
        span.innerHTML = content + '<br><br>';
        paragraph.parentNode.replaceChild(span, paragraph);
      });
    }

    // Function to wrap each text node in a styled span
    function wrapTextNodesWithStyledSpan(element) {
      if (!element) return;

      const childNodes = Array.from(element.childNodes);

      childNodes.forEach(node => {
        // If it's a text node with non-whitespace content
        if (node.nodeType === Node.TEXT_NODE && node.textContent.trim()) {
          const span = document.createElement('span');
          span.setAttribute('style', styleStr);
          span.textContent = node.textContent;
          element.replaceChild(span, node);
        }
        // If it's an element node, recursively process its children
        else if (node.nodeType === Node.ELEMENT_NODE) {
          // Skip processing of existing styled spans
          if (node.tagName.toLowerCase() === 'span' && node.getAttribute('style')) {
            return;
          }
          wrapTextNodesWithStyledSpan(node);
        }
      });
    }

    // Apply the paragraph replacement first
    replaceParagraphsWithBrs(tempDiv);

    // Then apply the wrapper function to our temp container
    wrapTextNodesWithStyledSpan(tempDiv);

    // Get the modified HTML
    modifiedHtmlText = tempDiv.innerHTML;

    try {
      // Focus the container first
      container.focus();

      // Try direct insertion for TinyMCE
      range.deleteContents();

      // Create a fragment with the styled content
      const fragment = document.createDocumentFragment();
      const tempDiv2 = document.createElement('div');
      tempDiv2.innerHTML = modifiedHtmlText;

      while (tempDiv2.firstChild) {
        fragment.appendChild(tempDiv2.firstChild);
      }

      // Insert the fragment directly
      range.insertNode(fragment);

      // Fix for text nodes after insertion losing styling
      const insertionPoint = range.endContainer;

      // Collect styles from current and ancestor spans
      const collectStyles = (node) => {
        let styles = {};
        let current = node;

        // Walk up the DOM tree to collect styles from spans
        while (current && current !== container) {
          if (current.nodeType === Node.ELEMENT_NODE &&
              current.tagName.toLowerCase() === 'span' &&
              current.getAttribute('style')) {
            const styleAttr = current.getAttribute('style');
            const stylePairs = styleAttr.split(';').filter(Boolean);

            for (const pair of stylePairs) {
              const [key, value] = pair.split(':').map(s => s.trim());
              if (key && value && !styles[key]) {
                styles[key] = value;
              }
            }
          }
          current = current.parentNode;
        }
        return styles;
      };

      // Get styles at insertion point
      const insertionStyles = collectStyles(insertionPoint);
      const styleStr = Object.entries(insertionStyles)
        .map(([key, value]) => `${key}: ${value}`)
        .join('; ');

      if (styleStr) {
        // Process following nodes to apply styles
        const processNextNodes = (node) => {
          let current = node;
          while (current && current !== container) {
            const next = current.nextSibling;
            if (!next) {
              current = current.parentNode;
              continue;
            }

            // Skip <br> tags
            if (next.nodeType === Node.ELEMENT_NODE && next.tagName.toLowerCase() === 'br') {
              current = next;
              continue;
            }

            // Handle text nodes
            if (next.nodeType === Node.TEXT_NODE && next.textContent.trim()) {
              const span = document.createElement('span');
              span.setAttribute('style', styleStr);
              span.textContent = next.textContent;
              next.parentNode.replaceChild(span, next);
              current = span;
              continue;
            }

            // Handle unstyled inline elements
            if (next.nodeType === Node.ELEMENT_NODE &&
                !next.getAttribute('style') &&
                window.getComputedStyle(next).display === 'inline') {
              const span = document.createElement('span');
              span.setAttribute('style', styleStr);
              next.parentNode.replaceChild(span, next);
              span.appendChild(next);
              current = span;
              continue;
            }

            current = next;
          }
        };

        // First, handle the insertion point itself if it's a text node
        if (insertionPoint.nodeType === Node.TEXT_NODE && insertionPoint.textContent.trim()) {
          const span = document.createElement('span');
          span.setAttribute('style', styleStr);
          span.textContent = insertionPoint.textContent;

          if (insertionPoint.parentNode) {
            insertionPoint.parentNode.replaceChild(span, insertionPoint);
            // Update insertionPoint reference to the new span
            const newInsertionPoint = span;

            // Process following nodes starting from the new insertion point
            processNextNodes(newInsertionPoint);
          }
        }
        // If it's an element node without style, apply styles to it
        else if (insertionPoint.nodeType === Node.ELEMENT_NODE &&
                insertionPoint.getAttribute('style') != styleStr) {
          // Also handle any unstyled text nodes inside the insertion point
          const textNodes = [];
          const findTextNodes = (node) => {
            if (node.nodeType === Node.TEXT_NODE && node.textContent.trim()) {
              textNodes.push(node);
            } else if (node.nodeType === Node.ELEMENT_NODE) {
              // Skip already styled spans
              if (node.tagName.toLowerCase() === 'span' && node.getAttribute('style') == styleStr) {
                return;
              }
              Array.from(node.childNodes).forEach(findTextNodes);
            }
          };

          findTextNodes(insertionPoint);
          // Wrap text nodes in styled spans
          textNodes.forEach(textNode => {
            const span = document.createElement('span');
            span.setAttribute('style', styleStr);
            span.textContent = textNode.textContent;
            textNode.parentNode.replaceChild(span, textNode);
          });

          // Process following nodes
          processNextNodes(insertionPoint);
        }
        else {
          // Process following nodes normally
          processNextNodes(insertionPoint);
        }
      }

      // Move cursor to end of inserted content
      range.collapse(false);

      // Update selection
      const selection = window.getSelection();
      selection.removeAllRanges();
      selection.addRange(range);

      // Fire events
      container.dispatchEvent(new Event('input', { bubbles: true }));
      container.dispatchEvent(new Event('change', { bubbles: true }));

      // Fire a keyup event - this sometimes helps TinyMCE recognize the change
      document.dispatchEvent(new KeyboardEvent('keyup', { bubbles: true }));

      return; // Skip standard paste logic
    } catch (e) {
      // Continue with standard paste if direct insertion fails
    }
  }

  // Standard paste logic for non-TinyMCE editors if TinyMCE paste logic failed
  let dt = new DataTransfer();
  dt.setData('text/plain', plainText);
  if (htmlText) {
    dt.setData('text/html', `<meta charset='utf-8'>${isTinyMCE ? modifiedHtmlText : htmlText}`);
  }

  const inputEventInit = {
    inputType: 'insertFromPaste',
    dataTransfer: dt,
    bubbles: true,
    cancelable: true,
    isComposing: false,
  };
  let event = new InputEvent('beforeinput', inputEventInit);

  const textPre = container.innerText;
  setTimeout(() => {
    range.startContainer.dispatchEvent(event);
    if (!event.defaultPrevented || textPre === container.innerText) {
      document.body.dataset.saplingSnippetInsert = true;
      document.execCommand('paste');
      delete document.body.dataset.saplingSnippetInsert;
    }
  }, 100);

  document.body.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true }));

  // Styles get clobbered on paste with SFDC. set them again after paste
  if (hostname.includes('force.com') && !isTinyMCE) {
    for (const [styleKey, styleVal] of Object.entries(style)) {
      // eslint-disable-next-line no-param-reassign
      container.style[styleKey] = styleVal;
    }
  }
}

export function replaceContentEditableSelection_slatejs(range, replacementText) {
  const inputEventInit = {
    inputType: 'insertReplacementText',
    data: replacementText,
    bubbles: true,
    cancelable: false,
  };

  applySingleRangeSelection(range);
  setTimeout(() => {
    range.startContainer.dispatchEvent(new InputEvent('beforeinput', inputEventInit));
  }, 0);
}

export function replaceContentEditableSelection_fb(range, replacementText) {
  applySingleRangeSelection(range);
  const inputEventInit = {
    inputType: 'insertText',
    data: replacementText,
    bubbles: true,
    cancelable: false,
  };
  applySingleRangeSelection(range);
  document.body.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true }));
  setTimeout(() => {
    const {
      startContainer, startOffset,
      endContainer, endOffset,
    } = range;

    // Clamp offsets to node length; the DOM may have mutated in the 50 ms delay.
    const safeStartOffset = Math.min(startOffset, startContainer.nodeType === Node.TEXT_NODE ? startContainer.length : startContainer.childNodes.length);
    const safeEndOffset = Math.min(endOffset, endContainer.nodeType === Node.TEXT_NODE ? endContainer.length : endContainer.childNodes.length);

    try {
      if (startContainer === endContainer) {
        startContainer.replaceData(safeStartOffset, safeEndOffset - safeStartOffset, replacementText);
      } else {
        range.deleteContents();
        startContainer.insertData(safeStartOffset, replacementText);
      }
    } catch (e) {
      // Ignore DOM mutation errors
    }

    // fire input event so sites with React propagate text changes
    range.startContainer.dispatchEvent(new InputEvent('input', inputEventInit));
    document.body.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true }));
  }, 50);
}

// only apply focus
export function applySingleRange(range) {
  const nativeSelection = window.getSelection();
  if (typeof nativeSelection.setBaseAndExtent === 'function') {
    nativeSelection.setBaseAndExtent(
      range.endContainer,
      range.endOffset,
      range.endContainer,
      range.endOffset,
    );
  } else {
    const newRange = document.createRange();
    newRange.setStart(range.endContainer, range.endOffset);
    nativeSelection.addRange(newRange);
  }
}

export function replaceContentEditableSelection(range, replacementText, containerDomElement) {
  if (isSlateElement(containerDomElement)) {
    replaceContentEditableSelection_slatejs(range, replacementText);
    return;
  }
  const hostname = getTopFrameHostname();
  if (hostname.endsWith('facebook.com') || hostname.endsWith('messenger.com') ||
      hostname.endsWith('whatsapp.com') || hostname.endsWith('workplace.com') ||
      hostname.endsWith('instagram.com') || isDraftJSElement(containerDomElement) ||
      isQuillJSEditor(containerDomElement) || isLexicalElement(containerDomElement)
    ) {
    replaceContentEditableSelection_fb(range, replacementText);
    return;
  }

  const {
    startContainer, startOffset,
    endContainer, endOffset,
  } = range;

  // Clamp offsets to node length to prevent IndexSizeError when the DOM has mutated
  // (e.g. direct nodeValue replacement by the host app) since the Range was captured.
  // Refs: SAPLING-WEBSITE-3DZ
  const safeStartOffset = Math.min(startOffset, startContainer.nodeType === Node.TEXT_NODE ? startContainer.length : startContainer.childNodes.length);
  const safeEndOffset = Math.min(endOffset, endContainer.nodeType === Node.TEXT_NODE ? endContainer.length : endContainer.childNodes.length);

  let staticRange;
  try {
    staticRange = new StaticRange({
      startContainer,
      startOffset: safeStartOffset,
      endContainer,
      endOffset: safeEndOffset,
    });
  } catch (e) {
    // skip if StaticRange construction fails (unsupported or detached node)
  }

  applySingleRangeSelection(range);
  const inputEventInit = {
    inputType: 'insertText',
    data: replacementText,
    bubbles: true,
    cancelable: false,
    ...(staticRange ? { targetRanges: [staticRange] } : {}),
  };
  // before input event needed by coda.io
  try {
    range.startContainer.dispatchEvent(new InputEvent('beforeinput', inputEventInit));
  } catch (e) {
    // Ignore InputEvent construction errors (e.g. offset out of range after concurrent mutation)
  }
  applySingleRange(range);
  document.body.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true }));

  if (startContainer === endContainer) {
    if (typeof startContainer.replaceData === 'function') {
      startContainer.replaceData(safeStartOffset, safeEndOffset - safeStartOffset, replacementText);
    } else {
      // startContainer is an Element node (no replaceData); fall back to range manipulation
      range.deleteContents();
      // Skip empty insert so backspace/delete paths (fillins.js) don't leave zero-length
      // text nodes that destabilize offset mapping in getLocationFromOffset
      if (replacementText !== '') {
        range.insertNode(document.createTextNode(replacementText));
      }
    }
  } else {
    // deleteContents() may detach startContainer from the DOM (e.g. when startOffset === 0
    // and the whole node is within the range), which would make startContainer.insertData a
    // silent no-op. Always insert via the range, which is collapsed to the correct point.
    range.deleteContents();
    if (typeof startContainer.insertData === 'function') {
      startContainer.insertData(safeStartOffset, replacementText);
    } else {
      // Skip empty insert so backspace/delete paths (fillins.js) don't leave zero-length
      // text nodes that destabilize offset mapping in getLocationFromOffset
      if (replacementText !== '') {
        range.insertNode(document.createTextNode(replacementText));
      }
    }
  }

  // fire input event so sites with React propagate text changes.
  // targetRanges must be omitted: the DOM has already mutated so any StaticRange
  // offsets may now exceed the node length, causing an IndexSizeError.
  const { targetRanges, ...inputEventInitWithoutRanges } = inputEventInit;
  range.startContainer.dispatchEvent(new InputEvent('input', inputEventInitWithoutRanges));
  document.body.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true }));

  if (isPSPDFKitElement(containerDomElement) || isTinyMCEElement(containerDomElement)) {
    containerDomElement.blur();
    containerDomElement.focus();
  }
}
