import { areAdvancedEditsEnabled, isAdvancedEditsEnabledOnSite } from '../settings';
import { getStatistics } from '../../requests/index';
import { SummaryAnnotations } from './annotations';
import { SAPLING_ENV } from '../../globals';

export class AnnotationsOverlay {
  constructor(containerId, shadowHost) {
    this.containerId = containerId;
    this.shadowHost = shadowHost;

    // Put this above badge
    this.annotationsContainer = null;
    this.summaryAnnotations = null;
    // Each annotation should have
    // - Range (optional if summary annotation)
    // - Annotation type (multiple types for both summary and inline)
    // - Explanation (this will be flexible)
    // - Count (if summary annotation)
    this.annotationsAlwaysVisible = false;
    this.editsVisible = true;
    this.annotationEditInfos = {}; // editId -> editInfo
    this.lastQueryText = null;
  }

  createUIElements() {
    if (!areAdvancedEditsEnabled()) return;
    if (!isAdvancedEditsEnabledOnSite()) {
      this.editsVisible = false;
    }
    let { shadowRoot } = this.shadowHost;

    this.annotationsContainer = $('.sapling-annotations-container', shadowRoot);
    if (!this.annotationsContainer.length) {
      this.annotationsContainer = $(`
        <div class="sapling-annotations-container">
        </div>
      `);
    }

    $(shadowRoot).append(this.annotationsContainer);

    if (!this.summaryAnnotations) {
      this.summaryAnnotations = new SummaryAnnotations(this.containerId, this);
      this.summaryAnnotations.maybeEmbedSaplingSummaryAnnotations();
    }

    this.hideSummaryAnnotations();
    if (SAPLING_ENV.MODE === 'SDK' && Sapling.autoShowAdvancedEdits) {
      this.annotationsAlwaysVisible = true;
    }
  }

  positionAnnotations() {
    let overlayRect = this.shadowHost.getBoundingClientRect();
    let summaryAnnotationsWrapper = this.summaryAnnotations.summaryWrapper;
    let left = overlayRect.left + window.scrollX + overlayRect.width -
      summaryAnnotationsWrapper.width() - 6;
    let top = overlayRect.bottom + window.scrollY -
      summaryAnnotationsWrapper.height() - 25;
    top = Math.max(top, 20);
    left = Math.max(left, 0);
    summaryAnnotationsWrapper.css({
      position: 'absolute',
      left,
      top,
    });
  }

  updateAnnotationSummary() {
    let summary = {};
    for (let editInfo of Object.values(this.annotationEditInfos)) {
      let type = editInfo.edit.category;
      if (!type) {
        continue;
      }
      let explanation = editInfo.edit.description;
      if (!summary[type]) {
        summary[type] = {
          type,
          count: 0,
          explanation,
        };
      }
      summary[type].count++;
    }
    this.summaryAnnotations.setSummaryAnnotations(Object.values(summary));
    this.positionAnnotations();
    this.summaryAnnotations.updateToggle(this.editsVisible);
  }

  updateAnnotationForOverlay(editId, editInfo) {

    this.annotationEditInfos[editId] = editInfo;
    for (let saplingSpan of editInfo.domElements) {
      if (this.annotationsAlwaysVisible || this.editsVisible) {
        $(saplingSpan).show();
      } else {
        $(saplingSpan).hide();
      }
    }
  }

  clearAnnotationForOverlay(editId) {
    delete this.annotationEditInfos[editId];
  }

  queryAndUpdate() {
    if (!areAdvancedEditsEnabled()) return;

    // Based on text editor state change, update the annotations
    this.summaryAnnotations.showSpinner();

    let queryEl = $(this.shadowHost).prevAll('[sapling-id],[sapling-textarea-id]').first()[0];
    if (typeof queryEl === 'undefined' || !queryEl) {
      // TODO Determine when this happens
      this.summaryAnnotations.hideSpinner();
      return;
    }
    let queryText = queryEl.innerHTML.trim();
    // No update
    if (!queryText || this.lastQueryText === queryText) {
      this.summaryAnnotations.hideSpinner();
      return;
    }
    this.lastQueryText = queryText;

    let sessionId = $(this.shadowHost).prev().attr('sapling-id');
    if (!sessionId) sessionId = $(this.shadowHost).prev().attr('sapling-textarea-id');

    getStatistics(queryText, 'en', sessionId, (data) => {
      this.summaryAnnotations.setStatistics(data.statistics);
    }, (error) => {
      if (error) {
        this.setErrorStatus(error.toString());
      }
    });

    this.summaryAnnotations.hideSpinner();
  }

  toggleSummaryAnnotations() {
    if (this.summaryAnnotations.summaryVisible()) {
      this.hideSummaryAnnotations();
    } else {
      this.showSummaryAnnotations();
    }
  }

  showEdits() {
    this.editsVisible = true;
    for (let editInfo of Object.values(this.annotationEditInfos)) {
      for (let saplingSpan of editInfo.domElements) {
        $(saplingSpan).show();
      }
    }
    this.summaryAnnotations.updateToggle(this.editsVisible);
  }

  hideEdits() {
    this.editsVisible = false;
    if (this.annotationsAlwaysVisible) {
      return;
    }
    for (let editInfo of Object.values(this.annotationEditInfos)) {
      for (let saplingSpan of editInfo.domElements) {
        $(saplingSpan).hide();
      }
    }
    this.summaryAnnotations.updateToggle(this.editsVisible);
  }

  showSummaryAnnotations() {
    this.summaryAnnotations.showSummary(this.editsVisible);
    this.positionAnnotations();

  }

  hideSummaryAnnotations() {
    this.summaryAnnotations.hideSummary();
  }

  removeUIElements() {
    if (this.shadowHost) {
      this.shadowHost.remove();
    }
    this.annotationEditInfos = {};
  }
}
