const Url = require('url-parse');

let TOP_FRAME_HOSTNAME = '';
let TOP_FRAME_PATHNAME = '';

export function setTopFrameUrl(url) {
  let parsedURL = new Url(url);
  TOP_FRAME_HOSTNAME = parsedURL.hostname || window.location.hostname;
  TOP_FRAME_PATHNAME = parsedURL.pathname || window.location.pathname;
}

export function getTopFrameHostname() {
  return TOP_FRAME_HOSTNAME;
}

export function getTopFramePathname() {
  return TOP_FRAME_PATHNAME;
}
