import { sendAuthenticatedBackendRequest } from '../utils';

let SNIPPETS = null;
let SET_TIME_MILLISECONDS = 0;
let REQUEST_TIME_MILLISECONDS = 0;
let TIME_DELTA = 15 * 1000;
let RESPONSES = [];

function isCacheFresh() {
  const currentDate = new Date();
  const currentTime = currentDate.getTime();
  if (SET_TIME_MILLISECONDS && (currentTime - SET_TIME_MILLISECONDS) < TIME_DELTA) {
    return true;
  }
  return false;
}

function isRequestInFlight() {
  const currentDate = new Date();
  const currentTime = currentDate.getTime();
  if (REQUEST_TIME_MILLISECONDS && (currentTime - REQUEST_TIME_MILLISECONDS) < TIME_DELTA) {
    return true;
  }
  return false;
}

export function getShortcutSnippetsFromCache(response) {
  if (SNIPPETS && isCacheFresh()) {
    response({ data: SNIPPETS, status: true, success: true });
    return;
  }

  RESPONSES.push(response);
  if (isRequestInFlight()) {
    return;
  }
  const currentDate = new Date();
  REQUEST_TIME_MILLISECONDS = currentDate.getTime();
  const timeZoneOffset = currentDate.getTimezoneOffset();
  sendAuthenticatedBackendRequest(
    `/snippets/shortcut_snippets?timeZoneOffset=${timeZoneOffset}`,
    'get',
    {},
    (resp) => {
      REQUEST_TIME_MILLISECONDS = 0;
      SET_TIME_MILLISECONDS = currentDate.getTime();
      SNIPPETS = resp.snippets;
      for (let idx = 0; idx < RESPONSES.length; idx += 1) {
        const response = RESPONSES[idx];
        response({ data: SNIPPETS, status: true, success: true });
      }
      RESPONSES = [];
    },
    (e) => {
      if (SNIPPETS) {
        response({ data: null, status: true, success: true });
      } else {
        response({ data: null, status: true, success: false });
      }
    },
  );
}
